function runtime_config_registry(): array
{
    return supplycore_runtime_settings_registry();
}

function runtime_config_flat_fields(): array
{
    $flat = [];
    foreach (runtime_config_registry() as $sectionKey => $sectionSpec) {
        foreach ((array) ($sectionSpec['fields'] ?? []) as $path => $fieldSpec) {
            $flat[$path] = ['section' => $sectionKey] + (array) $fieldSpec;
        }
    }

    return $flat;
}

function runtime_config_sections_for_ui(): array
{
    $effective = supplycore_runtime_config();
    $flat = runtime_config_flat_fields();
    $sections = [];

    foreach (runtime_config_registry() as $sectionKey => $sectionSpec) {
        $fields = [];
        foreach ((array) ($sectionSpec['fields'] ?? []) as $path => $fieldSpec) {
            $segments = explode('.', $path, 2);
            $groupKey = (string) ($segments[0] ?? '');
            $leafKey = (string) ($segments[1] ?? '');
            $value = $effective[$groupKey][$leafKey] ?? ($fieldSpec['default'] ?? '');
            $fields[$path] = (array) $fieldSpec + ['value' => $value];
        }
        $sections[$sectionKey] = [
            'title' => (string) ($sectionSpec['title'] ?? ucfirst(str_replace('_', ' ', $sectionKey))),
            'description' => (string) ($sectionSpec['description'] ?? ''),
            'fields' => $fields,
        ];
    }

    return $sections;
}

function runtime_config_settings_from_request(array $request): array
{
    $flat = runtime_config_flat_fields();
    $settings = [];

    foreach ($flat as $path => $spec) {
        if (($spec['database_backed'] ?? false) !== true || ($spec['editable'] ?? false) !== true) {
            continue;
        }

        $type = (string) ($spec['type'] ?? 'string');
        $input = runtime_config_request_value($request, $path);
        if ($type === 'bool') {
            $input = runtime_config_request_has_key($request, $path) ? '1' : '0';
        }
        $value = (string) supplycore_cast_runtime_config_value($input ?? ($spec['default'] ?? ''), $type);

        // Whitelist enum values: when a field declares ``options``, only
        // keys from that map are accepted. Anything else (stale form
        // submission, tampered POST) falls back to the declared default
        // so we never persist a value the reader can't make sense of.
        $options = is_array($spec['options'] ?? null) ? $spec['options'] : [];
        if ($options !== [] && !array_key_exists($value, $options)) {
            $value = (string) ($spec['default'] ?? '');
        }

        $settings[$path] = $value;
    }

    return $settings;
}

function runtime_config_request_key(string $path): string
{
    return str_replace('.', '_', $path);
}

function runtime_config_request_value(array $request, string $path): mixed
{
    if (array_key_exists($path, $request)) {
        return $request[$path];
    }

    $normalizedKey = runtime_config_request_key($path);
    if (array_key_exists($normalizedKey, $request)) {
        return $request[$normalizedKey];
    }

    return null;
}

function runtime_config_request_has_key(array $request, string $path): bool
{
    if (array_key_exists($path, $request)) {
        return true;
    }

    return array_key_exists(runtime_config_request_key($path), $request);
}

function migrate_local_config_to_app_settings(string $localConfigPath): array
{
    if (!is_file($localConfigPath)) {
        return ['ok' => false, 'message' => 'local.php not found', 'imported' => 0];
    }

    $loaded = (static function (string $path): mixed {
        return require $path;
    })($localConfigPath);
    if (!is_array($loaded)) {
        return ['ok' => false, 'message' => 'local.php must return an array', 'imported' => 0];
    }

    $registry = runtime_config_flat_fields();
    $toPersist = [];
    foreach ($registry as $path => $spec) {
        if (($spec['database_backed'] ?? false) !== true) {
            continue;
        }

        [$section, $key] = explode('.', $path, 2);
        if (!isset($loaded[$section]) || !is_array($loaded[$section]) || !array_key_exists($key, $loaded[$section])) {
            continue;
        }
        $toPersist[$path] = (string) supplycore_cast_runtime_config_value($loaded[$section][$key], (string) ($spec['type'] ?? 'string'));
    }

    if ($toPersist !== []) {
        save_settings($toPersist);
        supplycore_runtime_config_refresh();
    }

    return ['ok' => true, 'message' => 'Imported local.php runtime values into app_settings.', 'imported' => count($toPersist)];
}

function active_section(): string
{
    $section = (string) ($_GET['section'] ?? 'workspace');
    // Strip stray ?suffix when users append ?debug=perf with ? instead of &
    if (str_contains($section, '?')) {
        $section = strstr($section, '?', true);
    }
    $aliases = setting_section_aliases();
    if (array_key_exists($section, $aliases)) {
        $section = (string) $aliases[$section];
    }

    return array_key_exists($section, setting_sections()) ? $section : 'workspace';
}

function get_settings(array $keys = []): array
{
    try {
        $all = db_app_settings_all();
    } catch (Throwable) {
        return [];
    }

    if ($keys === []) {
        return $all;
    }

    $settings = [];
    foreach ($keys as $key) {
        $safeKey = (string) $key;
        if (array_key_exists($safeKey, $all)) {
            $settings[$safeKey] = $all[$safeKey];
        }
    }

    return $settings;
}

function get_setting(string $key, mixed $default = null): mixed
{
    try {
        return db_app_setting_get($key, $default);
    } catch (Throwable) {
        return $default;
    }
}

function save_settings(array $settings): bool
{
    try {
        db_transaction(function () use ($settings): void {
            db_app_settings_upsert_many($settings);
        });
    } catch (Throwable) {
        return false;
    }

    return true;
}

function supplycore_backup_data_scope_options(): array
{
    return [
        'none' => 'Settings only (app_settings)',
        'all' => 'Settings + all database tables',
    ];
}

function supplycore_backup_parse_scope(string $scope): string
{
    return array_key_exists($scope, supplycore_backup_data_scope_options()) ? $scope : 'none';
}

function supplycore_backup_selected_tables(string $scope): array
{
    if ($scope !== 'all') {
        return [];
    }

    try {
        return array_values(array_filter(
            db_table_names(),
            static fn (string $tableName): bool => $tableName !== 'app_settings'
        ));
    } catch (Throwable) {
        return [];
    }
}

function supplycore_backup_build_payload(string $scope = 'none'): array
{
    $safeScope = supplycore_backup_parse_scope($scope);
    $settings = get_settings();
    $tables = supplycore_backup_selected_tables($safeScope);
    $tablesPayload = [];

    if ($tables !== []) {
        $tablesPayload = db_tables_export_payload($tables);
    }

    $fingerprintSeed = [
        'scope' => $safeScope,
        'settings' => $settings,
        'data_row_counts' => array_map(
            static fn (array $table): int => (int) ($table['row_count'] ?? 0),
            $tablesPayload
        ),
    ];
    $fingerprint = hash('sha256', json_encode($fingerprintSeed, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE));

    return [
        'meta' => [
            'format' => 'supplycore-backup-v1',
            'created_at_utc' => gmdate('Y-m-d\TH:i:s\Z'),
            'app_name' => app_name(),
            'scope' => $safeScope,
            'fingerprint' => $fingerprint,
        ],
        'settings' => $settings,
        'data' => [
            'tables' => $tablesPayload,
            'table_count' => count($tablesPayload),
            'row_count_total' => array_sum(array_map(
                static fn (array $table): int => (int) ($table['row_count'] ?? 0),
                $tablesPayload
            )),
        ],
    ];
}

function supplycore_backup_send_download(array $payload): never
{
    $scope = (string) (($payload['meta']['scope'] ?? 'none'));
    $timestamp = gmdate('Ymd_His');
    $filename = sprintf('supplycore-backup-%s-%s.json', $scope, $timestamp);
    $json = json_encode($payload, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
    if (!is_string($json)) {
        throw new RuntimeException('Failed to encode backup payload.');
    }

    header('Content-Type: application/json; charset=utf-8');
    header('Content-Disposition: attachment; filename="' . $filename . '"');
    header('Cache-Control: no-store, no-cache, must-revalidate');
    header('Pragma: no-cache');
    echo $json;
    exit;
}

function supplycore_backup_decode_uploaded_file(array $file): array
{
    $tmp = (string) ($file['tmp_name'] ?? '');
    if ($tmp === '' || !is_uploaded_file($tmp)) {
        return ['ok' => false, 'message' => 'No backup file was uploaded.', 'payload' => null];
    }

    $raw = file_get_contents($tmp);
    if ($raw === false || trim($raw) === '') {
        return ['ok' => false, 'message' => 'Uploaded backup file is empty.', 'payload' => null];
    }

    try {
        $decoded = json_decode($raw, true, 512, JSON_THROW_ON_ERROR);
    } catch (Throwable $exception) {
        return ['ok' => false, 'message' => 'Uploaded file is not valid JSON: ' . $exception->getMessage(), 'payload' => null];
    }

    if (!is_array($decoded)) {
        return ['ok' => false, 'message' => 'Uploaded backup payload must be a JSON object.', 'payload' => null];
    }

    return ['ok' => true, 'message' => 'Backup file loaded.', 'payload' => $decoded];
}

function supplycore_backup_validate_payload(array $payload): array
{
    $format = (string) ($payload['meta']['format'] ?? '');
    if ($format !== 'supplycore-backup-v1') {
        return ['ok' => false, 'message' => 'Unsupported backup format. Expected supplycore-backup-v1.'];
    }

    if (!isset($payload['settings']) || !is_array($payload['settings'])) {
        return ['ok' => false, 'message' => 'Backup payload is missing a valid settings map.'];
    }

    $tables = (array) ($payload['data']['tables'] ?? []);
    foreach ($tables as $tableName => $tablePayload) {
        if (!is_string($tableName) || $tableName === '') {
            return ['ok' => false, 'message' => 'Backup payload contains an invalid table key.'];
        }
        if (!is_array($tablePayload)) {
            return ['ok' => false, 'message' => 'Backup payload contains an invalid table payload for ' . $tableName . '.'];
        }
        if (!is_array($tablePayload['rows'] ?? null)) {
            return ['ok' => false, 'message' => 'Backup payload table ' . $tableName . ' has no rows array.'];
        }
    }

    return ['ok' => true, 'message' => 'Backup payload validated.'];
}

function supplycore_backup_restore_payload(array $payload, bool $restoreSettings, bool $restoreData, bool $dryRun = false): array
{
    $validation = supplycore_backup_validate_payload($payload);
    if (($validation['ok'] ?? false) !== true) {
        return $validation;
    }

    $settings = (array) ($payload['settings'] ?? []);
    $tables = (array) ($payload['data']['tables'] ?? []);
    $tableNames = array_keys($tables);
    $summary = [
        'settings_keys' => count($settings),
        'table_count' => count($tableNames),
        'table_names' => $tableNames,
    ];

    if ($dryRun) {
        return ['ok' => true, 'message' => 'Dry-run completed. Backup payload is valid for restore.', 'summary' => $summary];
    }

    try {
        if ($restoreSettings) {
            save_settings($settings);
        }

        if ($restoreData && $tables !== []) {
            $summary['table_restore'] = db_tables_replace_from_payload($tables);
            db_app_settings_cache_clear();
        }

        supplycore_runtime_config_refresh();
    } catch (Throwable $exception) {
        return ['ok' => false, 'message' => 'Restore failed: ' . $exception->getMessage(), 'summary' => $summary];
    }

    return ['ok' => true, 'message' => 'Backup restore completed successfully.', 'summary' => $summary];
}

