function scheduler_pressure_summary(): array
{
    $view = sync_schedule_settings_view_model();

    return (array) ($view['health_summary'] ?? []);
}

function scheduler_record_lock_conflicts(): void
{
    foreach (db_sync_schedule_fetch_locked_due_jobs(25) as $job) {
        $jobKey = (string) ($job['job_key'] ?? '');
        if ($jobKey === '') {
            continue;
        }

        $nextDueAt = (string) ($job['next_due_at'] ?? '');
        $lateness = $nextDueAt !== '' ? max(0, time() - (int) strtotime($nextDueAt)) : 0;
        db_scheduler_job_event_insert($jobKey, 'lock_conflict', ['locked_until' => $job['locked_until'] ?? null], $lateness, null);
    }
}

function scheduler_should_defer_due_job(array $job, string $pressure): bool
{
    $priority = (string) ($job['priority'] ?? 'normal');
    if (scheduler_job_force_execution($job)) {
        return false;
    }

    if ($pressure === 'healthy') {
        return false;
    }

    // Never defer jobs that are significantly overdue (past 2x their interval).
    // This prevents pipeline compute jobs from being permanently starved by
    // high-priority sync jobs that consume all concurrency slots.
    $scheduledFor = trim((string) ($job['next_due_at'] ?? $job['next_run_at'] ?? ''));
    $intervalSeconds = max(60, (int) ($job['interval_minutes'] ?? 5) * 60);
    if ($scheduledFor !== '' && strtotime($scheduledFor) !== false) {
        $overdueSeconds = max(0, time() - (int) strtotime($scheduledFor));
        if ($overdueSeconds >= $intervalSeconds * 2) {
            return false;
        }
    }

    if ($pressure === 'busy') {
        return $priority === 'normal' && in_array((string) ($job['concurrency_policy'] ?? 'single'), ['background', 'single'], true);
    }

    if ($pressure === 'congested') {
        return !in_array($priority, ['highest', 'high'], true);
    }

    return !scheduler_is_protected_job((string) ($job['job_key'] ?? '')) && $priority !== 'highest';
}

function scheduler_defer_due_job(array $job, string $reason): void
{
    $scheduleId = (int) ($job['id'] ?? 0);
    if ($scheduleId <= 0) {
        return;
    }

    $intervalMinutes = max(1, (int) ($job['interval_minutes'] ?? 30));
    $nextDueAt = gmdate('Y-m-d H:i:s', time() + ($intervalMinutes * 60));
    db_sync_schedule_set_next_due_at($scheduleId, $nextDueAt, 'deferred_capacity');
    db_scheduler_job_event_insert((string) ($job['job_key'] ?? ''), 'deferred_capacity', ['reason' => $reason], 0, null);
    db_scheduler_tuning_action_log((string) ($job['job_key'] ?? ''), 'system', 'pressure_deferral', $reason, [], ['next_due_at' => $nextDueAt], ['pressure' => $reason]);
    if ((string) ($job['job_key'] ?? '') === 'deal_alerts_sync') {
        deal_alert_record_scheduler_deferral($reason, $job);
    }
}

function scheduler_due_jobs(): array
{
    scheduler_registry_bootstrap();
    scheduler_record_lock_conflicts();

    $definitions = scheduler_job_definitions();
    $pressure = scheduler_pressure_summary()['pressure'] ?? 'healthy';
    $due = db_sync_schedule_fetch_due_jobs(20);
    $claimed = [];

    foreach ($due as $job) {
        $scheduleId = (int) ($job['id'] ?? 0);
        if ($scheduleId <= 0) {
            continue;
        }

        $jobKey = (string) ($job['job_key'] ?? '');
        if ($jobKey === '') {
            continue;
        }

        $statusRow = db_scheduler_job_current_status_fetch_map([$jobKey])[$jobKey] ?? [];
        $changeDecision = scheduler_evaluate_change_aware_run($job, $statusRow);
        if (is_array($changeDecision) && !$changeDecision['run']) {
            scheduler_record_change_aware_skip($job + ['recent_skip_count' => ($statusRow['recent_skip_count'] ?? 0)], $changeDecision);
            continue;
        }

        if (scheduler_should_defer_due_job($job, (string) $pressure)) {
            scheduler_defer_due_job($job, 'Deferred low-priority job to preserve high-priority freshness under ' . $pressure . ' scheduler pressure.');
            continue;
        }

        $definition = $definitions[$jobKey] ?? null;
        $defaultTimeout = (int) (($definition['timeout_seconds'] ?? 0) ?: ($job['timeout_seconds'] ?? 300));
        $timeoutSeconds = scheduler_job_timeout_seconds($jobKey, $defaultTimeout, $job, $definition);
        $defaultLockTtl = (int) (($definition['lock_ttl_seconds'] ?? 0) ?: max(120, $timeoutSeconds + 60));
        $lockTtl = scheduler_job_lock_ttl_seconds($defaultLockTtl, $timeoutSeconds);
        $claimedJob = db_sync_schedule_claim_job($scheduleId, $lockTtl);
        if ($claimedJob !== null) {
            $claimed[] = $claimedJob;
            continue;
        }

        db_scheduler_job_event_insert($jobKey, 'lock_skipped', [], 0, null);
    }

    return $claimed;
}

function scheduler_idle_backfill_jobs(?callable $logger = null, int $limit = 12): array
{
    scheduler_registry_bootstrap();

    $definitions = scheduler_job_definitions();
    $candidates = db_sync_schedule_fetch_backfill_candidates($limit);
    if ($candidates === []) {
        return [];
    }

    $running = db_sync_schedule_fetch_running_jobs();
    if ($running !== []) {
        return [];
    }

    $state = scheduler_live_capacity_snapshot($running);
    foreach ($candidates as $job) {
        $scheduleId = (int) ($job['id'] ?? 0);
        $jobKey = (string) ($job['job_key'] ?? '');
        if ($scheduleId <= 0 || $jobKey === '') {
            continue;
        }

        $profile = scheduler_job_recent_resource_profile($jobKey, $job);
        $candidate = $job + $profile + [
            'projected_cpu_percent' => (float) ($profile['projection_cpu_percent'] ?? 0.0),
            'projected_memory_bytes' => (int) ($profile['projection_memory_bytes'] ?? 0),
            'scheduler_selection_mode' => 'idle_backfill',
        ];

        db_sync_schedule_mark_planner_state($scheduleId, [
            'current_projected_cpu_percent' => $candidate['projected_cpu_percent'],
            'current_projected_memory_bytes' => $candidate['projected_memory_bytes'],
            'current_pressure_state' => $state['pressure'] ?? 'healthy',
            'latest_allowed_start_at' => scheduler_latest_allowed_start_at($candidate),
            'must_run_alone' => !empty($candidate['must_run_alone']),
            'prefers_solo' => !empty($candidate['prefers_solo']),
            'allow_parallel' => !empty($candidate['allow_parallel']),
        ]);

        $reasons = [];
        $isCritical = scheduler_is_protected_job($jobKey);
        $projectedCpu = $state['current_cpu_used_percent'] + (float) $candidate['projected_cpu_percent'];
        $projectedMemory = $state['current_memory_used_bytes'] + (int) $candidate['projected_memory_bytes'];
        if ($projectedCpu > (float) ($state['cpu_budget_percent'] ?? 0.0)) {
            $reasons[] = 'cpu_budget';
        }
        if ($projectedMemory > (int) ($state['memory_budget_bytes'] ?? 0)) {
            $reasons[] = 'memory_budget';
        }
        if (!$isCritical && $projectedCpu > ((float) ($state['cpu_budget_percent'] ?? 0.0) - (float) ($state['reserved_critical_cpu_percent'] ?? 0.0))) {
            $reasons[] = 'reserved_critical_cpu';
        }
        if (!$isCritical && $projectedMemory > ((int) ($state['memory_budget_bytes'] ?? 0) - (int) ($state['reserved_critical_memory_bytes'] ?? 0))) {
            $reasons[] = 'reserved_critical_memory';
        }
        if (($state['pressure'] ?? 'healthy') === 'overload_protection' && !$isCritical) {
            $reasons[] = 'overload_guard';
        }

        if ($reasons !== []) {
            $primaryReason = $reasons[0];
            $decisionType = match ($primaryReason) {
                'cpu_budget', 'reserved_critical_cpu' => 'idle_backfill_deferred_cpu',
                'memory_budget', 'reserved_critical_memory' => 'idle_backfill_deferred_memory',
                default => 'idle_backfill_deferred_capacity',
            };
            $reasonText = match ($primaryReason) {
                'cpu_budget' => 'Idle backfill skipped because projected CPU demand would exceed the scheduler CPU budget.',
                'memory_budget' => 'Idle backfill skipped because projected memory demand would exceed the scheduler memory budget.',
                'reserved_critical_cpu', 'reserved_critical_memory' => 'Idle backfill skipped to preserve reserved headroom for critical due work.',
                'overload_guard' => 'Idle backfill skipped because overload protection is active.',
                default => 'Idle backfill skipped because current scheduler pressure made this candidate unsafe.',
            };
            db_scheduler_planner_decision_insert($scheduleId, $jobKey, $decisionType, (string) ($state['pressure'] ?? 'healthy'), $reasonText, [
                'selection_mode' => 'idle_backfill',
                'defer_reasons' => $reasons,
                'projected_cpu_percent' => $candidate['projected_cpu_percent'],
                'projected_memory_bytes' => $candidate['projected_memory_bytes'],
            ]);
            db_sync_schedule_mark_planner_state($scheduleId, [
                'current_projected_cpu_percent' => $candidate['projected_cpu_percent'],
                'current_projected_memory_bytes' => $candidate['projected_memory_bytes'],
                'current_pressure_state' => $state['pressure'] ?? 'healthy',
                'latest_allowed_start_at' => scheduler_latest_allowed_start_at($candidate),
                'must_run_alone' => !empty($candidate['must_run_alone']),
                'prefers_solo' => !empty($candidate['prefers_solo']),
                'allow_parallel' => !empty($candidate['allow_parallel']),
                'last_capacity_reason' => $reasonText,
            ]);
            continue;
        }

        $definition = $definitions[$jobKey] ?? null;
        $defaultTimeout = (int) (($definition['timeout_seconds'] ?? 0) ?: ($job['timeout_seconds'] ?? 300));
        $timeoutSeconds = scheduler_job_timeout_seconds($jobKey, $defaultTimeout, $job, $definition);
        $defaultLockTtl = (int) (($definition['lock_ttl_seconds'] ?? 0) ?: max(120, $timeoutSeconds + 60));
        $lockTtl = scheduler_job_lock_ttl_seconds($defaultLockTtl, $timeoutSeconds);
        $claimedJob = db_sync_schedule_claim_job_forced($scheduleId, $lockTtl);
        if ($claimedJob === null) {
            db_scheduler_job_event_insert($jobKey, 'lock_skipped', ['selection_mode' => 'idle_backfill'], 0, null);
            continue;
        }

        db_scheduler_planner_decision_insert($scheduleId, $jobKey, 'idle_backfill_allowed', (string) ($state['pressure'] ?? 'healthy'), 'Idle backfill selected this job because no due work was running and the projected resource cost fit the live scheduler budget.', [
            'selection_mode' => 'idle_backfill',
            'projected_cpu_percent' => $candidate['projected_cpu_percent'],
            'projected_memory_bytes' => $candidate['projected_memory_bytes'],
        ]);
        if ($logger !== null) {
            $logger('scheduler.idle_backfill_selected', [
                'job_id' => $scheduleId,
                'job' => $jobKey,
                'projected_cpu_percent' => $candidate['projected_cpu_percent'],
                'projected_memory_bytes' => $candidate['projected_memory_bytes'],
            ]);
        }

        return [$claimedJob + $candidate];
    }

    return [];
}

function scheduler_select_work_batch(?callable $logger = null): array
{
    $due = scheduler_due_jobs();
    if ($due !== []) {
        return [
            'mode' => 'due',
            'jobs' => $due,
            'running' => [],
        ];
    }

    $running = db_sync_schedule_fetch_running_jobs();
    if ($running !== []) {
        return [
            'mode' => 'idle',
            'jobs' => [],
            'running' => $running,
        ];
    }

    $backfill = scheduler_idle_backfill_jobs($logger);

    return [
        'mode' => $backfill === [] ? 'idle' : 'idle_backfill',
        'jobs' => $backfill,
        'running' => [],
    ];
}

function scheduler_refresh_job_resource_profile(array $job, array $runtimeMetric, string $resultStatus): array
{
    $jobKey = (string) ($job['job_key'] ?? '');
    $scheduleId = (int) ($job['id'] ?? 0);
    db_scheduler_resource_metric_insert($runtimeMetric);
    $profile = scheduler_job_recent_resource_profile($jobKey, $job);

    if ($scheduleId > 0) {
        db_sync_schedule_update_resource_profile($scheduleId, [
            'resource_class' => $profile['resource_class'] ?? 'medium',
            'resource_class_confidence' => $profile['resource_class_confidence'] ?? null,
            'telemetry_sample_count' => $profile['sample_count'] ?? 0,
            'learning_mode' => !empty($profile['learning_mode']),
            'allow_parallel' => !empty($profile['allow_parallel']),
            'prefers_solo' => !empty($profile['prefers_solo']),
            'must_run_alone' => !empty($profile['must_run_alone']),
            'last_cpu_percent' => $runtimeMetric['cpu_percent'] ?? null,
            'average_cpu_percent' => $profile['average_cpu_percent'] ?? null,
            'p95_cpu_percent' => $profile['p95_cpu_percent'] ?? null,
            'last_memory_peak_bytes' => $runtimeMetric['memory_peak_delta_bytes'] ?? $runtimeMetric['memory_peak_bytes'] ?? null,
            'average_memory_peak_bytes' => $profile['average_memory_peak_bytes'] ?? null,
            'p95_memory_peak_bytes' => $profile['p95_memory_peak_bytes'] ?? null,
            'last_queue_wait_seconds' => $runtimeMetric['queue_wait_seconds'] ?? null,
            'last_lock_wait_seconds' => $runtimeMetric['lock_wait_seconds'] ?? null,
            'average_lock_wait_seconds' => $profile['average_lock_wait_seconds'] ?? null,
            'recent_timeout_rate' => $profile['recent_timeout_rate'] ?? null,
            'recent_failure_rate' => $profile['recent_failure_rate'] ?? null,
            'last_overlap_count' => $runtimeMetric['overlap_count'] ?? 0,
            'last_overlapped' => !empty($runtimeMetric['overlapped']),
            'current_projected_cpu_percent' => $profile['projection_cpu_percent'] ?? null,
            'current_projected_memory_bytes' => $profile['projection_memory_bytes'] ?? null,
            'last_capacity_reason' => $resultStatus === 'failed' ? 'Last run failed under current resource envelope.' : 'Resource profile refreshed from the latest completed run.',
        ]);
    }

    return $profile;
}

function scheduler_job_runtime_snapshot(string $jobKey, string $resultLabel, bool $timeout = false): array
{
    $stats = db_sync_schedule_recent_job_run_stats($jobKey, 20);
    $profile = scheduler_job_recent_resource_profile($jobKey);
    $definitions = scheduler_job_definitions();
    $schedules = db_sync_schedule_fetch_by_job_keys([$jobKey]);
    $timeoutResolution = scheduler_resolve_job_timeout($jobKey, $schedules[0] ?? null, $definitions[$jobKey] ?? null);

    return [
        'last_result' => $resultLabel,
        'average_duration_seconds' => $stats['average_duration_seconds'] ?? $profile['average_duration_seconds'] ?? null,
        'p95_duration_seconds' => $stats['p95_duration_seconds'] ?? $profile['p95_duration_seconds'] ?? null,
        'timeout' => $timeout,
        'resolved_timeout_seconds' => $timeoutResolution['resolved_timeout_seconds'] ?? null,
        'enforced_timeout_seconds' => $timeoutResolution['enforced_timeout_seconds'] ?? null,
        'timeout_source' => $timeoutResolution['timeout_source'] ?? null,
    ];
}

function scheduler_run_job(array $job): array
{
    $jobKey = (string) ($job['job_key'] ?? '');
    $scheduleId = (int) ($job['id'] ?? 0);
    $definitions = scheduler_job_definitions();
    $definition = $definitions[$jobKey] ?? null;
    $datasetKey = scheduler_job_dataset_key($jobKey !== '' ? $jobKey : 'unknown');
    $executionMode = scheduler_job_execution_mode($job, $definition);
    $jobType = scheduler_job_runtime_type($job, $definition);
    $scheduledFor = (string) ($job['next_due_at'] ?? $job['next_run_at'] ?? '');
    $startedAtUnix = microtime(true);
    $startedAtIso = gmdate(DATE_ATOM, (int) $startedAtUnix);
    $latenessSeconds = $scheduledFor !== '' ? max(0, time() - (int) strtotime($scheduledFor)) : 0;
    $claimStartedAt = trim((string) ($job['last_started_at'] ?? ''));
    $claimStartedTs = $claimStartedAt !== '' ? (int) strtotime($claimStartedAt) : time();
    $queueWaitSeconds = $scheduledFor !== '' ? max(0.0, $startedAtUnix - (float) strtotime($scheduledFor)) : 0.0;
    $lockWaitSeconds = max(0.0, $startedAtUnix - (float) $claimStartedTs);
    $overlapJobs = $scheduleId > 0 ? db_sync_schedule_fetch_running_jobs([$scheduleId]) : [];
    $overlapCount = count($overlapJobs);
    $resourceStarted = scheduler_resource_usage_snapshot();
    $projectedCpuPercent = isset($job['current_projected_cpu_percent']) ? (float) $job['current_projected_cpu_percent'] : null;
    $projectedMemoryBytes = isset($job['current_projected_memory_bytes']) ? (int) $job['current_projected_memory_bytes'] : null;
    $pressureState = (string) ($job['current_pressure_state'] ?? scheduler_live_capacity_snapshot()['pressure'] ?? 'healthy');
    $statusRow = $jobKey !== '' ? (db_scheduler_job_current_status_fetch_map([$jobKey])[$jobKey] ?? []) : [];
    $changeDecision = scheduler_evaluate_change_aware_run($job, $statusRow);
    $dependencyMetadata = scheduler_dependency_metadata($jobKey);

    if ($executionMode === 'python') {
        $message = scheduler_normalize_error_message(
            'Routing/config error: Python-native job "' . ($jobKey !== '' ? $jobKey : '[empty]') . '" cannot execute through scheduler_run_job PHP handler path; dispatch it through the Python scheduler runtime.'
        );
        mark_sync_failure($datasetKey, 'incremental', $message);
        if ($scheduleId > 0) {
            db_sync_schedule_mark_failure($scheduleId, $message, scheduler_job_runtime_snapshot($jobKey, 'failed'));
        }
        db_scheduler_job_event_insert($jobKey, 'routing_error', [
            'error' => $message,
            'execution_mode' => $executionMode,
            'expected_runtime' => 'python',
            'actual_runtime' => 'php',
        ], $latenessSeconds, 0.0);

        return [
            'job_id' => $scheduleId,
            'job_key' => $jobKey,
            'job_type' => $jobType,
            'scheduled_for' => $scheduledFor,
            'started_at' => $startedAtIso,
            'finished_at' => gmdate(DATE_ATOM),
            'duration_ms' => (int) round((microtime(true) - $startedAtUnix) * 1000),
            'status' => 'failed',
            'error' => $message,
            'rows_seen' => 0,
            'rows_written' => 0,
            'warnings' => [],
            'meta' => [
                'execution_mode' => $executionMode,
                'routing_error' => true,
            ],
            'summary' => $message,
        ];
    }

    $runId = db_sync_run_start($datasetKey, 'incremental', null);

    if ($definition === null || !isset($definition['handler']) || !is_callable($definition['handler'])) {
        $message = scheduler_normalize_error_message('Unknown scheduler job key: ' . ($jobKey !== '' ? $jobKey : '[empty]') . '.');
        mark_sync_failure($datasetKey, 'incremental', $message);
        db_sync_run_finish($runId, 'failed', 0, 0, null, $message);
        $runtimeMetric = [
            'schedule_id' => $scheduleId,
            'job_key' => $jobKey,
            'run_status' => 'failed',
            'wall_duration_seconds' => 0.0,
            'queue_wait_seconds' => round($queueWaitSeconds, 2),
            'lock_wait_seconds' => round($lockWaitSeconds, 2),
            'overlap_count' => $overlapCount,
            'overlapped' => $overlapCount > 0,
            'projected_cpu_percent' => $projectedCpuPercent,
            'projected_memory_bytes' => $projectedMemoryBytes,
            'pressure_state' => $pressureState,
            'timed_out' => false,
            'failed' => true,
            'started_at' => gmdate('Y-m-d H:i:s', (int) $startedAtUnix),
            'finished_at' => gmdate('Y-m-d H:i:s'),
        ];
        scheduler_refresh_job_resource_profile($job, $runtimeMetric, 'failed');
        if ($scheduleId > 0) {
            db_sync_schedule_mark_failure($scheduleId, $message, scheduler_job_runtime_snapshot($jobKey, 'failed'));
        }
        db_scheduler_job_event_insert($jobKey, 'failure', ['error' => $message], $latenessSeconds, null);

        return [
            'job_id' => $scheduleId,
            'job_key' => $jobKey,
            'job_type' => $jobType,
            'scheduled_for' => $scheduledFor,
            'started_at' => $startedAtIso,
            'finished_at' => gmdate(DATE_ATOM),
            'duration_ms' => (int) round((microtime(true) - $startedAtUnix) * 1000),
            'status' => 'failed',
            'error' => $message,
            'rows_seen' => 0,
            'rows_written' => 0,
            'warnings' => [],
            'meta' => [],
            'summary' => $message,
        ];
    }

    $timeoutResolution = scheduler_resolve_job_timeout($jobKey, $job, $definition, (int) ($definition['timeout_seconds'] ?? 300));
    $timeoutSeconds = (int) ($timeoutResolution['enforced_timeout_seconds'] ?? 300);
    $startedAt = microtime(true);

    try {
        scheduler_enforce_php_runtime_limits();
        if (function_exists('set_time_limit')) {
            @set_time_limit($timeoutSeconds + 5);
        }
        scheduler_runtime_guard($startedAtUnix, $timeoutSeconds, 'startup');

        if (is_array($changeDecision) && !$changeDecision['run']) {
            $durationMs = (int) round((microtime(true) - $startedAt) * 1000);
            $skipStatus = (string) ($changeDecision['result_status'] ?? 'skipped_no_change');
            $warnings = [$changeDecision['reason'] ?? 'No upstream change detected.'];
            $skipCursor = 'skip:' . $jobKey . ':' . gmdate('Y-m-d H:i:s');
            $skipChecksum = sync_checksum([
                'job_key' => $jobKey,
                'status' => $skipStatus,
                'input_fingerprint' => $changeDecision['input_fingerprint'] ?? null,
            ]);
            $resourceFinished = scheduler_resource_usage_snapshot();
            $resourceMetric = scheduler_resource_usage_delta($resourceStarted, $resourceFinished) + [
                'schedule_id' => $scheduleId,
                'job_key' => $jobKey,
                'run_status' => $skipStatus,
                'queue_wait_seconds' => round($queueWaitSeconds, 2),
                'lock_wait_seconds' => round($lockWaitSeconds, 2),
                'overlap_count' => $overlapCount,
                'overlapped' => $overlapCount > 0,
                'projected_cpu_percent' => $projectedCpuPercent,
                'projected_memory_bytes' => $projectedMemoryBytes,
                'pressure_state' => $pressureState,
                'timed_out' => false,
                'failed' => false,
                'started_at' => gmdate('Y-m-d H:i:s', (int) $startedAtUnix),
                'finished_at' => gmdate('Y-m-d H:i:s'),
            ];
            scheduler_refresh_job_resource_profile($job, $resourceMetric, $skipStatus);
            $changeContext = [
                'job_key' => $jobKey,
                'trigger' => $changeDecision['trigger'] ?? 'no_change',
                'input_fingerprint' => $changeDecision['input_fingerprint'] ?? null,
                'last_upstream_change_seen' => $changeDecision['last_upstream_change_seen'] ?? null,
                'freshness_ceiling_seconds' => $changeDecision['freshness_ceiling_seconds'] ?? null,
                'minimum_rerun_gap_seconds' => $changeDecision['minimum_rerun_gap_seconds'] ?? null,
                'within_freshness_window' => !empty($changeDecision['within_freshness_window']),
                'within_minimum_gap' => !empty($changeDecision['within_minimum_gap']),
                'upstream_changed' => !empty($changeDecision['upstream_changed']),
                'signals' => $changeDecision['signals'] ?? [],
            ];
            mark_sync_success($datasetKey, 'incremental', $skipCursor, 0, $skipChecksum);
            db_sync_run_finish($runId, 'success', 0, 0, $skipCursor, null);

            if ($scheduleId > 0) {
                db_sync_schedule_mark_success($scheduleId, scheduler_job_runtime_snapshot($jobKey, $skipStatus) + [
                    'last_duration_seconds' => round($durationMs / 1000, 2),
                    'recent_skip_count' => max(1, (int) ($statusRow['recent_skip_count'] ?? 0) + 1),
                    'current_pressure_state' => $pressureState,
                    'change_aware' => true,
                    'dependencies_json' => $dependencyMetadata,
                    'last_change_detection_json' => $changeContext,
                    'last_execution_context_json' => $changeContext + [
                        'result_status' => $skipStatus,
                        'output_versions' => supplycore_ui_refresh_current_versions((array) ($dependencyMetadata['output_version_keys'] ?? [])),
                    ],
                    'last_no_change_skip_at' => gmdate('Y-m-d H:i:s'),
                    'last_no_change_reason' => $changeDecision['reason'] ?? null,
                ]);
            }

            db_scheduler_job_event_insert($jobKey, $skipStatus, [
                'warnings' => $warnings,
                'skip_reason' => $changeDecision['reason'] ?? 'No upstream change detected.',
                'change_aware' => true,
                'dependencies' => $dependencyMetadata,
                'change_detection' => $changeContext,
                'execution_context' => $changeContext + ['result_status' => $skipStatus],
                'cpu_percent' => $resourceMetric['cpu_percent'] ?? null,
                'memory_peak_delta_bytes' => $resourceMetric['memory_peak_delta_bytes'] ?? null,
            ], $latenessSeconds, round($durationMs / 1000, 2));

            $result = [
                'job_id' => $scheduleId,
                'job_key' => $jobKey,
                'job_type' => $jobType,
                'scheduled_for' => $scheduledFor,
                'started_at' => $startedAtIso,
                'finished_at' => gmdate(DATE_ATOM),
                'status' => $skipStatus,
                'error' => null,
                'rows_seen' => 0,
                'rows_written' => 0,
                'warnings' => $warnings,
                'duration_ms' => $durationMs,
                'meta' => [
                    'scheduler_result_status' => $skipStatus,
                    'outcome_reason' => $changeDecision['reason'] ?? 'No upstream change detected.',
                    'change_aware' => true,
                    'trigger' => $changeDecision['trigger'] ?? 'no_change',
                    'dependencies' => $dependencyMetadata,
                    'change_detection' => $changeContext,
                    'resource_usage' => [
                        'cpu_percent' => $resourceMetric['cpu_percent'] ?? null,
                        'memory_peak_bytes' => $resourceMetric['memory_peak_bytes'] ?? null,
                        'memory_peak_delta_bytes' => $resourceMetric['memory_peak_delta_bytes'] ?? null,
                        'queue_wait_seconds' => $resourceMetric['queue_wait_seconds'] ?? null,
                        'lock_wait_seconds' => $resourceMetric['lock_wait_seconds'] ?? null,
                        'overlap_count' => $resourceMetric['overlap_count'] ?? null,
                        'pressure_state' => $pressureState,
                    ],
                ],
            ];
            $result['summary'] = scheduler_job_summary_message($result);
            $result['ui_refresh'] = supplycore_ui_refresh_publish_for_job_result($result);

            return $result;
        }

        db_scheduler_job_event_insert($jobKey, 'started', [
            'execution_mode' => $executionMode,
            'queue_wait_seconds' => round($queueWaitSeconds, 2),
            'lock_wait_seconds' => round($lockWaitSeconds, 2),
            'overlap_count' => $overlapCount,
            'projected_cpu_percent' => $projectedCpuPercent,
            'projected_memory_bytes' => $projectedMemoryBytes,
            'pressure_state' => $pressureState,
            'memory_usage_bytes' => memory_get_usage(true),
            'memory_peak_bytes' => memory_get_peak_usage(true),
            'resolved_timeout_seconds' => $timeoutResolution['resolved_timeout_seconds'] ?? null,
            'enforced_timeout_seconds' => $timeoutResolution['enforced_timeout_seconds'] ?? null,
            'timeout_source' => $timeoutResolution['timeout_source'] ?? null,
            'change_aware' => !empty($changeDecision['change_aware']),
            'dependencies' => $dependencyMetadata,
            'change_detection' => $changeDecision,
        ], $latenessSeconds, null);

        $handler = $definition['handler'];
        $syncResult = $handler();
        $durationMs = (int) round((microtime(true) - $startedAt) * 1000);
        scheduler_runtime_guard($startedAtUnix, $timeoutSeconds, 'handler completion');
        if ($durationMs > ($timeoutSeconds * 1000)) {
            throw new RuntimeException('Job exceeded timeout of ' . $timeoutSeconds . ' seconds.');
        }

        $rowsSeen = max(0, (int) ($syncResult['rows_seen'] ?? 0));
        $rowsWritten = max(0, (int) ($syncResult['rows_written'] ?? 0));
        $warnings = scheduler_normalize_messages((array) ($syncResult['warnings'] ?? []));
        $status = scheduler_job_status_from_sync_result($syncResult);
        $changeContext = is_array($changeDecision) ? scheduler_change_aware_execution_context($jobKey, $changeDecision) : null;
        if ($status === 'success' && is_array($changeDecision) && (string) ($changeDecision['trigger'] ?? '') === 'staleness_ceiling') {
            $status = 'forced_refresh_due_to_staleness';
        }
        $cursor = isset($syncResult['cursor']) && $syncResult['cursor'] !== null
            ? mb_substr(trim((string) $syncResult['cursor']), 0, 190)
            : 'finished_at:' . gmdate('Y-m-d H:i:s') . ';duration_ms:' . $durationMs;
        $checksum = isset($syncResult['checksum']) && $syncResult['checksum'] !== null
            ? mb_substr(trim((string) $syncResult['checksum']), 0, 190)
            : sync_checksum([
                'job_key' => $jobKey,
                'rows_seen' => $rowsSeen,
                'rows_written' => $rowsWritten,
                'warnings' => $warnings,
            ]);
        $resourceFinished = scheduler_resource_usage_snapshot();
        $resourceMetric = scheduler_resource_usage_delta($resourceStarted, $resourceFinished) + [
            'schedule_id' => $scheduleId,
            'job_key' => $jobKey,
            'run_status' => $status,
            'queue_wait_seconds' => round($queueWaitSeconds, 2),
            'lock_wait_seconds' => round($lockWaitSeconds, 2),
            'overlap_count' => $overlapCount,
            'overlapped' => $overlapCount > 0,
            'projected_cpu_percent' => $projectedCpuPercent,
            'projected_memory_bytes' => $projectedMemoryBytes,
            'pressure_state' => $pressureState,
            'timed_out' => false,
            'failed' => $status === 'failed',
            'started_at' => gmdate('Y-m-d H:i:s', (int) $startedAtUnix),
            'finished_at' => gmdate('Y-m-d H:i:s'),
        ];
        scheduler_refresh_job_resource_profile($job, $resourceMetric, $status);

        if (in_array($status, scheduler_success_like_statuses(), true)) {
            mark_sync_success($datasetKey, 'incremental', $cursor, $rowsWritten, $checksum);
            db_sync_run_finish($runId, 'success', $rowsSeen, $rowsWritten, $cursor, null);
            if ($scheduleId > 0) {
                db_sync_schedule_mark_success($scheduleId, scheduler_job_runtime_snapshot($jobKey, $status) + [
                    'last_duration_seconds' => round($durationMs / 1000, 2),
                    'current_pressure_state' => $pressureState,
                    'change_aware' => !empty($changeDecision['change_aware']),
                    'dependencies_json' => $dependencyMetadata,
                    'last_change_detection_json' => $changeContext,
                    'last_warnings_json' => $warnings !== [] ? $warnings : null,
                ]);
            }
            db_scheduler_job_event_insert($jobKey, 'finished', [
                'status' => $status,
                'change_aware' => !empty($changeDecision['change_aware']),
                'dependencies' => $dependencyMetadata,
                'change_detection' => $changeContext,
                'cpu_percent' => $resourceMetric['cpu_percent'] ?? null,
                'memory_peak_delta_bytes' => $resourceMetric['memory_peak_delta_bytes'] ?? null,
            ], $latenessSeconds, round($durationMs / 1000, 2));
        } else {
            mark_sync_success($datasetKey, 'incremental', $cursor, $rowsWritten, $checksum);
            db_sync_run_finish($runId, 'success', $rowsSeen, $rowsWritten, $cursor, null);
            if ($scheduleId > 0) {
                db_sync_schedule_mark_success($scheduleId, scheduler_job_runtime_snapshot($jobKey, $status) + [
                    'last_duration_seconds' => round($durationMs / 1000, 2),
                    'recent_skip_count' => max(1, (int) ($statusRow['recent_skip_count'] ?? 0) + 1),
                    'current_pressure_state' => $pressureState,
                    'change_aware' => !empty($changeDecision['change_aware']),
                    'dependencies_json' => $dependencyMetadata,
                    'last_change_detection_json' => $changeContext,
                    'last_execution_context_json' => $changeContext,
                    'last_warnings_json' => $warnings !== [] ? $warnings : null,
                ]);
            }
            db_scheduler_job_event_insert($jobKey, $status, [
                'warnings' => $warnings,
                'skip_reason' => $warnings[0] ?? null,
                'change_aware' => !empty($changeDecision['change_aware']),
                'dependencies' => $dependencyMetadata,
                'change_detection' => $changeContext,
                'cpu_percent' => $resourceMetric['cpu_percent'] ?? null,
                'memory_peak_delta_bytes' => $resourceMetric['memory_peak_delta_bytes'] ?? null,
            ], $latenessSeconds, round($durationMs / 1000, 2));
        }

        if (in_array($jobKey, ['alliance_current_sync', 'market_hub_current_sync'], true)) {
            try {
                db_sync_schedule_force_due_by_job_keys(['deal_alerts_sync']);
            } catch (Throwable) {
            }
        }

        $result = [
            'job_id' => $scheduleId,
            'job_key' => $jobKey,
            'job_type' => $jobType,
            'scheduled_for' => $scheduledFor,
            'started_at' => $startedAtIso,
            'finished_at' => gmdate(DATE_ATOM),
            'status' => $status,
            'error' => null,
            'rows_seen' => $rowsSeen,
            'rows_written' => $rowsWritten,
            'warnings' => $warnings,
            'duration_ms' => $durationMs,
            'meta' => (is_array($syncResult['meta'] ?? null) ? $syncResult['meta'] : []) + [
                'resource_usage' => [
                    'cpu_percent' => $resourceMetric['cpu_percent'] ?? null,
                    'cpu_user_seconds' => $resourceMetric['cpu_user_seconds'] ?? null,
                    'cpu_system_seconds' => $resourceMetric['cpu_system_seconds'] ?? null,
                    'memory_peak_bytes' => $resourceMetric['memory_peak_bytes'] ?? null,
                    'memory_peak_delta_bytes' => $resourceMetric['memory_peak_delta_bytes'] ?? null,
                    'memory_usage_bytes' => memory_get_usage(true),
                    'queue_wait_seconds' => $resourceMetric['queue_wait_seconds'] ?? null,
                    'lock_wait_seconds' => $resourceMetric['lock_wait_seconds'] ?? null,
                    'overlap_count' => $resourceMetric['overlap_count'] ?? null,
                    'pressure_state' => $pressureState,
                ],
                'timeout' => [
                    'resolved_timeout_seconds' => $timeoutResolution['resolved_timeout_seconds'] ?? null,
                    'enforced_timeout_seconds' => $timeoutResolution['enforced_timeout_seconds'] ?? null,
                    'timeout_source' => $timeoutResolution['timeout_source'] ?? null,
                ],
                'scheduler_result_status' => $status,
                'outcome_reason' => is_array($changeDecision) ? (string) ($changeDecision['reason'] ?? '') : '',
                'execution_mode' => $executionMode,
                'change_aware' => !empty($changeDecision['change_aware']),
                'trigger' => $changeDecision['trigger'] ?? null,
                'dependencies' => $dependencyMetadata,
                'change_detection' => $changeContext,
            ],
        ];
        $result['summary'] = scheduler_job_summary_message($result);
        $result['ui_refresh'] = supplycore_ui_refresh_publish_for_job_result($result);
        if ($jobKey !== '') {
            $outputVersions = $result['ui_refresh']['freshness_versions'] ?? supplycore_ui_refresh_current_versions((array) ($dependencyMetadata['output_version_keys'] ?? []));
            db_scheduler_job_current_status_upsert($jobKey, [
                'change_aware' => !empty($changeDecision['change_aware']),
                'dependencies_json' => $dependencyMetadata,
                'last_change_detection_json' => $changeContext,
                'last_execution_context_json' => ($changeContext ?? []) + [
                    'result_status' => $status,
                    'output_versions' => $outputVersions,
                ],
                'last_no_change_skip_at' => in_array($status, ['skipped_no_change', 'skipped_within_freshness_window'], true) ? gmdate('Y-m-d H:i:s') : null,
                'last_no_change_reason' => in_array($status, ['skipped_no_change', 'skipped_within_freshness_window'], true) ? ($warnings[0] ?? null) : null,
            ]);
        }

        return $result;
    } catch (Throwable $exception) {
        $message = scheduler_normalize_error_message($exception->getMessage());
        $durationSeconds = round((microtime(true) - $startedAtUnix), 2);
        $isTimeout = str_contains(strtolower($message), 'timeout');
        if ($jobKey === 'deal_alerts_sync') {
            deal_alert_materialization_record([
                'last_job_key' => $jobKey,
                'last_run_started_at' => gmdate('Y-m-d H:i:s', (int) $startedAtUnix),
                'last_run_finished_at' => gmdate('Y-m-d H:i:s'),
                'last_attempt_status' => 'failed',
                'last_failure_reason' => $message,
                'last_duration_ms' => (int) round($durationSeconds * 1000),
                'metadata' => [
                    'scheduler_failure' => true,
                    'timed_out' => $isTimeout,
                ],
            ]);
        }
        mark_sync_failure($datasetKey, 'incremental', $message);
        db_sync_run_finish($runId, 'failed', 0, 0, null, $message);
        $resourceFinished = scheduler_resource_usage_snapshot();
        $resourceMetric = scheduler_resource_usage_delta($resourceStarted, $resourceFinished) + [
            'schedule_id' => $scheduleId,
            'job_key' => $jobKey,
            'run_status' => 'failed',
            'queue_wait_seconds' => round($queueWaitSeconds, 2),
            'lock_wait_seconds' => round($lockWaitSeconds, 2),
            'overlap_count' => $overlapCount,
            'overlapped' => $overlapCount > 0,
            'projected_cpu_percent' => $projectedCpuPercent,
            'projected_memory_bytes' => $projectedMemoryBytes,
            'pressure_state' => $pressureState,
            'timed_out' => $isTimeout,
            'failed' => true,
            'started_at' => gmdate('Y-m-d H:i:s', (int) $startedAtUnix),
            'finished_at' => gmdate('Y-m-d H:i:s'),
        ];
        scheduler_refresh_job_resource_profile($job, $resourceMetric, 'failed');
        if ($scheduleId > 0) {
            db_sync_schedule_mark_failure($scheduleId, $message, scheduler_job_runtime_snapshot($jobKey, 'failed', $isTimeout) + [
                'last_duration_seconds' => $durationSeconds,
                'change_aware' => !empty($changeDecision['change_aware']),
                'dependencies_json' => $dependencyMetadata,
                'last_change_detection_json' => $changeDecision,
            ]);
        }
        db_scheduler_job_event_insert($jobKey, $isTimeout ? 'timeout' : 'failure', [
            'error' => $message,
            'cpu_percent' => $resourceMetric['cpu_percent'] ?? null,
            'memory_peak_delta_bytes' => $resourceMetric['memory_peak_delta_bytes'] ?? null,
            'resolved_timeout_seconds' => $timeoutResolution['resolved_timeout_seconds'] ?? null,
            'enforced_timeout_seconds' => $timeoutResolution['enforced_timeout_seconds'] ?? null,
            'timeout_source' => $timeoutResolution['timeout_source'] ?? null,
            'change_aware' => !empty($changeDecision['change_aware']),
            'dependencies' => $dependencyMetadata,
            'change_detection' => $changeDecision,
        ], $latenessSeconds, $durationSeconds);

        $result = [
            'job_id' => $scheduleId,
            'job_key' => $jobKey,
            'job_type' => $jobType,
            'scheduled_for' => $scheduledFor,
            'started_at' => $startedAtIso,
            'finished_at' => gmdate(DATE_ATOM),
            'duration_ms' => (int) round((microtime(true) - $startedAtUnix) * 1000),
            'status' => 'failed',
            'error' => $message,
            'rows_seen' => 0,
            'rows_written' => 0,
            'warnings' => [],
            'meta' => [
                'resource_usage' => [
                    'cpu_percent' => $resourceMetric['cpu_percent'] ?? null,
                    'memory_peak_bytes' => $resourceMetric['memory_peak_bytes'] ?? null,
                    'memory_peak_delta_bytes' => $resourceMetric['memory_peak_delta_bytes'] ?? null,
                    'memory_usage_bytes' => memory_get_usage(true),
                    'queue_wait_seconds' => $resourceMetric['queue_wait_seconds'] ?? null,
                    'lock_wait_seconds' => $resourceMetric['lock_wait_seconds'] ?? null,
                    'overlap_count' => $resourceMetric['overlap_count'] ?? null,
                    'pressure_state' => $pressureState,
                ],
                'timeout' => [
                    'resolved_timeout_seconds' => $timeoutResolution['resolved_timeout_seconds'] ?? null,
                    'enforced_timeout_seconds' => $timeoutResolution['enforced_timeout_seconds'] ?? null,
                    'timeout_source' => $timeoutResolution['timeout_source'] ?? null,
                ],
                'execution_mode' => $executionMode,
            ],
            'summary' => $message,
        ];
        $result['ui_refresh'] = supplycore_ui_refresh_publish_for_job_result($result);

        return $result;
    }
}

function scheduler_can_auto_tune(array $job): bool
{
    return ((int) ($job['enabled'] ?? 1)) === 1
        && ((string) ($job['tuning_mode'] ?? 'automatic')) === 'automatic'
        && ((string) ($job['current_state'] ?? 'waiting')) !== 'running';
}

function scheduler_auto_tune_cooldown_minutes(): int
{
    return 30;
}

function scheduler_job_can_change_now(array $job): bool
{
    if (!scheduler_can_auto_tune($job)) {
        return false;
    }

    $lastTunedAt = trim((string) ($job['last_auto_tuned_at'] ?? ''));
    if ($lastTunedAt === '') {
        return true;
    }

    return (time() - (int) strtotime($lastTunedAt)) >= (scheduler_auto_tune_cooldown_minutes() * 60);
}

function scheduler_job_constraints(string $jobKey): array
{
    $definition = scheduler_registry_definitions()[$jobKey] ?? [];

    return [
        'min_interval_minutes' => (int) ($definition['min_interval_minutes'] ?? 1),
        'max_interval_minutes' => (int) ($definition['max_interval_minutes'] ?? 1440),
    ];
}

function scheduler_job_shares_protected_offset(string $jobKey, int $offsetMinutes, array $rows): bool
{
    foreach ($rows as $row) {
        $otherJobKey = trim((string) ($row['job_key'] ?? ''));
        if ($otherJobKey === '' || $otherJobKey === $jobKey || !scheduler_is_protected_job($otherJobKey)) {
            continue;
        }

        if ((int) ($row['offset_minutes'] ?? 0) === $offsetMinutes) {
            return true;
        }
    }

    return false;
}

function scheduler_recommended_offset_minutes_for_job(array $job, array $rows, bool $preserveProtectedOffsets = true): int
{
    $jobKey = trim((string) ($job['job_key'] ?? ''));
    $isProtected = scheduler_is_protected_job($jobKey);
    $counts = scheduler_offset_load_map(
        scheduler_discovery_offset_horizon_minutes(),
        [
            'rows' => $rows,
            'exclude_job_key' => $jobKey,
            'reserve_protected_offsets' => !$isProtected,
        ]
    );
    $reservedOffsets = [];
    if ($preserveProtectedOffsets) {
        foreach (scheduler_reserved_protected_offsets(count($counts), $jobKey) as $offset) {
            $reservedOffsets[$offset] = true;
        }
    }

    $bestOffset = max(0, (int) ($job['offset_minutes'] ?? 0));
    $bestScore = null;

    foreach ($counts as $offset => $count) {
        if ($isProtected && scheduler_job_shares_protected_offset($jobKey, (int) $offset, $rows)) {
            continue;
        }

        $score = [
            (!$isProtected && isset($reservedOffsets[$offset])) ? 1 : 0,
            (int) $count,
            abs((int) $offset - max(0, (int) ($job['offset_minutes'] ?? 0))),
            (int) $offset,
        ];
        if ($bestScore === null || $score < $bestScore) {
            $bestScore = $score;
            $bestOffset = (int) $offset;
        }
    }

    return $bestOffset;
}

function scheduler_job_needs_protected_offset_repair(array $job, array $rows): bool
{
    $jobKey = trim((string) ($job['job_key'] ?? ''));
    if (!scheduler_is_protected_job($jobKey)) {
        return false;
    }

    return scheduler_job_shares_protected_offset($jobKey, (int) ($job['offset_minutes'] ?? 0), $rows);
}

function scheduler_apply_tuning_change(array $job, string $actionType, string $reason, array $changes, array $metrics): bool
{
    $scheduleId = (int) ($job['id'] ?? 0);
    if ($scheduleId <= 0) {
        return false;
    }

    $before = [
        'interval_minutes' => (int) ($job['interval_minutes'] ?? 0),
        'offset_minutes' => (int) ($job['offset_minutes'] ?? 0),
        'timeout_seconds' => (int) ($job['timeout_seconds'] ?? 0),
    ];
    $after = $before + $changes;

    $applied = db_sync_schedule_apply_adjustment($scheduleId, $changes + ['last_auto_tune_reason' => $reason]);
    if ($applied) {
        db_scheduler_tuning_action_log((string) ($job['job_key'] ?? ''), 'system', $actionType, $reason, $before, $after, $metrics);
    }

    return $applied;
}

function scheduler_optimizer_recent_event_counters(array $statusProjection): array
{
    $latestStatus = trim((string) ($statusProjection['latest_status'] ?? ''));
    $latestEventType = trim((string) ($statusProjection['latest_event_type'] ?? ''));

    return [
        'lock_conflicts' => max(0, (int) ($statusProjection['recent_lock_conflict_count'] ?? 0)),
        'timeouts' => max(
            0,
            (int) ($statusProjection['recent_timeout_count'] ?? 0),
            ($latestStatus === 'timeout' || $latestEventType === 'timeout') ? 1 : 0
        ),
        'skips' => max(0, (int) ($statusProjection['recent_skip_count'] ?? 0))
            + max(0, (int) ($statusProjection['recent_deferral_count'] ?? 0)),
    ];
}

function scheduler_run_optimizer(): ?array
{
    $rows = db_sync_schedule_fetch_all();
    $pressure = scheduler_pressure_summary();
    $busiest = db_sync_schedule_busiest_offsets(4);
    $statusMap = db_scheduler_job_current_status_fetch_map(array_map(
        static fn (array $row): string => (string) ($row['job_key'] ?? ''),
        $rows
    ));

    foreach ($rows as $job) {
        if (!scheduler_job_can_change_now($job)) {
            continue;
        }

        $jobKey = (string) ($job['job_key'] ?? '');
        $constraints = scheduler_job_constraints($jobKey);
        $intervalMinutes = (int) ($job['interval_minutes'] ?? 30);
        $offsetMinutes = (int) ($job['offset_minutes'] ?? 0);
        $timeoutSeconds = (int) ($job['timeout_seconds'] ?? 300);
        $runStats = db_sync_schedule_recent_job_run_stats($jobKey, 20);
        $eventCounters = scheduler_optimizer_recent_event_counters($statusMap[$jobKey] ?? []);
        $lockConflicts = (int) ($eventCounters['lock_conflicts'] ?? 0);
        $timeouts = (int) ($eventCounters['timeouts'] ?? 0);
        $skips = (int) ($eventCounters['skips'] ?? 0);
        $metrics = [
            'average_duration_seconds' => $runStats['average_duration_seconds'],
            'p95_duration_seconds' => $runStats['p95_duration_seconds'],
            'lock_conflicts' => $lockConflicts,
            'timeouts' => $timeouts,
            'skips' => $skips,
            'pressure' => $pressure['pressure'] ?? 'healthy',
        ];

        if (scheduler_job_needs_protected_offset_repair($job, $rows)) {
            $newOffset = scheduler_recommended_offset_minutes_for_job($job, $rows);
            if ($newOffset !== $offsetMinutes && scheduler_apply_tuning_change($job, 'protected_offset_repair', 'Moved protected job onto a dedicated offset to avoid protected-job collisions.', ['offset_minutes' => $newOffset], $metrics)) {
                return ['job_key' => $jobKey, 'action' => 'protected_offset_repair'];
            }
        }

        foreach ($busiest as $busy) {
            if ((int) ($busy['offset_minutes'] ?? -1) === $offsetMinutes && (int) ($busy['job_count'] ?? 0) >= 2 && !in_array((string) ($job['priority'] ?? 'normal'), ['highest', 'high'], true)) {
                $newOffset = scheduler_recommended_offset_minutes_for_job($job, $rows);
                if ($newOffset !== $offsetMinutes) {
                    if (scheduler_apply_tuning_change($job, 'offset_shift', 'Shifted offset away from congested minute slot.', ['offset_minutes' => $newOffset], $metrics)) {
                        return ['job_key' => $jobKey, 'action' => 'offset_shift'];
                    }
                }
            }
        }

        if ($timeouts >= 2 && $runStats['p95_duration_seconds'] !== null) {
            $targetTimeout = max($timeoutSeconds, (int) ceil((float) $runStats['p95_duration_seconds'] + 60));
            if ($targetTimeout > $timeoutSeconds) {
                if (scheduler_apply_tuning_change($job, 'timeout_increase', 'Increased timeout due to repeated timeout pressure.', ['timeout_seconds' => $targetTimeout], $metrics)) {
                    return ['job_key' => $jobKey, 'action' => 'timeout_increase'];
                }
            }
        }

        if (($lockConflicts >= 2 || $timeouts >= 2) && $runStats['p95_duration_seconds'] !== null) {
            $newInterval = min($constraints['max_interval_minutes'], max($intervalMinutes + 1, (int) ceil($intervalMinutes * 1.25)));
            if ($newInterval > $intervalMinutes) {
                if (scheduler_apply_tuning_change($job, 'interval_increase', 'Increased interval due to repeated timeout pressure.', ['interval_minutes' => $newInterval], $metrics)) {
                    return ['job_key' => $jobKey, 'action' => 'interval_increase'];
                }
            }
        }

        if (($pressure['pressure'] ?? 'healthy') === 'healthy' && $runStats['average_duration_seconds'] !== null && $lockConflicts === 0 && $skips === 0) {
            $averageDuration = (float) $runStats['average_duration_seconds'];
            if ($averageDuration > 0 && $averageDuration < ($intervalMinutes * 60 * 0.15) && $intervalMinutes > $constraints['min_interval_minutes']) {
                $newInterval = max($constraints['min_interval_minutes'], $intervalMinutes - 1);
                if ($newInterval < $intervalMinutes) {
                    if (scheduler_apply_tuning_change($job, 'interval_reduce', 'Reduced interval because runtime is low and freshness headroom exists.', ['interval_minutes' => $newInterval], $metrics)) {
                        return ['job_key' => $jobKey, 'action' => 'interval_reduce'];
                    }
                }
            }
        }
    }

    return null;
}

function cron_tick_run(?callable $logger = null): array
{
    try {
        $bindingAudit = scheduler_enabled_python_worker_binding_audit();
        foreach ((array) ($bindingAudit['issues'] ?? []) as $issue) {
            if ($logger !== null) {
                $logger('job.binding_audit.failed', ['issue' => (string) $issue]);
            }
        }
    } catch (Throwable $exception) {
        if ($logger !== null) {
            $logger('job.binding_audit.error', ['error' => scheduler_normalize_error_message($exception->getMessage())]);
        }
    }

    $profiling = scheduler_profiling_tick($logger);
    if ($profiling !== null) {
        return [
            'ran_at' => gmdate('Y-m-d H:i:s'),
            'jobs_due' => 0,
            'jobs_planned' => 0,
            'jobs_deferred' => 0,
            'jobs_processed' => (int) ($profiling['jobs_processed'] ?? 0),
            'jobs_succeeded' => 0,
            'jobs_failed' => !empty($profiling['error']) ? 1 : 0,
            'jobs_dispatched' => 0,
            'planner' => ['mode' => 'profiling_pause'],
            'optimizer' => null,
            'profiling' => $profiling,
            'results' => [],
        ];
    }

    $workBatch = scheduler_select_work_batch($logger);
    $jobs = (array) ($workBatch['jobs'] ?? []);
    $planMode = (string) ($workBatch['mode'] ?? 'due');
    $runningJobs = (array) ($workBatch['running'] ?? []);
    if ($planMode === 'idle_backfill') {
        $capacity = scheduler_live_capacity_snapshot($runningJobs);
        $plan = [
            'mode' => 'idle_backfill',
            'allowed' => $jobs,
            'deferred' => [],
            'running' => $runningJobs,
            'state' => $capacity,
        ];
    } else {
        $plan = scheduler_plan_due_jobs($jobs);
        $plan['mode'] = $planMode;
    }
    $plannedJobs = (array) ($plan['allowed'] ?? []);
    $results = [];
    $successCount = 0;
    $failureCount = 0;
    $dispatchedCount = 0;

    foreach ($plannedJobs as $index => $job) {
        $jobId = (int) ($job['id'] ?? 0);
        $jobKey = (string) ($job['job_key'] ?? 'unknown_job');
        $jobType = scheduler_job_type($jobKey);
        $scheduledFor = (string) ($job['next_due_at'] ?? $job['next_run_at'] ?? '');
        $forceBackground = count($plannedJobs) > 1 || count((array) ($plan['running'] ?? [])) > 0;

        if ($logger !== null) {
            $logger('job.started', [
                'job_id' => $jobId,
                'job' => $jobKey,
                'job_type' => $jobType,
                'scheduled_for' => $scheduledFor,
                'selection_mode' => (string) ($job['scheduler_selection_mode'] ?? $planMode),
                'projected_cpu_percent' => $job['projected_cpu_percent'] ?? null,
                'projected_memory_bytes' => $job['projected_memory_bytes'] ?? null,
                'pressure_state' => $plan['state']['pressure'] ?? 'healthy',
            ]);
        }

        try {
            $result = ($forceBackground || scheduler_job_runs_in_background($jobKey) || scheduler_job_execution_mode($job) === 'python')
                ? scheduler_dispatch_background_job($job)
                : scheduler_run_job($job);
            if (($result['status'] ?? '') === 'dispatched') {
                db_scheduler_job_event_insert($jobKey, 'dispatch', [
                    'execution' => 'background',
                    'projected_cpu_percent' => $job['projected_cpu_percent'] ?? null,
                    'projected_memory_bytes' => $job['projected_memory_bytes'] ?? null,
                ], 0, 0.0);
            }
        } catch (Throwable $exception) {
            $result = scheduler_background_dispatch_failure_result($job, $exception);
        }
        $results[] = $result;

        if ($logger !== null) {
            $resultStatus = (string) ($result['status'] ?? 'failed');
            $jobEvent = match ($resultStatus) {
                'failed' => 'job.failed',
                'dispatched' => 'job.dispatched',
                default => 'job.completed',
            };
            $logger($jobEvent, [
                'job_id' => (int) ($result['job_id'] ?? $jobId),
                'job' => (string) ($result['job_key'] ?? $jobKey),
                'job_type' => (string) ($result['job_type'] ?? $jobType),
                'scheduled_for' => (string) ($result['scheduled_for'] ?? $scheduledFor),
                'selection_mode' => (string) ($job['scheduler_selection_mode'] ?? $planMode),
                'actual_start_time' => (string) ($result['started_at'] ?? ''),
                'finish_time' => (string) ($result['finished_at'] ?? ''),
                'duration_ms' => (int) ($result['duration_ms'] ?? 0),
                'status' => (string) ($result['status'] ?? 'failed'),
                'summary' => (string) ($result['summary'] ?? ''),
                'error' => ($result['status'] ?? '') === 'failed' ? (string) ($result['error'] ?? '') : null,
            ]);
        }

        $jobStatus = (string) ($result['status'] ?? 'failed');
        if ($jobStatus === 'success' || $jobStatus === 'skipped') {
            $successCount++;
            continue;
        }

        if ($jobStatus === 'dispatched') {
            $dispatchedCount++;
            continue;
        }

        if ($jobStatus === 'failed') {
            $failureCount++;
        }
    }

    $optimizerResult = scheduler_run_optimizer();

    return [
        'ran_at' => gmdate('Y-m-d H:i:s'),
        'jobs_due' => $planMode === 'due' ? count($jobs) : 0,
        'jobs_planned' => count($plannedJobs),
        'jobs_deferred' => count((array) ($plan['deferred'] ?? [])),
        'jobs_processed' => count($results),
        'jobs_succeeded' => $successCount,
        'jobs_failed' => $failureCount,
        'jobs_dispatched' => $dispatchedCount,
        'selection_mode' => $planMode,
        'planner' => $plan,
        'optimizer' => $optimizerResult,
        'results' => $results,
    ];
}

function sync_status_from_prefix(string $datasetPrefix, int $recentRunsLimit = 5): array
{
    try {
        $states = db_sync_state_by_dataset_prefix($datasetPrefix);
        $runs = db_sync_runs_recent_by_dataset_prefix($datasetPrefix, $recentRunsLimit);
    } catch (Throwable) {
        return [
            'states' => [],
            'runs' => [],
            'last_success_at' => null,
            'last_error_message' => null,
            'recent_rows_written' => 0,
        ];
    }

    $lastSuccessAt = null;
    foreach ($states as $state) {
        $candidate = $state['last_success_at'] ?? null;
        if (!is_string($candidate) || $candidate === '') {
            continue;
        }

        if ($lastSuccessAt === null || strtotime($candidate) > strtotime($lastSuccessAt)) {
            $lastSuccessAt = $candidate;
        }
    }

    $lastErrorMessage = null;
    foreach ($runs as $run) {
        if (($run['run_status'] ?? '') !== 'failed') {
            continue;
        }

        $message = trim((string) ($run['error_message'] ?? ''));
        if ($message !== '') {
            $lastErrorMessage = $message;
            break;
        }
    }

    if ($lastErrorMessage === null) {
        foreach ($states as $state) {
            $message = trim((string) ($state['last_error_message'] ?? ''));
            if ($message !== '') {
                $lastErrorMessage = $message;
                break;
            }
        }
    }

    $recentRowsWritten = 0;
    foreach ($runs as $run) {
        $recentRowsWritten += max(0, (int) ($run['written_rows'] ?? 0));
    }

    return [
        'states' => $states,
        'runs' => $runs,
        'last_success_at' => $lastSuccessAt,
        'last_error_message' => $lastErrorMessage,
        'recent_rows_written' => $recentRowsWritten,
    ];
}

