        'resolved_region_id' => isset($hubContext['region_id']) && $hubContext['region_id'] !== null ? (int) $hubContext['region_id'] : null,
        'resolved_structure_id' => isset($hubContext['structure_id']) && $hubContext['structure_id'] !== null ? (int) $hubContext['structure_id'] : null,
        'timeout_seconds' => (int) (scheduler_registry_definitions()['market_hub_local_history_sync']['timeout_seconds'] ?? 1800),
        'window_days' => market_hub_local_history_window_days_default(),
        'app_timezone' => app_timezone(),
        'history_read_table' => db_market_orders_history_read_table(),
        'local_history_source' => market_hub_local_history_source(),
    ];
}

function python_bridge_sync_run_start(string $datasetKey, string $runMode = 'incremental'): array
{
    $safeDatasetKey = trim($datasetKey);
    if ($safeDatasetKey === '') {
        throw new InvalidArgumentException('Dataset key is required to start a sync run.');
    }

    $safeRunMode = sync_mode_normalize($runMode);
    $cursorStart = sync_watermark($safeDatasetKey);
    $runId = db_sync_run_start($safeDatasetKey, $safeRunMode, $cursorStart);

    return [
        'run_id' => $runId,
        'dataset_key' => $safeDatasetKey,
        'run_mode' => $safeRunMode,
        'cursor_start' => $cursorStart,
    ];
}

function python_bridge_sync_cursor_upsert(array $payload): array
{
    $datasetKey = trim((string) ($payload['dataset_key'] ?? ''));
    if ($datasetKey === '') {
        throw new InvalidArgumentException('dataset_key is required to checkpoint a sync cursor.');
    }

    $runMode = sync_mode_normalize((string) ($payload['run_mode'] ?? 'incremental'));
    $cursor = isset($payload['cursor']) ? trim((string) $payload['cursor']) : '';
    if ($cursor === '') {
        return [
            'dataset_key' => $datasetKey,
            'run_mode' => $runMode,
            'cursor' => null,
            'checkpoint_updated' => false,
            'reason' => 'missing_cursor',
        ];
    }

    $updated = db_sync_cursor_upsert($datasetKey, $runMode, $cursor);

    return [
        'dataset_key' => $datasetKey,
        'run_mode' => $runMode,
        'cursor' => $cursor,
        'checkpoint_updated' => $updated,
        'reason' => $updated ? 'cursor_checkpointed' : 'checkpoint_write_failed',
        'rows_written' => max(0, (int) ($payload['rows_written'] ?? 0)),
        'outcome_reason' => trim((string) ($payload['outcome_reason'] ?? '')),
    ];
}

function python_bridge_sync_run_finish(array $payload): array
{
    $datasetKey = trim((string) ($payload['dataset_key'] ?? ''));
    if ($datasetKey === '') {
        throw new InvalidArgumentException('dataset_key is required to finish a sync run.');
    }

    $runId = max(0, (int) ($payload['run_id'] ?? 0));
    $runMode = sync_mode_normalize((string) ($payload['run_mode'] ?? 'incremental'));
    $jobKey = trim((string) ($payload['job_key'] ?? ''));
    $status = trim((string) ($payload['status'] ?? 'failed'));
    $status = $status === 'success' ? 'success' : 'failed';
    $rowsSeen = max(0, (int) ($payload['rows_seen'] ?? 0));
    $rowsWritten = max(0, (int) ($payload['rows_written'] ?? 0));
    $cursor = isset($payload['cursor']) && $payload['cursor'] !== null ? (string) $payload['cursor'] : null;
    $checksum = isset($payload['checksum']) && $payload['checksum'] !== null ? (string) $payload['checksum'] : null;
    $errorMessage = $status === 'failed'
        ? mb_substr(trim((string) ($payload['error_message'] ?? 'Python sync worker failed.')), 0, 500)
        : null;

    if ($status === 'success') {
        mark_sync_success($datasetKey, $runMode, $cursor, $rowsWritten, $checksum);
        if ($runId > 0) {
            db_sync_run_finish($runId, 'success', $rowsSeen, $rowsWritten, $cursor, null);
        }
    } else {
        mark_sync_failure($datasetKey, $runMode, $errorMessage ?? 'Python sync worker failed.');
        if ($runId > 0) {
            db_sync_run_finish($runId, 'failed', $rowsSeen, $rowsWritten, $cursor, $errorMessage);
        }
    }

    $downstream = python_bridge_post_sync_result($jobKey, $status, $rowsWritten);

    return [
        'run_id' => $runId,
        'dataset_key' => $datasetKey,
        'job_key' => $jobKey,
        'run_mode' => $runMode,
        'status' => $status,
        'rows_seen' => $rowsSeen,
        'rows_written' => $rowsWritten,
        'cursor' => $cursor,
        'checksum' => $checksum,
        'error_message' => $errorMessage,
        'downstream' => $downstream,
    ];
}

function python_bridge_post_sync_result(string $jobKey, string $status, int $rowsWritten): array
{
    $safeJobKey = trim($jobKey);
    if ($safeJobKey === '' || $status !== 'success') {
        return [
            'worker_jobs_forced' => 0,
            'schedule_jobs_forced' => 0,
            'job_keys' => [],
        ];
    }

    $downstreamJobKeys = [];
    if ($safeJobKey === 'killmail_r2z2_sync' && $rowsWritten > 0) {
        $downstreamJobKeys = ['activity_priority_summary_sync', 'loss_demand_summary_sync'];
    }

    if ($downstreamJobKeys === []) {
        return [
            'worker_jobs_forced' => 0,
            'schedule_jobs_forced' => 0,
            'job_keys' => [],
        ];
    }

    return [
        'worker_jobs_forced' => db_worker_job_force_available_by_job_keys($downstreamJobKeys),
        'schedule_jobs_forced' => db_sync_schedule_force_due_by_job_keys($downstreamJobKeys),
        'job_keys' => $downstreamJobKeys,
    ];
}

function python_bridge_process_killmail_batch(array $payloads, bool $skipEntityFilter = false): array
{
    if ($payloads === []) {
        return [
            'rows_seen' => 0,
            'rows_matched' => 0,
            'rows_skipped_existing' => 0,
            'rows_filtered_out' => 0,
            'rows_written' => 0,
            'killmails_fetched' => 0,
            'duplicates' => 0,
            'filtered' => 0,
            'invalid' => 0,
            'last_processed_sequence' => null,
            'no_write_reason' => 'empty_batch',
        ];
    }

    db_killmail_payload_schema_ensure();
    ['alliance_ids' => $trackedAllianceIds, 'corporation_ids' => $trackedCorporationIds] = killmail_active_tracked_entity_ids();
    ['alliance_ids' => $opponentAllianceIds, 'corporation_ids' => $opponentCorporationIds] = killmail_active_opponent_entity_ids();

    $rowsSeen = 0;
    $rowsMatched = 0;
    $rowsWritten = 0;
    $rowsWriteAttempted = 0;
    $rowsFailed = 0;
    $duplicates = 0;
    $filtered = 0;
    $invalid = 0;
    $lastProcessedSequence = null;
    $firstSequenceSeen = null;
    $lastSequenceSeen = null;
    $failureReason = '';

    foreach ($payloads as $payload) {
        $rowsSeen++;
        $requestedSequenceId = (int) ($payload['requested_sequence_id'] ?? $payload['sequence_id'] ?? 0);
        try {
            $result = killmail_persist_r2z2_payload($payload, $trackedAllianceIds, $trackedCorporationIds, false, $requestedSequenceId > 0 ? $requestedSequenceId : null, $opponentAllianceIds, $opponentCorporationIds, $skipEntityFilter);
        } catch (Throwable $exception) {
            $rowsFailed++;
            $failureReason = trim($exception->getMessage()) !== '' ? scheduler_normalize_error_message($exception->getMessage()) : 'Killmail write failed.';
            $lastProcessedSequence = $requestedSequenceId > 0 ? $requestedSequenceId - 1 : $lastProcessedSequence;
            break;
        }
        $sequenceId = (int) ($result['sequence_id'] ?? 0);
        $status = (string) ($result['status'] ?? 'invalid');
        if ($firstSequenceSeen === null && $sequenceId > 0) {
            $firstSequenceSeen = $sequenceId;
        }
        if ($sequenceId > 0) {
            $lastSequenceSeen = $sequenceId;
        }
        if ($status === 'invalid') {
            $invalid++;
            if ($requestedSequenceId > 0) {
                $lastProcessedSequence = $requestedSequenceId;
            }
            continue;
        }

        if ($status === 'duplicate') {
            $duplicates++;
            $rowsMatched++;
        } elseif ($status === 'filtered') {
            $filtered++;
        } elseif ($status === 'written') {
            $rowsWriteAttempted++;
            $rowsWritten++;
            $rowsMatched++;
        } elseif ($status === 'written_untracked') {
            $rowsWriteAttempted++;
            $rowsWritten++;
        }

        $lastProcessedSequence = $sequenceId;
    }

    $reasonForZeroWrite = '';
    if ($rowsWritten === 0) {
        if ($rowsFailed > 0) {
            $reasonForZeroWrite = 'write_failed';
        } elseif ($duplicates === $rowsSeen && $rowsSeen > 0) {
            $reasonForZeroWrite = 'already_existed_locally';
        } elseif ($filtered === $rowsSeen && $rowsSeen > 0) {
            $reasonForZeroWrite = 'no_tracked_entity_matches';
        } elseif ($invalid === $rowsSeen && $rowsSeen > 0) {
            $reasonForZeroWrite = 'unknown';
        } elseif (($filtered + $invalid) === $rowsSeen && $rowsSeen > 0) {
            $reasonForZeroWrite = 'filter_excluded_all';
        } else {
            $reasonForZeroWrite = 'unknown';
        }
    }

    return [
        'rows_seen' => $rowsSeen,
        'rows_matched' => $rowsMatched,
        'rows_skipped_existing' => $duplicates,
        'rows_filtered_out' => $filtered,
        'rows_write_attempted' => $rowsWriteAttempted,
        'rows_written' => $rowsWritten,
        'rows_failed' => $rowsFailed,
        'killmails_fetched' => $rowsSeen,
        'duplicates' => $duplicates,
        'filtered' => $filtered,
        'invalid' => $invalid,
        'last_processed_sequence' => $lastProcessedSequence,
        'reason_for_zero_write' => $reasonForZeroWrite,
        'no_write_reason' => $reasonForZeroWrite,
        'failure_reason' => $failureReason,
        'meta' => [
            'first_sequence_seen' => $firstSequenceSeen,
            'last_sequence_seen' => $lastSequenceSeen,
            'rows_seen' => $rowsSeen,
            'rows_matched' => $rowsMatched,
            'rows_filtered_out' => $filtered,
            'rows_skipped_existing' => $duplicates,
            'rows_write_attempted' => $rowsWriteAttempted,
            'rows_written' => $rowsWritten,
            'rows_failed' => $rowsFailed,
            'reason_for_zero_write' => $reasonForZeroWrite,
            'failure_reason' => $failureReason,
        ],
    ];
}

function python_bridge_repair_killmail_zkb(array $updates): array
{
    $updated = 0;
    $failed = 0;

    foreach ($updates as $entry) {
        $killmailId = (int) ($entry['killmail_id'] ?? 0);
        $zkb = is_array($entry['zkb'] ?? null) ? $entry['zkb'] : [];

        if ($killmailId <= 0 || $zkb === []) {
            $failed++;
            continue;
        }

        $totalValue = isset($zkb['totalValue']) && is_numeric($zkb['totalValue']) ? (float) $zkb['totalValue'] : null;
        $fittedValue = isset($zkb['fittedValue']) && is_numeric($zkb['fittedValue']) ? (float) $zkb['fittedValue'] : null;
        $droppedValue = isset($zkb['droppedValue']) && is_numeric($zkb['droppedValue']) ? (float) $zkb['droppedValue'] : null;
        $destroyedValue = isset($zkb['destroyedValue']) && is_numeric($zkb['destroyedValue']) ? (float) $zkb['destroyedValue'] : null;
        $points = isset($zkb['points']) && is_numeric($zkb['points']) ? (int) $zkb['points'] : null;
        $npc = isset($zkb['npc']) ? (!empty($zkb['npc']) ? 1 : 0) : null;
        $solo = isset($zkb['solo']) ? (!empty($zkb['solo']) ? 1 : 0) : null;
        $awox = isset($zkb['awox']) ? (!empty($zkb['awox']) ? 1 : 0) : null;

        if ($totalValue === null) {
            $failed++;
            continue;
        }

        try {
            db_execute(
                'UPDATE killmail_events SET
                    zkb_total_value = ?,
                    zkb_fitted_value = COALESCE(?, zkb_fitted_value),
                    zkb_dropped_value = COALESCE(?, zkb_dropped_value),
                    zkb_destroyed_value = COALESCE(?, zkb_destroyed_value),
                    zkb_points = COALESCE(?, zkb_points),
                    zkb_npc = COALESCE(?, zkb_npc),
                    zkb_solo = COALESCE(?, zkb_solo),
                    zkb_awox = COALESCE(?, zkb_awox)
                 WHERE killmail_id = ? AND zkb_total_value IS NULL',
                [$totalValue, $fittedValue, $droppedValue, $destroyedValue, $points, $npc, $solo, $awox, $killmailId]
            );

            // Also update the stored zkb_json in killmail_event_payloads
            $zkbJson = json_encode($zkb, JSON_UNESCAPED_SLASHES);
            db_execute(
                'UPDATE killmail_event_payloads p
                 INNER JOIN killmail_events e ON e.sequence_id = p.sequence_id
                 SET p.zkb_json = ?
                 WHERE e.killmail_id = ? AND (p.zkb_json IS NULL OR p.zkb_json = \'{}\' OR p.zkb_json = \'\')',
                [$zkbJson, $killmailId]
            );

            $updated++;
        } catch (Throwable $e) {
            $failed++;
        }
    }

    return ['updated' => $updated, 'failed' => $failed];
}

function python_bridge_run_job_handler(string $jobKey, string $reason = 'python-fallback'): array
{
    $definitions = scheduler_job_definitions();
    $definition = $definitions[$jobKey] ?? null;
    if (!is_array($definition) || !isset($definition['handler']) || !is_callable($definition['handler'])) {
        throw new InvalidArgumentException('No scheduler handler is registered for job key: ' . $jobKey);
    }

    $result = $definition['handler']();
    if (!is_array($result)) {
        $result = sync_result_shape();
    }

    return $result + [
        'meta' => (is_array($result['meta'] ?? null) ? $result['meta'] : []) + [
            'fallback_reason' => $reason,
        ],
    ];
}

function scheduler_finalize_python_job_result(array $job, array $pythonResult): array
{
    $jobKey = trim((string) ($job['job_key'] ?? ''));
    $scheduleId = (int) ($job['id'] ?? 0);
    $jobType = scheduler_job_runtime_type($job);
    $datasetKey = scheduler_job_dataset_key($jobKey !== '' ? $jobKey : 'unknown');
    $scheduledFor = (string) ($job['next_due_at'] ?? $job['next_run_at'] ?? '');
    $status = trim((string) ($pythonResult['status'] ?? 'failed'));
    $status = in_array($status, ['success', 'failed', 'skipped'], true) ? $status : 'failed';
    $error = $status === 'failed' ? scheduler_normalize_error_message((string) ($pythonResult['error'] ?? 'Python worker failed.')) : null;
    $rowsSeen = max(0, (int) ($pythonResult['rows_seen'] ?? 0));
    $rowsWritten = max(0, (int) ($pythonResult['rows_written'] ?? 0));
    $cursor = isset($pythonResult['cursor']) ? (string) $pythonResult['cursor'] : null;
    $checksum = isset($pythonResult['checksum']) ? (string) $pythonResult['checksum'] : null;
    $warnings = array_values(array_filter(array_map('strval', (array) ($pythonResult['warnings'] ?? [])), static fn (string $message): bool => true));
    $meta = is_array($pythonResult['meta'] ?? null) ? $pythonResult['meta'] : [];
    $durationMs = max(0, (int) ($pythonResult['duration_ms'] ?? 0));
    $durationSeconds = round($durationMs / 1000, 2);
    $runId = max(0, (int) ($pythonResult['run_id'] ?? 0));
    $startedAt = trim((string) ($pythonResult['started_at'] ?? ''));
    if ($startedAt === '') {
        $startedAt = gmdate(DATE_ATOM);
    }
    $finishedAt = trim((string) ($pythonResult['finished_at'] ?? ''));
    if ($finishedAt === '') {
        $finishedAt = gmdate(DATE_ATOM);
    }
    $summary = trim((string) ($pythonResult['summary'] ?? ''));
    if ($summary === '') {
        $summary = $status === 'failed' ? (string) $error : 'Python worker completed.';
    }

    if ($status === 'failed') {
        mark_sync_failure($datasetKey, 'incremental', (string) $error);
        if ($runId > 0) {
            db_sync_run_finish($runId, 'failed', $rowsSeen, $rowsWritten, $cursor, $error);
        }
        if ($scheduleId > 0) {
            db_sync_schedule_mark_failure($scheduleId, (string) $error, scheduler_job_runtime_snapshot($jobKey, 'failed') + [
                'last_duration_seconds' => $durationSeconds,
                'current_pressure_state' => $job['current_pressure_state'] ?? 'healthy',
            ]);
        }
        db_scheduler_job_event_insert($jobKey, 'failure', [
            'error' => $error,
            'execution_mode' => 'python',
            'rows_seen' => $rowsSeen,
            'rows_written' => $rowsWritten,
            'summary' => $summary,
            'meta' => $meta,
        ], 0, $durationSeconds);
    } else {
        mark_sync_success($datasetKey, 'incremental', $cursor, $rowsWritten, $checksum);
        if ($runId > 0) {
            db_sync_run_finish($runId, 'success', $rowsSeen, $rowsWritten, $cursor, null);
        }
        if ($scheduleId > 0) {
            db_sync_schedule_mark_success($scheduleId, scheduler_job_runtime_snapshot($jobKey, $status) + [
                'last_duration_seconds' => $durationSeconds,
                'current_pressure_state' => $job['current_pressure_state'] ?? 'healthy',
                'last_warnings_json' => $warnings !== [] ? $warnings : null,
            ]);
        }
        db_scheduler_job_event_insert($jobKey, $status === 'skipped' ? 'skipped' : 'finished', [
            'status' => $status,
            'execution_mode' => 'python',
            'rows_seen' => $rowsSeen,
            'rows_written' => $rowsWritten,
            'summary' => $summary,
            'warnings' => $warnings,
            'meta' => $meta,
        ], 0, $durationSeconds);
    }

    $result = [
        'job_id' => $scheduleId,
        'job_key' => $jobKey,
        'job_type' => $jobType,
        'scheduled_for' => $scheduledFor,
        'started_at' => $startedAt,
        'finished_at' => $finishedAt,
        'duration_ms' => $durationMs,
        'status' => $status,
        'error' => $error,
        'rows_seen' => $rowsSeen,
        'rows_written' => $rowsWritten,
        'warnings' => $warnings,
        'meta' => $meta + ['execution_mode' => 'python'],
        'summary' => $summary,
    ];
    $result['ui_refresh'] = supplycore_ui_refresh_publish_for_job_result($result);
    db_scheduler_daemon_request_wake(scheduler_daemon_key());

    return $result;
}

function sync_result_shape(): array
{
    return [
        'rows_seen' => 0,
        'rows_written' => 0,
        'cursor' => null,
        'checksum' => null,
        'warnings' => [],
        'meta' => [],
    ];
}

function sync_mode_normalize(string $runMode): string
{
