function sync_market_orders_history_prune(int $retentionDays, string $runMode = 'incremental'): array
{
    $result = sync_result_shape();
    $datasetKey = sync_dataset_key_maintenance_history_prune();
    $syncMode = sync_mode_normalize($runMode);
    $runId = db_sync_run_start($datasetKey, $syncMode, sync_watermark($datasetKey));

    try {
        $rawRetentionDays = db_market_history_retention_days('raw');
        $hourlyRetentionDays = db_market_history_retention_days('hourly');
        $dailyRetentionDays = db_market_history_retention_days('daily');
        $historyCleanup = db_market_history_tier_retention_cleanup(10000);
        $controlPlaneCleanup = db_control_plane_retention_cleanup(10000);
        $historyDeleted = array_sum(array_map(
            static fn (array $row): int => (int) ($row['rows_deleted'] ?? 0),
            (array) ($historyCleanup['deleted'] ?? [])
        ));
        $controlPlaneDeleted = array_sum(array_map(
            static fn (array $row): int => (int) ($row['rows_deleted'] ?? 0),
            (array) ($controlPlaneCleanup['deleted'] ?? [])
        ));
        $deletedRows = $historyDeleted + $controlPlaneDeleted;
        $rawCutoff = db_market_history_tier_cutoff('raw');
        $hourlyCutoff = db_market_history_tier_cutoff('hourly');
        $dailyCutoff = db_market_history_tier_cutoff('daily');

        $result['rows_seen'] = $deletedRows;
        $result['rows_written'] = $deletedRows;
        $result['cursor'] = 'raw:' . $rawCutoff . '|hourly:' . $hourlyCutoff . '|daily:' . $dailyCutoff;
        $result['checksum'] = sync_checksum([
            'deleted_rows' => $deletedRows,
            'deleted_history_rows' => $historyDeleted,
            'deleted_control_plane_rows' => $controlPlaneDeleted,
            'raw_retention_days' => $rawRetentionDays,
            'hourly_retention_days' => $hourlyRetentionDays,
            'daily_retention_days' => $dailyRetentionDays,
            'raw_cutoff' => $rawCutoff,
            'hourly_cutoff' => $hourlyCutoff,
            'daily_cutoff' => $dailyCutoff,
        ]);
        $result['meta'] = [
            'records_fetched' => $deletedRows,
            'records_inserted' => 0,
            'records_updated' => 0,
            'records_skipped' => 0,
            'records_deleted' => $deletedRows,
            'history_rows_generated' => 0,
            'market_history_retention' => [
                'raw_days' => $rawRetentionDays,
                'hourly_days' => $hourlyRetentionDays,
                'daily_days' => $dailyRetentionDays,
                'raw_cutoff' => $rawCutoff,
                'hourly_cutoff' => $hourlyCutoff,
                'daily_cutoff' => $dailyCutoff,
            ],
            'market_history_cleanup' => $historyCleanup['deleted'] ?? [],
            'control_plane_deleted' => $controlPlaneDeleted,
            'control_plane_cleanup' => $controlPlaneCleanup['deleted'] ?? [],
            'no_changes' => $deletedRows === 0,
        ];

        sync_run_finalize_success(
            $runId,
            $datasetKey,
            $syncMode,
            $result['rows_seen'],
            $result['rows_written'],
            $result['cursor'],
            $result['checksum']
        );

        return $result;
    } catch (Throwable $exception) {
        sync_run_finalize_failure($runId, $datasetKey, $syncMode, $exception->getMessage());
        $result['warnings'][] = 'History prune job failed: ' . $exception->getMessage();

        return $result;
    }
}

function esi_exchange_oauth_code(string $code): array
{
    $clientId = trim((string) get_setting('esi_client_id', ''));
    $clientSecret = trim((string) get_setting('esi_client_secret', ''));
    $redirectUri = trim((string) get_setting('esi_callback_url', base_url('/callback')));

    if ($clientId === '' || $clientSecret === '') {
        throw new RuntimeException('Missing ESI client credentials. Save them in Settings > ESI Login first.');
    }

    $tokenResponse = http_post_form(
        'https://login.eveonline.com/v2/oauth/token',
        [
            'Authorization: Basic ' . base64_encode($clientId . ':' . $clientSecret),
            'Content-Type: application/x-www-form-urlencoded',
            'Accept: application/json',
            'Host: login.eveonline.com',
        ],
        [
            'grant_type' => 'authorization_code',
            'code' => $code,
            'redirect_uri' => $redirectUri,
        ]
    );

    if (($tokenResponse['status'] ?? 500) >= 400) {
        throw new RuntimeException('ESI token exchange failed.');
    }

    $token = $tokenResponse['json'];
    $verifyResponse = http_get_json(
        'https://login.eveonline.com/oauth/verify',
        [
            'Authorization: Bearer ' . ($token['access_token'] ?? ''),
            'Accept: application/json',
            'Host: login.eveonline.com',
        ]
    );

    if (($verifyResponse['status'] ?? 500) >= 400) {
        throw new RuntimeException('ESI token verification failed.');
    }

    return [
        'token' => $token,
        'verify' => $verifyResponse['json'],
    ];
}

function esi_store_oauth_and_cache(array $tokenPayload, array $verifyPayload): void
{
    $expiresIn = (int) ($tokenPayload['expires_in'] ?? 0);
    $expiresAt = (new DateTimeImmutable('now', new DateTimeZone('UTC')))->modify('+' . max(0, $expiresIn) . ' seconds')->format('Y-m-d H:i:s');
    $scopes = isset($tokenPayload['scope']) ? (string) $tokenPayload['scope'] : esi_scopes_string();

    db_transaction(function () use ($tokenPayload, $verifyPayload, $expiresAt, $scopes): void {
        db_upsert_esi_oauth_token([
            'character_id' => (int) ($verifyPayload['CharacterID'] ?? 0),
            'character_name' => (string) ($verifyPayload['CharacterName'] ?? 'Unknown'),
            'owner_hash' => (string) ($verifyPayload['CharacterOwnerHash'] ?? ''),
            'access_token' => (string) ($tokenPayload['access_token'] ?? ''),
            'refresh_token' => (string) ($tokenPayload['refresh_token'] ?? ''),
            'token_type' => (string) ($tokenPayload['token_type'] ?? 'Bearer'),
            'scopes' => $scopes,
            'expires_at' => $expiresAt,
        ]);

        db_esi_cache_put('cache.esi.oauth.verify', 'latest', json_encode($verifyPayload, JSON_THROW_ON_ERROR));
        db_esi_cache_put('cache.esi.oauth.token', 'latest', json_encode([
            'access_token' => $tokenPayload['access_token'] ?? '',
            'refresh_token' => $tokenPayload['refresh_token'] ?? '',
            'token_type' => $tokenPayload['token_type'] ?? 'Bearer',
            'expires_in' => $tokenPayload['expires_in'] ?? null,
            'scope' => $scopes,
        ], JSON_THROW_ON_ERROR), null, $expiresAt);
    });
}

function esi_refresh_oauth_token(array $storedToken): array
{
    $clientId = trim((string) get_setting('esi_client_id', ''));
    $clientSecret = trim((string) get_setting('esi_client_secret', ''));
    $refreshToken = trim((string) ($storedToken['refresh_token'] ?? ''));

    if ($clientId === '' || $clientSecret === '' || $refreshToken === '') {
        throw new RuntimeException('ESI session is missing OAuth credentials. Please reconnect your character from Settings > ESI Login.');
    }

    $response = http_post_form(
        'https://login.eveonline.com/v2/oauth/token',
        [
            'Authorization: Basic ' . base64_encode($clientId . ':' . $clientSecret),
            'Content-Type: application/x-www-form-urlencoded',
            'Accept: application/json',
            'Host: login.eveonline.com',
        ],
        [
            'grant_type' => 'refresh_token',
            'refresh_token' => $refreshToken,
        ]
    );

    if (($response['status'] ?? 500) >= 400) {
        throw new RuntimeException('Unable to refresh ESI session. Please reconnect your character from Settings > ESI Login.');
    }

    $tokenPayload = $response['json'];
    $expiresIn = (int) ($tokenPayload['expires_in'] ?? 0);
    $expiresAt = (new DateTimeImmutable('now', new DateTimeZone('UTC')))->modify('+' . max(0, $expiresIn) . ' seconds')->format('Y-m-d H:i:s');
    $nextAccessToken = trim((string) ($tokenPayload['access_token'] ?? ''));
    $nextRefreshToken = trim((string) ($tokenPayload['refresh_token'] ?? ''));
    $tokenType = trim((string) ($tokenPayload['token_type'] ?? ($storedToken['token_type'] ?? 'Bearer')));
    $scopes = trim((string) ($tokenPayload['scope'] ?? ($storedToken['scopes'] ?? esi_scopes_string())));

    if ($nextAccessToken === '' || $nextRefreshToken === '' || (int) ($storedToken['id'] ?? 0) <= 0) {
        throw new RuntimeException('ESI session refresh returned an invalid token payload. Please reconnect your character.');
    }

    db_update_esi_oauth_token_refresh(
        (int) $storedToken['id'],
        $nextAccessToken,
        $nextRefreshToken,
        $tokenType !== '' ? $tokenType : 'Bearer',
        $scopes,
        $expiresAt
    );

    db_esi_cache_put('cache.esi.oauth.token', 'latest', json_encode([
        'access_token' => $nextAccessToken,
        'refresh_token' => $nextRefreshToken,
        'token_type' => $tokenType !== '' ? $tokenType : 'Bearer',
        'expires_in' => $tokenPayload['expires_in'] ?? null,
        'scope' => $scopes,
    ], JSON_THROW_ON_ERROR), null, $expiresAt);

    $storedToken['access_token'] = $nextAccessToken;
    $storedToken['refresh_token'] = $nextRefreshToken;
    $storedToken['token_type'] = $tokenType !== '' ? $tokenType : 'Bearer';
    $storedToken['scopes'] = $scopes;
    $storedToken['expires_at'] = $expiresAt;

    return $storedToken;
}

function esi_valid_access_token(int $refreshWindowSeconds = 120): string
{
    $storedToken = db_latest_esi_oauth_token();
    if ($storedToken === null) {
        throw new RuntimeException('No connected ESI character token found. Connect a character from Settings > ESI Login.');
    }

    $accessToken = trim((string) ($storedToken['access_token'] ?? ''));
    if ($accessToken === '') {
        throw new RuntimeException('Connected ESI token is invalid. Please reconnect your character.');
    }

    $expiresAt = strtotime((string) ($storedToken['expires_at'] ?? '')) ?: 0;
    if ($expiresAt <= (time() + max(0, $refreshWindowSeconds))) {
        $storedToken = esi_refresh_oauth_token($storedToken);
        $accessToken = trim((string) ($storedToken['access_token'] ?? ''));
        if ($accessToken === '') {
            throw new RuntimeException('Unable to refresh ESI session. Please reconnect your character from Settings > ESI Login.');
        }
    }

    return $accessToken;
}

function esi_user_agent(): string
{
    $configured = trim((string) get_setting('app_name', 'SupplyCore'));

    return $configured !== ''
        ? $configured . ' supplycore/1.0 (+https://github.com/cvweiss/supplycore)'
        : 'SupplyCore supplycore/1.0 (+https://github.com/cvweiss/supplycore)';
}

/**
 * Fetch entity names from ESI's /universe/names/ endpoint (public, no auth).
 *
 * Accepts up to 1000 IDs. Returns an array of [{id, name, category}] on
 * success, or null if ESI is unreachable / returned an error so the caller
 * can fall back gracefully.
 */
function esi_universe_names_fetch(array $ids): ?array
{
    $ids = array_values(array_unique(array_filter(
        array_map(static fn (mixed $id): int => (int) $id, $ids),
        static fn (int $id): bool => $id > 0
    )));

    if ($ids === []) {
        return [];
    }

    // ESI accepts max 1000 IDs per request — chunk if needed.
    $results = [];
    foreach (array_chunk($ids, 1000) as $chunk) {
        try {
            $response = http_post_json(
                'https://esi.evetech.net/latest/universe/names/?datasource=tranquility',
                [
                    'Accept: application/json',
                    'User-Agent: ' . esi_user_agent(),
                ],
                $chunk,
                10 // 10 second timeout — caller is waiting
            );

            $status = (int) ($response['status'] ?? 0);

            if ($status >= 500 || $status === 0) {
                // ESI is down — signal caller to use fallback.
                error_log('[esi-fetch] ESI /universe/names/ returned status ' . $status . ' — falling back to async resolution');
                return null;
            }

            if ($status === 404) {
                // All IDs were invalid — not an error, just no results for this chunk.
                continue;
            }

            if ($status >= 400) {
                error_log('[esi-fetch] ESI /universe/names/ returned status ' . $status);
                return null;
            }

            if (is_array($response['json'] ?? null)) {
                foreach ($response['json'] as $entry) {
                    $results[] = $entry;
                }
            }
        } catch (Throwable $e) {
            error_log('[esi-fetch] ESI /universe/names/ request failed: ' . $e->getMessage());
            return null;
        }
    }

    return $results;
}

function esi_lookup_context(array $requiredScopes = []): array
{
    $enabled = get_setting('esi_enabled', '0') === '1';
    if (!$enabled) {
        return ['ok' => false, 'status' => 403, 'error' => 'ESI login is disabled in settings.'];
    }

    $token = db_latest_esi_oauth_token();
    if ($token === null) {
        return ['ok' => false, 'status' => 401, 'error' => 'No connected ESI character token found.'];
    }

    try {
        $token['access_token'] = esi_valid_access_token();
    } catch (Throwable $exception) {
        return ['ok' => false, 'status' => 401, 'error' => $exception->getMessage()];
    }

    $missing = esi_missing_scopes($token, $requiredScopes);

    if ($missing !== []) {
        return ['ok' => false, 'status' => 403, 'error' => 'Missing required ESI scopes: ' . implode(', ', $missing) . '. Reconnect your character after updating scopes.'];
    }

    return ['ok' => true, 'token' => $token, 'status' => 200, 'error' => null];
}

function esi_structure_result_shape(array $structure): array
{
    $result = [
        'id' => (int) ($structure['id'] ?? 0),
        'name' => (string) ($structure['name'] ?? ''),
    ];

    if (!empty($structure['system'])) {
        $result['system'] = (string) $structure['system'];
    }

    if (!empty($structure['type'])) {
        $result['type'] = (string) $structure['type'];
    }

    return $result;
}


function esi_entity_result_shape(array $entity): array
{
    return [
        'id' => (int) ($entity['id'] ?? 0),
        'name' => (string) ($entity['name'] ?? ''),
        'type' => (string) ($entity['type'] ?? ''),
    ];
}

function esi_universe_names_lookup(array $ids): array
{
    $queryIds = array_values(array_unique(array_map(static fn (mixed $id): int => (int) $id, $ids)));
    $queryIds = array_values(array_filter($queryIds, static fn (int $id): bool => $id > 0));
    if ($queryIds === []) {
        return [];
    }

    // Phase 2: read from entity_metadata_cache instead of calling ESI directly.
    // Python's entity_metadata_resolve_sync job resolves pending entities asynchronously.
    $results = [];
    $resolvedIds = [];

    foreach (['alliance', 'corporation', 'character'] as $type) {
        $cached = db_entity_metadata_cache_get_many($type, $queryIds);
        foreach ($cached as $row) {
            $entityId = (int) ($row['entity_id'] ?? 0);
            $name = trim((string) ($row['entity_name'] ?? ''));
            if ($entityId > 0 && $name !== '' && ($row['resolution_status'] ?? '') === 'resolved') {
                $results[] = [
                    'id' => $entityId,
                    'name' => $name,
                    'category' => (string) ($row['entity_type'] ?? $type),
                ];
                $resolvedIds[$entityId] = true;
            }
        }
    }

    // Fetch unresolved IDs immediately from ESI while the caller waits.
    $unresolvedIds = array_values(array_filter($queryIds, static fn (int $id): bool => !isset($resolvedIds[$id])));
    if ($unresolvedIds !== []) {
        $fetched = esi_universe_names_fetch($unresolvedIds);

        if ($fetched !== null) {
            // ESI responded — upsert into cache and add to results.
            $upserts = [];
            $now = gmdate('Y-m-d H:i:s');
            $expiresAt = gmdate('Y-m-d H:i:s', time() + 86400);

            foreach ($fetched as $entry) {
                $entityId = (int) ($entry['id'] ?? 0);
                $name = trim((string) ($entry['name'] ?? ''));
                $category = strtolower(trim((string) ($entry['category'] ?? '')));

                if ($entityId <= 0 || $name === '') {
                    continue;
                }

                $results[] = [
                    'id' => $entityId,
                    'name' => $name,
                    'category' => $category,
                ];
                $resolvedIds[$entityId] = true;

                if (in_array($category, ['alliance', 'corporation', 'character'], true)) {
                    $upserts[] = [
                        'entity_type' => $category,
                        'entity_id' => $entityId,
                        'entity_name' => $name,
                        'image_url' => killmail_entity_image_url($category, $entityId),
                        'metadata_json' => null,
                        'source_system' => 'esi',
                        'resolution_status' => 'resolved',
                        'expires_at' => $expiresAt,
                        'resolved_at' => $now,
                        'last_error_message' => null,
                    ];
                }
            }

            if ($upserts !== []) {
                db_entity_metadata_cache_upsert($upserts);
            }
        } else {
            // ESI is down — fall back to marking pending for background resolution.
            try {
                db_entity_metadata_cache_mark_pending('character', $unresolvedIds);
            } catch (Throwable) {
                // Non-fatal.
            }
        }
    }

    return $results;
}

/**
 * Search alliances and corporations by name via authenticated ESI character search.
 *
 * Requires ``esi-search.search_structures.v1`` scope. Intentionally kept as a
 * PHP ESI callsite because the killmail entity settings UI needs synchronous
 * search results for the autocomplete typeahead.
 *
 * @todo Phase 3: route through a Python ESI search proxy for rate-limit coordination.
 */
function esi_alliance_and_corporation_search(string $query, array $tokenContext): array
{
    $term = trim($query);
    if ($term === '') {
        return [];
    }

    $characterId = (int) ($tokenContext['character_id'] ?? 0);
    if ($characterId <= 0) {
        return [];
    }

    $accessToken = esi_valid_access_token();
    $searchResponse = http_get_json(
        'https://esi.evetech.net/latest/characters/' . $characterId . '/search/?categories=alliance,corporation&strict=false&search=' . rawurlencode($term),
        [
            'Authorization: Bearer ' . $accessToken,
            'Accept: application/json',
            'User-Agent: ' . esi_user_agent(),
        ]
    );

    if (($searchResponse['status'] ?? 500) >= 400) {
        throw new RuntimeException('Failed to search alliances and corporations from ESI.');
    }

    $ids = [];
    $entityTypesById = [];
    foreach (['alliance' => 'Alliance', 'corporation' => 'Corporation'] as $category => $label) {
        foreach ((array) ($searchResponse['json'][$category] ?? []) as $rawId) {
            $id = (int) $rawId;
            if ($id <= 0) {
                continue;
            }

            $ids[] = $id;
            $entityTypesById[$id] = $label;
        }
    }

    $results = [];
    foreach (esi_universe_names_lookup($ids) as $row) {
        if (!is_array($row)) {
            continue;
        }

        $id = (int) ($row['id'] ?? 0);
        $name = trim((string) ($row['name'] ?? ''));
        if ($id <= 0 || $name === '' || !isset($entityTypesById[$id])) {
            continue;
        }

        if (mb_stripos($name, $term) === false) {
            continue;
        }

        $results[$id] = esi_entity_result_shape([
            'id' => $id,
            'name' => $name,
            'type' => $entityTypesById[$id],
        ]);
    }

    usort($results, static function (array $a, array $b): int {
        $typeCompare = strcasecmp((string) ($a['type'] ?? ''), (string) ($b['type'] ?? ''));
        if ($typeCompare !== 0) {
            return $typeCompare;
        }

        return strcasecmp((string) ($a['name'] ?? ''), (string) ($b['name'] ?? ''));
    });

    return array_slice(array_values($results), 0, 20);
}



function killmail_entity_type_label(?string $type): ?string
{
    $normalized = strtolower(trim((string) $type));

    return match ($normalized) {
        'alliance' => 'Alliance',
        'corporation' => 'Corporation',
        default => null,
    };
}

function killmail_public_entity_lookup_by_id(int $id, ?string $type = null): array
{
    if ($id <= 0) {
        return [];
    }

    // Phase 2: read from entity_metadata_cache instead of calling ESI directly.
    $normalizedType = killmail_entity_type_label($type);
    $typesToCheck = $normalizedType !== null ? [strtolower($normalizedType)] : ['alliance', 'corporation'];
    $results = [];

    foreach ($typesToCheck as $entityType) {
        $cached = db_entity_metadata_cache_get_many($entityType, [$id]);
        if (!empty($cached)) {
            $row = reset($cached);
            $name = trim((string) ($row['entity_name'] ?? ''));
            if ($name !== '' && ($row['resolution_status'] ?? '') === 'resolved') {
                $results[] = esi_entity_result_shape([
                    'id' => $id,
                    'name' => $name,
                    'type' => ucfirst($entityType),
                ]);
            }
        }
    }

    // Fetch immediately from ESI if nothing found in cache.
    if (empty($results)) {
        $fetched = esi_universe_names_fetch([$id]);

        if ($fetched !== null) {
            $upserts = [];
            $now = gmdate('Y-m-d H:i:s');
            $expiresAt = gmdate('Y-m-d H:i:s', time() + 86400);

            foreach ($fetched as $entry) {
                $entityId = (int) ($entry['id'] ?? 0);
                $name = trim((string) ($entry['name'] ?? ''));
                $category = strtolower(trim((string) ($entry['category'] ?? '')));

                if ($entityId !== $id || $name === '') {
                    continue;
                }

                $categoryLabel = ucfirst($category);
                if ($normalizedType !== null && $categoryLabel !== $normalizedType) {
                    continue;
                }

                $results[] = esi_entity_result_shape([
                    'id' => $entityId,
                    'name' => $name,
                    'type' => $categoryLabel,
                ]);

                if (in_array($category, ['alliance', 'corporation', 'character'], true)) {
                    $upserts[] = [
                        'entity_type' => $category,
                        'entity_id' => $entityId,
                        'entity_name' => $name,
                        'image_url' => killmail_entity_image_url($category, $entityId),
                        'metadata_json' => null,
                        'source_system' => 'esi',
                        'resolution_status' => 'resolved',
                        'expires_at' => $expiresAt,
                        'resolved_at' => $now,
                        'last_error_message' => null,
                    ];
                }
            }

            if ($upserts !== []) {
                db_entity_metadata_cache_upsert($upserts);
            }
        } else {
            // ESI is down — fall back to marking pending for background resolution.
            try {
                foreach ($typesToCheck as $entityType) {
                    db_entity_metadata_cache_mark_pending($entityType, [$id]);
                }
            } catch (Throwable) {
                // Non-fatal.
            }
        }
    }

    return $results;
}

function killmail_entity_search(string $query, ?string $type = null): array
{
    $term = trim($query);
    if ($term === '') {
        return [];
    }

    $allowedType = killmail_entity_type_label($type);
    $results = [];

    if (preg_match('/^[1-9][0-9]{0,19}$/', $term) === 1) {
        foreach (killmail_public_entity_lookup_by_id((int) $term, $allowedType) as $row) {
            $results[(string) ($row['type'] ?? '') . ':' . (string) ($row['id'] ?? 0)] = $row;
        }
    }

    $context = esi_lookup_context();
    if (($context['ok'] ?? false) === true) {
        try {
            foreach (esi_alliance_and_corporation_search($term, (array) ($context['token'] ?? [])) as $row) {
                $rowType = killmail_entity_type_label((string) ($row['type'] ?? ''));
                if ($rowType === null) {
                    continue;
                }

                if ($allowedType !== null && $rowType !== $allowedType) {
                    continue;
                }

                $results[$rowType . ':' . (string) ($row['id'] ?? 0)] = [
                    'id' => (int) ($row['id'] ?? 0),
                    'name' => (string) ($row['name'] ?? ''),
                    'type' => $rowType,
                ];
            }
        } catch (Throwable) {
            // Fallback to exact-ID results only.
        }
    }

    $rows = array_values(array_filter($results, static function (array $row): bool {
        return (int) ($row['id'] ?? 0) > 0 && trim((string) ($row['name'] ?? '')) !== '';
    }));

    usort($rows, static function (array $a, array $b): int {
        $typeCompare = strcasecmp((string) ($a['type'] ?? ''), (string) ($b['type'] ?? ''));
        if ($typeCompare !== 0) {
            return $typeCompare;
        }

        return strcasecmp((string) ($a['name'] ?? ''), (string) ($b['name'] ?? ''));
    });

    return array_slice($rows, 0, 20);
}

/**
 * Resolve alliance structure metadata (name) for a player-owned Upwell structure.
 *
 * Structures require an authenticated ESI call with ``esi-universe.read_structures.v1``
 * scope — ESI only returns details for structures where the character has docking rights.
 * This is intentionally kept as a PHP ESI callsite because settings validation (first-time
 * structure setup) requires synchronous feedback that the structure exists and is accessible.
 *
 * The function reads from the ``alliance_structure_metadata`` DB cache first.
 * On cache miss, it makes an authenticated ESI call, caches the result, and returns it.
 * Once cached, subsequent calls (and Python's market sync jobs) use the cached name.
 */
function esi_alliance_structure_metadata(int $structureId, array $tokenContext): ?array
{
    if ($structureId <= 0) {
        return null;
    }

    // Cache-first: return immediately if we already have the name.
    $cached = db_alliance_structure_metadata_get($structureId);
    if ($cached !== null && trim((string) ($cached['structure_name'] ?? '')) !== '') {
        return [
            'id' => $structureId,
            'name' => trim((string) $cached['structure_name']),
            'last_verified_at' => $cached['last_verified_at'] ?? null,
        ];
    }

    // Cache miss — authenticated ESI call required.
    // Structures are private: ESI only returns data for structures where the
    // character has docking rights (Keepstars, Fortizars, etc.).
    try {
        $accessToken = esi_valid_access_token();
    } catch (Throwable) {
        return null;
    }

    $response = http_get_json(
        'https://esi.evetech.net/latest/universe/structures/' . $structureId . '/',
        [
            'Authorization: Bearer ' . $accessToken,
            'Accept: application/json',
        ]
    );

    if (($response['status'] ?? 500) >= 400) {
        return null;
    }

    $name = trim((string) ($response['json']['name'] ?? ''));
    $updated = db_alliance_structure_metadata_upsert(
        $structureId,
        $name !== '' ? $name : null,
        gmdate('Y-m-d H:i:s')
    );
    if ($updated) {
        supplycore_cache_bust('metadata_structures');
    }

    return [
        'id' => $structureId,
        'name' => $name,
        'last_verified_at' => gmdate('Y-m-d H:i:s'),
    ];
}

/**
 * Search for player-owned structures by name via authenticated ESI.
 *
 * This requires ``esi-search.search_structures.v1`` scope and only returns
 * structures where the character has docking rights (Keepstars, Fortizars, etc.).
 * It is intentionally kept as a PHP ESI callsite because the settings UI needs
 * synchronous search results during first-time structure setup.
 *
 * @todo Phase 3: route through a Python ESI search proxy for rate-limit coordination.
 */
function esi_structure_search(string $query, array $tokenContext): array
{
    $term = trim($query);
    if ($term === '') {
        return [];
    }

    $characterId = (int) ($tokenContext['character_id'] ?? 0);
    if ($characterId <= 0) {
        return [];
    }

    $accessToken = esi_valid_access_token();

    $cached = db_esi_structure_search_cache_get($characterId, $term);
    if ($cached !== null && isset($cached['payload_json'])) {
        try {
            $payload = json_decode((string) $cached['payload_json'], true, 512, JSON_THROW_ON_ERROR);
            if (is_array($payload)) {
                return $payload;
            }
        } catch (Throwable) {
            // Continue to ESI fetch.
        }
    }

    $searchResponse = http_get_json(
        'https://esi.evetech.net/latest/characters/' . $characterId . '/search/?categories=structure&strict=false&search=' . rawurlencode($term),
        [
            'Authorization: Bearer ' . $accessToken,
            'Accept: application/json',
        ]
    );

    if (($searchResponse['status'] ?? 500) >= 400) {
        throw new RuntimeException('Failed to search structures from ESI.');
    }

    $structureIds = $searchResponse['json']['structure'] ?? [];
    if (!is_array($structureIds)) {
        return [];
    }

    $results = [];
    foreach (array_slice($structureIds, 0, 20) as $structureId) {
        $id = (int) $structureId;
        if ($id <= 0) {
            continue;
        }

        try {
            $structureResponse = http_get_json(
                'https://esi.evetech.net/latest/universe/structures/' . $id . '/',
                [
                    'Authorization: Bearer ' . $accessToken,
                    'Accept: application/json',
                ]
            );
        } catch (Throwable) {
            continue;
        }

        if (($structureResponse['status'] ?? 500) >= 400) {
            continue;
        }

        $name = trim((string) ($structureResponse['json']['name'] ?? ''));
        if ($name === '') {
            continue;
        }

        if (mb_stripos($name, $term) === false) {
            continue;
        }

        if (db_alliance_structure_metadata_upsert($id, $name, gmdate('Y-m-d H:i:s'))) {
            supplycore_cache_bust('metadata_structures');
        }

        $results[] = esi_structure_result_shape([
            'id' => $id,
            'name' => $name,
            'system' => isset($structureResponse['json']['solar_system_id']) ? (string) $structureResponse['json']['solar_system_id'] : null,
            'type' => 'Structure',
        ]);
    }

    db_esi_structure_search_cache_put(
        $characterId,
        $term,
        json_encode($results, JSON_THROW_ON_ERROR),
        gmdate('Y-m-d H:i:s', time() + 300)
    );

    return $results;
}

function esi_npc_station_search(string $query, array $tokenContext): array
{
    $term = trim($query);
    if ($term === '') {
        return [];
    }

    // Phase 2: search ref_npc_stations locally instead of calling ESI.
    $stations = db_ref_npc_station_search($term, 20);
    $results = [];
    foreach ($stations as $station) {
        $stationId = (int) ($station['station_id'] ?? 0);
        $name = (string) ($station['station_name'] ?? '');
        if ($stationId <= 0 || is_placeholder_station_name($name, $stationId)) {
            continue;
        }
        $results[] = esi_structure_result_shape([
            'id' => $stationId,
            'name' => $name,
            'system' => isset($station['system_id']) ? (string) $station['system_id'] : null,
            'type' => 'NPC Station',
        ]);
    }

    return $results;
}

function esi_npc_station_metadata(int $stationId): ?array
{
    if ($stationId <= 0) {
        return null;
    }

    // Phase 2: read from ref_npc_stations instead of calling ESI directly.
    $station = db_ref_npc_station_by_id($stationId);
    if ($station === null) {
        return null;
    }

    $name = trim((string) ($station['station_name'] ?? ''));
    if ($name === '' || is_placeholder_station_name($name, $stationId)) {
        return null;
    }

    return [
        'id' => $stationId,
        'name' => $name,
        'system' => isset($station['system_id']) ? (string) $station['system_id'] : null,
        'type' => 'NPC Station',
    ];
}



function runner_lock_acquire(string $lockName, int $timeoutSeconds = 0): bool
{
    if (supplycore_redis_locking_enabled()) {
        $ttl = max(30, $timeoutSeconds > 0 ? $timeoutSeconds : 300);
        $token = supplycore_redis_lock_acquire('runner:' . $lockName, $ttl);
        if ($token !== null) {
            $GLOBALS['__supplycore_runner_lock_tokens'][$lockName] = $token;

            return true;
        }
    }

    return db_runner_lock_acquire($lockName, $timeoutSeconds);
}

function runner_lock_release(string $lockName): bool
{
    $token = $GLOBALS['__supplycore_runner_lock_tokens'][$lockName] ?? null;
    if (is_string($token) && $token !== '') {
        unset($GLOBALS['__supplycore_runner_lock_tokens'][$lockName]);

        return supplycore_redis_lock_release('runner:' . $lockName, $token);
    }

    return db_runner_lock_release($lockName);
}

function static_data_source_key(): string
{
    return 'official.jsonl';
}

function static_data_source_url(): string
{
    $default = static_data_default_source_url();
    $configured = trim((string) get_setting('static_data_source_url', $default));

    return $configured !== '' ? $configured : $default;
}

function static_data_import_mode(string $requestedMode = 'auto'): string
{
    $normalized = trim(mb_strtolower($requestedMode));
    $incrementalEnabled = get_setting('incremental_updates_enabled', '1') === '1';

    if ($normalized === 'full') {
        return 'full';
    }

    if ($normalized === 'incremental') {
        return $incrementalEnabled ? 'incremental' : 'full';
    }

    return $incrementalEnabled ? 'incremental' : 'full';
}

function static_data_fetch_remote_build_info(string $sourceUrl): array
{
    $manifestUrl = static_data_manifest_url_for_source($sourceUrl);
    if ($manifestUrl !== null) {
        try {
            $manifestInfo = static_data_build_info_from_manifest($manifestUrl);
            if ($manifestInfo !== null) {
                return $manifestInfo;
            }
        } catch (Throwable) {
            // Fall back to archive headers for non-standard mirrors or manifest fetch failures.
        }
    }

    if (!function_exists('get_headers')) {
        throw new RuntimeException('Unable to fetch static-data metadata from source URL.');
    }

    $context = stream_context_create([
        'http' => [
            'method' => 'HEAD',
            'timeout' => 30,
            'ignore_errors' => true,
            'header' => "User-Agent: SupplyCore/1.0\r\nAccept: */*\r\n",
        ],
    ]);
    $headers = @get_headers($sourceUrl, true, $context);
    if ($headers === false && function_exists('curl_init')) {
        $ch = curl_init($sourceUrl);
        curl_setopt_array($ch, [
            CURLOPT_NOBODY => true,
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_HEADER => true,
            CURLOPT_FOLLOWLOCATION => true,
            CURLOPT_CONNECTTIMEOUT => 10,
            CURLOPT_TIMEOUT => 30,
            CURLOPT_HTTPHEADER => ['Accept: */*', 'User-Agent: SupplyCore/1.0'],
        ]);
        $rawHeaders = curl_exec($ch);
        $status = (int) curl_getinfo($ch, CURLINFO_RESPONSE_CODE);
        curl_close($ch);

        if (is_string($rawHeaders) && $rawHeaders !== '' && $status > 0 && $status < 400) {
            $headers = [];
            foreach (preg_split("/(?:\r\n|\n|\r)/", trim($rawHeaders)) as $line) {
                if (!str_contains($line, ':')) {
                    continue;
                }

                [$name, $value] = array_map('trim', explode(':', $line, 2));
                if ($name === '') {
                    continue;
                }

                if (isset($headers[$name])) {
                    $headers[$name] = array_merge((array) $headers[$name], [$value]);
                } else {
                    $headers[$name] = $value;
                }
            }
        }
    }

    if ($headers === false) {
        throw new RuntimeException('Unable to fetch static-data metadata from source URL.');
    }

    $lastModified = '';
    $etag = '';

    if (is_array($headers['Last-Modified'] ?? null)) {
        $lastModified = (string) end($headers['Last-Modified']);
    } elseif (isset($headers['Last-Modified'])) {
        $lastModified = (string) $headers['Last-Modified'];
    }

    if (is_array($headers['ETag'] ?? null)) {
        $etag = (string) end($headers['ETag']);
    } elseif (isset($headers['ETag'])) {
        $etag = (string) $headers['ETag'];
    }

    $buildId = sha1($sourceUrl . '|' . trim($etag, '"') . '|' . $lastModified);

    return [
        'build_id' => $buildId,
        'etag' => trim((string) $etag, '"'),
        'last_modified' => $lastModified,
    ];
}

function static_data_storage_paths(string $buildId): array
{
    $baseDir = dirname(__DIR__) . '/storage/static-data';

    return [
        'base_dir' => $baseDir,
        'archive_path' => $baseDir . '/' . $buildId . '.jsonl.zip',
    ];
}

function static_data_ensure_local_jsonl_archive(string $sourceUrl, string $buildId): string
{
    $paths = static_data_storage_paths($buildId);
    if (!is_dir($paths['base_dir']) && !mkdir($paths['base_dir'], 0775, true) && !is_dir($paths['base_dir'])) {
        throw new RuntimeException('Unable to create static-data storage directory.');
    }

    $normalizedSource = mb_strtolower($sourceUrl);
    if (!str_ends_with($normalizedSource, '.zip')) {
        throw new RuntimeException('Unsupported static-data format. This importer supports JSONL ZIP archives (.zip).');
    }

    if (!is_file($paths['archive_path'])) {
        $payload = static_data_fetch_binary_payload($sourceUrl);
        if (file_put_contents($paths['archive_path'], $payload) === false) {
            throw new RuntimeException('Failed to write static-data archive to local storage.');
        }
    }

    return $paths['archive_path'];
}

function static_data_record_value(array $row, array $keys, mixed $default = null): mixed
{
    foreach ($keys as $key) {
        if (array_key_exists($key, $row)) {
            return $row[$key];
        }
    }

    return $default;
}

function static_data_localized_text(mixed $value): ?string
{
    if (is_string($value)) {
        $text = trim($value);

        return $text === '' ? null : $text;
    }

    if (!is_array($value)) {
        return null;
    }

    foreach (['en', 'en-us', 'EN'] as $key) {
        if (isset($value[$key]) && is_string($value[$key]) && trim($value[$key]) !== '') {
            return trim($value[$key]);
        }
    }

    foreach ($value as $candidate) {
        if (is_string($candidate) && trim($candidate) !== '') {
            return trim($candidate);
        }
    }

    return null;
}

function static_data_parse_jsonl_entry(array $entry): ?array
{
    if (!isset($entry['name']) || !isset($entry['index'])) {
        return null;
    }

    $fileName = basename((string) $entry['name']);
    if (!str_ends_with(mb_strtolower($fileName), '.jsonl')) {
        return null;
    }

    return [
        'file_name' => $fileName,
        'index' => (int) $entry['index'],
    ];
}

function static_data_extract_reference_rows_from_jsonl_archive(string $archivePath): array
{
    if (!class_exists(ZipArchive::class)) {
        throw new RuntimeException('PHP ZipArchive extension is required to import JSONL static data archives.');
    }

    $zip = new ZipArchive();
    if ($zip->open($archivePath) !== true) {
        throw new RuntimeException('Unable to open static-data ZIP archive.');
    }

    $entries = [];
    for ($index = 0; $index < $zip->numFiles; $index++) {
        $stat = $zip->statIndex($index);
        if (!is_array($stat)) {
            continue;
        }

        $parsed = static_data_parse_jsonl_entry(['name' => $stat['name'] ?? null, 'index' => $index]);
        if ($parsed === null) {
            continue;
        }

        $entries[mb_strtolower($parsed['file_name'])] = $parsed['index'];
    }

    $targets = [
        'mapregions.jsonl' => 'regions',
        'mapconstellations.jsonl' => 'constellations',
        'mapsolarsystems.jsonl' => 'systems',
        'npcstations.jsonl' => 'stations',
        'stations.jsonl' => 'stations',
        'npcCorporations.jsonl' => 'npc_corps',
        'npccorporations.jsonl' => 'npc_corps',
        'staOperations.jsonl' => 'station_operations',
        'staoperations.jsonl' => 'station_operations',
        'stationOperations.jsonl' => 'station_operations',
        'stationoperations.jsonl' => 'station_operations',
        'mapPlanets.jsonl' => 'planets',
        'mapplanets.jsonl' => 'planets',
        'mapMoons.jsonl' => 'moons',
        'mapmoons.jsonl' => 'moons',
        'categories.jsonl' => 'categories',
        'invcategories.jsonl' => 'categories',
        'groups.jsonl' => 'groups',
        'invgroups.jsonl' => 'groups',
        'marketgroups.jsonl' => 'market_groups',
        'metatypes.jsonl' => 'meta_types',
        'invmetatypes.jsonl' => 'meta_types',
        'metagroups.jsonl' => 'meta_groups',
        'invmetagroups.jsonl' => 'meta_groups',
        'types.jsonl' => 'types',
        'stargates.jsonl' => 'stargates',
        'mapstargates.jsonl' => 'stargates',
        'mapsolarsystemjumps.jsonl' => 'stargates',
    ];

    $records = [
        'regions' => [],
        'constellations' => [],
        'systems' => [],
        'stations' => [],
        'npc_corps' => [],
        'station_operations' => [],
        'celestials' => [],
        'categories' => [],
        'groups' => [],
        'market_groups' => [],
        'meta_types' => [],
        'meta_groups' => [],
        'types' => [],
        'stargates' => [],
    ];

    foreach ($targets as $fileName => $targetKey) {
        if (!isset($entries[$fileName])) {
            continue;
        }

        $stream = $zip->getStream($zip->getNameIndex($entries[$fileName]));
        if (!is_resource($stream)) {
            continue;
        }

        while (($line = fgets($stream)) !== false) {
            $line = trim($line);
            if ($line === '') {
                continue;
            }

            try {
                $row = json_decode($line, true, 512, JSON_THROW_ON_ERROR);
            } catch (Throwable) {
                continue;
            }

            if (!is_array($row)) {
                continue;
            }

            if ($targetKey === 'regions') {
                $regionId = (int) static_data_record_value($row, ['regionID', 'region_id', '_key']);
                $regionName = static_data_localized_text(static_data_record_value($row, ['regionName', 'name']));
                if ($regionId > 0 && $regionName !== null) {
                    $records['regions'][] = ['region_id' => $regionId, 'region_name' => $regionName];
                }
                continue;
            }

            if ($targetKey === 'constellations') {
                $constellationId = (int) static_data_record_value($row, ['constellationID', 'constellation_id', '_key']);
                $regionId = (int) static_data_record_value($row, ['regionID', 'region_id', '_key']);
                $name = static_data_localized_text(static_data_record_value($row, ['constellationName', 'name']));
                if ($constellationId > 0 && $regionId > 0 && $name !== null) {
                    $records['constellations'][] = [
                        'constellation_id' => $constellationId,
                        'region_id' => $regionId,
                        'constellation_name' => $name,
                    ];
                }
                continue;
            }

            if ($targetKey === 'systems') {
                $systemId = (int) static_data_record_value($row, ['solarSystemID', 'system_id', '_key']);
                $constellationId = (int) static_data_record_value($row, ['constellationID', 'constellation_id', '_key']);
                $regionId = (int) static_data_record_value($row, ['regionID', 'region_id', '_key']);
                $name = static_data_localized_text(static_data_record_value($row, ['solarSystemName', 'name']));
                if ($systemId > 0 && $constellationId > 0 && $regionId > 0 && $name !== null) {
                    $records['systems'][] = [
                        'system_id' => $systemId,
                        'constellation_id' => $constellationId,
                        'region_id' => $regionId,
                        'system_name' => $name,
                        'security' => (float) static_data_record_value($row, ['securityStatus', 'security', 'security_status'], 0),
                    ];
                }
                // Also extract nested planet/moon data for station orbit name construction.
                // The JSONL format converts integer-keyed dicts to lists with a _key field.
                if ($systemId > 0) {
                    $planets = static_data_record_value($row, ['planets'], []);
                    if (is_array($planets)) {
                        foreach ($planets as $pKey => $planet) {
                            if (!is_array($planet)) {
                                continue;
                            }
                            $planetId = (int) (($planet['_key'] ?? null) ?? $pKey);
                            if ($planetId <= 0) {
                                continue;
                            }
                            $celestialIndex = (int) static_data_record_value($planet, ['celestialIndex', 'celestial_index'], 0);
                            $records['celestials'][] = [
                                'celestial_id' => $planetId,
                                'celestial_type' => 1,
                                'parent_id' => $systemId,
                                'celestial_index' => $celestialIndex > 0 ? $celestialIndex : null,
                                'system_id' => $systemId,
                            ];
                            $moons = static_data_record_value($planet, ['moons'], []);
                            if (is_array($moons)) {
                                foreach ($moons as $mKey => $moon) {
                                    if (!is_array($moon)) {
                                        continue;
                                    }
                                    $moonId = (int) (($moon['_key'] ?? null) ?? $mKey);
                                    if ($moonId <= 0) {
                                        continue;
                                    }
                                    $orbitIndex = (int) static_data_record_value($moon, ['orbitIndex', 'orbit_index'], 0);
                                    $records['celestials'][] = [
                                        'celestial_id' => $moonId,
                                        'celestial_type' => 2,
                                        'parent_id' => $planetId,
                                        'celestial_index' => $orbitIndex > 0 ? $orbitIndex : null,
                                        'system_id' => $systemId,
                                    ];
                                }
                            }
                        }
                    }
                }
                continue;
            }

            if ($targetKey === 'planets') {
                // Separate mapPlanets.jsonl file (not all SDE variants include this).
                $planetId = (int) static_data_record_value($row, ['planetID', 'planet_id', '_key']);
                $systemId = (int) static_data_record_value($row, ['solarSystemID', 'system_id'], 0);
                $celestialIndex = (int) static_data_record_value($row, ['celestialIndex', 'celestial_index'], 0);
                if ($planetId > 0 && $systemId > 0) {
                    $records['celestials'][] = [
                        'celestial_id' => $planetId,
                        'celestial_type' => 1,
                        'parent_id' => $systemId,
                        'celestial_index' => $celestialIndex > 0 ? $celestialIndex : null,
                        'system_id' => $systemId,
                    ];
                }
                continue;
            }

            if ($targetKey === 'moons') {
                // Separate mapMoons.jsonl file (not all SDE variants include this).
                $moonId = (int) static_data_record_value($row, ['moonID', 'moon_id', '_key']);
                $planetId = (int) static_data_record_value($row, ['planetID', 'planet_id'], 0);
                $systemId = (int) static_data_record_value($row, ['solarSystemID', 'system_id'], 0);
                $orbitIndex = (int) static_data_record_value($row, ['orbitIndex', 'orbit_index'], 0);
                if ($moonId > 0 && $planetId > 0 && $systemId > 0) {
                    $records['celestials'][] = [
                        'celestial_id' => $moonId,
                        'celestial_type' => 2,
                        'parent_id' => $planetId,
                        'celestial_index' => $orbitIndex > 0 ? $orbitIndex : null,
                        'system_id' => $systemId,
                    ];
                }
                continue;
            }

            if ($targetKey === 'npc_corps') {
                $corpId = (int) static_data_record_value($row, ['corporationID', 'corporation_id', '_key']);
                $corpName = static_data_localized_text(static_data_record_value($row, ['corporationName', 'corporation_name', 'name']));
                if ($corpId > 0 && $corpName !== null) {
                    $records['npc_corps'][] = ['corp_id' => $corpId, 'corp_name' => $corpName];
                }
                continue;
            }

            if ($targetKey === 'station_operations') {
                $operationId = (int) static_data_record_value($row, ['operationID', 'operation_id', '_key']);
                $operationName = static_data_localized_text(static_data_record_value($row, ['operationName', 'operation_name', 'name']));
                if ($operationId > 0 && $operationName !== null) {
                    $records['station_operations'][] = ['operation_id' => $operationId, 'operation_name' => $operationName];
                }
                continue;
            }

            if ($targetKey === 'stations') {
                $stationId = (int) static_data_record_value($row, ['stationID', 'station_id', '_key']);
                $name = static_data_localized_text(static_data_record_value($row, ['stationName', 'name']));
                if ($stationId > 0) {
                    if ($name === null) {
                        $name = 'Station ' . $stationId;
                    }
                    $orbitId = (int) static_data_record_value($row, ['orbitID', 'orbit_id'], 0);
                    $ownerId = (int) static_data_record_value($row, ['ownerID', 'owner_id'], 0);
                    $operationId = (int) static_data_record_value($row, ['operationID', 'operation_id'], 0);
                    $useOperationNameRaw = static_data_record_value($row, ['useOperationName', 'use_operation_name'], false);
                    $useOperationName = ($useOperationNameRaw === true || (int) $useOperationNameRaw === 1) ? 1 : 0;
                    $records['stations'][] = [
                        'station_id' => $stationId,
                        'station_name' => $name,
                        'system_id' => (int) static_data_record_value($row, ['solarSystemID', 'system_id'], 0),
                        'constellation_id' => (int) static_data_record_value($row, ['constellationID', 'constellation_id'], 0),
                        'region_id' => (int) static_data_record_value($row, ['regionID', 'region_id'], 0),
                        'station_type_id' => ($typeId = (int) static_data_record_value($row, ['stationTypeID', 'typeID', 'type_id'], 0)) > 0 ? $typeId : null,
                        'orbit_id' => $orbitId > 0 ? $orbitId : null,
                        'owner_id' => $ownerId > 0 ? $ownerId : null,
                        'operation_id' => $operationId > 0 ? $operationId : null,
                        'use_operation_name' => $useOperationName,
                    ];
                }
                continue;
            }

            if ($targetKey === 'stargates') {
                // Handle stargates.jsonl / mapStargates.jsonl formats
                $stargateId = (int) static_data_record_value($row, ['stargateID', 'stargate_id', '_key']);
                $systemId = (int) static_data_record_value($row, ['solarSystemID', 'system_id'], 0);
                $destStargateId = (int) static_data_record_value($row, ['destinationStargateID', 'destination_stargate_id', 'dest_stargate_id'], 0);
                $destSystemId = (int) static_data_record_value($row, ['destinationSystemID', 'destination_system_id', 'dest_system_id'], 0);
                // CCP SDE nested format: {"destination": {"solarSystemID": ..., "stargateID": ...}}
                if ($destSystemId <= 0 && isset($row['destination']) && is_array($row['destination'])) {
                    $destSystemId = (int) ($row['destination']['solarSystemID'] ?? $row['destination']['system_id'] ?? 0);
                    if ($destStargateId <= 0) {
                        $destStargateId = (int) ($row['destination']['stargateID'] ?? $row['destination']['stargate_id'] ?? 0);
                    }
                }
                // Handle mapsolarsystemjumps.jsonl format (fromSolarSystemID / toSolarSystemID)
                if ($stargateId <= 0 && $systemId <= 0) {
                    $systemId = (int) static_data_record_value($row, ['fromSolarSystemID', 'fromRegionID'], 0);
                    $destSystemId = (int) static_data_record_value($row, ['toSolarSystemID'], 0);
                }
                if ($systemId > 0 && $destSystemId > 0) {
                    $records['stargates'][] = [
                        'stargate_id' => $stargateId > 0 ? $stargateId : crc32("{$systemId}:{$destSystemId}"),
                        'system_id' => $systemId,
                        'dest_stargate_id' => $destStargateId > 0 ? $destStargateId : 0,
                        'dest_system_id' => $destSystemId,
                    ];
                }
                continue;
            }

            if ($targetKey === 'market_groups') {
                $groupId = (int) static_data_record_value($row, ['marketGroupID', 'market_group_id', '_key']);
                $name = static_data_localized_text(static_data_record_value($row, ['marketGroupName', 'name']));
                if ($groupId > 0 && $name !== null) {
                    $parentId = (int) static_data_record_value($row, ['parentGroupID', 'parent_group_id'], 0);
                    $records['market_groups'][] = [
                        'market_group_id' => $groupId,
                        'parent_group_id' => $parentId > 0 ? $parentId : null,
                        'market_group_name' => $name,
                        'description' => static_data_localized_text(static_data_record_value($row, ['description'])),
                    ];
                }
                continue;
            }

            if ($targetKey === 'categories') {
                $categoryId = (int) static_data_record_value($row, ['categoryID', 'category_id', '_key']);
                $name = static_data_localized_text(static_data_record_value($row, ['categoryName', 'name']));
                if ($categoryId > 0 && $name !== null) {
                    $publishedRaw = static_data_record_value($row, ['published'], 1);
                    $records['categories'][] = [
                        'category_id' => $categoryId,
                        'category_name' => $name,
                        'published' => ($publishedRaw === true || (int) $publishedRaw === 1) ? 1 : 0,
                    ];
                }
                continue;
            }

            if ($targetKey === 'groups') {
                $groupId = (int) static_data_record_value($row, ['groupID', 'group_id', '_key']);
                $categoryId = (int) static_data_record_value($row, ['categoryID', 'category_id']);
                $name = static_data_localized_text(static_data_record_value($row, ['groupName', 'name']));
                if ($groupId > 0 && $categoryId > 0 && $name !== null) {
                    $publishedRaw = static_data_record_value($row, ['published'], 1);
                    $records['groups'][] = [
                        'group_id' => $groupId,
                        'category_id' => $categoryId,
                        'group_name' => $name,
                        'published' => ($publishedRaw === true || (int) $publishedRaw === 1) ? 1 : 0,
                    ];
                }
                continue;
            }

            if ($targetKey === 'meta_groups') {
                $metaGroupId = (int) static_data_record_value($row, ['metaGroupID', 'meta_group_id', '_key']);
                $name = static_data_localized_text(static_data_record_value($row, ['metaGroupName', 'name']));
                if ($metaGroupId > 0 && $name !== null) {
                    $records['meta_groups'][] = [
                        'meta_group_id' => $metaGroupId,
                        'meta_group_name' => $name,
                    ];
                }
                continue;
            }

            if ($targetKey === 'meta_types') {
                $typeId = (int) static_data_record_value($row, ['typeID', 'type_id']);
                $metaGroupId = (int) static_data_record_value($row, ['metaGroupID', 'meta_group_id']);
                if ($typeId > 0 && $metaGroupId > 0) {
                    $records['meta_types'][$typeId] = $metaGroupId;
                }
                continue;
            }

            if ($targetKey === 'types') {
                $typeId = (int) static_data_record_value($row, ['typeID', 'type_id', '_key']);
                $groupId = (int) static_data_record_value($row, ['groupID', 'group_id']);
                $name = static_data_localized_text(static_data_record_value($row, ['typeName', 'name']));
                if ($typeId > 0 && $groupId > 0 && $name !== null) {
                    $categoryId = (int) static_data_record_value($row, ['categoryID', 'category_id'], 0);
                    $marketGroupId = (int) static_data_record_value($row, ['marketGroupID', 'market_group_id', '_key'], 0);
                    $metaGroupId = (int) static_data_record_value($row, ['metaGroupID', 'meta_group_id'], (int) ($records['meta_types'][$typeId] ?? 0));
                    $publishedRaw = static_data_record_value($row, ['published'], 0);
                    $records['types'][] = [
                        'type_id' => $typeId,
                        'category_id' => $categoryId,
                        'group_id' => $groupId,
                        'market_group_id' => $marketGroupId > 0 ? $marketGroupId : null,
                        'meta_group_id' => $metaGroupId > 0 ? $metaGroupId : null,
                        'type_name' => $name,
                        'description' => static_data_localized_text(static_data_record_value($row, ['description'])),
                        'published' => ($publishedRaw === true || (int) $publishedRaw === 1) ? 1 : 0,
                        'volume' => ($volume = static_data_record_value($row, ['volume'], null)) !== null ? (float) $volume : null,
                    ];
                }
            }
        }

        fclose($stream);
    }

    $zip->close();

    if ($records['regions'] === [] || $records['constellations'] === [] || $records['systems'] === [] || $records['market_groups'] === [] || $records['types'] === []) {
        throw new RuntimeException('Static-data archive is missing one or more required JSONL datasets for import.');
    }

    $groupCategoryById = [];
    foreach ($records['groups'] as $groupRow) {
        $groupId = (int) ($groupRow['group_id'] ?? 0);
        $categoryId = (int) ($groupRow['category_id'] ?? 0);
        if ($groupId > 0 && $categoryId > 0) {
            $groupCategoryById[$groupId] = $categoryId;
        }
    }

    foreach ($records['types'] as &$typeRow) {
        $categoryId = (int) ($typeRow['category_id'] ?? 0);
        if ($categoryId <= 0) {
            $typeRow['category_id'] = (int) ($groupCategoryById[(int) ($typeRow['group_id'] ?? 0)] ?? 0);
        }
    }
    unset($typeRow);

    $records['types'] = array_values(array_filter(
        $records['types'],
        static fn (array $row): bool => (int) ($row['category_id'] ?? 0) > 0
    ));

    // Deduplicate celestials: separate planet/moon files may overlap with nested data.
    if ($records['celestials'] !== []) {
        $uniqueCelestials = [];
        foreach ($records['celestials'] as $cel) {
            $id = (int) ($cel['celestial_id'] ?? 0);
            if ($id > 0) {
                $uniqueCelestials[$id] = $cel;
            }
        }
        $records['celestials'] = array_values($uniqueCelestials);
    }

    return $records;
}

function static_data_int_to_roman_numeral(int $n): string
{
    static $map = [
        '',
        'I', 'II', 'III', 'IV', 'V', 'VI', 'VII', 'VIII', 'IX', 'X',
        'XI', 'XII', 'XIII', 'XIV', 'XV', 'XVI', 'XVII', 'XVIII', 'XIX', 'XX',
        'XXI', 'XXII', 'XXIII', 'XXIV', 'XXV',
    ];

    if ($n >= 1 && $n <= 25) {
        return $map[$n];
    }

    return (string) $n;
}

/**
 * Construct real names for NPC stations that currently have placeholder names
 * ("Station <id>" format). The new official EVE SDE does not include station names;
 * they must be built from:
 *   <orbitName> - <corporationName> [<operationName>]
 * where orbitName is the name of the planet or moon the station orbits.
 *
 * Returns the number of station names updated.
 */
function static_data_build_npc_station_names(): int
{
    // Load all stations that have placeholder names and have enough lookup data.
    $stations = db_select(
        "SELECT ns.station_id, ns.station_name, ns.orbit_id, ns.owner_id, ns.operation_id,
                ns.use_operation_name, ns.system_id, sys.system_name
         FROM ref_npc_stations ns
         LEFT JOIN ref_systems sys ON sys.system_id = ns.system_id
         WHERE ns.station_name REGEXP '^Station[[:space:]#]+[0-9]+'
            OR ns.station_name REGEXP '^Station[0-9]+'
         ORDER BY ns.station_id ASC
         LIMIT 10000"
    );

    if ($stations === []) {
        return 0;
    }

    // Load NPC corporation names.
    $corps = [];
    try {
        foreach (db_select('SELECT corp_id, corp_name FROM ref_npc_corporations LIMIT 20000') as $row) {
            $corps[(int) $row['corp_id']] = (string) $row['corp_name'];
        }
    } catch (Throwable) {
        // Table may not exist yet on older installs; skip corp name enrichment.
    }

    // Load station operation names.
    $operations = [];
    try {
        foreach (db_select('SELECT operation_id, operation_name FROM ref_station_operations LIMIT 2000') as $row) {
            $operations[(int) $row['operation_id']] = (string) $row['operation_name'];
        }
    } catch (Throwable) {
        // Table may not exist yet; skip operation name enrichment.
    }

    // Load celestials (planets + moons) with system context for orbit name resolution.
    // For moons (type=2) we also join the parent planet to get its celestial_index.
    $celestials = [];
    try {
        $rows = db_select(
            "SELECT c.celestial_id, c.celestial_type, c.parent_id, c.celestial_index,
                    c.system_id, sys.system_name,
                    p.celestial_index AS planet_celestial_index
             FROM ref_celestials c
             LEFT JOIN ref_systems sys ON sys.system_id = c.system_id
             LEFT JOIN ref_celestials p ON p.celestial_id = c.parent_id AND c.celestial_type = 2
             LIMIT 200000"
        );
        foreach ($rows as $row) {
            $celestials[(int) $row['celestial_id']] = $row;
        }
    } catch (Throwable) {
        // Table may not exist yet; fall back to system-name-only orbit name.
    }

    // Construct and batch-update names.
    $count = 0;
    foreach ($stations as $station) {
        $stationId = (int) $station['station_id'];
        $orbitId = (int) ($station['orbit_id'] ?? 0);
        $ownerId = (int) ($station['owner_id'] ?? 0);
        $operationId = (int) ($station['operation_id'] ?? 0);
        $useOperationName = (bool) ($station['use_operation_name'] ?? false);
        $systemName = (string) ($station['system_name'] ?? '');

        // Resolve orbit name (planet or moon name).
        $orbitName = '';
        if ($orbitId > 0 && isset($celestials[$orbitId])) {
            $cel = $celestials[$orbitId];
            $celSystemName = (string) ($cel['system_name'] ?? $systemName);
            $celType = (int) $cel['celestial_type'];
            $celIndex = (int) ($cel['celestial_index'] ?? 0);

            if ($celType === 1) {
                // Planet: "<SystemName> <Roman(celestialIndex)>"
                $orbitName = $celSystemName;
                if ($celIndex > 0) {
                    $orbitName .= ' ' . static_data_int_to_roman_numeral($celIndex);
                }
            } elseif ($celType === 2) {
                // Moon: "<SystemName> <Roman(planetIndex)> - Moon <moonIndex>"
                $planetIndex = (int) ($cel['planet_celestial_index'] ?? 0);
                $orbitName = $celSystemName;
                if ($planetIndex > 0) {
                    $orbitName .= ' ' . static_data_int_to_roman_numeral($planetIndex);
                }
                if ($celIndex > 0) {
                    $orbitName .= ' - Moon ' . $celIndex;
                }
            }
        }

        // Fall back to system name if the orbit celestial is unknown.
        if ($orbitName === '' && $systemName !== '') {
            $orbitName = $systemName;
        }

        if ($orbitName === '') {
            continue;
        }

        $corpName = $ownerId > 0 ? ($corps[$ownerId] ?? '') : '';
        $operationName = ($useOperationName && $operationId > 0) ? ($operations[$operationId] ?? '') : '';

        if ($corpName !== '') {
            $name = $orbitName . ' - ' . $corpName;
            if ($operationName !== '') {
                $name .= ' ' . $operationName;
            }
        } else {
            // No corporation name available; use orbit name only as best effort.
            $name = $orbitName;
        }

        db_execute(
            'UPDATE ref_npc_stations SET station_name = ? WHERE station_id = ?',
            [$name, $stationId]
        );
        $count++;
    }

    return $count;
}

function static_data_import_reference_data(string $requestedMode = 'auto', bool $force = false): array
{
    $sourceKey = static_data_source_key();
    $sourceUrl = static_data_source_url();
    $state = db_static_data_import_state_get($sourceKey);
    $mode = static_data_import_mode($requestedMode);
    $checkedAt = gmdate('Y-m-d H:i:s');

    $remote = static_data_fetch_remote_build_info($sourceUrl);
    $remoteBuildId = (string) $remote['build_id'];
    $importedBuildId = (string) ($state['imported_build_id'] ?? '');

    if (!$force && $remoteBuildId === $importedBuildId) {
        db_static_data_import_state_upsert(
            $sourceKey,
            $sourceUrl,
            $remoteBuildId,
            $importedBuildId === '' ? null : $importedBuildId,
            $state['imported_mode'] ?? null,
            'success',
            $checkedAt,
            $state['last_import_started_at'] ?? null,
            $state['last_import_finished_at'] ?? null,
            null,
            json_encode(['remote' => $remote, 'note' => 'Already up to date.'], JSON_THROW_ON_ERROR)
        );

        return ['ok' => true, 'changed' => false, 'build_id' => $remoteBuildId, 'rows_written' => 0, 'mode' => $mode];
    }

    $startedAt = gmdate('Y-m-d H:i:s');
    db_static_data_import_state_upsert(
        $sourceKey,
        $sourceUrl,
        $remoteBuildId,
        $importedBuildId === '' ? null : $importedBuildId,
        $mode,
        'running',
        $checkedAt,
        $startedAt,
        null,
        null,
        json_encode(['remote' => $remote], JSON_THROW_ON_ERROR)
    );

    try {
        $archivePath = static_data_ensure_local_jsonl_archive($sourceUrl, $remoteBuildId);
        $dataset = static_data_extract_reference_rows_from_jsonl_archive($archivePath);

        $regions = $dataset['regions'];
        $constellations = $dataset['constellations'];
        $systems = $dataset['systems'];
        $stations = $dataset['stations'];
        $npcCorps = $dataset['npc_corps'];
        $stationOperations = $dataset['station_operations'];
        $celestials = $dataset['celestials'];
        $categories = $dataset['categories'];
        $groups = $dataset['groups'];
        $marketGroups = $dataset['market_groups'];
        $metaGroups = $dataset['meta_groups'];
        $types = $dataset['types'];
        $stargates = $dataset['stargates'];

        if ($mode === 'full') {
            db_reference_data_truncate_all();
        }

        $rowsWritten = db_transaction(static function () use ($regions, $constellations, $systems, $stations, $npcCorps, $stationOperations, $celestials, $categories, $groups, $marketGroups, $metaGroups, $types, $stargates): int {
            $written = 0;
            $written += db_ref_regions_bulk_upsert($regions);
            $written += db_ref_constellations_bulk_upsert($constellations);
            $written += db_ref_systems_bulk_upsert($systems);
            $written += db_ref_npc_stations_bulk_upsert($stations);
            $written += db_ref_npc_corporations_bulk_upsert($npcCorps);
            $written += db_ref_station_operations_bulk_upsert($stationOperations);
            $written += db_ref_celestials_bulk_upsert($celestials);
            $written += db_ref_item_categories_bulk_upsert($categories);
            $written += db_ref_item_groups_bulk_upsert($groups);
            $written += db_ref_market_groups_bulk_upsert($marketGroups);
            $written += db_ref_meta_groups_bulk_upsert($metaGroups);
            $written += db_ref_item_types_bulk_upsert($types);
            $written += db_ref_stargates_bulk_upsert($stargates);

            return $written;
        });

        // Backfill constellation_id/region_id for stations missing geography
        // (some SDE sources omit these fields, causing _key fallback to station_id).
        db_execute(
            "UPDATE ref_npc_stations ns
             INNER JOIN ref_systems rs ON rs.system_id = ns.system_id
             SET ns.constellation_id = rs.constellation_id,
                 ns.region_id = rs.region_id
             WHERE ns.system_id > 0
               AND (ns.region_id < 10000001 OR ns.region_id > 10000069
                    OR ns.constellation_id < 20000001 OR ns.constellation_id > 21000000)"
        );

        // Construct real station names for any stations that still have placeholder names.
        // The new official SDE does not include station names directly; they must be built
        // from orbit celestial name + NPC corporation name + station operation name.
        $namesBuilt = static_data_build_npc_station_names();

        $finishedAt = gmdate('Y-m-d H:i:s');
        db_static_data_import_state_upsert(
            $sourceKey,
            $sourceUrl,
            $remoteBuildId,
            $remoteBuildId,
            $mode,
            'success',
            $checkedAt,
            $startedAt,
            $finishedAt,
            null,
            json_encode([
                'remote' => $remote,
                'dataset_counts' => [
                    'regions' => count($regions),
                    'constellations' => count($constellations),
                    'systems' => count($systems),
                    'npc_stations' => count($stations),
                    'npc_corps' => count($npcCorps),
                    'station_operations' => count($stationOperations),
                    'celestials' => count($celestials),
                    'item_categories' => count($categories),
                    'item_groups' => count($groups),
                    'market_groups' => count($marketGroups),
                    'meta_groups' => count($metaGroups),
                    'item_types' => count($types),
                    'stargates' => count($stargates),
                    'station_names_built' => $namesBuilt,
                ],
            ], JSON_THROW_ON_ERROR)
        );

        supplycore_cache_invalidate_for_dataset('static_data.reference');

        return ['ok' => true, 'changed' => true, 'build_id' => $remoteBuildId, 'rows_written' => $rowsWritten, 'mode' => $mode];
    } catch (Throwable $exception) {
        db_static_data_import_state_upsert(
            $sourceKey,
            $sourceUrl,
            $remoteBuildId,
            $importedBuildId === '' ? null : $importedBuildId,
            $mode,
            'failed',
            $checkedAt,
            $startedAt,
            gmdate('Y-m-d H:i:s'),
            $exception->getMessage(),
            json_encode(['remote' => $remote], JSON_THROW_ON_ERROR)
        );

        throw $exception;
    }
}

function killmail_ingestion_enabled(): bool
{
    return sanitize_enabled_flag(get_setting('killmail_ingestion_enabled', '0')) === '1';
}

function killmail_sync_dataset_key(): string
{
