function killmail_poll_sleep_seconds(): int
{
    return max(6, min(300, (int) get_setting('killmail_ingestion_poll_sleep_seconds', '10')));
}

function killmail_max_sequences_per_run(): int
{
    return max(1, min(5000, (int) get_setting('killmail_ingestion_max_sequences_per_run', '5000')));
}

function killmail_universe_ids_lookup(array $names): array
{
    $queryNames = array_values(array_filter(array_map(static fn (mixed $name): string => trim((string) $name), $names), static fn (string $name): bool => $name !== ''));
    if ($queryNames === []) {
        return [];
    }

    // Phase 2: resolve name→ID from entity_metadata_cache instead of calling ESI.
    // The entity_metadata_cache is populated by Python's entity_metadata_resolve_sync.
    $results = [];
    $placeholders = implode(',', array_fill(0, count($queryNames), '?'));

    foreach (['alliance', 'corporation', 'character'] as $type) {
        $rows = db_select(
            "SELECT entity_id, entity_name, entity_type FROM entity_metadata_cache
             WHERE entity_type = ? AND entity_name IN ($placeholders) AND resolution_status = 'resolved'",
            array_merge([$type], $queryNames)
        );
        $pluralKey = match ($type) {
            'alliance' => 'alliances',
            'corporation' => 'corporations',
            'character' => 'characters',
            default => $type . 's',
        };
        foreach ($rows as $row) {
            $results[$pluralKey][] = [
                'id' => (int) ($row['entity_id'] ?? 0),
                'name' => (string) ($row['entity_name'] ?? ''),
            ];
        }
    }

    return $results;
}

function killmail_settings_from_request(array $request): array
{
    // Note: killmail_ingestion_enabled is NOT included here — it is controlled
    // exclusively from the Automation Control section to avoid accidentally
    // disabling ingestion when saving killmail intelligence settings.
    return [
        'settings' => [
            'killmail_ingestion_poll_sleep_seconds' => (string) max(6, min(300, (int) ($request['killmail_ingestion_poll_sleep_seconds'] ?? 10))),
            'killmail_ingestion_max_sequences_per_run' => (string) max(1, min(5000, (int) ($request['killmail_ingestion_max_sequences_per_run'] ?? 5000))),
            'killmail_demand_prediction_mode' => trim((string) ($request['killmail_demand_prediction_mode'] ?? 'baseline')),
            'friendly_coalition_name' => trim(mb_substr(trim((string) ($request['friendly_coalition_name'] ?? '')), 0, 100)),
            'opponent_coalition_name' => trim(mb_substr(trim((string) ($request['opponent_coalition_name'] ?? '')), 0, 100)),
        ],
        'manual_contacts' => killmail_parse_manual_contacts(
            (string) ($request['manual_friendly_alliance_contacts'] ?? ''),
            (string) ($request['manual_friendly_corporation_contacts'] ?? ''),
            (string) ($request['manual_hostile_alliance_contacts'] ?? ''),
            (string) ($request['manual_hostile_corporation_contacts'] ?? '')
        ),
    ];
}

/**
 * Parse manual contact entries from "ID | Name" textarea format (4 fields: friendly/hostile x alliance/corporation).
 * Friendly entries get +10 standing, hostile get -10.
 */
function killmail_parse_manual_contacts(string $friendlyAlliances, string $friendlyCorporations, string $hostileAlliances, string $hostileCorporations): array
{
    $contacts = [];
    $parse = static function (string $raw, string $type, float $standing) use (&$contacts): void {
        foreach (explode("\n", $raw) as $line) {
            $line = trim($line);
            if ($line === '') {
                continue;
            }
            $parts = explode('|', $line, 2);
            $id = (int) trim($parts[0] ?? '');
            if ($id <= 0) {
                continue;
            }
            $contacts[] = ['contact_id' => $id, 'contact_type' => $type, 'standing' => $standing];
        }
    };
    $parse($friendlyAlliances, 'alliance', 10.0);
    $parse($friendlyCorporations, 'corporation', 10.0);
    $parse($hostileAlliances, 'alliance', -10.0);
    $parse($hostileCorporations, 'corporation', -10.0);
    return $contacts;
}

function save_killmail_intelligence_settings(array $request): array
{
    $payload = killmail_settings_from_request($request);
    $saved = false;

    try {
        db_app_settings_upsert_many((array) ($payload['settings'] ?? []));
        db_corp_contacts_manual_replace((array) ($payload['manual_contacts'] ?? []));

        $reloadedSettings = get_settings(array_keys((array) ($payload['settings'] ?? [])));
        foreach ((array) ($payload['settings'] ?? []) as $key => $value) {
            if ((string) ($reloadedSettings[$key] ?? '') !== (string) $value) {
                throw new RuntimeException('Killmail settings readback mismatch for key ' . $key . '.');
            }
        }

        $saved = true;
    } catch (Throwable $e) {
        error_log('[killmail-settings] Save failed: ' . $e->getMessage());
        $saved = false;
    }

    if ($saved) {
        supplycore_cache_bust(['dashboard', 'killmail_overview', 'killmail_detail']);
    }

    return [
        'ok' => $saved,
        'settings' => (array) ($payload['settings'] ?? []),
    ];
}

function killmail_r2z2_fetch_json(string $url): array
{
    $userAgent = trim((string) get_setting('app_name', 'SupplyCore'));
    if ($userAgent === '') {
        $userAgent = 'SupplyCore';
    }

    $headers = [
        'Accept: application/json',
        'User-Agent: ' . $userAgent . ' killmail-ingestion/1.0 (+https://github.com/cvweiss/supplycore)',
    ];

    $ch = curl_init($url);
    curl_setopt_array($ch, [
        CURLOPT_RETURNTRANSFER => true,
        CURLOPT_TIMEOUT => 25,
        CURLOPT_HTTPHEADER => $headers,
    ]);
    $body = curl_exec($ch);
    $status = (int) curl_getinfo($ch, CURLINFO_HTTP_CODE);
    $error = curl_error($ch);
    curl_close($ch);

    if ($body === false) {
        throw new RuntimeException('R2Z2 request failed: ' . $error);
    }

    $json = json_decode($body, true);
    if (!is_array($json)) {
        $json = [];
    }

    return ['status' => $status, 'json' => $json, 'body' => $body];
}

function killmail_extract_items(array $items, int &$index, string $role): array
{
    $rows = [];
    foreach ($items as $item) {
        if (!is_array($item)) {
            continue;
        }

        $rows[] = [
            'item_index' => $index++,
            'item_type_id' => (int) ($item['item_type_id'] ?? 0),
            'item_flag' => isset($item['flag']) ? (int) $item['flag'] : null,
            'quantity_dropped' => isset($item['quantity_dropped']) ? (int) $item['quantity_dropped'] : null,
            'quantity_destroyed' => isset($item['quantity_destroyed']) ? (int) $item['quantity_destroyed'] : null,
            'singleton' => isset($item['singleton']) ? (int) $item['singleton'] : null,
            'item_role' => $role,
        ];

        if (isset($item['items']) && is_array($item['items'])) {
            foreach (killmail_extract_items($item['items'], $index, $role) as $nested) {
                $rows[] = $nested;
            }
        }
    }

    return $rows;
}

function killmail_region_id_from_system(?int $systemId): ?int
{
    if ($systemId === null || $systemId <= 0) {
        return null;
    }

    try {
        $row = db_select_one('SELECT region_id FROM ref_systems WHERE system_id = ? LIMIT 1', [$systemId]);
    } catch (Throwable) {
        return null;
    }

    return isset($row['region_id']) ? (int) $row['region_id'] : null;
}


function killmail_event_matches_tracked_entities(
    array $event,
    array $attackers,
    array $trackedAllianceIds,
    array $trackedCorporationIds,
    array $opponentAllianceIds = [],
    array $opponentCorporationIds = [],
): bool {
    $hasTracked = $trackedAllianceIds !== [] || $trackedCorporationIds !== [];
    $hasOpponents = $opponentAllianceIds !== [] || $opponentCorporationIds !== [];
    if (!$hasTracked && !$hasOpponents) {
        return true;
    }

    $victimAllianceId = (int) ($event['victim_alliance_id'] ?? 0);
    $victimCorporationId = (int) ($event['victim_corporation_id'] ?? 0);

    // Check victim against tracked (loss side)
    if ($victimAllianceId > 0 && isset($trackedAllianceIds[$victimAllianceId])) {
        return true;
    }
    if ($victimCorporationId > 0 && isset($trackedCorporationIds[$victimCorporationId])) {
        return true;
    }

    // Check victim against opponents (opponent_loss)
    if ($victimAllianceId > 0 && isset($opponentAllianceIds[$victimAllianceId])) {
        return true;
    }
    if ($victimCorporationId > 0 && isset($opponentCorporationIds[$victimCorporationId])) {
        return true;
    }

    // Check attackers against tracked (kill side)
    foreach ($attackers as $attacker) {
        if (!is_array($attacker)) {
            continue;
        }
        $attackerAllianceId = (int) ($attacker['alliance_id'] ?? 0);
        if ($attackerAllianceId > 0 && isset($trackedAllianceIds[$attackerAllianceId])) {
            return true;
        }
        $attackerCorporationId = (int) ($attacker['corporation_id'] ?? 0);
        if ($attackerCorporationId > 0 && isset($trackedCorporationIds[$attackerCorporationId])) {
            return true;
        }
        // Check attackers against opponents (opponent_kill)
        if ($attackerAllianceId > 0 && isset($opponentAllianceIds[$attackerAllianceId])) {
            return true;
        }
        if ($attackerCorporationId > 0 && isset($opponentCorporationIds[$attackerCorporationId])) {
            return true;
        }
    }

    return false;
}

function killmail_active_tracked_entity_ids(): array
{
    $trackedAllianceIds = [];
    foreach (db_killmail_tracked_alliances_active() as $row) {
        $id = (int) ($row['alliance_id'] ?? 0);
        if ($id > 0) {
            $trackedAllianceIds[$id] = true;
        }
    }

    $trackedCorporationIds = [];
    foreach (db_killmail_tracked_corporations_active() as $row) {
        $id = (int) ($row['corporation_id'] ?? 0);
        if ($id > 0) {
            $trackedCorporationIds[$id] = true;
        }
    }

    return [
        'alliance_ids' => $trackedAllianceIds,
        'corporation_ids' => $trackedCorporationIds,
    ];
}

function killmail_active_opponent_entity_ids(): array
{
    $opponentAllianceIds = [];
    foreach (db_killmail_opponent_alliances_active() as $row) {
        $id = (int) ($row['alliance_id'] ?? 0);
        if ($id > 0) {
            $opponentAllianceIds[$id] = true;
        }
    }

    $opponentCorporationIds = [];
    foreach (db_killmail_opponent_corporations_active() as $row) {
        $id = (int) ($row['corporation_id'] ?? 0);
        if ($id > 0) {
            $opponentCorporationIds[$id] = true;
        }
    }

    return [
        'alliance_ids' => $opponentAllianceIds,
        'corporation_ids' => $opponentCorporationIds,
    ];
}

function killmail_persist_r2z2_payload(
    array $payload,
    array $trackedAllianceIds,
    array $trackedCorporationIds,
    bool $strictSequenceId = false,
    ?int $requestedSequenceId = null,
    array $opponentAllianceIds = [],
    array $opponentCorporationIds = [],
    bool $skipEntityFilter = false,
): array {
    $transformed = killmail_transform_r2z2_payload($payload);
    $event = (array) ($transformed['event'] ?? []);
    $sequenceId = (int) ($event['sequence_id'] ?? 0);

    if ($sequenceId <= 0) {
        if ($strictSequenceId) {
            $streamSequence = $requestedSequenceId !== null && $requestedSequenceId > 0 ? $requestedSequenceId : 0;
            throw new RuntimeException('R2Z2 payload missing sequence_id for stream row ' . $streamSequence);
        }

        return [
            'status' => 'invalid',
            'sequence_id' => 0,
        ];
    }

    $killmailId = (int) ($event['killmail_id'] ?? 0);
    $killmailHash = (string) ($event['killmail_hash'] ?? '');
    if ($killmailId > 0 && $killmailHash !== '' && db_killmail_event_exists($sequenceId, $killmailId, $killmailHash)) {
        return [
            'status' => 'duplicate',
            'sequence_id' => $sequenceId,
        ];
    }

    $attackers = (array) ($transformed['attackers'] ?? []);

    // Determine mail_type with priority: own loss/kill > opponent loss/kill > untracked.
    // All killmails are now persisted (untracked ones for alliance relationship graph).
    $victimAllianceId = (int) ($event['victim_alliance_id'] ?? 0);
    $victimCorporationId = (int) ($event['victim_corporation_id'] ?? 0);
    $victimIsTracked = ($victimAllianceId > 0 && isset($trackedAllianceIds[$victimAllianceId]))
        || ($victimCorporationId > 0 && isset($trackedCorporationIds[$victimCorporationId]));
    $victimIsOpponent = ($victimAllianceId > 0 && isset($opponentAllianceIds[$victimAllianceId]))
        || ($victimCorporationId > 0 && isset($opponentCorporationIds[$victimCorporationId]));

    $attackerIsTracked = false;
    $attackerIsOpponent = false;
    foreach ($attackers as $attacker) {
        if (!is_array($attacker)) {
            continue;
        }
        $aAlly = (int) ($attacker['alliance_id'] ?? 0);
        $aCorp = (int) ($attacker['corporation_id'] ?? 0);
        if (!$attackerIsTracked && (($aAlly > 0 && isset($trackedAllianceIds[$aAlly])) || ($aCorp > 0 && isset($trackedCorporationIds[$aCorp])))) {
            $attackerIsTracked = true;
        }
        if (!$attackerIsOpponent && (($aAlly > 0 && isset($opponentAllianceIds[$aAlly])) || ($aCorp > 0 && isset($opponentCorporationIds[$aCorp])))) {
            $attackerIsOpponent = true;
        }
    }

    if ($victimIsTracked) {
        $mailType = 'loss';
    } elseif ($attackerIsTracked) {
        $mailType = 'kill';
    } elseif ($victimIsOpponent) {
        $mailType = 'opponent_loss';
    } elseif ($attackerIsOpponent) {
        $mailType = 'opponent_kill';
    } elseif ($skipEntityFilter) {
        $mailType = 'third_party';
    } else {
        $mailType = 'untracked';
    }
    $transformed['event']['mail_type'] = $mailType;

    killmail_prime_entity_metadata(killmail_entity_resolution_requests(
        $event,
        (array) ($transformed['attackers'] ?? []),
        (array) ($transformed['items'] ?? [])
    ));

    db_transaction(static function () use ($transformed, $sequenceId): void {
        db_killmail_event_upsert($transformed['event']);
        db_killmail_attackers_replace($sequenceId, $transformed['attackers']);
        db_killmail_items_replace($sequenceId, $transformed['items']);
    });

    // Enqueue all involved characters for background pipeline processing
    $pipelineCharIds = [];
    $victimId = (int) ($transformed['event']['victim_character_id'] ?? 0);
    if ($victimId > 0) {
        $pipelineCharIds[] = $victimId;
    }
    foreach ($transformed['attackers'] as $attacker) {
        $attackerId = (int) ($attacker['character_id'] ?? 0);
        if ($attackerId > 0) {
            $pipelineCharIds[] = $attackerId;
        }
    }
    if ($pipelineCharIds !== []) {
        db_character_pipeline_enqueue($pipelineCharIds, 'killmail_activity');
    }

    return [
        'status' => $mailType === 'untracked' ? 'written_untracked' : 'written',
        'sequence_id' => $sequenceId,
    ];
}

function killmail_transform_r2z2_payload(array $payload): array
{
    $killmail = is_array($payload['esi'] ?? null)
        ? $payload['esi']
        : (is_array($payload['killmail'] ?? null) ? $payload['killmail'] : []);
    $victim = is_array($killmail['victim'] ?? null) ? $killmail['victim'] : [];
    $zkb = is_array($payload['zkb'] ?? null) ? $payload['zkb'] : [];
    $sequenceId = (int) ($payload['sequence_id'] ?? $payload['requested_sequence_id'] ?? 0);
    $systemId = isset($killmail['solar_system_id']) ? (int) $killmail['solar_system_id'] : null;

    $event = [
        'sequence_id' => $sequenceId,
        'killmail_id' => (int) ($payload['killmail_id'] ?? 0),
        'killmail_hash' => (string) ($payload['hash'] ?? ''),
        'uploaded_at' => isset($payload['uploaded_at']) ? gmdate('Y-m-d H:i:s', (int) $payload['uploaded_at']) : null,
        'sequence_updated' => isset($payload['sequence_updated']) ? (int) $payload['sequence_updated'] : null,
        'killmail_time' => isset($killmail['killmail_time']) ? gmdate('Y-m-d H:i:s', strtotime((string) $killmail['killmail_time'])) : null,
        'solar_system_id' => $systemId,
        'region_id' => killmail_region_id_from_system($systemId),
        'victim_character_id' => isset($victim['character_id']) ? (int) $victim['character_id'] : null,
        'victim_corporation_id' => isset($victim['corporation_id']) ? (int) $victim['corporation_id'] : null,
        'victim_alliance_id' => isset($victim['alliance_id']) ? (int) $victim['alliance_id'] : null,
        'victim_ship_type_id' => isset($victim['ship_type_id']) ? (int) $victim['ship_type_id'] : null,
        'victim_damage_taken' => isset($victim['damage_taken']) ? (int) $victim['damage_taken'] : null,
        'zkb_total_value' => isset($zkb['totalValue']) && is_numeric($zkb['totalValue']) ? (float) $zkb['totalValue'] : null,
        'zkb_fitted_value' => isset($zkb['fittedValue']) && is_numeric($zkb['fittedValue']) ? (float) $zkb['fittedValue'] : null,
        'zkb_dropped_value' => isset($zkb['droppedValue']) && is_numeric($zkb['droppedValue']) ? (float) $zkb['droppedValue'] : null,
        'zkb_destroyed_value' => isset($zkb['destroyedValue']) && is_numeric($zkb['destroyedValue']) ? (float) $zkb['destroyedValue'] : null,
        'zkb_points' => isset($zkb['points']) && is_numeric($zkb['points']) ? (int) $zkb['points'] : null,
        'zkb_npc' => !empty($zkb['npc']),
        'zkb_solo' => !empty($zkb['solo']),
        'zkb_awox' => !empty($zkb['awox']),
        'zkb_json' => json_encode($zkb, JSON_UNESCAPED_SLASHES),
        'raw_killmail_json' => json_encode($killmail, JSON_UNESCAPED_SLASHES),
    ];

    $attackers = [];
    foreach ((array) ($killmail['attackers'] ?? []) as $i => $attacker) {
        if (!is_array($attacker)) {
            continue;
        }

        $attackers[] = [
            'attacker_index' => $i,
            'character_id' => isset($attacker['character_id']) ? (int) $attacker['character_id'] : null,
            'corporation_id' => isset($attacker['corporation_id']) ? (int) $attacker['corporation_id'] : null,
            'alliance_id' => isset($attacker['alliance_id']) ? (int) $attacker['alliance_id'] : null,
            'ship_type_id' => isset($attacker['ship_type_id']) ? (int) $attacker['ship_type_id'] : null,
            'weapon_type_id' => isset($attacker['weapon_type_id']) ? (int) $attacker['weapon_type_id'] : null,
            'damage_done' => isset($attacker['damage_done']) ? (int) $attacker['damage_done'] : null,
            'final_blow' => (bool) ($attacker['final_blow'] ?? false),
            'security_status' => isset($attacker['security_status']) ? (float) $attacker['security_status'] : null,
        ];
    }

    $itemIndex = 0;
    $items = killmail_extract_items((array) ($victim['items'] ?? []), $itemIndex, 'other');
    foreach ($items as &$item) {
        $hasDropped = (int) ($item['quantity_dropped'] ?? 0) > 0;
        $hasDestroyed = (int) ($item['quantity_destroyed'] ?? 0) > 0;
        $item['item_role'] = $hasDropped ? 'dropped' : ($hasDestroyed ? 'destroyed' : 'fitted');
    }

    return ['event' => $event, 'attackers' => $attackers, 'items' => $items];
}

function sync_killmail_r2z2_stream(string $runMode = 'incremental'): array
{
    $runMode = sync_mode_normalize($runMode);
    $datasetKey = killmail_sync_dataset_key();
    $runId = db_sync_run_start($datasetKey, $runMode, db_sync_cursor_get($datasetKey));
    $runtimeStartedAt = microtime(true);
    $runtimeTimeoutSeconds = max(30, min(3600, killmail_max_sequences_per_run() * 3));

    try {
        scheduler_runtime_guard($runtimeStartedAt, $runtimeTimeoutSeconds, 'killmail stream bootstrap');
        // Ensure any one-time killmail schema migrations run before per-row write transactions begin.
        db_killmail_payload_schema_ensure();
        ['alliance_ids' => $trackedAllianceIds, 'corporation_ids' => $trackedCorporationIds] = killmail_active_tracked_entity_ids();
        ['alliance_ids' => $opponentAllianceIds, 'corporation_ids' => $opponentCorporationIds] = killmail_active_opponent_entity_ids();

        $sequenceProbe = killmail_r2z2_fetch_json(killmail_r2z2_sequence_url());
        $sequenceProbeStatus = (int) ($sequenceProbe['status'] ?? 0);
        $cursor = db_sync_cursor_get($datasetKey);
        $lastSavedSequence = $cursor !== null && preg_match('/^[0-9]+$/', $cursor) === 1 ? (int) $cursor : null;
        $pollBackoffSeconds = killmail_poll_sleep_seconds();

        if ($sequenceProbeStatus === 403 || $sequenceProbeStatus === 429) {
            $cursorEnd = $cursor !== null ? $cursor : '0';
            $checksum = sync_checksum([0, 0, $cursorEnd]);
            $warnings = ['R2Z2 sequence probe returned status ' . $sequenceProbeStatus . '; worker hit rate limiting and is backing off for ' . $pollBackoffSeconds . 's.'];
            sleep($pollBackoffSeconds);
            $meta = [
                'last_saved_sequence_before_run' => $lastSavedSequence,
                'latest_remote_sequence' => null,
                'first_sequence_attempted' => null,
                'last_sequence_attempted' => null,
                'sequence_files_fetched' => 0,
                'sequence_404s_encountered' => 0,
                'killmails_fetched' => 0,
                'killmails_skipped_duplicates' => 0,
                'killmails_filtered_tracked_rules' => 0,
                'killmails_inserted' => 0,
                'outcome_reason' => 'sequence probe rate limited or forbidden',
                'last_processed_sequence' => null,
            ];
            sync_run_finalize_success($runId, $datasetKey, $runMode, 0, 0, $cursorEnd, $checksum, $warnings);

            return sync_result_shape() + [
                'rows_seen' => 0,
                'rows_written' => 0,
                'cursor' => $cursorEnd,
                'checksum' => $checksum,
                'warnings' => $warnings,
                'meta' => $meta,
            ];
        }

        if ($sequenceProbeStatus !== 200) {
            throw new RuntimeException('Unable to read killmail sequence.json, status=' . $sequenceProbeStatus);
        }

        $latestSequence = (int) (($sequenceProbe['json']['sequence'] ?? 0));
        $nextSequence = $lastSavedSequence !== null ? ($lastSavedSequence + 1) : $latestSequence;
        $maxSteps = killmail_max_sequences_per_run();

        $rowsSeen = 0;
        $rowsWritten = 0;
        $sequenceFilesFetched = 0;
        $sequence404s = 0;
        $duplicateCount = 0;
        $filteredCount = 0;
        $killmailsFetched = 0;
        $lastProcessed = null;
        $warnings = [];
        $firstSequenceAttempted = null;
        $lastSequenceAttempted = null;

        for ($step = 0; $step < $maxSteps; $step++) {
            scheduler_runtime_guard($runtimeStartedAt, $runtimeTimeoutSeconds, 'killmail sequence loop');
            if ($firstSequenceAttempted === null) {
                $firstSequenceAttempted = $nextSequence;
            }
            $lastSequenceAttempted = $nextSequence;

            $url = killmail_r2z2_base_url() . '/' . $nextSequence . '.json';
            $response = killmail_r2z2_fetch_json($url);
            $status = (int) ($response['status'] ?? 0);

            if ($status === 404) {
                $sequence404s++;
                $warnings[] = 'R2Z2 returned 404 for sequence ' . $nextSequence . '; worker reached end-of-feed and is backing off for ' . $pollBackoffSeconds . 's.';
                sleep($pollBackoffSeconds);
                break;
            }

            if ($status === 429 || $status === 403) {
                $warnings[] = 'R2Z2 returned status ' . $status . ' for sequence ' . $nextSequence . '; worker hit rate limiting and is backing off for ' . $pollBackoffSeconds . 's.';
                sleep($pollBackoffSeconds);
                break;
            }

            if ($status !== 200) {
                throw new RuntimeException('R2Z2 sequence fetch failed for ' . $nextSequence . ' with status=' . $status);
            }

            $sequenceFilesFetched++;
            $killmailsFetched++;
            $rowsSeen++;

            $result = killmail_persist_r2z2_payload(
                (array) ($response['json'] ?? []),
                $trackedAllianceIds,
                $trackedCorporationIds,
                true,
                $nextSequence,
                $opponentAllianceIds,
                $opponentCorporationIds,
            );
            $sequenceId = (int) ($result['sequence_id'] ?? 0);
            $statusKey = (string) ($result['status'] ?? 'invalid');
            if ($statusKey === 'duplicate') {
                $duplicateCount++;
                $nextSequence = $sequenceId + 1;
                $lastProcessed = $sequenceId;
                usleep(100000);
                continue;
            }

            if ($statusKey === 'filtered') {
                $filteredCount++;
                $nextSequence = $sequenceId + 1;
                $lastProcessed = $sequenceId;
                usleep(100000);
                continue;
            }

            if ($statusKey !== 'written' && $statusKey !== 'written_untracked') {
                throw new RuntimeException('Killmail ingestion returned an unexpected persistence status: ' . $statusKey);
            }

            $rowsWritten++;
            unset($response);
            if (function_exists('gc_collect_cycles')) {
                gc_collect_cycles();
            }

            $lastProcessed = $sequenceId;
            $nextSequence = $sequenceId + 1;
            usleep(100000);
        }

        $cursorEnd = $lastProcessed !== null ? (string) $lastProcessed : ($cursor ?? '0');
        $checksum = sync_checksum([$rowsSeen, $rowsWritten, $cursorEnd]);
        sync_run_finalize_success($runId, $datasetKey, $runMode, $rowsSeen, $rowsWritten, $cursorEnd, $checksum, $warnings);

        $outcomeReason = 'completed with inserts';
        if ($rowsWritten === 0) {
            if ($firstSequenceAttempted === null || ($lastSavedSequence !== null && $latestSequence <= $lastSavedSequence)) {
                $outcomeReason = 'no new sequences available';
            } elseif ($sequenceFilesFetched === 0 && $sequence404s > 0) {
                $outcomeReason = 'sequence state already current';
            } elseif ($killmailsFetched > 0 && $filteredCount === $killmailsFetched) {
                $outcomeReason = 'all fetched killmails filtered out';
            } elseif ($killmailsFetched > 0 && $duplicateCount === $killmailsFetched) {
                $outcomeReason = 'all fetched killmails were duplicates';
            } else {
                $outcomeReason = 'no records inserted';
            }
        }

        return sync_result_shape() + [
            'rows_seen' => $rowsSeen,
            'rows_written' => $rowsWritten,
            'cursor' => $cursorEnd,
            'checksum' => $checksum,
            'warnings' => $warnings,
            'meta' => [
                'last_saved_sequence_before_run' => $lastSavedSequence,
                'latest_remote_sequence' => $latestSequence,
                'first_sequence_attempted' => $firstSequenceAttempted,
                'last_sequence_attempted' => $lastSequenceAttempted,
                'sequence_files_fetched' => $sequenceFilesFetched,
                'sequence_404s_encountered' => $sequence404s,
                'killmails_fetched' => $killmailsFetched,
                'killmails_skipped_duplicates' => $duplicateCount,
                'killmails_filtered_tracked_rules' => $filteredCount,
                'killmails_inserted' => $rowsWritten,
                'outcome_reason' => $outcomeReason,
                'last_processed_sequence' => $lastProcessed,
            ],
        ];
    } catch (Throwable $exception) {
        sync_run_finalize_failure($runId, $datasetKey, $runMode, $exception->getMessage());
        throw $exception;
    }
}

/**
 * Search inventory types via authenticated ESI character search.
 *
 * Requires ``esi-search.search_structures.v1`` scope. Intentionally kept as a
 * PHP ESI callsite because the doctrine editor UI needs synchronous search
 * results for item type autocomplete.
 *
 * @todo Phase 3: route through a Python ESI search proxy for rate-limit coordination.
 */
function supplycore_summary_refresh_interval_seconds(): int
{
    $configured = (int) get_setting('summary_refresh_interval_seconds', '300');

    return max(60, min(3600, $configured > 0 ? $configured : 300));
}

function supplycore_summary_stale_after_seconds(): int
{
    return max(600, supplycore_summary_refresh_interval_seconds() * 3);
}

function supplycore_materialized_snapshot_keys(): array
{
    return [
        'doctrine_fit_intelligence',
        'doctrine_group_intelligence',
        'market_comparison_summaries',
        'loss_demand_summaries',
        'dashboard_summaries',
        'activity_priority_summaries',
    ];
}

function supplycore_materialized_snapshot_redis_key(string $snapshotKey): string
{
    return 'intelligence_snapshot:' . trim($snapshotKey);
}

function supplycore_materialized_snapshot_normalize_meta(string $snapshotKey, array $meta = []): array
{
    $intervalSeconds = max(60, (int) ($meta['refresh_interval_seconds'] ?? supplycore_summary_refresh_interval_seconds()));
    $staleAfterSeconds = max($intervalSeconds, (int) ($meta['stale_after_seconds'] ?? supplycore_summary_stale_after_seconds()));
    $computedAt = trim((string) ($meta['computed_at'] ?? ($meta['generated_at'] ?? '')));
    $status = trim((string) ($meta['status'] ?? 'ready'));
    if ($status === '') {
        $status = 'ready';
    }

    $computedUnix = $computedAt !== '' ? strtotime($computedAt) : false;
    $ageSeconds = $computedUnix !== false ? max(0, time() - $computedUnix) : null;
    $freshnessState = 'stale';
    if ($status === 'updating') {
        $freshnessState = 'updating';
    } elseif ($ageSeconds !== null && $ageSeconds <= (int) ceil($intervalSeconds * 1.5)) {
        $freshnessState = 'fresh';
    }

    return $meta + [
        'snapshot_key' => $snapshotKey,
        'status' => $status,
        'computed_at' => $computedAt !== '' ? $computedAt : null,
        'refresh_interval_seconds' => $intervalSeconds,
        'stale_after_seconds' => $staleAfterSeconds,
        'age_seconds' => $ageSeconds,
        'freshness_state' => $freshnessState,
        'freshness_label' => match ($freshnessState) {
            'fresh' => 'Fresh',
            'updating' => 'Updating',
            default => 'Stale',
        },
    ];
}

function supplycore_materialized_snapshot_fetch(string $snapshotKey): ?array
{
    try {
        $row = db_intelligence_snapshot_get($snapshotKey);
    } catch (Throwable) {
        $row = null;
    }

    if (!is_array($row)) {
        return null;
    }

    $payload = json_decode((string) ($row['payload_json'] ?? ''), true);
    if (!is_array($payload)) {
        $payload = [];
    }

    $storedMeta = json_decode((string) ($row['metadata_json'] ?? ''), true);
    $meta = supplycore_materialized_snapshot_normalize_meta($snapshotKey, is_array($storedMeta) ? $storedMeta : []);
    if (($row['computed_at'] ?? null) !== null) {
        $meta['computed_at'] = (string) $row['computed_at'];
    }
    if (($row['refresh_started_at'] ?? null) !== null) {
        $meta['refresh_started_at'] = (string) $row['refresh_started_at'];
    }
    if (($row['expires_at'] ?? null) !== null) {
        $meta['expires_at'] = (string) $row['expires_at'];
    }
    $meta['status'] = (string) ($row['snapshot_status'] ?? ($meta['status'] ?? 'ready'));
    $meta = supplycore_materialized_snapshot_normalize_meta($snapshotKey, $meta);

    return [
        'payload' => $payload,
        'meta' => $meta,
        'source' => 'db',
    ];
}

function supplycore_materialized_snapshot_attach_meta(array $payload, array $meta): array
{
    $payload['_freshness'] = supplycore_materialized_snapshot_normalize_meta((string) ($meta['snapshot_key'] ?? 'snapshot'), $meta);

    return $payload;
}

function supplycore_materialized_snapshot_store(string $snapshotKey, array $payload, array $meta = []): array
{
    $computedAt = gmdate(DATE_ATOM);
    $payloadJson = json_encode($payload, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
    $payloadHash = hash('sha256', is_string($payloadJson) ? $payloadJson : '{}');
    $normalizedMeta = supplycore_materialized_snapshot_normalize_meta($snapshotKey, $meta + [
        'snapshot_key' => $snapshotKey,
        'status' => 'ready',
        'computed_at' => $computedAt,
        'generated_at' => $computedAt,
        'payload_hash' => $payloadHash,
        'version_token' => $payloadHash,
    ]);
    $metaJson = json_encode($normalizedMeta, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
    $expiresAt = gmdate('Y-m-d H:i:s', time() + max(60, (int) $normalizedMeta['stale_after_seconds']));

    db_intelligence_snapshot_upsert(
        $snapshotKey,
        'ready',
        is_string($payloadJson) ? $payloadJson : null,
        is_string($metaJson) ? $metaJson : null,
        gmdate('Y-m-d H:i:s'),
        $normalizedMeta['refresh_started_at'] ?? null,
        $expiresAt
    );

    return supplycore_materialized_snapshot_attach_meta($payload, $normalizedMeta + ['expires_at' => $expiresAt]);
}

function supplycore_materialized_snapshot_mark_updating(string $snapshotKey, string $reason): void
{
    $existing = supplycore_materialized_snapshot_fetch($snapshotKey);
    $payload = is_array($existing['payload'] ?? null) ? $existing['payload'] : [];
    $meta = supplycore_materialized_snapshot_normalize_meta($snapshotKey, is_array($existing['meta'] ?? null) ? $existing['meta'] : []);
    $meta['status'] = 'updating';
    $meta['reason'] = $reason;
    $meta['refresh_started_at'] = gmdate(DATE_ATOM);
    $metaJson = json_encode($meta, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
    $expiresAt = gmdate('Y-m-d H:i:s', time() + max(60, (int) $meta['stale_after_seconds']));

    db_intelligence_snapshot_mark_updating($snapshotKey, is_string($metaJson) ? $metaJson : null, $expiresAt);
}

function supplycore_materialized_snapshot_read_or_bootstrap(string $snapshotKey, callable $builder, string $reason): array
{
    $snapshot = supplycore_materialized_snapshot_fetch($snapshotKey);

    // Serve existing snapshot even if stale/expired — never rebuild inline on
    // web requests.  Background Python jobs are responsible for keeping
    // snapshots fresh.  This prevents 64MB+ inline rebuilds on page load.
    if ($snapshot !== null && is_array($snapshot['payload'] ?? null) && $snapshot['payload'] !== []) {
        return supplycore_materialized_snapshot_attach_meta($snapshot['payload'], is_array($snapshot['meta'] ?? null) ? $snapshot['meta'] : []);
    }

    // Only rebuild if there is NO snapshot at all (first-time bootstrap)
    $payload = $builder();
    if (!is_array($payload)) {
        $payload = [];
    }

    return supplycore_materialized_snapshot_store($snapshotKey, $payload, [
        'reason' => $reason,
        'status' => 'ready',
    ]);
}

function supplycore_snapshot_freshness(string $snapshotKey): array
{
    $snapshot = supplycore_materialized_snapshot_fetch($snapshotKey);

    return is_array($snapshot['meta'] ?? null)
        ? supplycore_materialized_snapshot_normalize_meta($snapshotKey, $snapshot['meta'])
        : supplycore_materialized_snapshot_normalize_meta($snapshotKey, []);
}

function supplycore_ui_refresh_decode_json(mixed $value): array
{
    if (is_array($value)) {
        return $value;
    }

    if (!is_string($value) || trim($value) === '') {
        return [];
    }

    $decoded = json_decode($value, true);

    return is_array($decoded) ? $decoded : [];
}

function supplycore_ui_refresh_version_from_snapshot(string $sectionKey, string $snapshotKey, array $domains, array $uiSections): array
{
    $meta = supplycore_snapshot_freshness($snapshotKey);
    $fingerprint = trim((string) ($meta['payload_hash'] ?? $meta['version_token'] ?? ''));
    if ($fingerprint === '') {
        $fingerprint = hash('sha256', json_encode([
            'snapshot_key' => $snapshotKey,
            'computed_at' => (string) ($meta['computed_at'] ?? ''),
            'status' => (string) ($meta['status'] ?? ''),
        ], JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE));
    }

    return [
        'section_key' => $sectionKey,
        'fingerprint' => $fingerprint,
        'snapshot_key' => $snapshotKey,
        'domains' => array_values($domains),
        'ui_sections' => array_values($uiSections),
        'freshness' => $meta,
        'metadata' => [
            'source' => 'snapshot',
            'snapshot_key' => $snapshotKey,
            'computed_at' => $meta['computed_at'] ?? null,
            'freshness_state' => $meta['freshness_state'] ?? 'stale',
            'freshness_label' => $meta['freshness_label'] ?? 'Stale',
            'status' => $meta['status'] ?? 'ready',
        ],
    ];
}

function supplycore_ui_refresh_version_from_sync_state(string $sectionKey, array $datasetKeys, array $domains, array $uiSections, ?string $snapshotKey = null): array
{
    $status = sync_status_for_dataset_keys($datasetKeys);
    $states = array_values((array) ($status['states'] ?? []));
    $runs = array_values((array) ($status['runs'] ?? []));
    $fingerprintParts = [];

    foreach ($states as $state) {
        $fingerprintParts[] = [
            'dataset_key' => (string) ($state['dataset_key'] ?? ''),
            'status' => (string) ($state['status'] ?? ''),
            'checksum' => (string) ($state['last_checksum'] ?? ''),
            'rows' => (int) ($state['last_row_count'] ?? 0),
            'success_at' => (string) ($state['last_success_at'] ?? ''),
        ];
    }

    if ($fingerprintParts === [] && $runs !== []) {
        foreach ($runs as $run) {
            $fingerprintParts[] = [
                'dataset_key' => (string) ($run['dataset_key'] ?? ''),
                'run_status' => (string) ($run['run_status'] ?? ''),
                'written_rows' => (int) ($run['written_rows'] ?? 0),
                'finished_at' => (string) ($run['finished_at'] ?? ''),
            ];
        }
    }

    $fingerprint = hash('sha256', json_encode($fingerprintParts, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE));

    return [
        'section_key' => $sectionKey,
        'fingerprint' => $fingerprint,
        'snapshot_key' => $snapshotKey,
        'domains' => array_values($domains),
        'ui_sections' => array_values($uiSections),
        'freshness' => [
            'computed_at' => $status['last_success_at'] ?? null,
            'freshness_state' => ($status['last_success_at'] ?? null) !== null ? 'fresh' : 'stale',
            'freshness_label' => ($status['last_success_at'] ?? null) !== null ? 'Fresh' : 'Stale',
        ],
        'metadata' => [
            'source' => 'sync_state',
            'dataset_keys' => array_values($datasetKeys),
            'last_success_at' => $status['last_success_at'] ?? null,
            'recent_rows_written' => (int) ($status['recent_rows_written'] ?? 0),
            'last_error_message' => $status['last_error_message'] ?? null,
        ],
    ];
}

function deal_alerts_ui_refresh_version(): array
{
    $materialization = deal_alert_materialization_status();
    $fingerprint = hash('sha256', json_encode([
        'last_materialized_at' => $materialization['last_materialized_at'] ?? null,
        'persisted_row_count' => $materialization['persisted_row_count'] ?? 0,
        'last_attempt_status' => $materialization['last_attempt_status'] ?? 'never_ran',
        'last_success_status' => $materialization['last_success_status'] ?? null,
    ], JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE));

    return [
        'section_key' => 'deal_alerts_version',
        'fingerprint' => $fingerprint,
        'snapshot_key' => 'market_deal_alert_materialization_status',
        'domains' => ['deal_alerts'],
        'ui_sections' => ['deal-alerts-summary', 'deal-alerts-status', 'deal-alerts-table'],
        'freshness' => [
            'computed_at' => $materialization['last_materialized_at'] ?? null,
            'freshness_state' => ($materialization['last_materialized_at'] ?? null) !== null ? 'fresh' : 'stale',
            'freshness_label' => ($materialization['last_materialized_at'] ?? null) !== null ? 'Fresh' : 'Awaiting scan',
            'status' => $materialization['last_attempt_status'] ?? 'never_ran',
        ],
        'metadata' => [
            'source' => 'market_deal_alert_materialization_status',
            'last_attempt_status' => $materialization['last_attempt_status'] ?? 'never_ran',
            'persisted_row_count' => $materialization['persisted_row_count'] ?? 0,
        ],
    ];
}

function supplycore_ui_refresh_version_from_composite(string $sectionKey, array $parts, array $domains, array $uiSections, ?string $snapshotKey = null): array
{
    $fingerprints = [];
    $computedAtCandidates = [];
    $metadata = [];

    foreach ($parts as $part) {
        if (!is_array($part)) {
            continue;
        }

        $fingerprint = trim((string) ($part['fingerprint'] ?? ''));
        if ($fingerprint !== '') {
            $fingerprints[] = $fingerprint;
        }

        $computedAt = (string) (($part['freshness']['computed_at'] ?? $part['metadata']['last_success_at'] ?? ''));
        if ($computedAt !== '') {
            $computedAtCandidates[] = $computedAt;
        }

        $metadata[] = [
            'section_key' => (string) ($part['section_key'] ?? ''),
            'fingerprint' => $fingerprint,
            'computed_at' => $computedAt !== '' ? $computedAt : null,
            'source' => (string) ($part['metadata']['source'] ?? 'unknown'),
        ];
    }

    rsort($computedAtCandidates);
    $computedAt = $computedAtCandidates[0] ?? null;

    return [
        'section_key' => $sectionKey,
        'fingerprint' => hash('sha256', json_encode($fingerprints, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE)),
        'snapshot_key' => $snapshotKey,
        'domains' => array_values($domains),
        'ui_sections' => array_values($uiSections),
        'freshness' => [
            'computed_at' => $computedAt,
            'freshness_state' => $computedAt !== null ? 'fresh' : 'stale',
            'freshness_label' => $computedAt !== null ? 'Fresh' : 'Stale',
        ],
        'metadata' => [
            'source' => 'composite',
            'parts' => $metadata,
        ],
    ];
}

function supplycore_ui_refresh_section_version_definitions(): array
{
    return [
        'dashboard_summary_version' => [
            'domains' => ['dashboard'],
            'ui_sections' => ['page-freshness', 'dashboard-kpis', 'dashboard-buyall', 'dashboard-doctrine', 'dashboard-queues'],
            'resolver' => static fn (): array => supplycore_ui_refresh_version_from_snapshot('dashboard_summary_version', dashboard_snapshot_key(), ['dashboard'], ['page-freshness', 'dashboard-kpis', 'dashboard-buyall', 'dashboard-doctrine', 'dashboard-queues']),
        ],
        'activity_priority_version' => [
            'domains' => ['activity_priority', 'doctrine_activity'],
            'ui_sections' => ['activity-summary', 'activity-doctrines', 'activity-sidebar', 'activity-items', 'dashboard-doctrine'],
            'resolver' => static fn (): array => supplycore_ui_refresh_version_from_snapshot('activity_priority_version', activity_priority_snapshot_key(), ['activity_priority', 'doctrine_activity'], ['activity-summary', 'activity-doctrines', 'activity-sidebar', 'activity-items', 'dashboard-doctrine']),
        ],
        'deal_alerts_version' => [
            'domains' => ['deal_alerts'],
            'ui_sections' => ['deal-alerts-summary', 'deal-alerts-status', 'deal-alerts-table'],
            'resolver' => static fn (): array => deal_alerts_ui_refresh_version(),
        ],
        'buyall_version' => [
            'domains' => ['buyall'],
            'ui_sections' => ['dashboard-buyall', 'buyall-overview', 'buyall-results'],
            'resolver' => static function (): array {
                $hubRef = market_hub_setting_reference();
                $structureId = configured_alliance_structure_id();
                $parts = [
                    supplycore_ui_refresh_version_from_snapshot('market_comparison_version', market_comparison_snapshot_key(), ['market_comparison'], ['dashboard-queues', 'current-alliance-main', 'reference-comparison-main', 'missing-items-main', 'price-deviations-main']),
                    supplycore_ui_refresh_version_from_sync_state('market_prices_version', $hubRef !== '' ? [sync_dataset_key_market_hub_current_orders($hubRef)] : [], ['market_prices'], ['dashboard-queues', 'buyall-overview', 'buyall-results']),
                    supplycore_ui_refresh_version_from_sync_state('alliance_stock_version', $structureId !== null ? [sync_dataset_key_alliance_structure_orders_current((int) $structureId)] : [], ['alliance_stock'], ['dashboard-queues', 'buyall-overview', 'buyall-results', 'current-alliance-main']),
                ];

                return supplycore_ui_refresh_version_from_composite('buyall_version', $parts, ['buyall'], ['dashboard-buyall', 'buyall-overview', 'buyall-results']);
            },
        ],
        'market_prices_version' => [
            'domains' => ['market_prices', 'pricing_summaries', 'opportunity_queue', 'risk_queue'],
            'ui_sections' => ['dashboard-queues', 'buyall-overview', 'buyall-results', 'doctrine-fit-items', 'current-alliance-main', 'reference-comparison-main', 'missing-items-main', 'price-deviations-main'],
            'resolver' => static function (): array {
                $hubRef = market_hub_setting_reference();
                $datasetKeys = $hubRef !== '' ? [sync_dataset_key_market_hub_current_orders($hubRef)] : [];

                return supplycore_ui_refresh_version_from_sync_state('market_prices_version', $datasetKeys, ['market_prices', 'pricing_summaries', 'opportunity_queue', 'risk_queue'], ['dashboard-queues', 'buyall-overview', 'buyall-results', 'doctrine-fit-items', 'current-alliance-main', 'reference-comparison-main', 'missing-items-main', 'price-deviations-main']);
            },
        ],
        'alliance_stock_version' => [
            'domains' => ['alliance_stock'],
            'ui_sections' => ['dashboard-queues', 'buyall-overview', 'buyall-results', 'doctrine-fit-items', 'current-alliance-main', 'reference-comparison-main', 'missing-items-main', 'price-deviations-main'],
            'resolver' => static function (): array {
                $structureId = configured_alliance_structure_id();
                $datasetKeys = $structureId !== null ? [sync_dataset_key_alliance_structure_orders_current((int) $structureId)] : [];

                return supplycore_ui_refresh_version_from_sync_state('alliance_stock_version', $datasetKeys, ['alliance_stock'], ['dashboard-queues', 'buyall-overview', 'buyall-results', 'doctrine-fit-items', 'current-alliance-main', 'reference-comparison-main', 'missing-items-main', 'price-deviations-main']);
            },
        ],
        'market_comparison_version' => [
            'domains' => ['market_comparison', 'overlap', 'pricing_summaries'],
            'ui_sections' => ['dashboard-queues', 'current-alliance-main', 'reference-comparison-main', 'missing-items-main', 'price-deviations-main', 'buyall-results'],
            'resolver' => static fn (): array => supplycore_ui_refresh_version_from_snapshot('market_comparison_version', market_comparison_snapshot_key(), ['market_comparison', 'overlap', 'pricing_summaries'], ['dashboard-queues', 'current-alliance-main', 'reference-comparison-main', 'missing-items-main', 'price-deviations-main', 'buyall-results']),
        ],
        'loss_demand_version' => [
            'domains' => ['loss_aware_views'],
            'ui_sections' => ['dashboard-queues'],
            'resolver' => static fn (): array => supplycore_ui_refresh_version_from_snapshot('loss_demand_version', loss_demand_snapshot_key(), ['loss_aware_views'], ['dashboard-queues']),
        ],
        'killmail_activity_version' => [
            'domains' => ['doctrine_activity', 'loss_aware_views'],
            'ui_sections' => ['activity-doctrines', 'activity-sidebar', 'activity-items', 'doctrine-fit-history'],
            'resolver' => static function (): array {
                return supplycore_ui_refresh_version_from_sync_state('killmail_activity_version', [sync_dataset_key_killmail_r2z2_stream()], ['doctrine_activity', 'loss_aware_views'], ['activity-doctrines', 'activity-sidebar', 'activity-items', 'doctrine-fit-history']);
            },
        ],
        'killmail_overview_version' => [
            'domains' => ['killmail_overview', 'loss_aware_views'],
            'ui_sections' => ['killmail-overview-summary', 'killmail-overview-status', 'killmail-overview-table'],
            'resolver' => static function (): array {
                return supplycore_ui_refresh_version_from_sync_state('killmail_overview_version', [sync_dataset_key_killmail_r2z2_stream()], ['killmail_overview', 'loss_aware_views'], ['killmail-overview-summary', 'killmail-overview-status', 'killmail-overview-table']);
            },
        ],
        'log_viewer_version' => [
            'domains' => ['scheduler'],
            'ui_sections' => ['log-viewer-kpi', 'log-viewer-jobs', 'log-viewer-runs'],
            'resolver' => static function (): array {
                // Use a time-based fingerprint so the version bumps on every job completion.
                // The log viewer is inherently real-time — we always want to show the latest state.
                $fingerprint = hash('xxh3', gmdate('Y-m-d H:i:s'));
                return [
                    'section_key' => 'log_viewer_version',
                    'fingerprint' => $fingerprint,
                    'domains' => ['scheduler'],
                    'ui_sections' => ['log-viewer-kpi', 'log-viewer-jobs', 'log-viewer-runs'],
                    'freshness' => [
                        'computed_at' => gmdate('Y-m-d H:i:s'),
                        'freshness_state' => 'fresh',
                        'freshness_label' => 'Fresh',
                        'status' => 'ready',
                    ],
                    'metadata' => [
                        'source' => 'scheduler_job_current_status',
                    ],
                ];
            },
        ],
        'sovereignty_version' => [
            'domains' => ['sovereignty'],
            'ui_sections' => ['sovereignty-alerts', 'sovereignty-campaigns', 'sovereignty-map'],
            'resolver' => static function (): array {
                return supplycore_ui_refresh_version_from_sync_state(
                    'sovereignty_version',
                    ['sovereignty.campaigns', 'sovereignty.structures', 'sovereignty.map', 'sovereignty.alerts'],
                    ['sovereignty'],
                    ['sovereignty-alerts', 'sovereignty-campaigns', 'sovereignty-map']
                );
            },
        ],
    ];
}

