function supplycore_live_refresh_page_config(string $pageId): ?array
{
    $registry = supplycore_live_refresh_page_registry();
    $page = $registry[$pageId] ?? null;
    if (!is_array($page)) {
        return null;
    }

    $currentVersions = supplycore_ui_refresh_current_versions((array) ($page['version_keys'] ?? []));
    $latestEvent = db_ui_refresh_latest_event();

    return $page + [
        'page_id' => $pageId,
        'stream_url' => '/api/ui-refresh-stream.php?page_id=' . rawurlencode($pageId),
        'poll_url' => '/api/ui-refresh-state.php?page_id=' . rawurlencode($pageId),
        'fragment_url' => '/api/ui-refresh-fragment.php?page_id=' . rawurlencode($pageId),
        'current_versions' => $currentVersions,
        'latest_event' => is_array($latestEvent) ? supplycore_ui_refresh_normalize_event_row($latestEvent) : null,
        'transport' => 'sse',
        'debounce_ms' => 1200,
        'poll_interval_ms' => 30000,
        'auto_refresh_ms' => 60000,
        'query_string' => http_build_query($_GET),
    ];
}

function supplycore_live_refresh_page_data_attributes(?array $config): string
{
    if (!is_array($config) || $config === []) {
        return '';
    }

    $payload = json_encode($config, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
    if (!is_string($payload) || $payload === '') {
        return '';
    }

    return ' data-live-refresh-config="' . htmlspecialchars($payload, ENT_QUOTES) . '"';
}

function supplycore_live_refresh_should_include(?array $config): bool
{
    return is_array($config) && $config !== [];
}

function supplycore_live_refresh_matches_page(array $pageConfig, array $event): bool
{
    $pageDomains = array_values((array) ($pageConfig['domains'] ?? []));
    $pageSections = array_keys((array) ($pageConfig['sections'] ?? []));
    $eventDomains = array_values((array) ($event['affected_data_domains'] ?? []));
    $eventSections = array_values((array) ($event['affected_ui_sections'] ?? []));

    return array_intersect($pageDomains, $eventDomains) !== [] || array_intersect($pageSections, $eventSections) !== [];
}

function supplycore_live_refresh_state_payload(array $pageConfig): array
{
    // Reuse current_versions from page_config if already computed, otherwise resolve fresh
    $currentVersions = is_array($pageConfig['current_versions'] ?? null) && ($pageConfig['current_versions'] ?? []) !== []
        ? $pageConfig['current_versions']
        : supplycore_ui_refresh_current_versions((array) ($pageConfig['version_keys'] ?? []));

    return [
        'page_id' => (string) ($pageConfig['page_id'] ?? ''),
        'transport' => 'polling',
        'current_versions' => $currentVersions,
        'last_published_event' => ($latest = db_ui_refresh_latest_event()) ? supplycore_ui_refresh_normalize_event_row($latest) : null,
        'generated_at' => gmdate(DATE_ATOM),
    ];
}

function supplycore_live_refresh_extract_section(string $html, string $sectionKey): ?string
{
    $pattern = '/<!--\s*ui-section:' . preg_quote($sectionKey, '/') . ':start\s*-->(.*?)<!--\s*ui-section:' . preg_quote($sectionKey, '/') . ':end\s*-->/s';
    if (preg_match($pattern, $html, $matches) !== 1) {
        return null;
    }

    return trim((string) ($matches[1] ?? ''));
}

function supplycore_live_refresh_render_page_fragment(string $pageId, string $sectionKey, string $queryString = ''): ?string
{
    $registry = supplycore_live_refresh_page_registry();
    $page = $registry[$pageId] ?? null;
    if (!is_array($page) || !isset($page['sections'][$sectionKey])) {
        return null;
    }

    $script = (string) ($page['script'] ?? '');
    if ($script === '' || !is_file($script)) {
        return null;
    }

    parse_str($queryString, $query);
    if (!is_array($query)) {
        $query = [];
    }

    $previousGet = $_GET;
    $previousServer = $_SERVER;

    $_GET = $query;
    $_SERVER['REQUEST_URI'] = (string) ($page['public_path'] ?? '/') . ($queryString !== '' ? '?' . $queryString : '');
    $_SERVER['QUERY_STRING'] = $queryString;

    if (!defined('SUPPLYCORE_LIVE_FRAGMENT_CAPTURE')) {
        define('SUPPLYCORE_LIVE_FRAGMENT_CAPTURE', true);
    }

    ob_start();
    include $script;
    $html = (string) ob_get_clean();

    $_GET = $previousGet;
    $_SERVER = $previousServer;

    return supplycore_live_refresh_extract_section($html, $sectionKey);
}


function supplycore_format_datetime(?string $value): string
{
    if ($value === null) {
        return 'Unavailable';
    }

    $timestamp = strtotime($value);
    if ($timestamp === false) {
        return 'Unavailable';
    }

    return gmdate('Y-m-d H:i:s \U\T\C', $timestamp);
}

/**
 * Renders a datetime as relative text with a full UTC tooltip on hover.
 * Standard display pattern: "3m ago" with title="2026-04-07 23:08:00 UTC".
 */
function supplycore_datetime_html(?string $value): string
{
    if ($value === null) {
        return '<span class="text-slate-500">Never</span>';
    }

    $timestamp = strtotime($value);
    if ($timestamp === false) {
        return '<span class="text-slate-500">Unknown</span>';
    }

    $full = gmdate('Y-m-d H:i:s \U\T\C', $timestamp);
    $relative = supplycore_relative_datetime($value);

    return '<span title="' . htmlspecialchars($full, ENT_QUOTES) . '">' . htmlspecialchars($relative, ENT_QUOTES) . '</span>';
}

function supplycore_relative_datetime(?string $value): string
{
    if ($value === null) {
        return 'Never';
    }

    $timestamp = strtotime($value);
    if ($timestamp === false) {
        return 'Unknown';
    }

    $seconds = max(0, time() - $timestamp);

    return human_duration_ago($seconds) . ' ago';
}

function supplycore_operational_status_view_model(?string $status, ?string $fallbackLabel = null): array
{
    $normalized = strtolower(trim((string) ($status ?? '')));
    $bucket = match ($normalized) {
        'fresh', 'healthy', 'ok', 'tracked', 'ready', 'success', 'running' => $normalized === 'running' ? 'updating' : 'fresh',
        'updating', 'syncing', 'active', 'in_progress' => 'updating',
        'warning', 'degraded', 'delayed' => 'delayed',
        'blocked', 'critical', 'stale', 'failed', 'error', 'not synced', 'awaiting sync', 'stopped', 'offline' => 'stale',
        default => 'delayed',
    };

    $label = $fallbackLabel !== null && trim($fallbackLabel) !== ''
        ? trim($fallbackLabel)
        : match ($bucket) {
            'fresh' => 'Fresh',
            'updating' => 'Updating',
            'stale' => 'Stale',
            default => 'Delayed',
        };

    return [
        'state' => $bucket,
        'label' => $label,
        'tone' => match ($bucket) {
            'fresh' => 'border-emerald-400/20 bg-emerald-500/10 text-emerald-100',
            'updating' => 'border-sky-400/20 bg-sky-500/10 text-sky-100',
            'stale' => 'border-rose-400/20 bg-rose-500/10 text-rose-100',
            default => 'border-amber-400/20 bg-amber-500/10 text-amber-100',
        },
    ];
}

function supplycore_live_refresh_summary(?array $config): array
{
    if (!is_array($config) || $config === []) {
        return [
            'mode_label' => 'Off',
            'mode_tone' => 'border-slate-400/15 bg-slate-500/10 text-slate-200',
            'last_refresh_relative' => 'Never',
            'last_refresh_at' => 'Unavailable',
            'health_label' => 'Off',
            'health_tone' => 'border-slate-400/15 bg-slate-500/10 text-slate-200',
            'health_message' => 'Live updates are unavailable for this page.',
            'show_advanced' => false,
            'latest_event' => null,
            'current_versions' => [],
        ];
    }

    $latestEvent = is_array($config['latest_event'] ?? null) ? $config['latest_event'] : null;
    $lastRefreshAt = isset($latestEvent['finished_at']) ? (string) $latestEvent['finished_at'] : null;
    $minutesSinceRefresh = null;
    if ($lastRefreshAt !== null) {
        $timestamp = strtotime($lastRefreshAt);
        if ($timestamp !== false) {
            $minutesSinceRefresh = max(0, (int) floor((time() - $timestamp) / 60));
        }
    }

    $healthState = match (true) {
        $minutesSinceRefresh === null => 'delayed',
        $minutesSinceRefresh <= 15 => 'fresh',
        $minutesSinceRefresh <= 45 => 'updating',
        $minutesSinceRefresh <= 120 => 'delayed',
        default => 'stale',
    };
    $health = supplycore_operational_status_view_model($healthState);

    return [
        'mode_label' => 'On',
        'mode_tone' => 'border-emerald-400/20 bg-emerald-500/10 text-emerald-100',
        'last_refresh_relative' => supplycore_relative_datetime($lastRefreshAt),
        'last_refresh_at' => supplycore_format_datetime($lastRefreshAt),
        'health_label' => $health['label'],
        'health_tone' => $health['tone'],
        'health_message' => match ($healthState) {
            'fresh' => 'Live updates are flowing normally.',
            'updating' => 'A newer refresh is still landing.',
            'stale' => 'Live updates look stale. Open advanced diagnostics if this persists.',
            default => 'Live updates have slowed down. Polling fallback or a manual refresh may be needed.',
        },
        'show_advanced' => in_array($healthState, ['delayed', 'stale'], true),
        'latest_event' => $latestEvent,
        'current_versions' => is_array($config['current_versions'] ?? null) ? $config['current_versions'] : [],
    ];
}

function supplycore_page_freshness_view_model(array $freshness): array
{
    $computedAt = isset($freshness['computed_at']) ? (string) $freshness['computed_at'] : null;
    $state = (string) ($freshness['freshness_state'] ?? 'stale');
    $status = supplycore_operational_status_view_model($state, (string) ($freshness['freshness_label'] ?? ucfirst($state)));

    return [
        'state' => $status['state'],
        'label' => $status['label'],
        'computed_at' => supplycore_format_datetime($computedAt),
        'computed_relative' => supplycore_relative_datetime($computedAt),
        'reason' => (string) ($freshness['reason'] ?? ''),
        'tone' => $status['tone'],
        'message' => match ($status['state']) {
            'fresh' => 'Background summaries are current.',
            'updating' => 'A background refresh is currently rebuilding this view.',
            'stale' => 'Displayed results are stale and should be refreshed before acting.',
            default => 'Displayed results are older than the target refresh cadence.',
        },
    ];
}

function analytics_bucket_refresh_job_result(string $resolution = '1h', string $reason = 'manual'): array
{
    $result = db_time_series_refresh_all($resolution);
    $meta = is_array($result['meta'] ?? null) ? $result['meta'] : [];
    $safeResolution = $resolution === '1d' ? '1d' : '1h';
    $killmailMeta = is_array($meta['killmail'] ?? null) ? $meta['killmail'] : [];
    $marketMeta = is_array($meta['market'] ?? null) ? $meta['market'] : [];

    return sync_result_shape() + [
        'rows_seen' => (int) ($result['rows_seen'] ?? 0),
        'rows_written' => (int) ($result['rows_written'] ?? 0),
        'cursor' => 'analytics_bucket:' . $safeResolution . ':' . gmdate('Y-m-d H:i:s'),
        'checksum' => sync_checksum([
            'resolution' => $safeResolution,
            'rows_seen' => (int) ($result['rows_seen'] ?? 0),
            'rows_written' => (int) ($result['rows_written'] ?? 0),
            'reason' => $reason,
        ]),
        'meta' => [
            'outcome_reason' => 'MariaDB analytics bucket tables were incrementally upserted for ' . $safeResolution . ' windows.',
            'resolution' => $safeResolution,
            'killmail_rows_processed' => (int) ($killmailMeta['source_rows'] ?? $killmailMeta['rows_seen'] ?? 0),
            'market_rows_processed' => (int) ($marketMeta['source_rows'] ?? $marketMeta['rows_seen'] ?? 0),
            'killmail_duration_ms' => (int) ($killmailMeta['duration_ms'] ?? 0),
            'market_duration_ms' => (int) ($marketMeta['duration_ms'] ?? 0),
            'last_killmail_processed_timestamp' => (string) ($killmailMeta['last_processed_timestamp'] ?? ''),
            'last_market_processed_timestamp' => (string) ($marketMeta['last_processed_timestamp'] ?? ''),
            'has_more_work' => !empty($meta['has_more_work']),
        ] + $meta,
    ];
}

function supplycore_refresh_current_state_cache(string $reason = 'manual'): array
{
    $market = market_comparison_refresh_summary($reason . ':market');
    $lossDemand = loss_demand_refresh_summary($reason . ':loss-demand');
    $dashboard = dashboard_refresh_summary($reason . ':dashboard');
    supplycore_cache_bust(['dashboard', 'market_compare']);

    $rows = count((array) ($market['rows'] ?? []));
    $queues = count((array) ($dashboard['priority_queues']['opportunities'] ?? []))
        + count((array) ($dashboard['priority_queues']['risks'] ?? []))
        + count((array) ($dashboard['priority_queues']['missing_items'] ?? []));

    return sync_result_shape() + [
        'rows_seen' => $rows,
        'rows_written' => $queues + count((array) ($lossDemand['rows'] ?? [])),
        'cursor' => 'current_state:' . gmdate('Y-m-d H:i:s'),
        'checksum' => sync_checksum([
            'reason' => $reason,
            'rows' => $rows,
            'queues' => $queues,
        ]),
        'meta' => [
            'outcome_reason' => 'Market comparison, loss-demand, and dashboard summaries were refreshed into materialized current-state layers.',
        ],
    ];
}

function supplycore_rebuild_window_bounds(?int $windowDays = null): array
{
    $safeWindowDays = market_hub_local_history_window_days_normalize($windowDays);
    $startObservedAt = market_hub_local_history_window_start_observed_at($safeWindowDays);

    return [
        'window_days' => $safeWindowDays,
        'start_observed_at' => $startObservedAt,
        'start_date' => substr($startObservedAt, 0, 10),
        'end_date' => gmdate('Y-m-d'),
    ];
}

function supplycore_rebuild_partitioned_market_history(array $window): array
{
    $startDate = (string) ($window['start_date'] ?? '');
    $endDate = (string) ($window['end_date'] ?? '');

    db_market_orders_history_partitioned_schema_ensure();
    db_market_order_snapshots_summary_partitioned_schema_ensure();

    $historyBackfill = db_market_orders_history_backfill_window($startDate, $endDate);
    $summaryBackfill = db_market_order_snapshots_summary_backfill_window($startDate, $endDate);
    $historyCutover = db_market_orders_history_cutover_swap('partitioned', 'dual');
    $summaryCutover = db_market_order_snapshots_summary_cutover_swap('partitioned', 'dual');

    return [
        'history_backfill_rows' => $historyBackfill,
        'summary_backfill_rows' => $summaryBackfill,
        'history_cutover' => $historyCutover,
        'summary_cutover' => $summaryCutover,
    ];
}

function supplycore_rebuild_current_layers(string $reason = 'manual', bool $fullReset = false): array
{
    $sourceRows = db_market_rebuild_source_keys();
    $resetTables = ['market_order_current_projection', 'market_source_snapshot_state'];
    $resetCount = db_truncate_tables($resetTables);
    $sourcesProcessed = 0;
    $projectionRowsWritten = 0;

    foreach ($sourceRows as $source) {
        $sourceType = trim((string) ($source['source_type'] ?? ''));
        $sourceId = (int) ($source['source_id'] ?? 0);
        if ($sourceType === '' || $sourceId <= 0) {
            continue;
        }

        $snapshotRows = db_market_orders_current_latest_snapshot_rows($sourceType, $sourceId);
        if ($snapshotRows === []) {
            continue;
        }

        $projectionRowsWritten += db_market_order_current_projection_refresh_snapshots(
            db_market_order_current_projection_rows_from_orders($snapshotRows)
        );
        db_market_source_snapshot_state_upsert([
            'source_type' => $sourceType,
            'source_id' => $sourceId,
            'latest_current_observed_at' => (string) ($snapshotRows[0]['observed_at'] ?? ''),
            'current_order_count' => count($snapshotRows),
            'current_distinct_type_count' => market_order_distinct_type_count($snapshotRows),
            'last_synced_at' => (string) ($snapshotRows[0]['observed_at'] ?? ''),
        ]);
        $sourcesProcessed++;
    }

    return [
        'reason' => $reason,
        'reset_tables' => $resetTables,
        'reset_count' => $resetCount,
        'sources_processed' => $sourcesProcessed,
        'projection_rows_written' => $projectionRowsWritten,
    ];
}

function supplycore_rebuild_rollup_layers(string $reason = 'manual', ?int $windowDays = null, bool $fullReset = false): array
{
    $window = supplycore_rebuild_window_bounds($windowDays);
    $startObservedAt = (string) ($window['start_observed_at'] ?? '');
    $startDate = (string) ($window['start_date'] ?? '');
    $endDate = (string) ($window['end_date'] ?? '');
    $sourceRows = db_market_rebuild_source_keys();
    $resetTables = [
        'market_order_snapshot_rollup_1h',
        'market_order_snapshot_rollup_1d',
    ];

    if ($fullReset) {
        array_push(
            $resetTables,
            'market_order_snapshots_summary',
            db_market_order_snapshots_summary_partitioned_table(),
            'market_history_daily',
            'market_hub_local_history_daily'
        );
    }

    $resetCount = $fullReset ? db_truncate_tables($resetTables) : 0;
    $sourcesProcessed = 0;
    $summaryRowsWritten = 0;
    $rollupRowsWritten = ['1h' => 0, '1d' => 0];
    $dailyRowsWritten = 0;
    $localDailyRowsWritten = 0;

    foreach ($sourceRows as $source) {
        $sourceType = trim((string) ($source['source_type'] ?? ''));
        $sourceId = (int) ($source['source_id'] ?? 0);
        if ($sourceType === '' || $sourceId <= 0) {
            continue;
        }

        if (!$fullReset) {
            db_market_order_snapshots_summary_delete_window($sourceType, $sourceId, $startDate, $endDate);
            db_market_snapshot_rollup_delete_window('1h', $sourceType, $sourceId, $startDate, $endDate);
            db_market_snapshot_rollup_delete_window('1d', $sourceType, $sourceId, $startDate, $endDate);
            db_market_history_daily_delete_window($sourceType, $sourceId, $startDate, $endDate);
            if ($sourceType === 'market_hub') {
                db_market_hub_local_history_daily_delete_window(market_hub_local_history_source(), $sourceId, $startDate, $endDate);
            }
        }

        $summaryRows = db_market_orders_snapshot_metrics_window_raw($sourceType, $sourceId, $startObservedAt);
        if ($summaryRows !== []) {
            $summaryRowsWritten += db_market_order_snapshots_summary_bulk_upsert($summaryRows);
            $rollupRowsWritten['1h'] += db_market_snapshot_rollup_bulk_upsert('1h', db_market_snapshot_rollup_rows_from_summary('1h', $summaryRows));
            $rollupRowsWritten['1d'] += db_market_snapshot_rollup_bulk_upsert('1d', db_market_snapshot_rollup_rows_from_summary('1d', $summaryRows));
        }

        $snapshotMetrics = db_market_orders_snapshot_metrics_window($sourceType, $sourceId, $startObservedAt);
        if ($snapshotMetrics === []) {
            continue;
        }

        $rebuiltDaily = market_history_daily_rebuild_from_snapshot_metrics($snapshotMetrics, $sourceType);
        $dailyRowsWritten += db_market_history_daily_bulk_upsert((array) ($rebuiltDaily['rows'] ?? []));

        if ($sourceType === 'market_hub') {
            $rebuiltLocalDaily = market_hub_local_history_daily_rebuild_from_snapshot_metrics($snapshotMetrics);
            $localDailyRowsWritten += db_market_hub_local_history_daily_bulk_upsert((array) ($rebuiltLocalDaily['rows'] ?? []));
        }

        $sourcesProcessed++;
    }

    $currentState = supplycore_refresh_current_state_cache($reason . ':current-state');
    // Legacy doctrine snapshot refresh is retired.
    $activity = activity_priority_refresh_summary($reason . ':activity-priority');

    return [
        'reason' => $reason,
        'window' => $window,
        'reset_tables' => $resetTables,
        'reset_count' => $resetCount,
        'sources_processed' => $sourcesProcessed,
        'summary_rows_written' => $summaryRowsWritten,
        'rollup_rows_written' => $rollupRowsWritten,
        'daily_rows_written' => $dailyRowsWritten,
        'local_daily_rows_written' => $localDailyRowsWritten,
        'current_state_rows_written' => (int) ($currentState['rows_written'] ?? 0),
        'doctrine_snapshot_groups' => 0,
        'activity_rows' => count((array) ($activity['rows'] ?? [])),
    ];
}

function supplycore_forecasting_snapshot_setting_key(): string
{
    return 'supplycore_forecasting_snapshot_v1';
}

function supplycore_forecasting_snapshot_metadata_setting_key(): string
{
    return 'supplycore_forecasting_snapshot_meta_v1';
}

function supplycore_forecasting_snapshot(): array
{
    $raw = trim((string) get_setting(supplycore_forecasting_snapshot_setting_key(), ''));
    if ($raw === '') {
        return [];
    }

    $decoded = json_decode($raw, true);

    return is_array($decoded) ? $decoded : [];
}

function supplycore_forecasting_snapshot_store(array $snapshot, string $reason): bool
{
    $meta = [
        'generated_at' => gmdate(DATE_ATOM),
        'reason' => $reason,
        'forecast_count' => count((array) ($snapshot['forecast_rows'] ?? [])),
        'anomaly_count' => count((array) ($snapshot['anomalies'] ?? [])),
    ];

    return save_settings([
        supplycore_forecasting_snapshot_setting_key() => json_encode($snapshot, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
        supplycore_forecasting_snapshot_metadata_setting_key() => json_encode($meta, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
    ]);
}

function supplycore_forecasting_snapshot_build(string $reason = 'manual'): array
{
    // Legacy forecasting snapshot relied on doctrine intelligence tables,
    // all of which have been retired. Returns an empty snapshot shape so
    // forecasting_ai_sync keeps running without fataling.
    return [
        'reason' => $reason,
        'generated_at' => gmdate(DATE_ATOM),
        'rows' => [],
        'anomalies' => [],
        'briefings' => [],
    ];
}

function supplycore_refresh_forecasting_snapshot_job_result(string $reason = 'manual'): array
{
    $snapshot = supplycore_forecasting_snapshot_build($reason);
    supplycore_forecasting_snapshot_store($snapshot, $reason);

    return sync_result_shape() + [
        'rows_seen' => count((array) ($snapshot['forecast_rows'] ?? [])),
        'rows_written' => count((array) ($snapshot['briefings'] ?? [])) + count((array) ($snapshot['anomalies'] ?? [])),
        'cursor' => 'forecasting_snapshot:' . gmdate('Y-m-d H:i:s'),
        'checksum' => sync_checksum([
            'generated_at' => (string) ($snapshot['generated_at'] ?? gmdate(DATE_ATOM)),
            'reason' => $reason,
            'forecast_rows' => count((array) ($snapshot['forecast_rows'] ?? [])),
        ]),
        'meta' => [
            'outcome_reason' => 'Slow forecasting batch refreshed target-adjustment, anomaly, briefing, and recommendation-explanation views from the latest medium snapshot.',
        ],
    ];
}

function supplycore_ai_ollama_config(): array
{
    static $config = null;

    // Runtime override (e.g. "Generate Intel" button forcing local Ollama + model).
    // Set $GLOBALS['supplycore_ai_ollama_runtime_override'] to an assoc array before
    // calling into the AI pipeline to force specific config values for this request.
    $override = $GLOBALS['supplycore_ai_ollama_runtime_override'] ?? null;
    if (is_array($override) && $override !== []) {
        return $override;
    }

    if (is_array($config)) {
        return $config;
    }

    $defaults = ai_briefing_setting_defaults();
    $settings = get_settings(ai_briefing_setting_keys());
    $provider = sanitize_ollama_provider($settings['ollama_provider'] ?? $defaults['ollama_provider']);

    $localModel = sanitize_ollama_model($settings['ollama_model'] ?? $defaults['ollama_model']);
    $runpodModel = sanitize_runpod_model($settings['runpod_model'] ?? $defaults['runpod_model']);
    // If no Runpod-specific model is configured, fall back to the local
    // Ollama model. Pre-split installs stored a single model shared
    // across both providers; preserving that fallback avoids breaking
    // existing deployments.
    if ($runpodModel === '') {
        $runpodModel = $localModel;
    }

    $localTimeout = max(1, (int) sanitize_ollama_timeout($settings['ollama_timeout'] ?? $defaults['ollama_timeout']));
    $runpodTimeout = (int) sanitize_provider_timeout($settings['runpod_timeout'] ?? $defaults['runpod_timeout'], 120, 900);
    $claudeTimeout = (int) sanitize_provider_timeout($settings['claude_timeout'] ?? $defaults['claude_timeout'], 60, 600);
    $groqTimeout = (int) sanitize_provider_timeout($settings['groq_timeout'] ?? $defaults['groq_timeout'], 30, 300);

    // `timeout` and `model` resolve to the *active* provider's values
    // so existing callers that read $config['timeout'] / $config['model']
    // keep working without branching on provider everywhere.
    $activeTimeout = match ($provider) {
        'runpod' => $runpodTimeout,
        'claude' => $claudeTimeout,
        'groq' => $groqTimeout,
        default => $localTimeout,
    };
    $activeModel = match ($provider) {
        'runpod' => $runpodModel,
        'claude' => trim((string) ($settings['claude_model'] ?? $defaults['claude_model'])),
        'groq' => trim((string) ($settings['groq_model'] ?? $defaults['groq_model'])),
        default => $localModel,
    };

    // Per-provider capability tier overrides. Each provider can have its
    // own tier pinned so a tiny local model ('small') doesn't drag down
    // the prompt strategy when the operator also runs a large Runpod
    // model. 'auto' infers from the provider's model name.
    $localCapTier = sanitize_ollama_capability_tier($settings['ollama_capability_tier'] ?? $defaults['ollama_capability_tier']);
    $runpodCapTier = sanitize_ollama_capability_tier($settings['runpod_capability_tier'] ?? $defaults['runpod_capability_tier']);
    $claudeCapTier = sanitize_ollama_capability_tier($settings['claude_capability_tier'] ?? $defaults['claude_capability_tier']);
    $groqCapTier = sanitize_ollama_capability_tier($settings['groq_capability_tier'] ?? $defaults['groq_capability_tier']);

    $activeCapTier = match ($provider) {
        'runpod' => $runpodCapTier,
        'claude' => $claudeCapTier,
        'groq' => $groqCapTier,
        default => $localCapTier,
    };

    $config = [
        'enabled' => (($settings['ollama_enabled'] ?? $defaults['ollama_enabled']) === '1'),
        'provider' => $provider,
        'url' => sanitize_ollama_url($settings['ollama_url'] ?? $defaults['ollama_url']),
        'model' => $activeModel,
        'timeout' => $activeTimeout,
        'capability_override' => $activeCapTier,

        // Per-provider resolved values. Callers targeting a specific
        // provider should read these rather than the active 'model' /
        // 'timeout' fields so they always see the right setting even
        // when the global provider is different.
        'local_ollama_model' => $localModel,
        'local_ollama_timeout' => $localTimeout,
        'local_ollama_capability_tier' => $localCapTier,
        'runpod_url' => sanitize_ollama_runpod_url($settings['ollama_runpod_url'] ?? $defaults['ollama_runpod_url']),
        'runpod_api_key' => sanitize_ollama_runpod_api_key($settings['ollama_runpod_api_key'] ?? $defaults['ollama_runpod_api_key']),
        'runpod_model' => $runpodModel,
        'runpod_timeout' => $runpodTimeout,
        'runpod_capability_tier' => $runpodCapTier,
        'claude_api_key' => trim((string) ($settings['claude_api_key'] ?? $defaults['claude_api_key'])),
        'claude_model' => trim((string) ($settings['claude_model'] ?? $defaults['claude_model'])),
        'claude_timeout' => $claudeTimeout,
        'claude_capability_tier' => $claudeCapTier,
        'groq_api_key' => trim((string) ($settings['groq_api_key'] ?? $defaults['groq_api_key'])),
        'groq_model' => trim((string) ($settings['groq_model'] ?? $defaults['groq_model'])),
        'groq_timeout' => $groqTimeout,
        'groq_capability_tier' => $groqCapTier,
    ];

    $inferredTier = supplycore_ai_infer_model_capability_tier((string) ($config['model'] ?? ''));
    $effectiveTier = ($activeCapTier !== 'auto')
        ? $activeCapTier
        : $inferredTier;
    $strategy = supplycore_ai_capability_strategy($effectiveTier);

    return [
        'enabled' => (bool) ($config['enabled'] ?? false),
        'provider' => (string) ($config['provider'] ?? $defaults['ollama_provider']),
        'url' => (string) ($config['url'] ?? $defaults['ollama_url']),
        'model' => (string) ($config['model'] ?? $defaults['ollama_model']),
        'timeout' => max(1, (int) ($config['timeout'] ?? (int) $defaults['ollama_timeout'])),
        'capability_override' => (string) ($activeCapTier),
        'local_ollama_model' => (string) ($config['local_ollama_model'] ?? $defaults['ollama_model']),
        'local_ollama_timeout' => max(1, (int) ($config['local_ollama_timeout'] ?? (int) $defaults['ollama_timeout'])),
        'local_ollama_capability_tier' => (string) ($config['local_ollama_capability_tier'] ?? 'auto'),
        'runpod_url' => (string) ($config['runpod_url'] ?? ''),
        'runpod_api_key' => (string) ($config['runpod_api_key'] ?? ''),
        'runpod_api_key_masked' => supplycore_mask_secret((string) ($config['runpod_api_key'] ?? '')),
        'runpod_model' => (string) ($config['runpod_model'] ?? ''),
        'runpod_timeout' => max(1, (int) ($config['runpod_timeout'] ?? (int) $defaults['runpod_timeout'])),
        'runpod_capability_tier' => (string) ($config['runpod_capability_tier'] ?? 'auto'),
        'claude_api_key' => (string) ($config['claude_api_key'] ?? ''),
        'claude_api_key_masked' => supplycore_mask_secret((string) ($config['claude_api_key'] ?? '')),
        'claude_model' => (string) ($config['claude_model'] ?? 'claude-sonnet-4-20250514'),
        'claude_timeout' => max(1, (int) ($config['claude_timeout'] ?? (int) $defaults['claude_timeout'])),
        'claude_capability_tier' => (string) ($config['claude_capability_tier'] ?? 'large'),
        'groq_api_key' => (string) ($config['groq_api_key'] ?? ''),
        'groq_api_key_masked' => supplycore_mask_secret((string) ($config['groq_api_key'] ?? '')),
        'groq_model' => (string) ($config['groq_model'] ?? 'meta-llama/llama-4-scout-17b-16e-instruct'),
        'groq_timeout' => max(1, (int) ($config['groq_timeout'] ?? (int) $defaults['groq_timeout'])),
        'groq_capability_tier' => (string) ($config['groq_capability_tier'] ?? 'auto'),
        'inferred_tier' => $inferredTier,
        'capability_tier' => $effectiveTier,
        'strategy' => $strategy,
    ];
}

/**
 * Build the Ollama /generate 'options' object sized to the active model
 * and capability tier. Centralises temperature, num_predict and num_ctx
 * so the theater and opposition call sites don't drift apart, and so
 * large-context models (e.g. Gemma 4 26B A4B with a 256K window) get a
 * context allocation that actually lets their quality show.
 *
 * Passing $overrides lets individual callers bump creativity / output
 * length for their specific prompt (e.g. long AAR summaries).
 *
 * NOTE: num_ctx is also the KV-cache size on the Ollama daemon side, so
 * we deliberately DON'T max out model capability — 32K on a 26B model
 * already costs several GB of VRAM. Operators on beefier hardware can
 * pin the tier to 'large' to get the bigger context.
 */
function supplycore_ai_ollama_request_options(array $config, array $overrides = []): array
{
    $tier = (string) ($config['capability_tier'] ?? 'small');

    // Per-tier defaults:
    //   small  — tiny models (qwen 1.5B, gemma e4b): compact prompts
    //   medium — 7-8B dense models: room for one long section
    //   large  — 13B+ dense, or MoE like gemma4:26b-a4b: deep briefings
    $defaults = match ($tier) {
        'large' => [
            'temperature' => 0.2,
            'num_predict' => 6144,
            'num_ctx' => 32768,
        ],
        'medium' => [
            'temperature' => 0.2,
            'num_predict' => 4096,
            'num_ctx' => 16384,
        ],
        default => [
            'temperature' => 0.2,
            'num_predict' => 2048,
            'num_ctx' => 8192,
        ],
    };

    // Allow the configured timeout to pull num_ctx down — tiny request
    // timeouts on weak hardware shouldn't be promised a 32K context
    // they can't serve inside the window.
    $timeoutSeconds = (int) ($config['timeout'] ?? ($config['local_ollama_timeout'] ?? 20));
    if ($timeoutSeconds > 0 && $timeoutSeconds < 30 && $defaults['num_ctx'] > 8192) {
        $defaults['num_ctx'] = 8192;
    }

    return $overrides + $defaults;
}

function supplycore_mask_secret(string $value): string
{
    $trimmed = trim($value);
    if ($trimmed === '') {
        return '';
    }

    $length = mb_strlen($trimmed);
    if ($length <= 8) {
        return str_repeat('•', $length);
    }

    return mb_substr($trimmed, 0, 4) . str_repeat('•', max(4, $length - 8)) . mb_substr($trimmed, -4);
}

function supplycore_ai_infer_model_capacity_billions(string $model): ?float
{
    $normalized = mb_strtolower(trim($model));
    if ($normalized === '') {
        return null;
    }

    if (preg_match('/(?:^|[:\-_ ])(\d+(?:\.\d+)?)\s*b(?:[^a-z0-9]|$)/i', $normalized, $matches) === 1) {
        return max(0.0, (float) $matches[1]);
    }

    if (preg_match('/(\d+(?:\.\d+)?)\s*b\b/i', $normalized, $matches) === 1) {
        return max(0.0, (float) $matches[1]);
    }

    return null;
}

function supplycore_ai_infer_model_capability_tier(string $model): string
{
    $billions = supplycore_ai_infer_model_capacity_billions($model);
    if ($billions !== null) {
        if ($billions < 3.0) {
            return 'small';
        }

        if ($billions <= 8.0) {
            return 'medium';
        }

        return 'large';
    }

    $normalized = mb_strtolower(trim($model));
    if ($normalized === '') {
        return 'small';
    }

    if (str_contains($normalized, '1.5b') || str_contains($normalized, '2b')) {
        return 'small';
    }

    if (str_contains($normalized, '3b') || str_contains($normalized, '7b') || str_contains($normalized, '8b')) {
        return 'medium';
    }

    return 'medium';
}

function supplycore_ai_capability_strategy(string $tier): array
{
    $normalizedTier = in_array($tier, ['small', 'medium', 'large'], true) ? $tier : 'small';

    $base = [
        'tier' => $normalizedTier,
        'background_only' => true,
        'strict_json' => true,
        'authoritative_source' => 'deterministic',
        'candidate_limit' => 5,
        'dashboard_limit' => 3,
        'history_limit' => 0,
        'group_history_fit_limit' => 0,
        'prompt_style' => 'compact',
        'prompt_max_chars' => 1600,
        'summary_max_chars' => 240,
        'action_max_chars' => 220,
        'explanation_max_chars' => 0,
        'operator_briefing_max_chars' => 0,
        'trend_max_chars' => 0,
        'task_labels' => [
            'fit' => 'doctrine fit briefing',
            'group' => 'doctrine group briefing',
        ],
        'enabled_tasks' => [
            'fit_briefing',
            'group_briefing',
            'dashboard_critical_note',
        ],
        'include_previous_recommendation' => false,
        'include_snapshot_delta' => false,
        'include_cross_signal_reasoning' => false,
        'include_historical_context' => false,
        'include_operator_briefing' => false,
        'include_trend_interpretation' => false,
        'forecast_language' => 'avoid',
    ];

    return match ($normalizedTier) {
        'medium' => $base + [
            'candidate_limit' => 12,
            'dashboard_limit' => 6,
            'history_limit' => 2,
            'group_history_fit_limit' => 2,
            'prompt_style' => 'balanced',
            'prompt_max_chars' => 3200,
            'summary_max_chars' => 420,
            'action_max_chars' => 320,
            'explanation_max_chars' => 260,
            'enabled_tasks' => [
                'fit_briefing',
                'group_briefing',
                'dashboard_critical_note',
                'recommendation_change_explanation',
                'doctrine_pressure_summary',
                'prioritized_restock_note',
            ],
            'include_previous_recommendation' => true,
            'include_snapshot_delta' => true,
            'include_cross_signal_reasoning' => true,
            'forecast_language' => 'minimal',
        ],
        'large' => $base + [
            'candidate_limit' => 20,
            'dashboard_limit' => 8,
            'history_limit' => 4,
            'group_history_fit_limit' => 3,
            'prompt_style' => 'rich',
            'prompt_max_chars' => 5200,
            'summary_max_chars' => 600,
            'action_max_chars' => 420,
            'explanation_max_chars' => 360,
            'operator_briefing_max_chars' => 360,
            'trend_max_chars' => 320,
            'enabled_tasks' => [
                'fit_briefing',
                'group_briefing',
                'dashboard_critical_note',
                'recommendation_change_explanation',
                'doctrine_pressure_summary',
                'prioritized_restock_note',
                'top_doctrine_risk_briefing',
                'market_doctrine_synthesis',
                'operator_guidance',
                'limited_forecast_commentary',
            ],
            'include_previous_recommendation' => true,
            'include_snapshot_delta' => true,
            'include_cross_signal_reasoning' => true,
            'include_historical_context' => true,
            'include_operator_briefing' => true,
            'include_trend_interpretation' => true,
            'forecast_language' => 'bounded',
        ],
        default => $base,
    };
}

function supplycore_ai_strategy(): array
{
    $config = supplycore_ai_ollama_config();

    return is_array($config['strategy'] ?? null)
        ? $config['strategy']
        : supplycore_ai_capability_strategy((string) ($config['capability_tier'] ?? 'small'));
}

function supplycore_ai_ollama_enabled(): bool
{
    $config = supplycore_ai_ollama_config();

    if ($config['enabled'] !== true) {
        return false;
    }

    $provider = (string) ($config['provider'] ?? 'local');

    return match ($provider) {
        'claude' => ($config['claude_api_key'] ?? '') !== '',
        'groq' => ($config['groq_api_key'] ?? '') !== '',
        'runpod' => ($config['runpod_url'] ?? '') !== '' && ($config['runpod_api_key'] ?? '') !== '',
        default => ($config['url'] ?? '') !== '' && ($config['model'] ?? '') !== '',
    };
}

/**
 * Test the current AI provider connection with a minimal request.
 */
function supplycore_ai_test_connection(): array
{
    $config = supplycore_ai_ollama_config();
    $provider = (string) ($config['provider'] ?? 'local');

    $systemPrompt = 'You are a test assistant. Return valid JSON only.';
    $userPrompt = 'Respond with: {"status":"ok","provider":"' . $provider . '"}';
    $schema = [
        'type' => 'object',
        'required' => ['status', 'provider'],
        'properties' => [
            'status' => ['type' => 'string'],
            'provider' => ['type' => 'string'],
        ],
    ];

    try {
        $startTime = microtime(true);
        if ($provider === 'claude') {
            $decoded = supplycore_ai_claude_generate_json($config, $systemPrompt, $userPrompt, $schema);
            $model = (string) ($config['claude_model'] ?? '');
        } elseif ($provider === 'groq') {
            $decoded = supplycore_ai_groq_generate_json($config, $systemPrompt, $userPrompt, $schema);
            $model = (string) ($config['groq_model'] ?? '');
        } elseif ($provider === 'runpod') {
            // Fast-path: go through /runsync with a trivial payload and a
            // 10-second cap. The settings test must never block on an
            // async RunPod cold start — that's what the ai_jobs worker
            // is for. This check only verifies reachability + auth.
            $probe = supplycore_ai_runpod_probe($config);
            if (!($probe['success'] ?? false)) {
                return [
                    'success' => false,
                    'error' => (string) ($probe['error'] ?? 'Runpod probe failed'),
                    'provider' => $provider,
                ];
            }
            return [
                'success' => true,
                'provider' => $provider,
                'model' => (string) ($config['model'] ?? ''),
                'response' => 'Runpod endpoint reachable (status: ' . (string) ($probe['job_status'] ?? 'OK') . ').',
                'elapsed_ms' => (int) ($probe['elapsed_ms'] ?? 0),
            ];
        } else {
            $response = http_get_json(
                rtrim((string) $config['url'], '/') . '/tags',
                [],
                min(10, max(1, (int) ($config['timeout'] ?? 10)))
            );
            $status = (int) ($response['status'] ?? 0);
            if ($status < 200 || $status >= 300) {
                return ['success' => false, 'error' => 'Ollama returned HTTP ' . $status, 'provider' => $provider];
            }
            $models = $response['json']['models'] ?? [];
            $modelNames = array_map(fn($m) => $m['name'] ?? '', $models);
            $elapsed = round((microtime(true) - $startTime) * 1000);
            return [
                'success' => true,
                'provider' => $provider,
                'model' => (string) ($config['model'] ?? ''),
                'response' => 'Connected. Available models: ' . (implode(', ', $modelNames) ?: 'none'),
                'elapsed_ms' => $elapsed,
            ];
        }

        $elapsed = round((microtime(true) - $startTime) * 1000);
        return [
            'success' => true,
            'provider' => $provider,
            'model' => $model,
            'response' => json_encode($decoded, JSON_UNESCAPED_SLASHES),
            'elapsed_ms' => $elapsed,
        ];
    } catch (Throwable $e) {
        return ['success' => false, 'error' => $e->getMessage(), 'provider' => $provider];
    }
}

function supplycore_ai_ollama_available(): bool
{
    static $availability = [];

    $config = supplycore_ai_ollama_config();
    if (!supplycore_ai_ollama_enabled()) {
        return false;
    }

    $cacheKey = implode('|', [
        (string) ($config['provider'] ?? 'local'),
        (string) ($config['url'] ?? ''),
        (string) ($config['runpod_url'] ?? ''),
        (string) ($config['model'] ?? ''),
        (string) ($config['timeout'] ?? 20),
    ]);
    if (array_key_exists($cacheKey, $availability)) {
        return $availability[$cacheKey];
    }

    if (($config['provider'] ?? 'local') === 'runpod') {
        $availability[$cacheKey] = ($config['runpod_url'] ?? '') !== '' && ($config['runpod_api_key'] ?? '') !== '';

        return $availability[$cacheKey];
    }

    $endpoint = rtrim((string) ($config['url'] ?? ''), '/') . '/tags';

    try {
        $response = http_get_json($endpoint, [], max(1, (int) ($config['timeout'] ?? 20)));
        $status = (int) ($response['status'] ?? 0);
        $json = is_array($response['json'] ?? null) ? $response['json'] : [];
        $availability[$cacheKey] = $status >= 200 && $status < 300 && is_array($json['models'] ?? null);
    } catch (Throwable) {
        $availability[$cacheKey] = false;
    }

    return $availability[$cacheKey];
}

function supplycore_ai_status_summary(): array
{
    $config = supplycore_ai_ollama_config();
    $provider = (string) ($config['provider'] ?? 'local');
    $available = supplycore_ai_ollama_available();

    if ($provider === 'runpod') {
        return [
            'ok' => $available,
            'label' => $available ? 'Runpod configured' : 'Runpod incomplete',
            'description' => $available
                ? 'Runpod serverless endpoint and API key are saved for AI briefing requests.'
                : 'Save both the Runpod endpoint and API key to enable serverless AI briefings.',
        ];
    }

    return [
        'ok' => $available,
        'label' => $available ? 'Ollama reachable' : 'Ollama not reachable',
        'description' => 'Status is checked against the configured local Ollama API endpoint.',
    ];
}

function supplycore_ai_log(string $event, array $payload = []): void
{
    try {
        error_log('[supplycore.ai] ' . json_encode([
            'event' => $event,
            'ts' => gmdate(DATE_ATOM),
        ] + $payload, JSON_THROW_ON_ERROR | JSON_UNESCAPED_SLASHES));
    } catch (Throwable) {
        error_log('[supplycore.ai] ' . $event);
    }
}

function supplycore_ai_priority_rank(string $priority): int
{
    return match ($priority) {
        'critical' => 4,
        'high' => 3,
        'medium' => 2,
        default => 1,
    };
}

function supplycore_ai_priority_tone(string $priority): string
{
    return match ($priority) {
        'critical' => 'border-rose-400/20 bg-rose-500/10 text-rose-200',
        'high' => 'border-amber-400/20 bg-amber-500/10 text-amber-100',
        'medium' => 'border-sky-400/20 bg-sky-500/10 text-sky-100',
        default => 'border-emerald-400/20 bg-emerald-500/10 text-emerald-100',
    };
}

function supplycore_ai_ollama_generate_json(array $sourcePayload): array
{
    // Doctrine AI briefings are retired — no prompts to generate.
    throw new RuntimeException('Doctrine AI briefings have been retired.');
}

function supplycore_ai_runpod_generate_json(array $config, string $systemPrompt, string $userPrompt, array $schema): array
{
    $headers = ['Authorization: Bearer ' . (string) ($config['runpod_api_key'] ?? '')];

    // Resolve the model that should actually run on the RunPod worker.
    $runpodModel = (string) ($config['runpod_model'] ?? '');
    if ($runpodModel === '') {
        $runpodModel = (string) ($config['model'] ?? '');
    }

    $schemaJson = json_encode($schema, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
    if (!is_string($schemaJson)) {
        $schemaJson = '{}';
    }

    // Build an OpenAI-compatible messages payload. Most RunPod Ollama
    // workers route messages-style input through their OpenAI engine
    // which forwards to Ollama's /v1/chat/completions — including the
    // model name. Raw prompt-only payloads often lose the model field
    // because the legacy OllamaEngine path may not forward it.
    $schemaInstruction = "Return valid JSON only. Do not include markdown fences or any commentary outside the JSON object.\n"
        . "The JSON object must match this schema exactly:\n" . $schemaJson;

    $requestPayload = [
        'input' => [
            // OpenAI chat-completions format — picked up by the worker's
            // OllamaOpenAiEngine and forwarded with the model to
            // POST localhost:11434/v1/chat/completions
            'model' => $runpodModel,
            'messages' => [
                ['role' => 'system', 'content' => $systemPrompt . "\n\n" . $schemaInstruction],
                ['role' => 'user', 'content' => $userPrompt],
            ],
            'temperature' => 0.2,
            'max_tokens' => 6144,
            // Also include the flat prompt as a fallback for workers
            // that only support the legacy OllamaEngine format.
            'prompt' => supplycore_ai_runpod_prompt($config, $systemPrompt, $userPrompt, $schema),
        ],
    ];

    error_log('[runpod-submit] model=' . $runpodModel . ' url=' . supplycore_ai_runpod_submit_url((string) ($config['runpod_url'] ?? '')));

    $response = http_post_json(
        supplycore_ai_runpod_submit_url((string) ($config['runpod_url'] ?? '')),
        $headers,
        $requestPayload,
        supplycore_ai_runpod_request_timeout($config)
    );
    $polledResponse = supplycore_ai_runpod_poll_until_complete($config, $headers, $response);

    return supplycore_ai_decode_runpod_response($polledResponse);
}

function supplycore_ai_runpod_prompt(array $config, string $systemPrompt, string $userPrompt, array $schema): string
{
    $schemaJson = json_encode($schema, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
    if (!is_string($schemaJson)) {
        $schemaJson = '{}';
    }

    // Prefer the Runpod-specific model if one is configured, otherwise
    // fall back to the active/local model name. Pre-split installs only
    // had a single shared field.
    $model = (string) ($config['runpod_model'] ?? '');
    if ($model === '') {
        $model = (string) ($config['model'] ?? '');
    }

    return trim(implode("\n\n", [
        'You are using the model "' . $model . '" through a Runpod serverless endpoint.',
        'SYSTEM INSTRUCTIONS',
        $systemPrompt,
        'USER REQUEST',
        $userPrompt,
        'OUTPUT REQUIREMENTS',
        'Return JSON only. Do not include markdown fences or any commentary outside the JSON object.',
        'The JSON object must match this schema exactly:',
        $schemaJson,
    ]));
}

function supplycore_ai_runpod_submit_url(string $url): string
{
    $normalized = rtrim(trim($url), '/');
    if ($normalized === '') {
        return '';
    }

    if (preg_match('#/runsync$#i', $normalized) === 1) {
        return (string) preg_replace('#/runsync$#i', '/run', $normalized);
    }

    return $normalized;
}

function supplycore_ai_runpod_status_url(string $url, string $jobId): string
{
    $normalized = rtrim(trim($url), '/');
    if ($normalized === '') {
        throw new RuntimeException('Runpod endpoint is not configured.');
    }

    if (preg_match('#/(?:run|runsync)$#i', $normalized) === 1) {
        return (string) preg_replace('#/(?:run|runsync)$#i', '/status/' . rawurlencode($jobId), $normalized);
    }

    return $normalized . '/status/' . rawurlencode($jobId);
}

function supplycore_ai_runpod_request_timeout(array $config): int
{
    // Prefer the Runpod-specific per-HTTP-call timeout if configured.
    // Fall back to the active/local 'timeout' for pre-split installs.
    $configuredTimeout = max(1, (int) ($config['runpod_timeout'] ?? $config['timeout'] ?? 20));

    // Per-HTTP cap — individual /run and /status calls should be quick;
    // this is NOT the total polling budget.
    return min(30, $configuredTimeout);
}

function supplycore_ai_runpod_poll_budget_seconds(array $config): int
{
    // Allow callers (primarily the ai_jobs CLI worker) to pin the polling
    // budget explicitly — the worker sizes this against its own lease
    // rather than inheriting the user-facing Ollama timeout.
    if (isset($config['runpod_poll_budget_seconds'])) {
        return max(30, (int) $config['runpod_poll_budget_seconds']);
    }

    // Prefer the Runpod-specific timeout if configured. Pre-split
    // installs fall back to the active 'timeout' field.
    $configuredTimeout = max(1, (int) ($config['runpod_timeout'] ?? $config['timeout'] ?? 20));

    // Floor of 2 minutes as a safety net when called outside the worker
    // (e.g. from bin/ai_briefing_worker.php --once debugging).
    return max(120, $configuredTimeout * 6);
}

function supplycore_ai_runpod_poll_until_complete(array $config, array $headers, array $response): array
{
    $status = (int) ($response['status'] ?? 0);
    $json = is_array($response['json'] ?? null) ? $response['json'] : [];
    if ($status < 200 || $status >= 300) {
        throw new RuntimeException('Runpod returned HTTP ' . $status . '.');
    }

    $jobStatus = supplycore_ai_runpod_job_status($json);
    if (in_array($jobStatus, ['COMPLETED', 'SUCCESS'], true)) {
        return $response;
    }

    if ($jobStatus === '' && supplycore_ai_runpod_response_has_output($json)) {
        return $response;
    }

    if (in_array($jobStatus, ['FAILED', 'CANCELLED', 'TIMED_OUT'], true)) {
        throw new RuntimeException('Runpod job failed with status: ' . $jobStatus . '.');
    }

    $jobId = trim((string) ($json['id'] ?? $json['job_id'] ?? ''));
    if ($jobId === '') {
        throw new RuntimeException('Runpod did not return a job ID for async polling.');
    }

    $deadline = microtime(true) + supplycore_ai_runpod_poll_budget_seconds($config);
    $pollDelayMicroseconds = 750000;
    $maxPollDelayMicroseconds = 5000000;
    $statusUrl = supplycore_ai_runpod_status_url((string) ($config['runpod_url'] ?? ''), $jobId);
    $lastKnownStatus = $jobStatus !== '' ? $jobStatus : 'SUBMITTED';

    while (microtime(true) < $deadline) {
        usleep($pollDelayMicroseconds);
        $pollDelayMicroseconds = (int) min($maxPollDelayMicroseconds, (int) round($pollDelayMicroseconds * 1.25));

        $statusResponse = http_get_json($statusUrl, $headers, supplycore_ai_runpod_request_timeout($config));
        $statusCode = (int) ($statusResponse['status'] ?? 0);
        $statusJson = is_array($statusResponse['json'] ?? null) ? $statusResponse['json'] : [];
        if ($statusCode < 200 || $statusCode >= 300) {
            throw new RuntimeException('Runpod status returned HTTP ' . $statusCode . '.');
        }

        $lastKnownStatus = supplycore_ai_runpod_job_status($statusJson);
        if (in_array($lastKnownStatus, ['COMPLETED', 'SUCCESS'], true)) {
            return $statusResponse;
        }

        if ($lastKnownStatus === '' && supplycore_ai_runpod_response_has_output($statusJson)) {
            return $statusResponse;
        }

        if (in_array($lastKnownStatus, ['FAILED', 'CANCELLED', 'TIMED_OUT'], true)) {
            throw new RuntimeException('Runpod job failed with status: ' . $lastKnownStatus . '.');
        }
    }

    throw new RuntimeException('Runpod job did not finish before timeout (last status: ' . $lastKnownStatus . ').');
}

function supplycore_ai_runpod_job_status(array $payload): string
{
    return strtoupper(trim((string) ($payload['status'] ?? '')));
}

function supplycore_ai_runpod_response_has_output(array $payload): bool
{
    return array_key_exists('output', $payload) || array_key_exists('response', $payload);
}

function supplycore_ai_decode_runpod_response(array $response): array
{
    $status = (int) ($response['status'] ?? 0);
    $json = is_array($response['json'] ?? null) ? $response['json'] : [];
    if ($status < 200 || $status >= 300) {
        throw new RuntimeException('Runpod returned HTTP ' . $status . '.');
    }

    $jobStatus = supplycore_ai_runpod_job_status($json);
    if ($jobStatus !== '' && !in_array($jobStatus, ['COMPLETED', 'SUCCESS'], true)) {
        throw new RuntimeException('Runpod job did not complete synchronously (status: ' . $jobStatus . ').');
    }

    $candidates = [
        // OpenAI chat completions format (from OllamaOpenAiEngine):
        //   {"output": {"choices": [{"message": {"content": "..."}}]}}
        $json['output']['choices'][0]['message']['content'] ?? null,
        $json['output']['choices'][0]['text'] ?? null,
        // Legacy Ollama /api/generate format (from OllamaEngine):
        //   {"output": {"response": "..."}} or {"output": {"text": "..."}}
        $json['output']['response'] ?? null,
        $json['output']['text'] ?? null,
        $json['output'][0]['response'] ?? null,
        $json['output'][0]['text'] ?? null,
        // Top-level fallbacks
        $json['response'] ?? null,
        $json['output'] ?? null,
    ];

    foreach ($candidates as $candidate) {
        if (is_array($candidate)) {
            if ($candidate !== [] && array_keys($candidate) !== range(0, count($candidate) - 1)) {
                return $candidate;
            }

            $candidate = json_encode($candidate, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
        }

        $decoded = supplycore_ai_decode_json_string((string) $candidate);
        if (is_array($decoded)) {
            return $decoded;
        }
    }

    // Dump the raw payload so operators can diagnose what the worker
    // actually returned (wrong model, markdown-wrapped JSON, empty
    // output, unexpected structure, etc.).
    $rawDump = json_encode($json, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
    error_log('[runpod-decode] Unsupported response payload: ' . mb_substr((string) $rawDump, 0, 4000));

    throw new RuntimeException('Runpod returned an unsupported response payload. Check journalctl for raw output.');
}

function supplycore_ai_decode_json_string(string $value): ?array
{
    $trimmed = trim($value);
    if ($trimmed === '') {
        return null;
    }

    $decoded = json_decode($trimmed, true);
    if (is_array($decoded)) {
        return $decoded;
    }

    if (preg_match('/\{.*\}/s', $trimmed, $matches) === 1) {
        $decoded = json_decode((string) $matches[0], true);
        if (is_array($decoded)) {
            return $decoded;
        }
    }

    return null;
}

// ---------------------------------------------------------------------------
// AI job queue (ai_jobs table) + per-feature provider resolution
// ---------------------------------------------------------------------------
//
// The web tier enqueues a row into ai_jobs and returns immediately; the CLI
// worker (bin/ai_briefing_worker.php, managed by systemd) drains the queue,
// runs the actual AI call (which may take minutes for a RunPod cold start),
// and writes the result back. This keeps php-fpm, nginx, and the browser
// out of the long-running job's critical path.

/**
 * Resolve the AI config that should be used for a specific feature.
 *
 * Per-feature provider overrides let operators pick different providers
 * per use case (e.g. cheap local Ollama for theater summaries, RunPod for
 * opposition briefings). If the feature's override is 'default' or not
 * recognised, falls back to the global provider.
 */
function supplycore_ai_resolve_feature_config(string $feature, ?string $explicitProvider = null): array
{
    $config = supplycore_ai_ollama_config();

    if ($explicitProvider !== null && $explicitProvider !== '') {
        $provider = sanitize_ollama_provider($explicitProvider);
    } else {
        $settingKey = 'ai_provider_' . $feature;
        $featureOverride = sanitize_ai_feature_provider(
            get_setting($settingKey, 'default')
        );
        $provider = $featureOverride === 'default'
            ? (string) ($config['provider'] ?? 'local')
            : $featureOverride;
    }

    $config['provider'] = $provider;

    // Re-point the active 'model' and 'timeout' at the chosen provider's
    // fields so generic callers that read $config['timeout'] / ['model']
    // see the right value for this feature. The per-provider fields
    // (runpod_model, claude_timeout, …) still carry the full picture for
    // providers that need them.
    $runpodModel = (string) ($config['runpod_model'] ?? '');
    if ($runpodModel === '') {
        $runpodModel = (string) ($config['local_ollama_model'] ?? $config['model'] ?? '');
    }
    $config['model'] = match ($provider) {
        'runpod' => $runpodModel,
        'claude' => (string) ($config['claude_model'] ?? ''),
        'groq' => (string) ($config['groq_model'] ?? ''),
        default => (string) ($config['local_ollama_model'] ?? $config['model'] ?? ''),
    };
    $config['timeout'] = max(1, (int) match ($provider) {
        'runpod' => (int) ($config['runpod_timeout'] ?? $config['timeout'] ?? 120),
        'claude' => (int) ($config['claude_timeout'] ?? $config['timeout'] ?? 60),
        'groq' => (int) ($config['groq_timeout'] ?? $config['timeout'] ?? 30),
        default => (int) ($config['local_ollama_timeout'] ?? $config['timeout'] ?? 20),
    });

    // Re-compute the capability tier against the now-resolved provider's
    // model and tier override so features running on a different provider
    // (e.g. local defaults to a small qwen but a feature routes to
    // Runpod gemma4:26b-a4b) get the tier/strategy that actually matches.
    $providerCapTier = match ($provider) {
        'runpod' => (string) ($config['runpod_capability_tier'] ?? 'auto'),
        'claude' => (string) ($config['claude_capability_tier'] ?? 'large'),
        'groq' => (string) ($config['groq_capability_tier'] ?? 'auto'),
        default => (string) ($config['local_ollama_capability_tier'] ?? $config['capability_override'] ?? 'auto'),
    };
    $config['capability_override'] = $providerCapTier;
    $inferredTier = supplycore_ai_infer_model_capability_tier((string) ($config['model'] ?? ''));
    $effectiveTier = ($providerCapTier !== 'auto')
        ? $providerCapTier
        : $inferredTier;
    $config['inferred_tier'] = $inferredTier;
    $config['capability_tier'] = $effectiveTier;
    $config['strategy'] = supplycore_ai_capability_strategy($effectiveTier);

    return $config;
}

/**
 * Whether a provider needs the async ai_jobs queue. Only RunPod has
 * multi-minute cold starts that would blow past web request timeouts.
 * Local Ollama, Claude, and Groq respond in seconds and can run
 * inline on the web request thread.
 */
function supplycore_ai_needs_queue(string $feature): bool
{
    $config = supplycore_ai_resolve_feature_config($feature);
    return ((string) ($config['provider'] ?? 'local')) === 'runpod';
}

function supplycore_ai_jobs_feature_valid(string $feature): bool
{
    static $valid = null;
    if ($valid === null) {
        $valid = array_flip(['theater_lock', 'opposition_global', 'opposition_alliance']);
    }
    return isset($valid[$feature]);
}

/**
 * Enqueue an AI job if one isn't already queued/running for the same
 * (feature, target_key). Returns the job id (new or pre-existing).
 */
function supplycore_ai_jobs_enqueue(
    string $feature,
    string $targetKey,
    array $payload,
    ?string $providerOverride = null,
    int $priority = 0
): int {
    if (!supplycore_ai_jobs_feature_valid($feature)) {
        throw new InvalidArgumentException('Unknown AI job feature: ' . $feature);
    }
    if ($targetKey === '') {
        throw new InvalidArgumentException('AI job target_key is required.');
    }

    $config = supplycore_ai_resolve_feature_config($feature, $providerOverride);
    $provider = (string) ($config['provider'] ?? 'local');
    $model = match ($provider) {
        'runpod' => (string) ($config['runpod_model'] ?? $config['model'] ?? ''),
        'claude' => (string) ($config['claude_model'] ?? ''),
        'groq' => (string) ($config['groq_model'] ?? ''),
        default => (string) ($config['model'] ?? ''),
    };

    $payloadJson = json_encode($payload, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
    if ($payloadJson === false) {
        throw new RuntimeException('AI job payload could not be JSON-encoded.');
    }

    return db_transaction(static function () use ($feature, $targetKey, $provider, $model, $payloadJson, $priority): int {
        $existing = db_select_one(
            "SELECT id FROM ai_jobs
             WHERE feature = ? AND target_key = ? AND status IN ('queued','running')
             ORDER BY id DESC LIMIT 1",
            [$feature, $targetKey]
        );
        if (is_array($existing) && isset($existing['id'])) {
            return (int) $existing['id'];
        }

        db_execute(
            'INSERT INTO ai_jobs (feature, target_key, provider, model, status, priority, payload_json)
             VALUES (?, ?, ?, ?, \'queued\', ?, ?)',
            [$feature, $targetKey, $provider, $model, $priority, $payloadJson]
        );

        return (int) db()->lastInsertId();
    });
}

function supplycore_ai_jobs_find_active(string $feature, string $targetKey): ?array
{
    return db_select_one(
        "SELECT * FROM ai_jobs
         WHERE feature = ? AND target_key = ? AND status IN ('queued','running')
         ORDER BY id DESC LIMIT 1",
        [$feature, $targetKey]
    );
}

function supplycore_ai_jobs_find_latest(string $feature, string $targetKey): ?array
{
    return db_select_one(
        'SELECT * FROM ai_jobs
         WHERE feature = ? AND target_key = ?
         ORDER BY id DESC LIMIT 1',
        [$feature, $targetKey]
    );
}

function supplycore_ai_jobs_get(int $id): ?array
{
    return db_select_one('SELECT * FROM ai_jobs WHERE id = ?', [$id]);
}

/**
 * Claim the next queued job. Uses FOR UPDATE SKIP LOCKED (MariaDB >= 10.6)
 * so multiple worker slots never fight over the same row.
 */
function supplycore_ai_jobs_claim(string $workerId, int $leaseSeconds = 900): ?array
{
    db_query_cache_clear();
    $pdo = db();
    $pdo->beginTransaction();
    try {
        $stmt = $pdo->prepare(
            "SELECT id FROM ai_jobs
             WHERE status = 'queued'
             ORDER BY priority DESC, id ASC
             LIMIT 1
             FOR UPDATE SKIP LOCKED"
        );
        $stmt->execute();
        $row = $stmt->fetch(PDO::FETCH_ASSOC);
        if (!is_array($row) || !isset($row['id'])) {
            $pdo->commit();
            return null;
        }
        $id = (int) $row['id'];

        $update = $pdo->prepare(
            "UPDATE ai_jobs
             SET status = 'running',
                 attempts = attempts + 1,
                 worker_id = ?,
                 lease_until = DATE_ADD(NOW(), INTERVAL ? SECOND),
                 started_at = COALESCE(started_at, NOW())
             WHERE id = ?"
        );
        $update->execute([$workerId, max(60, $leaseSeconds), $id]);
        $pdo->commit();
    } catch (Throwable $e) {
        if ($pdo->inTransaction()) {
            $pdo->rollBack();
        }
        throw $e;
    }

    return supplycore_ai_jobs_get($id);
}

function supplycore_ai_jobs_complete(int $id, array $result, int $durationMs): void
{
    $resultJson = json_encode($result, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
    if ($resultJson === false) {
        $resultJson = '{}';
    }
    db_execute(
        "UPDATE ai_jobs
         SET status = 'done',
             result_json = ?,
             duration_ms = ?,
             completed_at = NOW(),
             lease_until = NULL,
             last_error = NULL
         WHERE id = ?",
        [$resultJson, max(0, $durationMs), $id]
    );
}

/**
 * Mark a job as failed. If the job still has retries available and the
 * caller signals the error is transient, it is requeued instead.
 */
function supplycore_ai_jobs_fail(int $id, string $error, bool $transient): void
{
    $job = supplycore_ai_jobs_get($id);
    if ($job === null) {
        return;
    }

    $attempts = (int) ($job['attempts'] ?? 0);
    $maxAttempts = (int) ($job['max_attempts'] ?? 1);
    $shouldRetry = $transient && $attempts < $maxAttempts;

    if ($shouldRetry) {
        db_execute(
            "UPDATE ai_jobs
             SET status = 'queued',
                 worker_id = NULL,
                 lease_until = NULL,
                 last_error = ?
             WHERE id = ?",
            [mb_substr($error, 0, 2000), $id]
        );
        return;
    }

    db_execute(
        "UPDATE ai_jobs
         SET status = 'failed',
             last_error = ?,
             completed_at = NOW(),
             lease_until = NULL
         WHERE id = ?",
        [mb_substr($error, 0, 2000), $id]
    );
}

/**
 * Reclaim rows whose worker lease has expired (crash-safety). Any row in
 * 'running' state with lease_until < NOW() is pushed back to 'queued' if it
 * still has retries, or marked 'failed' otherwise.
 */
function supplycore_ai_jobs_sweep_expired_leases(): int
{
    $rows = db_select(
        "SELECT id, attempts, max_attempts FROM ai_jobs
         WHERE status = 'running' AND lease_until IS NOT NULL AND lease_until < NOW()"
    );
    foreach ($rows as $row) {
        $id = (int) ($row['id'] ?? 0);
        if ($id === 0) {
            continue;
        }
        supplycore_ai_jobs_fail((int) $id, 'Worker lease expired (crash or hang).', true);
    }
    return count($rows);
}

/**
 * Execute a claimed AI job by dispatching to the feature-specific handler.
 * Returns the normalized result payload; throws on failure.
 */
function supplycore_ai_jobs_execute(array $job): array
{
    $feature = (string) ($job['feature'] ?? '');
    $payload = [];
    $payloadJson = (string) ($job['payload_json'] ?? '');
    if ($payloadJson !== '') {
        $decoded = json_decode($payloadJson, true);
        if (is_array($decoded)) {
            $payload = $decoded;
        }
    }
    $providerOverride = (string) ($job['provider'] ?? '');
    // Force the feature config to use the provider captured at enqueue time
    // so later settings changes don't silently re-route in-flight jobs.
    $override = supplycore_ai_resolve_feature_config($feature, $providerOverride);
    // Give RunPod polling a generous budget tied to the worker lease
    // rather than the user-facing Ollama timeout. 14 minutes leaves a
    // small safety margin before a default 15-minute lease expires.
    $override['runpod_poll_budget_seconds'] = 14 * 60;
    $GLOBALS['supplycore_ai_ollama_runtime_override'] = $override;

    try {
        return match ($feature) {
            'theater_lock' => supplycore_ai_jobs_run_theater_lock($payload),
            'opposition_global' => supplycore_ai_jobs_run_opposition_global($payload),
            'opposition_alliance' => supplycore_ai_jobs_run_opposition_alliance($payload),
            default => throw new RuntimeException('Unknown AI job feature: ' . $feature),
        };
    } finally {
        unset($GLOBALS['supplycore_ai_ollama_runtime_override']);
    }
}

function supplycore_ai_jobs_run_theater_lock(array $payload): array
{
    $theaterId = trim((string) ($payload['theater_id'] ?? ''));
    if ($theaterId === '') {
        throw new RuntimeException('theater_lock payload missing theater_id.');
    }
    $result = theater_ai_summary_generate($theaterId, true);
    if ($result === null) {
        throw new RuntimeException('theater_ai_summary_generate returned null for ' . $theaterId);
    }
    return $result;
}

function supplycore_ai_jobs_run_opposition_global(array $payload): array
{
    $date = trim((string) ($payload['date'] ?? ''));
    if ($date === '' || preg_match('/^\d{4}-\d{2}-\d{2}$/', $date) !== 1) {
        throw new RuntimeException('opposition_global payload missing/invalid date.');
    }
    $generated = opposition_ai_generate_daily_briefings($date);
    return ['date' => $date, 'generated' => $generated];
}

function supplycore_ai_jobs_run_opposition_alliance(array $payload): array
{
    // Alliance-level briefings are generated inside
    // opposition_ai_generate_daily_briefings() today. This hook exists so
    // future callers can enqueue per-alliance regenerations without
    // touching the global path.
    return supplycore_ai_jobs_run_opposition_global($payload);
}

/**
 * Fast-path RunPod connectivity probe used by the settings "Test
 * connection" button. Uses /runsync with a trivial payload and a hard
 * 10-second cap so the health check never blocks on an async cold start.
 */
function supplycore_ai_runpod_probe(array $config): array
{
    $url = rtrim(trim((string) ($config['runpod_url'] ?? '')), '/');
    $apiKey = trim((string) ($config['runpod_api_key'] ?? ''));
    if ($url === '' || $apiKey === '') {
        return ['success' => false, 'error' => 'Runpod endpoint or API key not configured.'];
    }

    // Force /runsync regardless of how the user typed the URL. The probe
    // must NOT go through the async /run path.
    $probeUrl = preg_match('#/(?:run|runsync)$#i', $url) === 1
        ? (string) preg_replace('#/(?:run|runsync)$#i', '/runsync', $url)
        : $url . '/runsync';

    $headers = ['Authorization: Bearer ' . $apiKey];
    $payload = ['input' => ['prompt' => 'ping']];

    $startedAt = microtime(true);
    try {
        $response = http_post_json($probeUrl, $headers, $payload, 10);
    } catch (Throwable $e) {
        return ['success' => false, 'error' => 'Runpod probe failed: ' . $e->getMessage()];
    }
    $elapsedMs = (int) round((microtime(true) - $startedAt) * 1000);

    $status = (int) ($response['status'] ?? 0);
    if ($status === 401 || $status === 403) {
        return ['success' => false, 'error' => 'Runpod auth rejected (HTTP ' . $status . '). Check API key.'];
    }
    if ($status === 404) {
        return ['success' => false, 'error' => 'Runpod endpoint not found (HTTP 404). Check endpoint URL.'];
    }
    if ($status < 200 || $status >= 300) {
        return ['success' => false, 'error' => 'Runpod probe HTTP ' . $status . '.'];
    }

    $json = is_array($response['json'] ?? null) ? $response['json'] : [];
    $jobStatus = strtoupper(trim((string) ($json['status'] ?? '')));
    // /runsync returns COMPLETED on fast-path; IN_QUEUE/IN_PROGRESS means
    // the worker is still cold-starting but the endpoint is reachable and
    // auth worked — that's a healthy probe result.
    return [
        'success' => true,
        'elapsed_ms' => $elapsedMs,
        'job_status' => $jobStatus !== '' ? $jobStatus : 'OK',
    ];
}

// ---------------------------------------------------------------------------
// Claude API Provider
// ---------------------------------------------------------------------------

function supplycore_ai_claude_generate_json(array $config, string $systemPrompt, string $userPrompt, array $schema): array
{
    $apiKey = trim((string) ($config['claude_api_key'] ?? ''));
    if ($apiKey === '') {
        throw new RuntimeException('Claude API key is not configured');
    }
    $model = trim((string) ($config['claude_model'] ?? 'claude-sonnet-4-20250514'));

    $schemaJson = json_encode($schema, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);

    $requestPayload = [
        'model' => $model,
        'max_tokens' => 4096,
        'system' => $systemPrompt,
        'messages' => [
            [
                'role' => 'user',
                'content' => $userPrompt . "\n\nReturn JSON only matching this schema:\n" . $schemaJson,
            ],
        ],
    ];

    $response = http_post_json(
        'https://api.anthropic.com/v1/messages',
        [
            'x-api-key: ' . $apiKey,
            'anthropic-version: 2023-06-01',
        ],
        $requestPayload,
        max(30, (int) ($config['claude_timeout'] ?? $config['timeout'] ?? 60))
    );

    $status = (int) ($response['status'] ?? 0);
    $json = is_array($response['json'] ?? null) ? $response['json'] : [];
    if ($status < 200 || $status >= 300) {
        $errorMsg = (string) ($json['error']['message'] ?? 'unknown');
        throw new RuntimeException('Claude API returned HTTP ' . $status . ': ' . $errorMsg);
    }

    $content = $json['content'] ?? [];
    $textBlock = '';
    foreach ($content as $block) {
        if (($block['type'] ?? '') === 'text') {
            $textBlock .= (string) ($block['text'] ?? '');
        }
    }

    $textBlock = trim($textBlock);
    // Strip markdown JSON fences if present
    if (str_starts_with($textBlock, '```')) {
        $textBlock = preg_replace('/^```(?:json)?\s*/i', '', $textBlock);
        $textBlock = preg_replace('/\s*```\s*$/', '', $textBlock);
    }

    $decoded = json_decode($textBlock, true);
    if (!is_array($decoded)) {
        throw new RuntimeException('Claude API returned malformed JSON');
    }

    return $decoded;
}

function supplycore_ai_groq_generate_json(array $config, string $systemPrompt, string $userPrompt, array $schema): array
{
    $apiKey = trim((string) ($config['groq_api_key'] ?? ''));
    if ($apiKey === '') {
        throw new RuntimeException('Groq API key is not configured');
    }
    $model = trim((string) ($config['groq_model'] ?? 'meta-llama/llama-4-scout-17b-16e-instruct'));

    $schemaJson = json_encode($schema, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);

    $requestPayload = [
        'model' => $model,
        'temperature' => 0.2,
        'max_completion_tokens' => 4096,
        'response_format' => ['type' => 'json_object'],
        'messages' => [
            ['role' => 'system', 'content' => $systemPrompt . "\n\nYou MUST return valid JSON matching this schema:\n" . $schemaJson],
            ['role' => 'user', 'content' => $userPrompt],
        ],
    ];

    error_log('[groq-api] Sending request: model=' . $model . ', system_len=' . strlen($requestPayload['messages'][0]['content']) . ', user_len=' . strlen($requestPayload['messages'][1]['content']));

    $response = http_post_json(
        'https://api.groq.com/openai/v1/chat/completions',
        [
            'Authorization: Bearer ' . $apiKey,
        ],
        $requestPayload,
        max(15, (int) ($config['groq_timeout'] ?? $config['timeout'] ?? 30))
    );

    $status = (int) ($response['status'] ?? 0);
    $body = (string) ($response['body'] ?? '');
    $json = is_array($response['json'] ?? null) ? $response['json'] : [];

    error_log('[groq-api] Response: HTTP ' . $status . ', body_len=' . strlen($body));

    if ($status < 200 || $status >= 300) {
        $errorMsg = (string) ($json['error']['message'] ?? $body);
        error_log('[groq-api] Error: ' . $errorMsg);
        throw new RuntimeException('Groq API returned HTTP ' . $status . ': ' . $errorMsg);
    }

    $choices = $json['choices'] ?? [];
    if ($choices === []) {
        error_log('[groq-api] No choices in response: ' . mb_substr($body, 0, 2000));
        throw new RuntimeException('Groq API returned no choices');
    }

    $finishReason = (string) ($choices[0]['finish_reason'] ?? '');
    $rawResponse = trim((string) ($choices[0]['message']['content'] ?? ''));

    error_log('[groq-api] finish_reason=' . $finishReason . ', content_len=' . strlen($rawResponse));

    if ($rawResponse === '') {
        error_log('[groq-api] Empty content. Response: ' . mb_substr($body, 0, 2000));
        throw new RuntimeException('Groq API returned empty response (finish_reason=' . $finishReason . ')');
    }

    // Strip markdown JSON fences if present
    if (str_starts_with($rawResponse, '```')) {
        $rawResponse = preg_replace('/^```(?:json)?\s*/i', '', $rawResponse);
        $rawResponse = preg_replace('/\s*```\s*$/', '', $rawResponse);
    }

    $decoded = json_decode($rawResponse, true);
    if (!is_array($decoded)) {
        throw new RuntimeException('Groq API returned malformed JSON');
    }

    return $decoded;
}

// ---------------------------------------------------------------------------
// Theater Intelligence AI Summary
// ---------------------------------------------------------------------------

function theater_ai_summary_generate(string $theaterId, bool $forceRegenerate = false): ?array
{
    if (!supplycore_ai_ollama_enabled()) {
        return null;
    }

    $theater = db_theater_detail($theaterId);
    if ($theater === null) {
        return null;
    }

    // Skip if already generated, unless force-regenerating
    if (!$forceRegenerate) {
        $existingSummary = $theater['ai_summary'] ?? null;
        if ($existingSummary !== null && trim((string) $existingSummary) !== '') {
            return [
                'headline' => (string) ($theater['ai_headline'] ?? ''),
                'summary' => (string) $existingSummary,
                'verdict' => (string) ($theater['ai_verdict'] ?? ''),
                'model' => (string) ($theater['ai_summary_model'] ?? ''),
                'generated_at' => (string) ($theater['ai_summary_at'] ?? ''),
                'cached' => true,
            ];
        }
    }

    $config = supplycore_ai_ollama_config();
    $facts = theater_ai_build_facts($theaterId, $theater);

    $systemPrompt = theater_ai_system_prompt();
    $userPrompt = theater_ai_user_prompt($facts);
    $schema = theater_ai_output_schema();

    // Concurrency lock: only one AI generation at a time (CPU Ollama is single-threaded)
    $lockFile = sys_get_temp_dir() . '/supplycore_ai_generation.lock';
    $lockFp = fopen($lockFile, 'c');
    if ($lockFp === false) {
        error_log('[theater-ai] Cannot open lock file');
        return null;
    }
    if (!flock($lockFp, LOCK_EX | LOCK_NB)) {
        fclose($lockFp);
        error_log('[theater-ai] Another AI generation is already running, skipping ' . $theaterId);
        return null;
    }

    try {
        $provider = (string) ($config['provider'] ?? 'local');
        if ($provider === 'claude') {
            $decoded = supplycore_ai_claude_generate_json($config, $systemPrompt, $userPrompt, $schema);
        } elseif ($provider === 'groq') {
            $decoded = supplycore_ai_groq_generate_json($config, $systemPrompt, $userPrompt, $schema);
        } elseif ($provider === 'runpod') {
            $decoded = supplycore_ai_runpod_generate_json($config, $systemPrompt, $userPrompt, $schema);
        } else {
            $endpoint = $config['url'] . '/generate';
            $requestPayload = [
                'model' => $config['model'],
                'stream' => false,
                'system' => $systemPrompt,
                'prompt' => $userPrompt,
                'format' => $schema,
                'options' => supplycore_ai_ollama_request_options($config),
            ];
            $response = http_post_json($endpoint, [], $requestPayload, max(300, $config['timeout']));
            $status = (int) ($response['status'] ?? 0);
            $json = is_array($response['json'] ?? null) ? $response['json'] : [];
            if ($status < 200 || $status >= 300) {
                throw new RuntimeException('Ollama returned HTTP ' . $status);
            }
            $rawResponse = trim((string) ($json['response'] ?? ''));
            if ($rawResponse === '') {
                throw new RuntimeException('Ollama returned empty response');
            }
            $decoded = json_decode($rawResponse, true);
            if (!is_array($decoded)) {
                throw new RuntimeException('Ollama returned malformed JSON');
            }
        }

        $headline = mb_substr(trim((string) ($decoded['headline'] ?? '')), 0, 255);
        $summary = mb_substr(trim((string) ($decoded['summary'] ?? '')), 0, 16000);
        $verdict = mb_substr(trim((string) ($decoded['verdict'] ?? '')), 0, 32);

        if ($summary === '') {
            throw new RuntimeException('AI returned empty summary');
        }
        if ($headline === '') {
            $headline = mb_substr($summary, 0, 80);
        }

        $modelLabel = match ($provider) {
            'runpod' => (string) ($config['runpod_model'] ?? $config['model'] ?? ''),
            'claude' => (string) ($config['claude_model'] ?? 'claude-sonnet-4-20250514'),
            'groq' => (string) ($config['groq_model'] ?? 'llama-4-scout'),
            default => (string) $config['model'],
        };
        theater_ai_summary_store($theaterId, $headline, $summary, $verdict, $modelLabel);

        flock($lockFp, LOCK_UN);
        fclose($lockFp);

        return [
            'headline' => $headline,
            'summary' => $summary,
            'verdict' => $verdict,
            'model' => $modelLabel,
            'generated_at' => date('Y-m-d H:i:s'),
            'cached' => false,
        ];
    } catch (Throwable $e) {
        flock($lockFp, LOCK_UN);
        fclose($lockFp);
        $errorMsg = $e->getMessage();
        error_log('[theater-ai] Failed to generate AAR for ' . $theaterId . ': ' . $errorMsg);
        return ['error' => $errorMsg];
    }
}

function theater_ai_build_facts(string $theaterId, array $theater): array
{
    return theater_ai_build_facts_from_snapshot($theaterId, $theater, [
        'alliance_summary' => db_theater_alliance_summary($theaterId),
        'turning_points' => db_theater_turning_points($theaterId),
        'systems' => db_theater_systems($theaterId),
        'fleet_comp' => db_theater_fleet_composition($theaterId),
        'notable_kills' => db_theater_notable_kills($theaterId, 10),
        'top_performers' => db_theater_top_performers($theaterId, 10),
    ]);
}

function theater_ai_build_facts_from_snapshot(string $theaterId, array $theater, array $snapshot): array
{
    $allianceSummary = (array) ($snapshot['alliance_summary'] ?? []);
    $turningPoints = (array) ($snapshot['turning_points'] ?? []);
    $systems = (array) ($snapshot['systems'] ?? []);
    $fleetComp = (array) ($snapshot['fleet_comp'] ?? []);
    $notableKills = (array) ($snapshot['notable_kills'] ?? []);
    $topPerformers = (array) ($snapshot['top_performers'] ?? []);

    // The Python theater analysis already classifies sides as "friendly", "opponent", "third_party"
    // in the theater_alliance_summary, theater_participants, and fleet_composition tables.
    // We use these directly — no need to re-derive from tracked alliance settings.
    $ourSide = 'friendly';
    $enemySide = 'opponent';

    // Build alliance side data — track losses per side (friendly, opponent, third_party)
    $sideData = ['friendly' => [], 'opponent' => []];
    $sidePilotTotals = ['friendly' => 0, 'opponent' => 0];
    $friendlyIskLost = 0.0;
    $enemyIskLost = 0.0;
    $thirdPartyIskLost = 0.0;
    foreach ($allianceSummary as $a) {
        $side = (string) ($a['side'] ?? '');
        $aid = (int) ($a['alliance_id'] ?? 0);
        $participantCount = (int) ($a['participant_count'] ?? 0);
        $iskLost = (float) ($a['total_isk_lost'] ?? 0);

        // Accumulate ISK lost for ALL sides (including third_party)
        if ($side === 'friendly') {
            $friendlyIskLost += $iskLost;
        } elseif ($side === 'opponent') {
            $enemyIskLost += $iskLost;
        } else {
            $thirdPartyIskLost += $iskLost;
        }

        if (!isset($sideData[$side])) continue;
        $sidePilotTotals[$side] += max(0, $participantCount);
        $sideData[$side][] = [
            'alliance' => (string) ($a['alliance_name'] ?? "Alliance #{$aid}"),
            'pilots' => $participantCount,
            'kills' => (int) ($a['total_kills'] ?? 0),
            'losses' => (int) ($a['total_losses'] ?? 0),
            'isk_killed' => round((float) ($a['total_isk_killed'] ?? 0)),
            'isk_lost' => round($iskLost),
            'efficiency' => round((float) ($a['efficiency'] ?? 0) * 100, 1) . '%',
        ];
    }

    // Build fleet composition per side
    $friendlyComp = [];
    $enemyComp = [];
    foreach ($fleetComp as $fc) {
        $shipGroup = (string) ($fc['ship_group'] ?? '');
        $entry = [
            'ship' => (string) $fc['ship_name'],
            'class' => $shipGroup !== '' ? $shipGroup : 'Unknown',
            'pilots' => (int) $fc['pilot_count'],
        ];
        if (($fc['side'] ?? '') === $ourSide) {
            $friendlyComp[] = $entry;
        } elseif (($fc['side'] ?? '') === $enemySide) {
            $enemyComp[] = $entry;
        }
    }

    // Build notable kills
    $notableKillList = [];
    foreach ($notableKills as $nk) {
        $victimSide = (string) ($nk['victim_side'] ?? '');
        $notableKillList[] = [
            'victim' => (string) ($nk['victim_name'] ?? '?'),
            'ship' => (string) ($nk['ship_name'] ?? '?'),
            'ship_class' => (string) ($nk['ship_group'] ?? ''),
            'alliance' => (string) ($nk['victim_alliance_name'] ?? '?'),
            'isk' => number_format((float) ($nk['isk_value'] ?? 0), 0) . ' ISK',
            'time' => (string) ($nk['kill_time'] ?? ''),
            'lost_by' => $victimSide === $ourSide ? 'friendly' : ($victimSide === $enemySide ? 'enemy' : 'unknown'),
        ];
    }

    // Build top performers
    $performerList = [];
    foreach ($topPerformers as $tp) {
        $shipName = (string) ($tp['ship_name'] ?? '');
        $shipGroup = (string) ($tp['ship_group'] ?? '');
        $entry = [
            'character' => (string) ($tp['character_name'] ?? '?'),
            'alliance' => (string) ($tp['alliance_name'] ?? '?'),
            'side' => ($tp['side'] ?? '') === $ourSide ? 'friendly' : 'enemy',
            'kills' => (int) ($tp['kills'] ?? 0),
            'deaths' => (int) ($tp['deaths'] ?? 0),
            'damage_done' => round((float) ($tp['damage_done'] ?? 0)),
            'role' => fleet_function_label((string) ($tp['role_proxy'] ?? 'mainline_dps')),
        ];
        if ($shipName !== '') {
            $entry['ship'] = $shipName;
        }
        if ($shipGroup !== '') {
            $entry['ship_class'] = $shipGroup;
        }
        $performerList[] = $entry;
    }

    // Friendly alliance names
    $friendlyNames = array_map(fn($a) => $a['alliance'], $sideData[$ourSide]);
    $enemyNames = array_map(fn($a) => $a['alliance'], $sideData[$enemySide]);

    // Two-side efficiency: isk_killed / (isk_killed + isk_lost)
    // friendly_isk_killed == enemy_isk_lost, so: enemy_lost / (enemy_lost + friendly_lost)
    // Third-party losses excluded from efficiency — included only in total_isk_destroyed.
    $twoSideTotal = $friendlyIskLost + $enemyIskLost;
    $efficiency = $twoSideTotal > 0 ? round(($enemyIskLost / $twoSideTotal) * 100, 1) : 0;

    $facts = [
        'theater_id' => $theaterId,
        'location' => (string) ($theater['primary_system_name'] ?? 'Unknown') . ' (' . (string) ($theater['region_name'] ?? 'Unknown') . ')',
        'systems' => array_map(fn($s) => (string) ($s['system_name'] ?? '?'), $systems),
        'start_time' => (string) ($theater['start_time'] ?? ''),
        'end_time' => (string) ($theater['end_time'] ?? ''),
        'duration_minutes' => round((int) ($theater['duration_seconds'] ?? 0) / 60, 1),
        'battle_count' => (int) ($theater['battle_count'] ?? 0),
        'total_kills' => (int) ($theater['total_kills'] ?? 0),
        'participant_count' => (int) ($theater['participant_count'] ?? 0),
        'friendly_alliance' => implode(', ', $friendlyNames) ?: 'Unknown',
        'enemy_alliances' => implode(', ', $enemyNames) ?: 'Unknown',
        'friendly_coalition' => $sideData[$ourSide],
        'enemy_coalition' => $sideData[$enemySide],
        'friendly_pilots' => $sidePilotTotals[$ourSide],
        'enemy_pilots' => $sidePilotTotals[$enemySide],
        'friendly_isk_killed' => number_format($enemyIskLost, 0) . ' ISK',
        'friendly_isk_lost' => number_format($friendlyIskLost, 0) . ' ISK',
        'enemy_isk_killed' => number_format($friendlyIskLost, 0) . ' ISK',
        'enemy_isk_lost' => number_format($enemyIskLost, 0) . ' ISK',
        'total_isk_destroyed' => number_format($friendlyIskLost + $enemyIskLost + $thirdPartyIskLost, 0) . ' ISK',
        'efficiency' => $efficiency . '%',
        'friendly_fleet_composition' => array_slice($friendlyComp, 0, 20),
        'enemy_fleet_composition' => array_slice($enemyComp, 0, 20),
        'notable_kills' => $notableKillList,
        'top_performers' => $performerList,
    ];

    if ($turningPoints !== []) {
        $facts['turning_points'] = array_map(fn($tp) => [
            'time' => (string) ($tp['turning_point_at'] ?? ''),
            'direction' => (string) ($tp['direction'] ?? ''),
            'side' => theater_ai_side_label_from_direction((string) ($tp['direction'] ?? ''), $ourSide),
            'magnitude' => round((float) ($tp['magnitude'] ?? 0), 3),
            'description' => (string) ($tp['description'] ?? ''),
        ], array_slice($turningPoints, 0, 5));
    }

    return $facts;
}

function theater_ai_side_label_from_direction(string $direction, string $friendlySide): string
{
    $normalizedDirection = strtolower(trim($direction));
    if ($normalizedDirection === '') {
        return 'unknown';
    }

    // Turning point directions from Python use "friendly_surge" / "opponent_surge"
    if (str_contains($normalizedDirection, 'friendly')) {
        return 'friendly';
    }
    if (str_contains($normalizedDirection, 'opponent')) {
        return 'enemy';
    }

    // Legacy fallback for side_a/side_b format
    $enemySide = $friendlySide === 'side_a' ? 'side_b' : 'side_a';
    if (str_contains($normalizedDirection, $friendlySide)) {
        return 'friendly';
    }
    if (str_contains($normalizedDirection, $enemySide)) {
        return 'enemy';
    }

    return 'unknown';
}

function theater_ai_system_prompt(): string
{
    $config = supplycore_ai_ollama_config();
    $provider = (string) ($config['provider'] ?? 'local');

    if ($provider === 'claude' || $provider === 'groq') {
        return "You are an experienced EVE Online Fleet Commander and military analyst writing a detailed After Action Report (AAR).\n\n"
             . "IMPORTANT INSTRUCTIONS:\n"
             . "- Generate a COMPREHENSIVE, DETAILED report. Aim for 1500-3000 words in the summary field.\n"
             . "- Follow ALL numbered sections in the user prompt. Each section must have substantial content.\n"
             . "- Use markdown formatting: ## for section headers, **bold** for emphasis, - for bullet points.\n"
             . "- Analyze the battle data thoroughly. Reference specific alliances, ship types, ISK values, and pilot names.\n"
             . "- Focus on what the data shows: kills, ISK values, ship types, timelines, systems, and pilot stats.\n"
             . "- Do NOT speculate about things not in the data (target calling, positioning, EWAR, logistics, comms, intel leaks, pilot behavior).\n"
             . "- CRITICAL PERSPECTIVE RULES:\n"
             . "  * The AAR is ALWAYS written from the perspective of the 'friendly' coalition — these are OUR pilots, OUR fleets, OUR losses.\n"
             . "  * 'enemy' / 'opponent' is the OTHER side — they are the hostiles.\n"
             . "  * The 'friendly_alliance' field in the battle data tells you exactly which alliances are on OUR side. Use 'we/our/us' when referring to them.\n"
             . "  * Use 'the enemy' or refer to hostile alliances by name when discussing the opposing side.\n"
             . "  * If the friendly side LOST the fight, write a loss analysis from our perspective — do NOT write a victory report for the enemy. Frame it as what WE need to improve, what went wrong for US, and how WE can do better.\n"
             . "  * The headline must reflect OUR outcome (e.g. 'Defeat in X-7OMU' not 'Enemy Victory in X-7OMU').\n"
             . "  * NEVER frame the report as congratulating or praising the enemy's performance. Analyze their tactics objectively but the tone is always from our side.\n"
             . "- The 'efficiency' field is our ISK efficiency. Above 50% means we destroyed more ISK than we lost.\n\n"
             . "Return valid JSON with the required fields. The 'summary' field must contain the full multi-section AAR in markdown.";
    }

    // Concise prompt for local Ollama (CPU-friendly)
    return "You are an EVE Online FC writing a battle After Action Report (AAR).\n\n"
         . "INSTRUCTIONS:\n"
         . "- Write a clear, structured AAR (300-800 words).\n"
         . "- Use ## headers, **bold**, and - bullets.\n"
         . "- Reference alliances, ships, ISK values from the data.\n"
         . "- Focus on what happened, who won, and why based on the data.\n"
         . "- Only state things derivable from kills, ISK, ships, timestamps. Do not speculate about EWAR, target calling, positioning, or pilot behavior.\n\n"
         . "Return valid JSON with the required fields.";
}

function theater_ai_user_prompt(array $facts): string
{
    // Load custom prompt from settings, fall back to default
    $defaults = ai_briefing_setting_defaults();
    $settings = get_settings(ai_briefing_setting_keys());
    $customPrompt = trim((string) ($settings['theater_aar_prompt'] ?? $defaults['theater_aar_prompt']));

    $dataJson = json_encode($facts, JSON_UNESCAPED_SLASHES | JSON_PRETTY_PRINT | JSON_INVALID_UTF8_SUBSTITUTE);

    if ($customPrompt !== '') {
        return $customPrompt . "\n\n---\n\nBATTLE DATA:\n" . $dataJson;
    }

    $friendlyLabel = (string) ($facts['friendly_alliance'] ?? 'Unknown');
    $enemyLabel = (string) ($facts['enemy_alliances'] ?? 'Unknown');

    return <<<PROMPT
You are an experienced EVE Online Fleet Commander and military analyst.

Generate a clear, structured After Action Report (AAR) based on the provided battle data.

Focus on tactical clarity, decision-making, and actionable insights. Avoid fluff.

CRITICAL — WHO WE ARE:
- OUR coalition ("friendly" in the data) is: {$friendlyLabel}
- THE ENEMY ("enemy" in the data) is: {$enemyLabel}
- This AAR is written FOR and FROM the perspective of {$friendlyLabel}. Use "we/our/us" when referring to {$friendlyLabel}.
- If we lost the fight, this is a LOSS REPORT — analyze what went wrong for US and how WE improve. Do NOT write a victory report for the enemy.
- The headline must describe OUR outcome (e.g. "Defeat in X-7OMU — 26% ISK Efficiency" not "Enemy Prevails in X-7OMU").

DATA CONTEXT:
- "friendly" = our coalition ({$friendlyLabel})
- "enemy" = the opposing coalition ({$enemyLabel})
- "friendly_isk_killed" = ISK value destroyed BY our side; "friendly_isk_lost" = ISK value WE lost
- "efficiency" = our ISK efficiency (friendly_isk_killed / total ISK destroyed)
- In "notable_kills", "lost_by" indicates which side lost the ship ("friendly" = we lost it, "enemy" = we killed it)
- In "fleet_composition", each entry has "ship" (name), "class" (ship group e.g. Battleship), and "pilots" (count)
- In "top_performers", "side" indicates which coalition the pilot belongs to


OUTPUT FORMAT:

1. Executive Summary
Provide a 2-3 sentence high-level outcome (win/loss, ISK efficiency, kill totals).

2. Battle Overview
Describe the timeline: when the fight started, how long it lasted, and how the kill tempo evolved. Reference specific timestamps and systems from the data.

3. Fleet Composition Analysis
Compare ship types, ship classes, and pilot counts on each side. Note any doctrinal advantages or mismatches visible in the composition data.

4. Key Losses & Kills
Highlight the most expensive ships destroyed on each side, who lost them, and when. Reference ISK values and ship classes from the notable_kills data.

5. Performance Breakdown
Using the top_performers data, highlight which pilots had the most kills and damage dealt. Note kill/death ratios and which ships they were flying.

6. Recommendations
Based on the fleet composition and losses, provide 1 concrete suggestion for future engagements (e.g. doctrine choice, fleet size, ship class gaps).

---

STYLE GUIDELINES:
- Be concise, analytical, and neutral
- Avoid roleplay or storytelling fluff
- Use short paragraphs and bullet points where useful
- Prioritize insights over description
- ONLY state things that can be directly derived from the provided data (kills, ISK, ships, timestamps, systems, pilot stats)
- Do NOT speculate about target calling, positioning, EWAR usage, logistics performance, comms, intel leaks, or pilot behavior — these cannot be determined from killmail data

---

Determine the verdict from {$friendlyLabel}'s perspective: one of "decisive_victory", "victory", "close_fight", "defeat", "decisive_defeat", or "stalemate". If {$friendlyLabel} lost the ISK war and the fight, the verdict MUST be "defeat" or "decisive_defeat", NOT "victory".

---

BATTLE DATA:
{$dataJson}
PROMPT;
}

function theater_ai_output_schema(): array
{
    $config = supplycore_ai_ollama_config();
    $provider = (string) ($config['provider'] ?? 'local');

    if ($provider === 'claude' || $provider === 'groq') {
        $summaryDesc = 'Full structured After Action Report (1500-3000 words). Must include ALL numbered sections from the prompt with detailed analysis. Use markdown: ## for headers, **bold** for emphasis, - for bullets. Each section needs multiple paragraphs or bullet points.';
    } else {
        $summaryDesc = 'Structured After Action Report (300-800 words). Cover the key sections from the prompt. Use markdown: ## for headers, **bold** for emphasis, - for bullets.';
    }

    return [
        'type' => 'object',
        'required' => ['headline', 'summary', 'verdict'],
        'properties' => [
            'headline' => [
                'type' => 'string',
                'description' => 'One-line outcome summary (max 100 chars). Example: "Decisive victory in 4-HWWF — 100% ISK efficiency"',
            ],
            'summary' => [
                'type' => 'string',
                'description' => $summaryDesc,
            ],
            'verdict' => [
                'type' => 'string',
                'enum' => ['decisive_victory', 'victory', 'close_fight', 'defeat', 'decisive_defeat', 'stalemate'],
                'description' => 'Outcome from our tracked coalition perspective.',
            ],
        ],
        'additionalProperties' => false,
    ];
}

function theater_ai_summary_generate_pending(): int
{
    if (!supplycore_ai_ollama_enabled()) {
        return 0;
    }
    $trackedAllianceIds = array_map('intval', array_column(db_killmail_tracked_alliances_active(), 'alliance_id'));
    if ($trackedAllianceIds === []) {
        return 0;
    }
    $placeholders = implode(',', array_fill(0, count($trackedAllianceIds), '?'));
    $pending = db_select(
        'SELECT DISTINCT t.theater_id
         FROM theaters t
         INNER JOIN theater_alliance_summary tas
             ON tas.theater_id = t.theater_id
             AND tas.alliance_id IN (' . $placeholders . ')
             AND tas.participant_count >= 2
         WHERE t.ai_summary IS NULL
           AND t.locked_at IS NOT NULL
         ORDER BY t.start_time DESC
         LIMIT 5',
        $trackedAllianceIds
    );
    $generated = 0;
    foreach ($pending as $row) {
        $result = theater_ai_summary_generate((string) $row['theater_id']);
        if ($result !== null) {
            $generated++;
        }
    }
    return $generated;
}

function theater_ai_summary_read(string $theaterId): ?array
{
    $theater = db_theater_detail($theaterId);
    if ($theater === null) {
        return null;
    }
    $existingSummary = $theater['ai_summary'] ?? null;
    if ($existingSummary === null || trim((string) $existingSummary) === '') {
        return null;
    }
    return [
        'headline' => (string) ($theater['ai_headline'] ?? ''),
        'summary' => (string) $existingSummary,
        'verdict' => (string) ($theater['ai_verdict'] ?? ''),
        'model' => (string) ($theater['ai_summary_model'] ?? ''),
        'generated_at' => (string) ($theater['ai_summary_at'] ?? ''),
        'cached' => true,
    ];
}

function theater_ai_summary_store(string $theaterId, string $headline, string $summary, string $verdict, string $model): void
{
    db_execute(
        'UPDATE theaters SET ai_headline = ?, ai_summary = ?, ai_verdict = ?, ai_summary_model = ?, ai_summary_at = NOW() WHERE theater_id = ?',
        [$headline, $summary, $verdict, $model, $theaterId]
    );
}

function theater_lock_report(string $theaterId): ?array
{
    $theater = db_theater_detail($theaterId);
    if ($theater === null) {
        return ['error' => 'Theater not found'];
    }
    if (($theater['locked_at'] ?? null) !== null) {
        return ['error' => 'Battle report is already locked'];
    }

    // Lock the theater immediately regardless of AI outcome.
    db_execute('UPDATE theaters SET locked_at = NOW() WHERE theater_id = ?', [$theaterId]);

    if (!supplycore_ai_ollama_enabled()) {
        return ['ai_status' => 'disabled'];
    }

    // Only RunPod needs the async ai_jobs queue (cold starts can take
    // minutes). Local Ollama / Claude / Groq respond in seconds and
    // run inline on the web request thread.
    if (supplycore_ai_needs_queue('theater_lock')) {
        try {
            $jobId = supplycore_ai_jobs_enqueue(
                'theater_lock',
                $theaterId,
                ['theater_id' => $theaterId]
            );
        } catch (Throwable $e) {
            error_log('[theater-lock] Failed to enqueue AI job: ' . $e->getMessage());
            return ['ai_status' => 'error', 'error' => $e->getMessage()];
        }
        return ['ai_status' => 'queued', 'ai_job_id' => $jobId];
    }

    // Inline execution for non-RunPod providers.
    try {
        $result = theater_ai_summary_generate($theaterId, true);
        return $result ?? ['ai_status' => 'done'];
    } catch (Throwable $e) {
        error_log('[theater-lock] Inline AI generation failed: ' . $e->getMessage());
        return ['ai_status' => 'error', 'error' => $e->getMessage()];
    }
}

/**
 * Snapshot the current AI briefing state for a theater. Returns the cached
 * summary if present, otherwise the active job's status (queued/running/
 * failed) so the UI can render progress or retry affordances.
 */
function theater_ai_status_snapshot(string $theaterId): array
{
    $cached = theater_ai_summary_read($theaterId);
    if ($cached !== null) {
        return ['status' => 'done', 'summary' => $cached];
    }

    $job = supplycore_ai_jobs_find_latest('theater_lock', $theaterId);
    if ($job === null) {
        return ['status' => 'none'];
    }

    return [
        'status' => (string) ($job['status'] ?? 'unknown'),
        'provider' => (string) ($job['provider'] ?? ''),
        'model' => (string) ($job['model'] ?? ''),
        'attempts' => (int) ($job['attempts'] ?? 0),
        'error' => (string) ($job['last_error'] ?? ''),
        'updated_at' => (string) ($job['updated_at'] ?? ''),
    ];
}

/**
 * Compute derived view variables from raw theater data arrays.
 *
 * Extracted so the lock flow can recompute after finalize reload,
 * eliminating any pre-finalize/post-finalize state mismatch.
 *
 * @return array{
 *   side_labels: array, side_alliances_by_pilots: array,
 *   opponent_model: array, side_panels: array,
 *   duration_label: string, total_isk_destroyed: float,
 *   theater_start_actual: string, theater_end_actual: string,
 *   display_kill_total: int, reported_kill_total: int, observed_kill_total: int,
 *   data_quality_notes: array, classify_alliance: Closure
 * }
 */
function theater_compute_derived_view(
    array $theater,
    array $battles,
    array $timeline,
    array $allianceSummary,
    array $participantsAll,
    array $resolvedEntities,
    array $structureKills,
    Closure $classifyAlliance,
): array {
    $durationSec = max(1, (int) ($theater['duration_seconds'] ?? 0));
    $durationLabel = $durationSec >= 120 ? number_format($durationSec / 60, 0) . 'm' : $durationSec . 's';
    $totalIskDestroyed = (float) ($theater['total_isk'] ?? 0);

    // Theater time window from actual battle data
    $theaterStartActual = $theater['start_time'] ?? '';
    $theaterEndActual = $theater['end_time'] ?? '';
    if ($battles !== []) {
        $battleStarts = array_filter(array_map(fn($b) => (string) ($b['started_at'] ?? ''), $battles), fn($s) => $s !== '');
        $battleEnds = array_filter(array_map(fn($b) => (string) ($b['ended_at'] ?? ''), $battles), fn($s) => $s !== '');
        if ($battleStarts) $theaterStartActual = min($battleStarts);
        if ($battleEnds) $theaterEndActual = max($battleEnds);
    }

    // Timeline aggregates
    $timelineKillTotal = 0;
    foreach ($timeline as $row) {
        $timelineKillTotal += (int) ($row['kills'] ?? 0);
    }

    // Kill totals
    $participantKillTotalsBySide = ['friendly' => 0, 'opponent' => 0, 'third_party' => 0];
    foreach ($participantsAll as $row) {
        $ck = (int) ($row['contributed_kills'] ?? $row['kills'] ?? 0);
        $side = $classifyAlliance((int) ($row['alliance_id'] ?? 0), (int) ($row['corporation_id'] ?? 0));
        if (isset($participantKillTotalsBySide[$side])) {
            $participantKillTotalsBySide[$side] += $ck;
        }
    }
    $reportedKillTotal = (int) ($theater['total_kills'] ?? 0);
    $observedKillTotal = $timelineKillTotal;
    $displayKillTotal = $reportedKillTotal > 0 ? $reportedKillTotal : $observedKillTotal;

    $dataQualityNotes = [];
    if ($reportedKillTotal !== $observedKillTotal && $reportedKillTotal > 0 && $observedKillTotal > 0) {
        $dataQualityNotes[] = 'Theater aggregate kills (' . number_format($reportedKillTotal) . ') differ from observed detail kills (' . number_format($observedKillTotal) . ').';
    }

    // Side classification from alliance summary
    $sideAlliancesByPilots = ['friendly' => [], 'opponent' => [], 'third_party' => []];
    foreach ($allianceSummary as $a) {
        $aid = (int) ($a['alliance_id'] ?? 0);
        $corpId = (int) ($a['corporation_id'] ?? 0);
        $pilots = (int) ($a['participant_count'] ?? 0);
        $classification = $classifyAlliance($aid, $corpId);
        $groupKey = $aid > 0 ? "a:{$aid}" : "c:{$corpId}";
        $sideAlliancesByPilots[$classification][$groupKey] = ($sideAlliancesByPilots[$classification][$groupKey] ?? 0) + $pilots;
    }
    if ($sideAlliancesByPilots['opponent'] === [] && $sideAlliancesByPilots['third_party'] !== []) {
        $sideAlliancesByPilots['opponent'] = $sideAlliancesByPilots['third_party'];
        $sideAlliancesByPilots['third_party'] = [];
    }

    // Side labels
    $sideLabels = ['friendly' => 'Friendlies', 'opponent' => 'Opposition', 'third_party' => 'Third Party'];
    foreach (['friendly', 'opponent', 'third_party'] as $side) {
        $alliances = $sideAlliancesByPilots[$side];
        if ($alliances === []) continue;
        arsort($alliances);
        $preferredKey = (string) array_key_first($alliances);
        if (str_starts_with($preferredKey, 'c:')) {
            $preferredName = killmail_entity_preferred_name($resolvedEntities, 'corporation', (int) substr($preferredKey, 2), '', 'Corporation');
        } else {
            $preferredName = killmail_entity_preferred_name($resolvedEntities, 'alliance', (int) substr($preferredKey, 2), '', 'Alliance');
        }
        $otherCount = count($alliances) - 1;
        $sideLabels[$side] = $preferredName . ($otherCount > 0 ? " +{$otherCount}" : '');
    }
    $friendlyCoalitionName = trim((string) db_app_setting_get('friendly_coalition_name', ''));
    $opponentCoalitionName = trim((string) db_app_setting_get('opponent_coalition_name', ''));
    if ($friendlyCoalitionName !== '' && $sideAlliancesByPilots['friendly'] !== []) {
        $otherCount = count($sideAlliancesByPilots['friendly']) - 1;
        $sideLabels['friendly'] = $friendlyCoalitionName . ($otherCount > 0 ? " +{$otherCount}" : '');
    }
    if ($opponentCoalitionName !== '' && $sideAlliancesByPilots['opponent'] !== []) {
        $otherCount = count($sideAlliancesByPilots['opponent']) - 1;
        $sideLabels['opponent'] = $opponentCoalitionName . ($otherCount > 0 ? " +{$otherCount}" : '');
    }

    // Opponent model
    $opponentModel = ['primary_opponent' => null, 'opponents' => [], 'opponent_summary_label' => $sideLabels['opponent']];
    $opponentAlliances = $sideAlliancesByPilots['opponent'];
    arsort($opponentAlliances);
    foreach ($opponentAlliances as $groupKey => $pilots) {
        $groupKey = (string) $groupKey;
        if (str_starts_with($groupKey, 'c:')) {
            $eid = (int) substr($groupKey, 2);
            $name = killmail_entity_preferred_name($resolvedEntities, 'corporation', $eid, '', 'Corporation');
            $entry = ['alliance_id' => 0, 'corporation_id' => $eid, 'name' => $name, 'pilots' => $pilots];
        } else {
            $eid = (int) substr($groupKey, 2);
            $name = killmail_entity_preferred_name($resolvedEntities, 'alliance', $eid, '', 'Alliance');
            $entry = ['alliance_id' => $eid, 'name' => $name, 'pilots' => $pilots];
        }
        $opponentModel['opponents'][] = $entry;
        if ($opponentModel['primary_opponent'] === null) {
            $opponentModel['primary_opponent'] = $entry;
        }
    }
    if ($opponentModel['opponents'] === []) {
        $opponentModel['opponent_summary_label'] = 'Unclassified Hostiles';
    } elseif (count($opponentModel['opponents']) === 1) {
        $opponentModel['opponent_summary_label'] = $opponentModel['primary_opponent']['name'];
    }

    // Side panels
    $sidePanels = [
        'friendly'    => ['pilots' => 0, 'kills' => 0, 'losses' => 0, 'isk_killed' => 0.0, 'isk_lost' => 0.0, 'alliances' => [], 'ship_pilots' => 0, 'ships' => [], 'kill_involvements' => 0, 'efficiency' => 0.0],
        'opponent'    => ['pilots' => 0, 'kills' => 0, 'losses' => 0, 'isk_killed' => 0.0, 'isk_lost' => 0.0, 'alliances' => [], 'ship_pilots' => 0, 'ships' => [], 'kill_involvements' => 0, 'efficiency' => 0.0],
        'third_party' => ['pilots' => 0, 'kills' => 0, 'losses' => 0, 'isk_killed' => 0.0, 'isk_lost' => 0.0, 'alliances' => [], 'ship_pilots' => 0, 'ships' => [], 'kill_involvements' => 0, 'efficiency' => 0.0],
    ];
    foreach ($allianceSummary as $a) {
        $aid = (int) ($a['alliance_id'] ?? 0);
        $corpId = (int) ($a['corporation_id'] ?? 0);
        $side = $classifyAlliance($aid, $corpId);
        if (!isset($sidePanels[$side])) continue;
        $sidePanels[$side]['pilots'] += (int) ($a['participant_count'] ?? 0);
        $sidePanels[$side]['kills'] += (int) ($a['total_kills'] ?? 0);
        $sidePanels[$side]['losses'] += (int) ($a['total_losses'] ?? 0);
        $sidePanels[$side]['isk_killed'] += (float) ($a['total_isk_killed'] ?? 0);
        $sidePanels[$side]['isk_lost'] += (float) ($a['total_isk_lost'] ?? 0);
        if ($aid > 0) {
            $entryName = killmail_entity_preferred_name($resolvedEntities, 'alliance', $aid, (string) ($a['alliance_name'] ?? ''), 'Alliance');
        } else {
            $entryName = killmail_entity_preferred_name($resolvedEntities, 'corporation', $corpId, (string) ($a['alliance_name'] ?? ''), 'Corporation');
        }
        $sidePanels[$side]['alliances'][] = [
            'alliance_id' => $aid,
            'corporation_id' => $corpId,
            'name' => $entryName,
            'pilots' => (int) ($a['participant_count'] ?? 0),
        ];
    }
    // Structure kills into side panels
    foreach ($structureKills as $sk) {
        $skSide = (string) ($sk['side'] ?? '');
        $skIsk = (float) ($sk['isk_lost'] ?? 0);
        if ($skIsk <= 0 || !isset($sidePanels[$skSide])) continue;
        $sidePanels[$skSide]['isk_lost'] += $skIsk;
        $sidePanels[$skSide]['losses'] += 1;
        $killerAid = (int) ($sk['killer_alliance_id'] ?? 0);
        $killerCid = (int) ($sk['killer_corporation_id'] ?? 0);
        if ($killerAid > 0 || $killerCid > 0) {
            $killerSide = $classifyAlliance($killerAid, $killerCid);
            if (isset($sidePanels[$killerSide])) {
                $sidePanels[$killerSide]['isk_killed'] += $skIsk;
                $sidePanels[$killerSide]['kills'] += 1;
            }
        }
    }
    foreach (['friendly', 'opponent', 'third_party'] as $side) {
        $total = $sidePanels[$side]['isk_killed'] + $sidePanels[$side]['isk_lost'];
        $sidePanels[$side]['efficiency'] = $total > 0
            ? $sidePanels[$side]['isk_killed'] / $total : 0.0;
        $sidePanels[$side]['kill_involvements'] = (int) ($participantKillTotalsBySide[$side] ?? 0);
        usort($sidePanels[$side]['alliances'], static fn(array $l, array $r): int => $r['pilots'] <=> $l['pilots']);
        $sidePanels[$side]['alliances'] = array_slice($sidePanels[$side]['alliances'], 0, 4);
    }

    return [
        'side_labels' => $sideLabels,
        'side_alliances_by_pilots' => $sideAlliancesByPilots,
        'opponent_model' => $opponentModel,
        'side_panels' => $sidePanels,
        'duration_label' => $durationLabel,
        'total_isk_destroyed' => $totalIskDestroyed,
        'theater_start_actual' => $theaterStartActual,
        'theater_end_actual' => $theaterEndActual,
        'display_kill_total' => $displayKillTotal,
        'reported_kill_total' => $reportedKillTotal,
        'observed_kill_total' => $observedKillTotal,
        'data_quality_notes' => $dataQualityNotes,
    ];
}

function theater_view_snapshot_save(string $theaterId, array $viewState): void
{
    $json = json_encode($viewState, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
    if ($json !== false) {
        db_execute('UPDATE theaters SET snapshot_data = ? WHERE theater_id = ?', [$json, $theaterId]);
    }
}

function theater_view_snapshot_load(array $theater): ?array
{
    if (($theater['locked_at'] ?? null) === null) {
        return null;
    }

    $raw = $theater['snapshot_data'] ?? null;
    if ($raw === null || !is_string($raw) || $raw === '') {
        return null;
    }

    $data = json_decode($raw, true);
    if (!is_array($data)) {
        return null;
    }

    return $data;
}

function theater_is_locked(array $theater): bool
{
    return ($theater['locked_at'] ?? null) !== null;
}

function theater_unlock_report(string $theaterId): array
{
    $theater = db_theater_detail($theaterId);
    if ($theater === null) {
        return ['ok' => false, 'error' => 'Theater not found'];
    }
    if (($theater['locked_at'] ?? null) === null) {
        return ['ok' => false, 'error' => 'Theater is not locked'];
    }

    db_execute(
        'UPDATE theaters SET locked_at = NULL, ai_headline = NULL, ai_summary = NULL, ai_verdict = NULL, ai_summary_model = NULL, ai_summary_at = NULL, snapshot_data = NULL WHERE theater_id = ?',
        [$theaterId]
    );

    return ['ok' => true];
}

function theater_ai_verdict_label(string $verdict): string
{
    return match ($verdict) {
        'decisive_victory' => 'Decisive Victory',
        'victory' => 'Victory',
        'close_fight' => 'Close Fight',
        'defeat' => 'Defeat',
        'decisive_defeat' => 'Decisive Defeat',
        'stalemate' => 'Stalemate',
        default => ucfirst(str_replace('_', ' ', $verdict)),
    };
}

function theater_ai_verdict_color_class(string $verdict): string
{
    return match ($verdict) {
        'decisive_victory' => 'text-green-400',
        'victory' => 'text-green-300',
        'close_fight' => 'text-yellow-400',
        'defeat' => 'text-red-300',
        'decisive_defeat' => 'text-red-400',
        'stalemate' => 'text-slate-400',
        default => 'text-slate-300',
    };
}

function rebuild_ai_briefings_job_result(string $reason = 'manual'): array
{
    // Doctrine AI briefings have been retired — return a success/no-op result
    // so the scheduler can check off the job without fatal errors.
    return sync_result_shape() + [
        'rows_seen' => 0,
        'rows_written' => 0,
        'cursor' => 'doctrine_ai_briefings:retired',
        'checksum' => 'retired',
        'meta' => [
            'outcome_reason' => 'Doctrine AI briefings retired.',
        ],
    ];
}

function activity_priority_snapshot_key(): string
{
    return 'activity_priority_summaries';
}

function activity_priority_snapshot_payload(): array
{
    $doctrineCached = supplycore_cached_json_read(supplycore_activity_doctrine_cache_key());
    $itemsCached = supplycore_cached_json_read(supplycore_activity_items_cache_key());
    if (is_array($doctrineCached) && is_array($itemsCached) && $doctrineCached !== [] && $itemsCached !== []) {
        return $doctrineCached + $itemsCached;
    }

    return supplycore_materialized_snapshot_read_or_bootstrap(
        activity_priority_snapshot_key(),
        static fn (): array => activity_priority_summary_build('bootstrap'),
        'activity-priority-bootstrap'
    );
}

function activity_priority_refresh_summary(string $reason = 'manual'): array
{
    supplycore_materialized_snapshot_mark_updating(activity_priority_snapshot_key(), $reason);
    $snapshot = activity_priority_summary_build($reason);
    $stored = supplycore_materialized_snapshot_store(activity_priority_snapshot_key(), $snapshot, [
        'reason' => $reason,
        'group_count' => count((array) ($snapshot['active_doctrines'] ?? [])),
        'item_count' => count((array) ($snapshot['priority_items'] ?? [])),
    ]);

    supplycore_cached_json_write(supplycore_activity_doctrine_cache_key(), [
        'summary_cards' => array_values((array) ($stored['summary_cards'] ?? [])),
        'active_doctrines' => array_values((array) ($stored['active_doctrines'] ?? [])),
        'active_fits' => array_values((array) ($stored['active_fits'] ?? [])),
        'trend_movement' => is_array($stored['trend_movement'] ?? null) ? $stored['trend_movement'] : [],
        '_freshness' => is_array($stored['_freshness'] ?? null) ? $stored['_freshness'] : [],
    ]);
    supplycore_cached_json_write(supplycore_activity_items_cache_key(), [
        'priority_items' => array_values((array) ($stored['priority_items'] ?? [])),
        'questions_answered' => is_array($stored['questions_answered'] ?? null) ? $stored['questions_answered'] : [],
        '_freshness' => is_array($stored['_freshness'] ?? null) ? $stored['_freshness'] : [],
    ]);

    return $stored;
}

function activity_priority_refresh_summary_job_result(string $reason = 'manual'): array
{
    $snapshot = activity_priority_refresh_summary($reason);
    $rowCount = count((array) ($snapshot['active_doctrines'] ?? [])) + count((array) ($snapshot['priority_items'] ?? []));
    $freshness = is_array($snapshot['_freshness'] ?? null) ? $snapshot['_freshness'] : [];

    return sync_result_shape() + [
        'rows_seen' => $rowCount,
        'rows_written' => $rowCount,
        'cursor' => 'activity_priority:' . gmdate('Y-m-d H:i:s'),
        'checksum' => sync_checksum([
            'rows' => $rowCount,
            'computed_at' => (string) ($freshness['computed_at'] ?? gmdate(DATE_ATOM)),
            'reason' => $reason,
        ]),
        'meta' => [
            'outcome_reason' => 'Doctrine activity and item-priority summaries were recomputed from tracked losses, doctrine definitions, and local market pressure signals.',
            'snapshot_generated_at' => (string) ($freshness['computed_at'] ?? ''),
        ],
    ];
}

/**
 * Aggregate loss counts per hull_type_id over 1d / 3d / 7d / 30d
 * windows directly from ``killmail_events`` — the authoritative ingest
 * table. We intentionally don't use ``killmail_hull_loss_1d`` /
 * ``killmail_item_loss_1d`` here because the rollup populator is on a
 * separate schedule and the rollups can lag or stay empty on servers
 * where the analytics bucket jobs aren't actively running.
 *
 * Returns ``{hull_type_id: {h24, h3d, h7d, h30d}}`` for hulls.
 */
function activity_priority_hull_loss_windows(array $hullTypeIds): array
{
    $hullTypeIds = array_values(array_unique(array_filter(array_map('intval', $hullTypeIds), static fn (int $id): bool => $id > 0)));
    if ($hullTypeIds === []) {
        return [];
    }
    $placeholders = implode(',', array_fill(0, count($hullTypeIds), '?'));
    $rows = db_select(
        "SELECT victim_ship_type_id AS hull_type_id,
                SUM(CASE WHEN killmail_time >= DATE_SUB(UTC_TIMESTAMP(), INTERVAL 1 DAY)  THEN 1 ELSE 0 END) AS h24,
                SUM(CASE WHEN killmail_time >= DATE_SUB(UTC_TIMESTAMP(), INTERVAL 3 DAY)  THEN 1 ELSE 0 END) AS h3d,
                SUM(CASE WHEN killmail_time >= DATE_SUB(UTC_TIMESTAMP(), INTERVAL 7 DAY)  THEN 1 ELSE 0 END) AS h7d,
                SUM(CASE WHEN killmail_time >= DATE_SUB(UTC_TIMESTAMP(), INTERVAL 30 DAY) THEN 1 ELSE 0 END) AS h30d
           FROM killmail_events
          WHERE mail_type = 'loss'
            AND victim_ship_type_id IN ({$placeholders})
            AND killmail_time >= DATE_SUB(UTC_TIMESTAMP(), INTERVAL 30 DAY)
          GROUP BY victim_ship_type_id",
        $hullTypeIds
    );
    $out = [];
    foreach ($rows as $row) {
        $out[(int) ($row['hull_type_id'] ?? 0)] = [
            'h24'  => (int) ($row['h24'] ?? 0),
            'h3d'  => (int) ($row['h3d'] ?? 0),
            'h7d'  => (int) ($row['h7d'] ?? 0),
            'h30d' => (int) ($row['h30d'] ?? 0),
        ];
    }
    return $out;
}

/**
 * Aggregate fitted-module losses per hull_type_id over 24h / 3d / 7d
 * windows. Counts ``killmail_items`` rows from loss killmails joined on
 * the configured fitted-slot flag ranges, filtered to actual modules
 * (category 7) and subsystems (category 32) to match the detector's
 * cluster-input filter.
 */
function activity_priority_module_loss_windows(array $hullTypeIds): array
{
    $hullTypeIds = array_values(array_unique(array_filter(array_map('intval', $hullTypeIds), static fn (int $id): bool => $id > 0)));
    if ($hullTypeIds === []) {
        return [];
    }
    $placeholders = implode(',', array_fill(0, count($hullTypeIds), '?'));
    $rows = db_select(
        "SELECT ke.victim_ship_type_id AS hull_type_id,
                SUM(CASE WHEN ke.killmail_time >= DATE_SUB(UTC_TIMESTAMP(), INTERVAL 1 DAY) THEN 1 ELSE 0 END) AS h24,
                SUM(CASE WHEN ke.killmail_time >= DATE_SUB(UTC_TIMESTAMP(), INTERVAL 3 DAY) THEN 1 ELSE 0 END) AS h3d,
                SUM(CASE WHEN ke.killmail_time >= DATE_SUB(UTC_TIMESTAMP(), INTERVAL 7 DAY) THEN 1 ELSE 0 END) AS h7d
           FROM killmail_events ke
           INNER JOIN killmail_items ki ON ki.sequence_id = ke.sequence_id
           INNER JOIN ref_item_types rit ON rit.type_id = ki.item_type_id
          WHERE ke.mail_type = 'loss'
            AND ke.victim_ship_type_id IN ({$placeholders})
            AND ke.killmail_time >= DATE_SUB(UTC_TIMESTAMP(), INTERVAL 7 DAY)
            AND (ki.item_flag BETWEEN 11 AND 34
                 OR ki.item_flag BETWEEN 92 AND 94
                 OR ki.item_flag BETWEEN 125 AND 132)
            AND rit.category_id IN (7, 32)
          GROUP BY ke.victim_ship_type_id",
        $hullTypeIds
    );
    $out = [];
    foreach ($rows as $row) {
        $out[(int) ($row['hull_type_id'] ?? 0)] = [
            'h24' => (int) ($row['h24'] ?? 0),
            'h3d' => (int) ($row['h3d'] ?? 0),
            'h7d' => (int) ($row['h7d'] ?? 0),
        ];
    }
    return $out;
}

/**
 * For every active doctrine in ``$doctrineIds`` compute how many
 * complete fits the current alliance stock can already cover.
 *
 * The bottleneck is the minimum across every module in the fit:
 *     fits_per_module   = floor(alliance_stock[type_id] / per_fit_qty)
 *     fits_covered      = min(fits_per_module across all modules)
 *
 * Returns ``{doctrine_id: {covered, bottleneck_type_id, bottleneck_fits}}``.
 * Two batched queries regardless of how many doctrines or modules —
 * one to load all modules, one to load all alliance stock snapshots.
 *
 * Doctrines whose core module set is empty return ``covered = 0``
 * (nothing to stock, so no coverage signal).
 */
function activity_priority_stock_coverage(array $doctrineIds): array
{
    $doctrineIds = array_values(array_unique(array_filter(array_map('intval', $doctrineIds), static fn (int $id): bool => $id > 0)));
    if ($doctrineIds === []) {
        return [];
    }

    // Step 1: pull every module row for the target doctrines in one go.
    $placeholders = implode(',', array_fill(0, count($doctrineIds), '?'));
    $moduleRows = db_select(
        "SELECT doctrine_id, type_id, quantity
           FROM auto_doctrine_modules
          WHERE doctrine_id IN ({$placeholders})",
        $doctrineIds
    );

    // Group modules by doctrine and collect every unique type_id.
    $modulesByDoctrine = [];
    $typeIdSet = [];
    foreach ($moduleRows as $row) {
        $doctrineId = (int) ($row['doctrine_id'] ?? 0);
        $typeId = (int) ($row['type_id'] ?? 0);
        $qty = max(1, (int) ($row['quantity'] ?? 1));
        if ($doctrineId <= 0 || $typeId <= 0) {
            continue;
        }
        $modulesByDoctrine[$doctrineId][] = ['type_id' => $typeId, 'quantity' => $qty];
        $typeIdSet[$typeId] = true;
    }

    // Step 2: latest alliance-structure stock snapshot per type_id.
    $stockByType = [];
    if ($typeIdSet !== []) {
        $typeIds = array_keys($typeIdSet);
        $typePlaceholders = implode(',', array_fill(0, count($typeIds), '?'));
        $stockRows = db_select(
            "SELECT mss.type_id,
                    COALESCE(mss.total_sell_volume, 0) AS stock_qty
               FROM market_order_snapshots_summary mss
               JOIN (
                   SELECT type_id, MAX(observed_at) AS latest_at
                     FROM market_order_snapshots_summary
                    WHERE source_type = 'alliance_structure'
                      AND type_id IN ({$typePlaceholders})
                    GROUP BY type_id
               ) latest
                 ON latest.type_id = mss.type_id
                AND latest.latest_at = mss.observed_at
              WHERE mss.source_type = 'alliance_structure'",
            $typeIds
        );
        foreach ($stockRows as $row) {
            $stockByType[(int) ($row['type_id'] ?? 0)] = (int) ($row['stock_qty'] ?? 0);
        }
    }

    // Step 3: compute the bottleneck per doctrine.
    $out = [];
    foreach ($doctrineIds as $doctrineId) {
        $modules = $modulesByDoctrine[$doctrineId] ?? [];
        if ($modules === []) {
            $out[$doctrineId] = ['covered' => 0, 'bottleneck_type_id' => 0];
            continue;
        }
        $bottleneckFits = PHP_INT_MAX;
        $bottleneckTypeId = 0;
        foreach ($modules as $m) {
            $typeId = (int) $m['type_id'];
            $perFitQty = max(1, (int) $m['quantity']);
            $stock = (int) ($stockByType[$typeId] ?? 0);
            $fitsForThisModule = intdiv($stock, $perFitQty);
            if ($fitsForThisModule < $bottleneckFits) {
                $bottleneckFits = $fitsForThisModule;
                $bottleneckTypeId = $typeId;
            }
        }
        if ($bottleneckFits === PHP_INT_MAX) {
            $bottleneckFits = 0;
        }
        $out[$doctrineId] = [
            'covered'             => $bottleneckFits,
            'bottleneck_type_id'  => $bottleneckTypeId,
        ];
    }

    return $out;
}

function activity_priority_page_data(): array
{
    // The legacy snapshot flow populated doctrine_activity_snapshots from
    // doctrine_fit_activity_1d — both dropped. We now reshape the auto
    // doctrine list into the key-shape the existing template expects so
    // the page renders without template changes.
    $doctrines = function_exists('auto_doctrine_list') ? auto_doctrine_list(['include_hidden' => false]) : [];
    $settings = function_exists('auto_doctrine_settings') ? auto_doctrine_settings() : [
        'window_days' => 30,
        'default_runway_days' => 14,
    ];

    $active = array_values(array_filter($doctrines, static fn (array $d): bool => (bool) ($d['is_active'] ?? false) || (bool) ($d['is_pinned'] ?? false)));
    // Batch-resolve hull-level 24h / 3d / 7d loss windows once. These
    // are keyed by hull_type_id and shared by every fingerprint on the
    // same hull, because ``killmail_events`` has no fingerprint column
    // and we only rollup 30d per-fingerprint counts on the clustering
    // pass. The 24h/3d/7d breakdown is therefore explicitly labelled
    // as "hull-level" on the page so operators know it's an aggregate
    // across every cluster sharing that hull.
    $hullTypeIds = array_values(array_unique(array_map(static fn (array $d): int => (int) ($d['hull_type_id'] ?? 0), $active)));
    $hullWindows = activity_priority_hull_loss_windows($hullTypeIds);
    $moduleWindows = activity_priority_module_loss_windows($hullTypeIds);

    // Stock coverage per doctrine: how many complete fits the current
    // alliance-structure snapshot can cover, bottlenecked by the most
    // constrained module in each fit. Used to override the readiness
    // label and resupply pressure tier so "Critical gap · Urgent
    // resupply" does not fire on doctrines whose stock is fine.
    $activeDoctrineIds = array_map(static fn (array $d): int => (int) ($d['id'] ?? 0), $active);
    $stockCoverage = activity_priority_stock_coverage($activeDoctrineIds);

    $windowDays = max(1, (int) $settings['window_days']);
    $defaultRunway = max(1, (int) $settings['default_runway_days']);

    // Compute per-fingerprint activity scores FIRST so we can sort and
    // rank against the real per-cluster numbers instead of the
    // hull-level aggregate.
    $scored = [];
    foreach ($active as $d) {
        $perFingerprintWindowLosses = (int) ($d['loss_count_window'] ?? 0);
        $runwayDays = (int) ($d['runway_days_effective'] ?? $defaultRunway);
        if ($runwayDays <= 0) {
            $runwayDays = $defaultRunway;
        }
        $perFingerprintDailyRate = $perFingerprintWindowLosses / $windowDays;
        $perFingerprintTargetFits = (int) ceil($perFingerprintDailyRate * $runwayDays);
        if ($perFingerprintTargetFits < 1 && (bool) ($d['is_pinned'] ?? false)) {
            $perFingerprintTargetFits = 1;
        }
        $scored[] = [
            'doctrine'    => $d,
            'win_losses'  => $perFingerprintWindowLosses,
            'daily_rate'  => $perFingerprintDailyRate,
            'target_fits' => $perFingerprintTargetFits,
            'runway_days' => $runwayDays,
            'score'       => round($perFingerprintDailyRate * $runwayDays, 2),
        ];
    }
    usort(
        $scored,
        static fn (array $a, array $b): int => ($b['score'] <=> $a['score'])
            ?: ($b['win_losses'] <=> $a['win_losses'])
    );

    $activeDoctrines = [];
    $activeFits = [];
    foreach ($scored as $index => $s) {
        $d = $s['doctrine'];
        $hullTypeId = (int) ($d['hull_type_id'] ?? 0);
        $hullW = $hullWindows[$hullTypeId] ?? ['h24' => 0, 'h3d' => 0, 'h7d' => 0, 'h30d' => 0];
        $modW = $moduleWindows[$hullTypeId] ?? ['h24' => 0, 'h3d' => 0, 'h7d' => 0];

        $windowLosses = $s['win_losses'];
        $dailyRate = $s['daily_rate'];
        $targetFits = $s['target_fits'];
        $runwayDays = $s['runway_days'];
        $activityScore = $s['score'];

        // Stock-aware readiness: subtract how many complete fits the
        // current alliance-structure stock can already cover from the
        // per-fingerprint target. ``realGap`` is the number of fits
        // we STILL need after stock is counted — that's what actually
        // drives whether operators should be alarmed.
        $coveredFits = (int) ($stockCoverage[(int) ($d['id'] ?? 0)]['covered'] ?? 0);
        $realGap = max(0, $targetFits - $coveredFits);

        // Activity level stays loss-driven — it's a signal about how
        // actively the fit is being burned, independent of stock.
        $activityLevel = match (true) {
            $targetFits >= 10 => 'critical',
            $targetFits >= 3  => 'elevated',
            default            => 'low',
        };

        // Readiness / resupply tier, on the other hand, only fires
        // when stock cannot cover the demand. Thresholds are scaled
        // against target_fits so a proportional shortfall (roughly a
        // third of the target) still trips the "Critical gap" label
        // even on low-volume doctrines.
        $criticalCut = max(3, (int) ceil($targetFits / 3));
        if ($realGap <= 0) {
            $readinessLabel = 'Market ready';
            $resupplyPressure = 'Stable';
        } elseif ($realGap >= $criticalCut) {
            $readinessLabel = 'Critical gap';
            $resupplyPressure = 'Urgent resupply';
        } else {
            $readinessLabel = 'Partial gap';
            $resupplyPressure = 'Moderate pressure';
        }

        $row = [
            'entity_id'          => (int) ($d['id'] ?? 0),
            'rank_position'      => $index + 1,
            'doctrine_name'      => (string) ($d['canonical_name'] ?? ''),
            'activity_level'     => $activityLevel,
            'activity_score'     => $activityScore,
            // Score / rank deltas would need a persisted previous
            // snapshot which the auto doctrine pipeline does not keep
            // yet. Leaving them at 0 with a neutral movement label is
            // honest — the template renders the values only if they
            // change, and the label now reads "—" instead of a fake
            // "Holding" so operators can tell the difference.
            'score_delta'        => 0.0,
            'rank_delta'         => 0,
            'movement_label'     => '—',
            'explanation'        => sprintf(
                '%d losses for this fit in the last %dd · daily rate %.2f · target %d fits, %d covered by stock, %d still needed (runway %dd)',
                $windowLosses,
                $windowDays,
                $dailyRate,
                $targetFits,
                $coveredFits,
                $realGap,
                $runwayDays
            ),
            // "hull_losses_*" are the hull-level windows shared across
            // every fingerprint on the same hull. The template labels
            // them "(hull)" so operators see that they are aggregates.
            'hull_losses_24h'              => $hullW['h24'],
            'hull_losses_3d'               => $hullW['h3d'],
            'hull_losses_7d'               => $hullW['h7d'],
            'module_losses_24h'            => $modW['h24'],
            'module_losses_3d'             => $modW['h3d'],
            'module_losses_7d'             => $modW['h7d'],
            'fit_equivalent_losses_24h'    => (float) $hullW['h24'],
            'fit_equivalent_losses_7d'     => (float) $hullW['h7d'],
            'readiness_label'              => $readinessLabel,
            'resupply_pressure'            => $resupplyPressure,
            // Surface the REAL gap (after subtracting stock) instead
            // of the raw target_fits so the "X fit gaps" text in the
            // template agrees with the readiness label.
            'readiness_gap_count'          => $realGap,
            'score_components'             => [
                sprintf('Fit losses (%dd)', $windowDays)  => (string) $windowLosses,
                'Daily rate'                               => number_format($dailyRate, 2),
                'Target fits'                              => (string) $targetFits,
                'Covered by stock'                         => (string) $coveredFits,
                'Real gap (needed)'                        => (string) $realGap,
                'Runway (days)'                            => (string) $runwayDays,
                'Hull total (7d)'                          => (string) $hullW['h7d'],
            ],
            'top_fits' => [
                [
                    'fit_name'       => (string) ($d['canonical_name'] ?? ''),
                    'activity_level' => $activityLevel,
                    'activity_score' => $activityScore,
                ],
            ],
        ];
        $activeDoctrines[] = $row;

        $activeFits[] = [
            'entity_id'        => (int) ($d['id'] ?? 0),
            'doctrine_name'    => (string) ($d['canonical_name'] ?? ''),
            'readiness_label'  => $readinessLabel,
            'resupply_pressure' => $resupplyPressure,
            'activity_score'   => $activityScore,
            'movement_label'   => 'Holding',
        ];
    }

    // Summary cards: keep labels stable for any dashboard consumers.
    $summaryCards = [
        [
            'label'   => 'Active Doctrines',
            'value'   => (string) count($active),
            'context' => 'Auto-detected doctrines with fit gaps right now',
        ],
        [
            'label'   => 'Fits Needing Stock',
            'value'   => (string) count(array_filter($activeDoctrines, static fn (array $r): bool => (string) $r['resupply_pressure'] === 'Urgent resupply')),
            'context' => 'Doctrines where alliance stock cannot cover the target fit count',
        ],
        [
            'label'   => 'Total Window Losses',
            'value'   => (string) array_sum(array_column($active, 'loss_count_window')),
            'context' => sprintf('Killmail losses over the last %d days', (int) $settings['window_days']),
        ],
        [
            'label'   => 'Runway (days)',
            'value'   => (string) (int) $settings['default_runway_days'],
            'context' => 'Default buy-all runway (override per doctrine)',
        ],
    ];

    return [
        'summary_cards'    => $summaryCards,
        'active_doctrines' => $activeDoctrines,
        'active_fits'      => array_slice($activeFits, 0, 25),
        'priority_items'   => [],
        'trend_movement'   => [
            'doctrines_moving_up'  => [],
            'items_newly_elevated' => [],
            'items_cooling_down'   => [],
        ],
        '_freshness'       => [
            'computed_at'      => gmdate(DATE_ATOM),
            'freshness_state'  => 'fresh',
            'freshness_label'  => 'Fresh',
        ],
    ];
}

function activity_priority_snapshot_has_computed_metrics(array $snapshot): bool
{
    $rows = array_values((array) ($snapshot['active_doctrines'] ?? []));
    if ($rows === []) {
        return true;
    }

    $row = (array) ($rows[0] ?? []);
    $hasDoctrineIdentity = array_key_exists('entity_id', $row)
        || array_key_exists('id', $row);
    $hasDoctrineName = array_key_exists('doctrine_name', $row)
        || array_key_exists('group_name', $row)
        || array_key_exists('entity_name', $row);
    $hasScore = array_key_exists('activity_score', $row);
    $hasLossMetrics = array_key_exists('hull_losses_24h', $row)
        || array_key_exists('module_losses_24h', $row)
        || array_key_exists('fit_equivalent_losses_24h', $row);

    return $hasDoctrineIdentity && $hasDoctrineName && $hasScore && $hasLossMetrics;
}


/**
 * Target runway in days for consumption-based buy quantity predictions.
 *
 * When an item has killmail-derived burn-rate data the planner recommends
 * enough units to cover this many days of expected consumption beyond the
 * current stock level.
 */

function activity_priority_level_from_score(float $score): string
{
    if ($score >= 200.0) {
        return 'highly active';
    }
    if ($score >= 80.0) {
        return 'active';
    }
    if ($score >= 30.0) {
        return 'moderate';
    }

    return 'low';
}

function activity_priority_item_band(float $score): string
{
    if ($score >= 200.0) {
        return 'critical';
    }
    if ($score >= 80.0) {
        return 'high';
    }
    if ($score >= 30.0) {
        return 'elevated';
    }

    return 'watch';
}

function activity_priority_level_tone(string $level): string
{
    return match ($level) {
        'highly active', 'critical' => 'border-rose-400/20 bg-rose-500/10 text-rose-100',
        'active', 'high' => 'border-orange-400/20 bg-orange-500/10 text-orange-100',
        'moderate', 'elevated' => 'border-amber-400/20 bg-amber-500/10 text-amber-100',
        default => 'border-slate-400/15 bg-slate-500/10 text-slate-200',
    };
}

function activity_priority_repeated_usage_weight(float $window24h, float $window3d, float $window7d): float
{
    $activeWindows = 0;
    foreach ([$window24h, $window3d, $window7d] as $value) {
        if ($value > 0) {
            $activeWindows++;
        }
    }

    $carryForward = max(0.0, $window3d - $window24h) + max(0.0, $window7d - $window3d);

    return round(min(16.0, ($activeWindows * 3.5) + ($carryForward * 2.2)), 2);
}

function activity_priority_recency_weight(float $window24h, float $window3d, float $window7d): float
{
    if ($window24h > 0) {
        return min(18.0, 10.0 + ($window24h * 2.2));
    }
    if ($window3d > 0) {
        return min(12.0, 6.0 + ($window3d * 1.1));
    }
    if ($window7d > 0) {
        return min(6.0, 2.5 + ($window7d * 0.4));
    }

    return 0.0;
}

function activity_priority_pressure_bonus(string $pressureState): float
{
    return match ($pressureState) {
        'urgent_resupply' => 8.0,
        'resupply_soon' => 6.0,
        'elevated' => 3.0,
        default => 0.0,
    };
}

function activity_priority_item_history_index(array $typeIds): array
{
    // Legacy doctrine_local_history_index has been retired. Activity-
    // priority views now rely on the new auto doctrine pipeline; this
    // helper just returns the raw history rows keyed by type_id.
    $normalizedTypeIds = array_values(array_unique(array_filter(array_map('intval', $typeIds), static fn (int $typeId): bool => $typeId > 0)));
    if ($normalizedTypeIds === []) {
        return [];
    }
    return [];
}

function activity_priority_fit_item_windows(array $items, array $itemLossByType): array
{
    $moduleLosses24h = 0;
    $moduleLosses3d = 0;
    $moduleLosses7d = 0;
    $equivalent24h = 0.0;
    $equivalent3d = 0.0;
    $equivalent7d = 0.0;

    foreach ($items as $item) {
        $typeId = max(0, (int) ($item['type_id'] ?? 0));
        $requiredQty = max(1, (int) ($item['quantity'] ?? 1));
        if ($typeId <= 0) {
            continue;
        }

        $loss = $itemLossByType[$typeId] ?? [];
        $qty24h = max(0, (int) ($loss['quantity_24h'] ?? 0));
        $qty3d = max(0, (int) ($loss['quantity_3d'] ?? 0));
        $qty7d = max(0, (int) ($loss['quantity_7d'] ?? 0));

        $moduleLosses24h += $qty24h;
        $moduleLosses3d += $qty3d;
        $moduleLosses7d += $qty7d;
        $equivalent24h = max($equivalent24h, $qty24h / $requiredQty);
        $equivalent3d = max($equivalent3d, $qty3d / $requiredQty);
        $equivalent7d = max($equivalent7d, $qty7d / $requiredQty);
    }

    return [
        'module_losses_24h' => $moduleLosses24h,
        'module_losses_3d' => $moduleLosses3d,
        'module_losses_7d' => $moduleLosses7d,
        'fit_equivalent_losses_24h' => round($equivalent24h, 2),
        'fit_equivalent_losses_3d' => round($equivalent3d, 2),
        'fit_equivalent_losses_7d' => round($equivalent7d, 2),
    ];
}

function activity_priority_doctrine_explanation(array $row): string
{
    $parts = [];
    if ((int) ($row['hull_losses_24h'] ?? 0) > 0 || (int) ($row['hull_losses_7d'] ?? 0) > 0) {
        $parts[] = doctrine_format_quantity((int) ($row['hull_losses_24h'] ?? 0)) . ' hull losses in 24h and ' . doctrine_format_quantity((int) ($row['hull_losses_7d'] ?? 0)) . ' in 7d';
    }
    if ((float) ($row['fit_equivalent_losses_7d'] ?? 0.0) > 0) {
        $parts[] = number_format((float) ($row['fit_equivalent_losses_7d'] ?? 0.0), 1) . ' fit-equivalent module losses over 7d';
    }
    if ((int) ($row['readiness_gap_count'] ?? 0) > 0) {
        $parts[] = doctrine_format_quantity((int) ($row['readiness_gap_count'] ?? 0)) . ' fit gaps still open locally';
    }
    if (((string) ($row['resupply_pressure_state'] ?? 'stable')) !== 'stable') {
        $parts[] = 'resupply pressure is ' . strtolower((string) ($row['resupply_pressure'] ?? 'elevated'));
    }

    return ucfirst(implode(' · ', array_slice($parts, 0, 4))) . ($parts === [] ? 'No recent tracked loss pressure is pushing this doctrine higher right now.' : '.');
}

function activity_priority_item_explanation(array $row): string
{
    $parts = [];
    if ((bool) ($row['is_doctrine_linked'] ?? false)) {
        $parts[] = 'valid for ' . doctrine_format_quantity((int) ($row['valid_fits_count'] ?? $row['linked_doctrine_count'] ?? 0)) . ' fits across ' . doctrine_format_quantity((int) ($row['valid_doctrine_count'] ?? 0)) . ' doctrines';
    }
    if ((int) ($row['linked_active_doctrine_count'] ?? 0) > 0) {
        $parts[] = doctrine_format_quantity((int) ($row['linked_active_doctrine_count'] ?? 0)) . ' linked doctrines are active now';
    }
    if ((int) ($row['deterministic_blocked_fits'] ?? 0) > 0) {
        $parts[] = 'deterministically blocks ' . doctrine_format_quantity((int) ($row['deterministic_blocked_fits'] ?? 0)) . ' target fits';
    } elseif ((int) ($row['exact_deficit_quantity'] ?? 0) > 0) {
        $parts[] = 'exact doctrine deficit is ' . doctrine_format_quantity((int) ($row['exact_deficit_quantity'] ?? 0)) . ' units';
    }
    if ((int) ($row['recent_loss_qty_24h'] ?? 0) > 0 || (int) ($row['recent_loss_qty_7d'] ?? 0) > 0) {
        $parts[] = doctrine_format_quantity((int) ($row['recent_loss_qty_24h'] ?? 0)) . ' units lost in 24h and ' . doctrine_format_quantity((int) ($row['recent_loss_qty_7d'] ?? 0)) . ' in 7d';
    }
    if ((int) ($row['local_sell_volume'] ?? 0) <= 0) {
        $parts[] = 'no local sell stock currently listed';
    } elseif ((string) ($row['depletion_state'] ?? 'stable') === 'draining') {
        $parts[] = 'local stock is draining versus the prior window';
    }
    if ((float) ($row['activity_pressure_modifier'] ?? 1.0) > 1.05) {
        $parts[] = 'activity modifier is ' . number_format((float) ($row['activity_pressure_modifier'] ?? 1.0), 2) . 'x for this hull family';
    }

    return ucfirst(implode(' · ', array_slice($parts, 0, 5))) . ($parts === [] ? 'Signals are steady, so the item remains on watch rather than elevated.' : '.');
}

function activity_priority_movement_label(int $rankDelta, float $scoreDelta): string
{
    if ($rankDelta >= 5 || $scoreDelta >= 12.0) {
        return 'Rising fast';
    }
    if ($rankDelta > 0 || $scoreDelta > 4.0) {
        return 'Moving up';
    }
    if ($rankDelta <= -5 || $scoreDelta <= -12.0) {
        return 'Cooling down';
    }
    if ($rankDelta < 0 || $scoreDelta < -4.0) {
        return 'Softening';
    }

    return 'Holding';
}

function activity_priority_summary_build(string $reason = 'manual'): array
{
    // The full per-fit activity summary used doctrine_snapshot_cache_payload(),
    // doctrine_refresh_intelligence(), db_doctrine_fit_items_by_fit_ids(),
    // db_doctrine_activity_snapshot_bulk_insert(), and buy_all_item_impact_map()
    // — all of which have been retired along with the hand-maintained doctrine
    // system. Return an empty, well-shaped summary so dependent snapshot
    // storage still functions without the rich per-fit detail.
    $now = gmdate(DATE_ATOM);
    return [
        'reason' => $reason,
        'generated_at' => $now,
        'fits' => [],
        'groups' => [],
        'items' => [],
        'rows' => [],
        'freshness' => [
            'computed_at' => $now,
            'freshness_state' => 'retired',
            'freshness_label' => 'Legacy summary retired',
        ],
    ];
}

