function battle_intelligence_character_data(int $characterId, ?array $prefetchedCharacter = null): array
{
    $character = $prefetchedCharacter ?? db_battle_intelligence_character($characterId);
    $battles = db_battle_intelligence_character_battles($characterId, 30);
    $evidence = db_battle_intelligence_character_evidence($characterId, 60);
    $orgHistory = [];

    if (is_array($character)) {
        $decodedOrgHistory = json_decode((string) ($character['org_history_json'] ?? '[]'), true);
        if (is_array($decodedOrgHistory)) {
            // The raw EveWho payload stores corporation_history at the top level,
            // but the rendering code expects a {'history': [...], 'info': {...}} structure.
            if (isset($decodedOrgHistory['corporation_history']) && is_array($decodedOrgHistory['corporation_history'])) {
                $rawHistory = $decodedOrgHistory['corporation_history'];
                // Sort by start_date ascending so we can compute end_date from the next entry
                usort($rawHistory, static function (array $a, array $b): int {
                    return strcmp((string) ($a['start_date'] ?? ''), (string) ($b['start_date'] ?? ''));
                });
                $history = [];
                $count = count($rawHistory);
                for ($i = 0; $i < $count; $i++) {
                    $entry = $rawHistory[$i];
                    $startDate = (string) ($entry['start_date'] ?? '');
                    // end_date is the start_date of the next entry, or null if current
                    $endDate = ($i + 1 < $count) ? (string) ($rawHistory[$i + 1]['start_date'] ?? '') : null;
                    // Normalize ISO dates to Y-m-d format
                    if ($startDate !== '') {
                        $startDate = substr($startDate, 0, 10);
                    }
                    if ($endDate !== null && $endDate !== '') {
                        $endDate = substr($endDate, 0, 10);
                    }
                    $history[] = [
                        'corporation_id' => (int) ($entry['corporation_id'] ?? 0),
                        'start_date' => $startDate,
                        'end_date' => $endDate,
                    ];
                }
                $orgHistory = [
                    'history' => $history,
                    'info' => [
                        'corporation_id' => (int) ($decodedOrgHistory['corporation_id'] ?? 0),
                        'alliance_id' => (int) ($decodedOrgHistory['alliance_id'] ?? 0),
                    ],
                ];
            } elseif (isset($decodedOrgHistory['history'])) {
                // Already in the expected format
                $orgHistory = $decodedOrgHistory;
            }
        }
    }

    foreach ($evidence as &$evidenceRow) {
        $payload = json_decode((string) ($evidenceRow['evidence_payload_json'] ?? 'null'), true);
        $evidenceRow['evidence_payload'] = is_array($payload) ? $payload : null;
    }
    unset($evidenceRow);

    foreach ($battles as &$battle) {
        if (!isset($battle['anomaly_class']) || trim((string) $battle['anomaly_class']) === '') {
            $battle['anomaly_class'] = ((float) ($battle['overperformance_score'] ?? 0.0)) > 0.0 ? 'overperformance' : 'normal';
        }
    }
    unset($battle);

    return [
        'character' => $character,
        'battles' => $battles,
        'evidence' => $evidence,
        'org_history' => $orgHistory,
    ];
}

function battle_intelligence_battle_data(string $battleId): array
{
    $battle = db_battle_intelligence_battle($battleId);
    $sides = db_battle_intelligence_battle_sides($battleId);
    $actors = db_battle_intelligence_battle_notable_actors($battleId, 40);
    $hullAnomalies = db_battle_intelligence_battle_hull_anomalies($battleId, 80);

    foreach ($sides as &$side) {
        $decoded = json_decode((string) ($side['evidence_json'] ?? '{}'), true);
        $side['evidence'] = is_array($decoded) ? $decoded : [];
    }
    unset($side);

    return [
        'battle' => $battle,
        'sides' => $sides,
        'actors' => $actors,
        'hull_anomalies' => $hullAnomalies,
    ];
}

// ---------------------------------------------------------------------------
// On-demand character intelligence computation
// ---------------------------------------------------------------------------

/**
 * Compute character intelligence scores on-demand for a single character.
 *
 * Replicates the core scoring logic from the Python compute_counterintel_pipeline
 * job so that users can get immediate results without waiting for the scheduler.
 */
function compute_character_intelligence_on_demand(int $characterId): array
{
    if ($characterId <= 0) {
        return ['ok' => false, 'message' => 'Invalid character ID.'];
    }

    // 1. Find all eligible battles the character participated in
    $participations = db_select(
        'SELECT bp.battle_id, bp.side_key, bp.corporation_id, bp.alliance_id,
                COALESCE(cgi.bridge_score, 0) AS bridge_score
         FROM battle_participants bp
         LEFT JOIN character_graph_intelligence cgi ON cgi.character_id = bp.character_id
         WHERE bp.character_id = ?
           AND bp.battle_id IN (
               SELECT br.battle_id FROM battle_rollups br
               WHERE br.eligible_for_suspicion = 1
                 AND br.participant_count >= 20
           )',
        [$characterId]
    );

    if ($participations === []) {
        return ['ok' => false, 'message' => 'No eligible battle participation found for this character. The character must appear in battles with 20+ participants to generate intelligence.'];
    }

    $battleIds = array_values(array_unique(array_column($participations, 'battle_id')));
    if ($battleIds === []) {
        return ['ok' => false, 'message' => 'No battle IDs found.'];
    }

    // 2. Fetch overperformance scores for those battles
    $placeholders = implode(',', array_fill(0, count($battleIds), '?'));
    $overRows = db_select(
        "SELECT battle_id, side_key, anomaly_class, sustain_lift_score
         FROM battle_enemy_overperformance_scores
         WHERE battle_id IN ({$placeholders})",
        $battleIds
    );

    $anomalousBattles = [];
    $controlBattles = [];
    $sustainByBattleSide = [];
    foreach ($overRows as $row) {
        $key = $row['battle_id'] . '|' . $row['side_key'];
        $sustainByBattleSide[$key] = (float) ($row['sustain_lift_score'] ?? 0.0);
        if ($row['anomaly_class'] === 'high_enemy_overperformance') {
            $anomalousBattles[$key] = true;
        } else {
            $controlBattles[$key] = true;
        }
    }

    // 3. Compute features for this character
    $anomalyHits = 0;
    $controlHits = 0;
    $sustainLifts = [];
    $bridgeScores = [];
    $anomalousBattleIds = [];

    foreach ($participations as $row) {
        $battleId = (string) $row['battle_id'];
        $sideKey = (string) ($row['side_key'] ?? 'unknown');
        $key = $battleId . '|' . $sideKey;

        if (isset($anomalousBattles[$key])) {
            $anomalyHits++;
            $anomalousBattleIds[$battleId] = true;
        }
        if (isset($controlBattles[$key])) {
            $controlHits++;
        }

        $bridgeScores[] = (float) ($row['bridge_score'] ?? 0.0);

        // Get enemy sustain lift (from opposing sides)
        foreach ($overRows as $over) {
            if ((string) $over['battle_id'] === $battleId && (string) $over['side_key'] !== $sideKey) {
                $sustainLifts[] = (float) ($over['sustain_lift_score'] ?? 0.0);
            }
        }
    }

    $anomalousBattleDenominator = max(1, count($anomalousBattles));
    $controlBattleDenominator = max(1, count($controlBattles));
    $anomalousRate = $anomalousBattleDenominator > 0 ? (float) $anomalyHits / (float) $anomalousBattleDenominator : 0.0;
    $controlRate = $controlBattleDenominator > 0 ? (float) $controlHits / (float) $controlBattleDenominator : 0.0;
    $presenceDelta = $anomalousRate - $controlRate;
    $enemySustainLift = count($sustainLifts) > 0 ? array_sum($sustainLifts) / (float) count($sustainLifts) : 0.0;
    $bridge = count($bridgeScores) > 0 ? array_sum($bridgeScores) / (float) count($bridgeScores) : 0.0;

    // Org history metrics
    $orgRow = db_select_one(
        "SELECT corp_hops_180d, short_tenure_hops_180d
         FROM character_org_history_cache
         WHERE character_id = ? AND source = 'evewho'
           AND (expires_at IS NULL OR expires_at > UTC_TIMESTAMP())
         ORDER BY fetched_at DESC LIMIT 1",
        [$characterId]
    );
    $corpHops = (int) ($orgRow['corp_hops_180d'] ?? 0);
    $shortHops = (int) ($orgRow['short_tenure_hops_180d'] ?? 0);
    $corpHopFrequency = $corpHops / 180.0;
    $shortTenureRatio = $corpHops > 0 ? (float) $shortHops / (float) $corpHops : 0.0;

    // Repeatability
    $repeatability = min(1.0, (float) $anomalyHits / 3.0);

    // 4. Compute review priority score (same formula as Python pipeline)
    $reviewScore = max(0.0, min(1.0,
        0.24 * $anomalousRate
        + 0.1 * max(0.0, $presenceDelta)
        + 0.26 * min(1.0, $enemySustainLift / 1.5)
        + 0.2 * min(1.0, $bridge / 5.0)
        + 0.1 * min(1.0, $corpHopFrequency * 10)
        + 0.1 * $repeatability
    ));

    $confidenceScore = min(1.0, (float) ($anomalyHits + $controlHits) / 8.0);
    $computedAt = gmdate('Y-m-d H:i:s');

    // 5. Write features
    db_execute(
        'INSERT INTO character_counterintel_features (
            character_id, anomalous_battle_presence_count, control_battle_presence_count,
            anomalous_battle_denominator, control_battle_denominator,
            anomalous_presence_rate, control_presence_rate, enemy_same_hull_survival_lift,
            enemy_sustain_lift, co_presence_anomalous_density, graph_bridge_score,
            corp_hop_frequency_180d, short_tenure_ratio_180d, repeatability_score, computed_at
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        ON DUPLICATE KEY UPDATE
            anomalous_battle_presence_count = VALUES(anomalous_battle_presence_count),
            control_battle_presence_count = VALUES(control_battle_presence_count),
            anomalous_battle_denominator = VALUES(anomalous_battle_denominator),
            control_battle_denominator = VALUES(control_battle_denominator),
            anomalous_presence_rate = VALUES(anomalous_presence_rate),
            control_presence_rate = VALUES(control_presence_rate),
            enemy_same_hull_survival_lift = VALUES(enemy_same_hull_survival_lift),
            enemy_sustain_lift = VALUES(enemy_sustain_lift),
            co_presence_anomalous_density = VALUES(co_presence_anomalous_density),
            graph_bridge_score = VALUES(graph_bridge_score),
            corp_hop_frequency_180d = VALUES(corp_hop_frequency_180d),
            short_tenure_ratio_180d = VALUES(short_tenure_ratio_180d),
            repeatability_score = VALUES(repeatability_score),
            computed_at = VALUES(computed_at)',
        [
            $characterId, $anomalyHits, $controlHits,
            count($anomalousBattles), count($controlBattles),
            $anomalousRate, $controlRate, $enemySustainLift,
            $enemySustainLift, $anomalousRate, $bridge,
            $corpHopFrequency, $shortTenureRatio, $repeatability, $computedAt,
        ]
    );

    // 6. Write scores (percentile_rank set to 0; full cohort ranking requires full pipeline)
    db_execute(
        'INSERT INTO character_counterintel_scores (
            character_id, review_priority_score, percentile_rank, confidence_score, evidence_count, computed_at
        ) VALUES (?, ?, ?, ?, ?, ?)
        ON DUPLICATE KEY UPDATE
            review_priority_score = VALUES(review_priority_score),
            percentile_rank = VALUES(percentile_rank),
            confidence_score = VALUES(confidence_score),
            evidence_count = VALUES(evidence_count),
            computed_at = VALUES(computed_at)',
        [$characterId, $reviewScore, 0.0, $confidenceScore, 8, $computedAt]
    );

    // 7. Write core evidence signals
    $presencePayload = json_encode([
        'anomalous' => ['numerator' => $anomalyHits, 'denominator' => count($anomalousBattles), 'rate' => $anomalousRate],
        'control' => ['numerator' => $controlHits, 'denominator' => count($controlBattles), 'rate' => $controlRate],
        'delta' => $presenceDelta,
    ]);
    $sustainPayload = json_encode([
        'enemy_same_hull_survival_lift' => $enemySustainLift,
        'sample_count' => count($sustainLifts),
    ]);
    $graphPayload = json_encode([
        'co_presence_anomalous_density' => $anomalousRate,
        'graph_bridge_score' => $bridge,
    ]);
    $orgPayload = json_encode([
        'window_days' => 180,
        'corp_hops' => $corpHops,
        'short_tenure_hops' => $shortHops,
        'corp_hop_frequency_per_day' => $corpHopFrequency,
        'short_tenure_ratio' => $shortTenureRatio,
    ]);
    $repeatPayload = json_encode([
        'anomalous_battle_count' => count($anomalousBattleIds),
        'repeatability_score' => $repeatability,
    ]);

    $evidenceRows = [
        ['anomalous_battle_presence_count', 'all_time', (float) $anomalyHits, "present in {$anomalyHits}/" . count($anomalousBattles) . " anomalous large battle-sides", $presencePayload],
        ['anomalous_presence_rate', 'all_time', $anomalousRate, sprintf('anomalous presence rate %.3f vs control %.3f', $anomalousRate, $controlRate), $presencePayload],
        ['presence_rate_delta', 'all_time', $presenceDelta, sprintf('presence delta %.3f', $presenceDelta), $presencePayload],
        ['enemy_sustain_lift', 'all_time', $enemySustainLift, sprintf('enemy sustain lift %.3f when present', $enemySustainLift), $sustainPayload],
        ['enemy_same_hull_survival_lift_detail', 'all_time', $enemySustainLift, sprintf('same-hull enemy survival lift %.3f across %d samples', $enemySustainLift, count($sustainLifts)), $sustainPayload],
        ['graph_copresence_cluster_proximity', 'all_time', min(1.0, $bridge / 5.0), sprintf('graph bridge %.3f, anomalous co-presence density %.3f', $bridge, $anomalousRate), $graphPayload],
        ['org_history_movement_180d', '180d', $corpHopFrequency, sprintf('org movement over 180d: %d hops, %d short-tenure, ratio %.3f', $corpHops, $shortHops, $shortTenureRatio), $orgPayload],
        ['repeatability_across_battles_windows', 'all_time', $repeatability, sprintf('repeatability %.3f: %d anomalous battles', $repeatability, count($anomalousBattleIds)), $repeatPayload],
    ];

    foreach ($evidenceRows as [$evidenceKey, $windowLabel, $evidenceValue, $evidenceText, $payloadJson]) {
        db_execute(
            'INSERT INTO character_counterintel_evidence (
                character_id, evidence_key, window_label, evidence_value, evidence_text, evidence_payload_json, computed_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?)
            ON DUPLICATE KEY UPDATE
                evidence_value = VALUES(evidence_value),
                evidence_text = VALUES(evidence_text),
                evidence_payload_json = VALUES(evidence_payload_json),
                computed_at = VALUES(computed_at)',
            [$characterId, $evidenceKey, $windowLabel, $evidenceValue, $evidenceText, $payloadJson, $computedAt]
        );
    }

    // 8. Lane 2: compute behavioral signals from killmail activity (last 90 days)
    $cutoff = gmdate('Y-m-d H:i:s', strtotime('-90 days'));
    $killRows = db_select(
        'SELECT ka.damage_done, ka.alliance_id,
                ke.sequence_id, ke.killmail_time, ke.solar_system_id,
                ke.victim_alliance_id,
                COALESCE(br.participant_count, 0) AS participant_count
         FROM killmail_attackers ka
         INNER JOIN killmail_events ke ON ke.sequence_id = ka.sequence_id
         LEFT JOIN battle_rollups br ON br.battle_id = ke.battle_id
         WHERE ka.character_id = ?
           AND ke.effective_killmail_at >= ?
         ORDER BY ke.killmail_time',
        [$characterId, $cutoff]
    );

    if ($killRows !== []) {
        // Count attackers per kill for copresence/asymmetry signals.
        $seqIds = array_unique(array_column($killRows, 'sequence_id'));
        $seqPlaceholders = implode(',', array_fill(0, count($seqIds), '?'));
        $attackerCounts = [];
        if ($seqIds !== []) {
            $acRows = db_select(
                "SELECT sequence_id, COUNT(*) AS cnt FROM killmail_attackers WHERE sequence_id IN ({$seqPlaceholders}) GROUP BY sequence_id",
                array_values($seqIds)
            );
            foreach ($acRows as $ac) {
                $attackerCounts[(int) $ac['sequence_id']] = (int) $ac['cnt'];
            }
        }

        $soloKills = $gangKills = $largeBattleKills = 0;
        $systemCounts = [];
        $timestamps = [];
        $ownAlliances = [];
        $crossSideKills = 0;

        foreach ($killRows as $k) {
            $pc = (int) $k['participant_count'];
            if ($pc <= 4)       $soloKills++;
            elseif ($pc <= 19)  $gangKills++;
            else                $largeBattleKills++;
            $sys = (int) ($k['solar_system_id'] ?? 0);
            if ($sys > 0) $systemCounts[$sys] = ($systemCounts[$sys] ?? 0) + 1;
            $t = strtotime((string) ($k['killmail_time'] ?? ''));
            if ($t) $timestamps[] = $t;
            $a = (int) ($k['alliance_id'] ?? 0);
            if ($a > 0) $ownAlliances[$a] = true;
        }
        foreach ($killRows as $k) {
            $va = (int) ($k['victim_alliance_id'] ?? 0);
            $pc = (int) $k['participant_count'];
            if ($pc < 20 && $va > 0 && isset($ownAlliances[$va])) $crossSideKills++;
        }

        $totalKills = count($killRows);
        $smallKills = $soloKills + $gangKills;

        // Fleet-absence ratio.
        $largeBattleCount = (int) (db_select_one(
            'SELECT COUNT(DISTINCT bp.battle_id) AS cnt FROM battle_participants bp
             INNER JOIN battle_rollups br ON br.battle_id = bp.battle_id
             WHERE bp.character_id = ? AND br.participant_count >= 20 AND br.started_at >= ?',
            [$characterId, $cutoff]
        ) ?? [])['cnt'] ?? 0;
        $fleetAbsenceRatio = ($smallKills + $largeBattleCount) > 0
            ? $smallKills / ($smallKills + $largeBattleCount) : 0.0;

        // Continuation rate.
        sort($timestamps);
        $contHits = $contEligible = 0;
        for ($i = 0; $i < count($timestamps) - 1; $i++) {
            $contEligible++;
            for ($j = $i + 1; $j < min($i + 10, count($timestamps)); $j++) {
                if (($timestamps[$j] - $timestamps[$i]) <= 1800) { $contHits++; break; }
                if (($timestamps[$j] - $timestamps[$i]) > 1800) break;
            }
        }
        $continuationRate = $contEligible > 0 ? $contHits / $contEligible : 0.0;

        // Geographic Gini.
        $sysValues = array_values($systemCounts);
        sort($sysValues);
        $n = count($sysValues); $total = array_sum($sysValues);
        $geoGini = 0.0;
        if ($n > 1 && $total > 0) {
            $cum = 0.0; $area = 0.0;
            foreach ($sysValues as $i => $v) {
                $cum += $v; $area += $cum / $total - ($i + 1) / $n;
            }
            $geoGini = min(1.0, max(0.0, 2.0 * $area / $n * $n / ($n - 1)));
        }

        // Temporal burstiness.
        $temporalReg = 0.0;
        if (count($timestamps) >= 3) {
            $intervals = [];
            for ($i = 0; $i < count($timestamps) - 1; $i++) {
                $d = $timestamps[$i + 1] - $timestamps[$i];
                if ($d > 0) $intervals[] = (float) $d;
            }
            if (count($intervals) >= 2) {
                $mu = array_sum($intervals) / count($intervals);
                $sigma = sqrt(array_sum(array_map(fn($x) => ($x - $mu) ** 2, $intervals)) / count($intervals));
                $b = ($sigma + $mu) > 0 ? ($sigma - $mu) / ($sigma + $mu) : 0.0;
                $temporalReg = min(1.0, max(0.0, ($b + 1.0) / 2.0));
            }
        }

        // Asymmetry preference (solo tier only).
        $soloCounts = array_filter(array_map(
            fn($k) => (int) $k['participant_count'] <= 4 ? ($attackerCounts[(int) $k['sequence_id']] ?? 1) : null,
            $killRows
        ));
        $asymmetry = count($soloCounts) > 0
            ? count(array_filter($soloCounts, fn($c) => $c >= 5)) / count($soloCounts) : 0.0;

        // Cross-side rate.
        $crossSideRate = $smallKills > 0 ? $crossSideKills / $smallKills : 0.0;

        // Kill concentration.
        $asymCounts = array_filter(array_column(
            array_map(fn($k) => ['pc' => (int) $k['participant_count'], 'seq' => (int) $k['sequence_id']], $killRows),
            'pc'
        ), fn($pc) => $pc <= 4);
        $killConc = $totalKills > 0 ? count(array_filter(
            array_map(fn($k) => ($attackerCounts[(int) $k['sequence_id']] ?? 1), $killRows),
            fn($c) => $c >= 5
        )) / $totalKills : 0.0;

        // Companion consistency (fraction of small kills with a co-attacker seen 2+ times).
        $companionCounts = [];
        foreach ($killRows as $k) {
            if ((int) $k['participant_count'] >= 20) continue;
            // We don't have per-kill attacker lists here; skip for on-demand.
        }
        $companionConsistency = 0.0; // Deferred to batch pipeline for full accuracy.

        $behScore = max(0.0, min(1.0,
            0.15 * $fleetAbsenceRatio
            + 0.10 * (1.0 - $continuationRate)
            + 0.10 * $killConc
            + 0.10 * $geoGini
            + 0.10 * $temporalReg
            + 0.20 * $companionConsistency
            + 0.15 * $crossSideRate
            + 0.10 * $asymmetry
        ));
        $behConfidence = $totalKills >= 30 ? 'high' : ($totalKills >= 10 ? 'medium' : 'low');

        db_execute(
            'INSERT INTO character_behavioral_scores (
                character_id, behavioral_risk_score, percentile_rank, confidence_tier,
                total_kill_count, solo_kill_count, gang_kill_count, large_battle_count,
                fleet_absence_ratio, post_engagement_continuation_rate,
                kill_concentration_score, geographic_concentration_score,
                temporal_regularity_score, companion_consistency_score,
                cross_side_small_rate, asymmetry_preference, computed_at
            ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
            ON DUPLICATE KEY UPDATE
                behavioral_risk_score = VALUES(behavioral_risk_score),
                confidence_tier = VALUES(confidence_tier),
                total_kill_count = VALUES(total_kill_count),
                solo_kill_count = VALUES(solo_kill_count),
                gang_kill_count = VALUES(gang_kill_count),
                large_battle_count = VALUES(large_battle_count),
                fleet_absence_ratio = VALUES(fleet_absence_ratio),
                post_engagement_continuation_rate = VALUES(post_engagement_continuation_rate),
                kill_concentration_score = VALUES(kill_concentration_score),
                geographic_concentration_score = VALUES(geographic_concentration_score),
                temporal_regularity_score = VALUES(temporal_regularity_score),
                companion_consistency_score = VALUES(companion_consistency_score),
                cross_side_small_rate = VALUES(cross_side_small_rate),
                asymmetry_preference = VALUES(asymmetry_preference),
                computed_at = VALUES(computed_at)',
            [
                $characterId, round($behScore, 6), 0.0, $behConfidence,
                $totalKills, $soloKills, $gangKills, $largeBattleCount,
                round($fleetAbsenceRatio, 6), round($continuationRate, 6),
                round($killConc, 6), round($geoGini, 6),
                round($temporalReg, 6), 0.0,
                round($crossSideRate, 6), round($asymmetry, 6), $computedAt,
            ]
        );
    }

    return [
        'ok' => true,
        'message' => sprintf(
            'Intelligence computed: %.2f priority score from %d battles (%d anomalous, %d control). Behavioral signals updated from %d kills.',
            $reviewScore,
            count($battleIds),
            $anomalyHits,
            $controlHits,
            count($killRows ?? [])
        ),
    ];
}

// ---------------------------------------------------------------------------
// Automatic database migration system
// ---------------------------------------------------------------------------

function supplycore_migrations_dir(): string
{
    return dirname(__DIR__) . '/database/migrations';
}

function supplycore_migration_files(): array
{
    $dir = supplycore_migrations_dir();
    if (!is_dir($dir)) {
        return [];
    }

    $files = [];
    foreach (scandir($dir) as $entry) {
        if (str_ends_with($entry, '.sql') && $entry[0] !== '.') {
            $files[] = $entry;
        }
    }
    sort($files);

    return $files;
}

function supplycore_migration_pdo(): PDO
{
    // Dedicated connection for migrations.  Emulated prepares are enabled so
    // that MariaDB never leaves an unconsumed result set from exec()/query()
    // blocking a subsequent prepared-statement execute().
    $dsn = sprintf(
        'mysql:host=%s;port=%d;dbname=%s;charset=%s',
        (string) supplycore_base_config_value('db.host', '127.0.0.1'),
        (int) supplycore_base_config_value('db.port', 3306),
        (string) supplycore_base_config_value('db.database', ''),
        (string) supplycore_base_config_value('db.charset', 'utf8mb4')
    );

    return new PDO(
        $dsn,
        (string) supplycore_base_config_value('db.username', ''),
        (string) supplycore_base_config_value('db.password', ''),
        [
            PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
            PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
            PDO::ATTR_EMULATE_PREPARES => true,
        ]
    );
}

function supplycore_run_migrations(bool $dryRun = false, bool $statusOnly = false): array
{
    // Use a dedicated PDO connection so migration DDL never conflicts with
    // open cursors on the main app connection (MariaDB unbuffered-query fix).
    $pdo = supplycore_migration_pdo();

    $pdo->exec(
        'CREATE TABLE IF NOT EXISTS schema_migrations (
            id INT UNSIGNED NOT NULL AUTO_INCREMENT PRIMARY KEY,
            filename VARCHAR(255) NOT NULL,
            file_hash CHAR(64) NOT NULL,
            applied_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
            duration_ms INT UNSIGNED NOT NULL DEFAULT 0,
            status ENUM("applied","failed") NOT NULL DEFAULT "applied",
            error_message TEXT DEFAULT NULL,
            UNIQUE KEY uq_schema_migrations_filename (filename)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4'
    );

    $stmt = $pdo->query('SELECT filename, file_hash, applied_at, status, error_message FROM schema_migrations ORDER BY filename ASC');
    $existingRows = $stmt->fetchAll();
    $applied = [];
    foreach ($existingRows as $row) {
        $applied[(string) $row['filename']] = $row;
    }

    $migrationFiles = supplycore_migration_files();
    $dir = supplycore_migrations_dir();
    $pending = [];
    $errors = [];
    $migrationsRun = 0;

    foreach ($migrationFiles as $filename) {
        $filePath = $dir . '/' . $filename;
        $fileHash = hash_file('sha256', $filePath);

        if (isset($applied[$filename])) {
            $prev = $applied[$filename];
            if ((string) $prev['file_hash'] === $fileHash && (string) $prev['status'] === 'applied') {
                continue;
            }
        }

        $pending[] = $filename;
    }

    if ($statusOnly) {
        return ['applied' => $applied, 'pending' => $pending];
    }

    $recordStmt = $pdo->prepare(
        'INSERT INTO schema_migrations (filename, file_hash, applied_at, duration_ms, status, error_message)
         VALUES (?, ?, UTC_TIMESTAMP(), ?, ?, ?)
         ON DUPLICATE KEY UPDATE
            file_hash = VALUES(file_hash),
            applied_at = VALUES(applied_at),
            duration_ms = VALUES(duration_ms),
            status = VALUES(status),
            error_message = VALUES(error_message)'
    );

    foreach ($pending as $filename) {
        $filePath = $dir . '/' . $filename;
        $fileHash = hash_file('sha256', $filePath);
        $sql = file_get_contents($filePath);
        if ($sql === false || trim($sql) === '') {
            continue;
        }

        if ($dryRun) {
            $migrationsRun++;
            continue;
        }

        $startedAt = microtime(true);
        try {
            $statements = supplycore_split_sql_statements($sql);
            foreach ($statements as $statement) {
                $trimmed = trim($statement);
                if ($trimmed === '') {
                    continue;
                }
                // Use query() + closeCursor() instead of exec() so that
                // SELECT statements (e.g. validation queries) have their
                // result sets fully consumed before the next statement.
                $result = $pdo->query($trimmed);
                if ($result instanceof PDOStatement) {
                    $result->closeCursor();
                }
            }
            $durationMs = (int) ((microtime(true) - $startedAt) * 1000);
            $recordStmt->execute([$filename, $fileHash, $durationMs, 'applied', null]);
            $migrationsRun++;
        } catch (Throwable $e) {
            $durationMs = (int) ((microtime(true) - $startedAt) * 1000);
            $errorMsg = mb_substr($e->getMessage(), 0, 2000);
            try {
                $recordStmt->execute([$filename, $fileHash, $durationMs, 'failed', $errorMsg]);
            } catch (Throwable) {
                // If recording fails too, just capture the original error.
            }
            $errors[] = ['file' => $filename, 'message' => $errorMsg];
        }
    }

    return [
        'migrations_run' => $migrationsRun,
        'errors' => $errors,
        'pending_count' => count($pending),
    ];
}

function supplycore_split_sql_statements(string $sql): array
{
    $statements = [];
    $current = '';
    $delimiter = ';';
    $inString = false;
    $stringChar = '';
    $escaped = false;
    $len = strlen($sql);

    for ($i = 0; $i < $len; $i++) {
        $char = $sql[$i];

        if ($escaped) {
            $current .= $char;
            $escaped = false;
            continue;
        }

        if ($char === '\\') {
            $current .= $char;
            $escaped = true;
            continue;
        }

        if ($inString) {
            $current .= $char;
            if ($char === $stringChar) {
                $inString = false;
            }
            continue;
        }

        if ($char === '\'' || $char === '"') {
            $inString = true;
            $stringChar = $char;
            $current .= $char;
            continue;
        }

        if ($char === '-' && $i + 1 < $len && $sql[$i + 1] === '-') {
            $end = strpos($sql, "\n", $i);
            if ($end === false) {
                break;
            }
            $i = $end;
            $current .= "\n";
            continue;
        }

        if ($char === $delimiter) {
            $trimmed = trim($current);
            if ($trimmed !== '') {
                $statements[] = $trimmed;
            }
            $current = '';
            continue;
        }

        $current .= $char;
    }

    $trimmed = trim($current);
    if ($trimmed !== '') {
        $statements[] = $trimmed;
    }

    return $statements;
}

function supplycore_check_pending_migrations(): array
{
    try {
        $pdo = supplycore_migration_pdo();
        $pdo->exec(
            'CREATE TABLE IF NOT EXISTS schema_migrations (
                id INT UNSIGNED NOT NULL AUTO_INCREMENT PRIMARY KEY,
                filename VARCHAR(255) NOT NULL,
                file_hash CHAR(64) NOT NULL,
                applied_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
                duration_ms INT UNSIGNED NOT NULL DEFAULT 0,
                status ENUM("applied","failed") NOT NULL DEFAULT "applied",
                error_message TEXT DEFAULT NULL,
                UNIQUE KEY uq_schema_migrations_filename (filename)
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4'
        );
        $stmt = $pdo->query('SELECT filename, file_hash, status FROM schema_migrations ORDER BY filename ASC');
        $existingRows = $stmt->fetchAll();
    } catch (Throwable) {
        return ['pending' => 0, 'files' => []];
    }

    $applied = [];
    foreach ($existingRows as $row) {
        $applied[(string) $row['filename']] = $row;
    }

    $migrationFiles = supplycore_migration_files();
    $dir = supplycore_migrations_dir();
    $pending = [];

    foreach ($migrationFiles as $filename) {
        $filePath = $dir . '/' . $filename;
        if (!is_file($filePath)) {
            continue;
        }
        $fileHash = hash_file('sha256', $filePath);

        if (isset($applied[$filename])) {
            $prev = $applied[$filename];
            if ((string) $prev['file_hash'] === $fileHash && (string) $prev['status'] === 'applied') {
                continue;
            }
        }

        $pending[] = $filename;
    }

    return ['pending' => count($pending), 'files' => $pending];
}

// ── Item Criticality Helpers ───────────────────────────────────────────────

function trend_regime_label(string $regime): string
{
    return match ($regime) {
        'spike'   => 'Price Spike',
        'crash'   => 'Price Crash',
        'rising'  => 'Rising',
        'falling' => 'Falling',
        'stable'  => 'Stable',
        default   => ucfirst($regime),
    };
}

function trend_regime_color_class(string $regime): string
{
    return match ($regime) {
        'spike'   => 'text-red-400',
        'crash'   => 'text-orange-400',
        'rising'  => 'text-amber-300',
        'falling' => 'text-sky-300',
        'stable'  => 'text-emerald-300',
        default   => 'text-zinc-400',
    };
}

function criticality_tier(float $score): string
{
    if ($score >= 70) return 'critical';
    if ($score >= 45) return 'high';
    if ($score >= 20) return 'medium';
    return 'low';
}

function criticality_tier_color_class(string $tier): string
{
    return match ($tier) {
        'critical' => 'text-red-400',
        'high'     => 'text-orange-400',
        'medium'   => 'text-amber-300',
        'low'      => 'text-zinc-400',
        default    => 'text-zinc-400',
    };
}

// ── Economic Warfare ─────────────────────────────────────────────────────────

function economic_warfare_page_data(array $filters = []): array
{
    $safeFilters = [];
    if (isset($filters['hostile_alliance_id']) && (int) $filters['hostile_alliance_id'] > 0) {
        $safeFilters['hostile_alliance_id'] = (int) $filters['hostile_alliance_id'];
    }
    if (isset($filters['min_score'])) {
        $safeFilters['min_score'] = max(0, min(1, (float) $filters['min_score']));
    }
    if (isset($filters['meta_group_id']) && (int) $filters['meta_group_id'] > 0) {
        $safeFilters['meta_group_id'] = (int) $filters['meta_group_id'];
    }

    $limit = max(1, min(200, (int) ($filters['limit'] ?? 100)));
    $offset = max(0, (int) ($filters['offset'] ?? 0));

    $summary = db_economic_warfare_summary();
    $scores = db_economic_warfare_scores($safeFilters, $limit, $offset);
    $families = db_hostile_fit_families($safeFilters, 50, 0);
    $hostileAlliances = db_economic_warfare_hostile_alliances();

    $totalFamilies = 0;
    $totalObservations = 0;
    foreach ($families as $fam) {
        $totalFamilies++;
        $totalObservations += (int) ($fam['observation_count'] ?? 0);
    }

    $topTarget = null;
    if ($scores !== []) {
        $topTarget = $scores[0]['type_name'] ?? ('Type #' . ($scores[0]['type_id'] ?? '?'));
    }

    return [
        'summary' => [
            'modules_scored' => (int) ($summary['modules_scored'] ?? 0),
            'fit_families' => $totalFamilies,
            'total_observations' => $totalObservations,
            'hostile_alliances' => count($hostileAlliances),
            'top_target' => $topTarget,
            'avg_replacement_friction' => round((float) ($summary['avg_replacement_friction'] ?? 0), 3),
            'computed_at' => $summary['computed_at'] ?? null,
        ],
        'scores' => $scores,
        'families' => $families,
        'hostile_alliances' => $hostileAlliances,
        'filters' => $safeFilters,
    ];
}

function ew_constraint_label(float $score): string
{
    if ($score >= 0.7) {
        return 'high_constraint';
    }
    if ($score >= 0.4) {
        return 'medium_constraint';
    }
    return 'low_constraint';
}

function ew_constraint_color_class(float $score): string
{
    if ($score >= 0.7) {
        return 'text-red-400';
    }
    if ($score >= 0.4) {
        return 'text-amber-300';
    }
    return 'text-zinc-400';
}

function ew_meta_group_label(int $metaGroupId): string
{
    return match ($metaGroupId) {
        1  => 'T1',
        2  => 'T2',
        4  => 'Faction',
        6  => 'Deadspace',
        14 => 'T3',
        53 => 'Officer',
        default => 'Meta ' . $metaGroupId,
    };
}

// ---------------------------------------------------------------------------
// Page cache helpers (DB-backed, works without Redis)
// ---------------------------------------------------------------------------

function page_cache_get(string $key): mixed
{
    $row = db_select_one(
        "SELECT cache_value FROM page_cache WHERE cache_key = ? AND expires_at > NOW()",
        [$key]
    );

    return $row ? json_decode($row['cache_value'], true) : null;
}

function page_cache_set(string $key, mixed $data, int $ttl = 300): void
{
    db_execute(
        "REPLACE INTO page_cache (cache_key, cache_value, computed_at, expires_at)
         VALUES (?, ?, NOW(), DATE_ADD(NOW(), INTERVAL ? SECOND))",
        [$key, json_encode($data, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE), $ttl]
    );
}

function page_cache_clear(string $key): void
{
    db_execute("DELETE FROM page_cache WHERE cache_key = ?", [$key]);
}

function page_cache_flush_expired(): int
{
    db_execute("DELETE FROM page_cache WHERE expires_at <= NOW()");

    return 0;
}

// ---------------------------------------------------------------------------
// Log Viewer
// ---------------------------------------------------------------------------

function log_viewer_page_data(): array
{
    $registry = supplycore_authoritative_job_registry();

    // ── Schedules with current status ─────────────────────────────────
    $schedules = db_select(
        "SELECT s.*, cs.latest_status, cs.latest_event_type,
                cs.last_started_at, cs.last_finished_at,
                cs.last_success_at, cs.last_failure_at, cs.last_failure_message,
                cs.current_pressure_state, cs.recent_timeout_count,
                cs.recent_lock_conflict_count, cs.recent_deferral_count,
                cs.recent_skip_count, cs.last_planner_decision_type,
                cs.last_planner_reason_text,
                cs.last_run_summary
         FROM sync_schedules s
         LEFT JOIN scheduler_job_current_status cs ON cs.job_key = s.job_key
         ORDER BY s.job_key"
    );

    // ── Recent runs — one row per job showing latest run ───────────────
    // Instead of 200 raw rows (mostly noise), show the most recent run per
    // unique job, plus any currently running or failed runs for context.
    $recentRunsRaw = db_select(
        "SELECT r.dataset_key, r.run_status, r.started_at, r.finished_at,
                r.source_rows, r.written_rows, r.error_message, r.summary,
                TIMESTAMPDIFF(SECOND, r.started_at, COALESCE(r.finished_at, NOW())) AS duration_seconds
         FROM sync_runs r
         ORDER BY r.started_at DESC
         LIMIT 500"
    );

    // Build a compact view: latest run per job + all running/failed entries
    $recentByJob = [];
    $recentExtra = []; // running or failed entries beyond the first per job
    foreach ($recentRunsRaw as $run) {
        $key = $run['dataset_key'];
        $isNotable = $run['run_status'] === 'running' || $run['run_status'] === 'failed';

        if (!isset($recentByJob[$key])) {
            $recentByJob[$key] = $run;
            $recentByJob[$key]['recent_success_count'] = $run['run_status'] === 'success' ? 1 : 0;
        } else {
            if ($run['run_status'] === 'success') {
                $recentByJob[$key]['recent_success_count'] = ($recentByJob[$key]['recent_success_count'] ?? 0) + 1;
            }
            if ($isNotable) {
                $recentExtra[] = $run;
            }
        }
    }

    // Merge: all notable extras + latest per job, sorted by started_at desc
    $recentRuns = array_merge(array_values($recentByJob), $recentExtra);
    usort($recentRuns, fn (array $a, array $b) => strcmp((string) ($b['started_at'] ?? ''), (string) ($a['started_at'] ?? '')));
    $recentRuns = array_slice($recentRuns, 0, 80);

    // ── Failed runs (last 24 h) — grouped by job + error pattern ──────
    $failedRunsRaw = db_select(
        "SELECT r.dataset_key, r.run_status, r.started_at, r.finished_at,
                r.error_message,
                TIMESTAMPDIFF(SECOND, r.started_at, COALESCE(r.finished_at, NOW())) AS duration_seconds
         FROM sync_runs r
         WHERE r.run_status = 'failed'
           AND r.started_at >= DATE_SUB(NOW(), INTERVAL 24 HOUR)
         ORDER BY r.started_at DESC"
    );

    // Group failures by job + error signature (first 120 chars) for deduplication
    $failedRunsGrouped = [];
    foreach ($failedRunsRaw as $run) {
        $errSig = substr(trim((string) ($run['error_message'] ?? '')), 0, 120);
        $groupKey = $run['dataset_key'] . '|' . $errSig;
        if (!isset($failedRunsGrouped[$groupKey])) {
            $failedRunsGrouped[$groupKey] = [
                'dataset_key' => $run['dataset_key'],
                'error_message' => $run['error_message'],
                'count' => 0,
                'latest_started_at' => $run['started_at'],
                'oldest_started_at' => $run['started_at'],
                'duration_seconds' => $run['duration_seconds'],
            ];
        }
        $failedRunsGrouped[$groupKey]['count']++;
        if ($run['started_at'] < $failedRunsGrouped[$groupKey]['oldest_started_at']) {
            $failedRunsGrouped[$groupKey]['oldest_started_at'] = $run['started_at'];
        }
    }
    $failedRuns = array_values($failedRunsGrouped);

    // ── Stuck / timed-out runs (running > default timeout) ────────────
    $defaultTimeout = (int) get_setting('scheduler.default_timeout_seconds', 300);
    $stuckRunsRaw = db_select(
        "SELECT r.dataset_key, r.run_status, r.started_at,
                TIMESTAMPDIFF(SECOND, r.started_at, NOW()) AS running_seconds
         FROM sync_runs r
         WHERE r.run_status = 'running'
           AND r.started_at < DATE_SUB(NOW(), INTERVAL ? SECOND)
         ORDER BY r.started_at ASC",
        [$defaultTimeout]
    );

    // Group stuck runs by job name for a cleaner display
    $stuckRunsGrouped = [];
    foreach ($stuckRunsRaw as $run) {
        $key = $run['dataset_key'];
        if (!isset($stuckRunsGrouped[$key])) {
            $stuckRunsGrouped[$key] = [
                'dataset_key' => $key,
                'count' => 0,
                'oldest_started_at' => $run['started_at'],
                'newest_started_at' => $run['started_at'],
                'max_running_seconds' => (float) $run['running_seconds'],
                'min_running_seconds' => (float) $run['running_seconds'],
            ];
        }
        $stuckRunsGrouped[$key]['count']++;
        if ($run['started_at'] < $stuckRunsGrouped[$key]['oldest_started_at']) {
            $stuckRunsGrouped[$key]['oldest_started_at'] = $run['started_at'];
            $stuckRunsGrouped[$key]['max_running_seconds'] = (float) $run['running_seconds'];
        }
        if ($run['started_at'] > $stuckRunsGrouped[$key]['newest_started_at']) {
            $stuckRunsGrouped[$key]['newest_started_at'] = $run['started_at'];
            $stuckRunsGrouped[$key]['min_running_seconds'] = (float) $run['running_seconds'];
        }
    }
    $stuckRuns = array_values($stuckRunsGrouped);

    // ── Jobs that never ran ───────────────────────────────────────────
    $neverRan = [];
    foreach ($schedules as $s) {
        if ($s['enabled'] && $s['last_run_at'] === null) {
            $neverRan[] = $s;
        }
    }

    // ── Build unified job rows ────────────────────────────────────────
    $jobs = [];
    foreach ($schedules as $s) {
        $key = $s['job_key'];
        $meta = $registry[$key] ?? [];
        $label = $meta['label'] ?? $key;

        $status = strtolower(trim((string) ($s['latest_status'] ?? $s['last_status'] ?? 'unknown')));
        $pressure = strtolower(trim((string) ($s['current_pressure_state'] ?? 'healthy')));

        // Detect stuck "running" jobs: status is running but last_started_at is
        // older than the job's timeout (or a generous fallback).  These are
        // almost certainly zombie processes whose workers crashed without
        // reporting a final status.
        $isStuckRunning = false;
        if ($status === 'running' && $s['last_run_at'] !== null) {
            $startedTs = strtotime((string) ($s['last_started_at'] ?? $s['last_run_at']));
            $stuckThreshold = max((int) ($meta['timeout_seconds'] ?? $defaultTimeout), (int) $s['interval_seconds']) * 2;
            if ($stuckThreshold < 600) {
                $stuckThreshold = 600; // at least 10 minutes
            }
            if ($startedTs !== false && (time() - $startedTs) > $stuckThreshold) {
                $isStuckRunning = true;
            }
        }

        // Determine health bucket
        if (!$s['enabled']) {
            $health = 'disabled';
            $healthTone = 'border-slate-400/20 bg-slate-500/10 text-slate-300';
            $healthLabel = 'Disabled';
        } elseif ($s['last_run_at'] === null) {
            $health = 'never_ran';
            $healthTone = 'border-violet-400/20 bg-violet-500/10 text-violet-100';
            $healthLabel = 'Never ran';
        } elseif ($status === 'failed' || $status === 'error' || $isStuckRunning) {
            $health = $isStuckRunning ? 'stuck' : 'failed';
            $healthTone = 'border-rose-400/20 bg-rose-500/10 text-rose-100';
            $healthLabel = $isStuckRunning ? 'Stuck' : 'Failed';
        } elseif ($pressure === 'critical' || ($s['recent_timeout_count'] ?? 0) > 2) {
            $health = 'timeout';
            $healthTone = 'border-orange-400/20 bg-orange-500/10 text-orange-100';
            $healthLabel = 'Timeout';
        } elseif ($pressure === 'elevated' || $status === 'delayed' || $status === 'degraded') {
            $health = 'degraded';
            $healthTone = 'border-amber-400/20 bg-amber-500/10 text-amber-100';
            $healthLabel = 'Degraded';
        } elseif ($status === 'running') {
            $health = 'running';
            $healthTone = 'border-sky-400/20 bg-sky-500/10 text-sky-100';
            $healthLabel = 'Running';
        } elseif ($status === 'success' || $status === 'completed') {
            // If the job reports success but has never actually succeeded
            // (last_success_at is NULL), demote it to "Unhealthy" so the
            // operator knows it has not produced useful output yet.
            $hasEverSucceeded = ($s['last_success_at'] ?? null) !== null;
            if ($hasEverSucceeded) {
                $health = 'healthy';
                $healthTone = 'border-emerald-400/20 bg-emerald-500/10 text-emerald-100';
                $healthLabel = 'Healthy';
            } else {
                $health = 'unhealthy';
                $healthTone = 'border-amber-400/20 bg-amber-500/10 text-amber-100';
                $healthLabel = 'Unhealthy';
            }
        } else {
            $health = 'unknown';
            $healthTone = 'border-slate-400/20 bg-slate-500/10 text-slate-200';
            $healthLabel = 'Unknown';
        }

        // Check overdue: enabled, has interval, last_run_at + interval * 2 < NOW.
        // Also flag enabled jobs that have *never* run as overdue when they've
        // existed for longer than twice their interval (created_at based).
        $overdue = false;
        if ($s['enabled'] && (int) $s['interval_seconds'] > 0) {
            if ($s['last_run_at'] !== null) {
                $lastRun = strtotime((string) $s['last_run_at']);
                if ($lastRun !== false && (time() - $lastRun) > ((int) $s['interval_seconds'] * 2)) {
                    $overdue = true;
                }
            } elseif (($s['created_at'] ?? null) !== null) {
                $createdAt = strtotime((string) $s['created_at']);
                if ($createdAt !== false && (time() - $createdAt) > ((int) $s['interval_seconds'] * 2)) {
                    $overdue = true;
                }
            }
        }

        $jobs[] = [
            'job_key' => $key,
            'label' => $label,
            'description' => $meta['description'] ?? '',
            'enabled' => (bool) $s['enabled'],
            'interval_seconds' => (int) $s['interval_seconds'],
            'last_run_at' => $s['last_run_at'],
            'last_run_relative' => supplycore_relative_datetime($s['last_run_at']),
            'last_success_at' => $s['last_success_at'] ?? null,
            'last_success_relative' => supplycore_relative_datetime($s['last_success_at'] ?? null),
            'last_failure_at' => $s['last_failure_at'] ?? null,
            'last_failure_message' => $s['last_failure_message'] ?? null,
            'next_run_at' => $s['next_run_at'],
            'next_run_relative' => supplycore_relative_datetime($s['next_run_at']),
            'health' => $health,
            'health_tone' => $healthTone,
            'health_label' => $healthLabel,
            'overdue' => $overdue,
            'pressure_state' => $pressure,
            'recent_timeout_count' => (int) ($s['recent_timeout_count'] ?? 0),
            'recent_deferral_count' => (int) ($s['recent_deferral_count'] ?? 0),
            'recent_skip_count' => (int) ($s['recent_skip_count'] ?? 0),
            'last_planner_reason' => $s['last_planner_reason_text'] ?? null,
            'last_run_summary' => $s['last_run_summary'] ?? null,
            'timeout_seconds' => $meta['timeout_seconds'] ?? $defaultTimeout,
        ];
    }

    // ── Include registry jobs missing from sync_schedules ────────────
    $scheduledKeys = array_column($jobs, 'job_key');
    $scheduledKeySet = array_flip($scheduledKeys);
    foreach ($registry as $regKey => $regMeta) {
        if (isset($scheduledKeySet[$regKey])) {
            continue;
        }
        // Only show user-visible, schedulable jobs (skip internal/child tasks).
        if (empty($regMeta['user_visible']) || empty($regMeta['schedulable'])) {
            continue;
        }
        // Skip child jobs (have a parent_job_key).
        if (!empty($regMeta['parent_job_key'])) {
            continue;
        }
        $jobs[] = [
            'job_key' => $regKey,
            'label' => $regMeta['label'] ?? $regKey,
            'description' => $regMeta['description'] ?? '',
            'enabled' => !empty($regMeta['enabled_by_default']),
            'interval_seconds' => ((int) ($regMeta['default_interval_minutes'] ?? 30)) * 60,
            'last_run_at' => null,
            'last_run_relative' => 'Never',
            'last_success_at' => null,
            'last_success_relative' => 'Never',
            'last_failure_at' => null,
            'last_failure_message' => null,
            'next_run_at' => null,
            'next_run_relative' => 'Not scheduled',
            'health' => 'never_ran',
            'health_tone' => 'border-violet-400/20 bg-violet-500/10 text-violet-100',
            'health_label' => 'Never ran',
            'overdue' => false,
            'pressure_state' => 'healthy',
            'recent_timeout_count' => 0,
            'recent_deferral_count' => 0,
            'recent_skip_count' => 0,
            'last_planner_reason' => 'No schedule row — job exists in registry but has not been provisioned into sync_schedules yet.',
            'last_run_summary' => null,
            'timeout_seconds' => $regMeta['timeout_seconds'] ?? $defaultTimeout,
        ];
    }

    // ── KPI counts ────────────────────────────────────────────────────
    $totalEnabled = count(array_filter($jobs, fn (array $j) => $j['enabled']));
    $totalFailed = count(array_filter($jobs, fn (array $j) => $j['health'] === 'failed' || $j['health'] === 'stuck'));
    $totalTimeout = count(array_filter($jobs, fn (array $j) => $j['health'] === 'timeout'));
    $totalNeverRan = count(array_filter($jobs, fn (array $j) => $j['health'] === 'never_ran'));
    $totalOverdue = count(array_filter($jobs, fn (array $j) => $j['overdue']));
    $totalHealthy = count(array_filter($jobs, fn (array $j) => $j['health'] === 'healthy'));

    // ── Log files on disk ─────────────────────────────────────────────
    $logDir = rtrim((string) realpath(__DIR__ . '/../storage/logs'), '/');
    $logFiles = [];
    if ($logDir !== '' && is_dir($logDir)) {
        $entries = scandir($logDir);
        foreach ($entries as $entry) {
            if ($entry === '.' || $entry === '..' || $entry === '.gitkeep') {
                continue;
            }
            $fullPath = $logDir . '/' . $entry;
            if (is_file($fullPath)) {
                $sizeBytes = filesize($fullPath);
                $modifiedAt = filemtime($fullPath);
                $logFiles[] = [
                    'filename' => $entry,
                    'size_bytes' => $sizeBytes,
                    'size_human' => log_viewer_format_bytes($sizeBytes),
                    'modified_at' => $modifiedAt !== false ? gmdate('Y-m-d H:i:s', $modifiedAt) : null,
                    'modified_relative' => $modifiedAt !== false ? human_duration_ago(max(0, time() - $modifiedAt)) . ' ago' : 'Unknown',
                    'tail_lines' => log_viewer_tail_file($fullPath, 5),
                ];
            }
        }
        usort($logFiles, fn (array $a, array $b) => ($b['size_bytes'] ?? 0) <=> ($a['size_bytes'] ?? 0));
    }

    // ── Worker job queue depth (backlog) ─────────────────────────────────
    $workerQueueRaw = db_select(
        "SELECT status, queue_name, COUNT(*) AS cnt
         FROM worker_jobs
         WHERE status IN ('queued', 'running', 'retry')
         GROUP BY status, queue_name"
    );
    $backlogQueue = ['queued' => 0, 'running' => 0, 'retry' => 0, 'total' => 0];
    $backlogByQueue = [];
    foreach ($workerQueueRaw as $row) {
        $s = $row['status'];
        $q = $row['queue_name'] ?? 'default';
        $cnt = (int) $row['cnt'];
        $backlogQueue[$s] = ($backlogQueue[$s] ?? 0) + $cnt;
        $backlogQueue['total'] += $cnt;
        $backlogByQueue[$q][$s] = $cnt;
    }

    // ── Overdue job details ───────────────────────────────────────────
    $overdueJobs = array_filter($jobs, fn (array $j) => $j['overdue'] && $j['health'] !== 'disabled');
    usort($overdueJobs, function (array $a, array $b) {
        $aAge = $a['last_run_at'] ? (time() - strtotime((string) $a['last_run_at'])) : PHP_INT_MAX;
        $bAge = $b['last_run_at'] ? (time() - strtotime((string) $b['last_run_at'])) : PHP_INT_MAX;
        return $bAge <=> $aAge;
    });
    $overdueJobsList = array_values($overdueJobs);

    return [
        'jobs' => $jobs,
        'recent_runs' => $recentRuns,
        'failed_runs' => $failedRuns,
        'stuck_runs' => $stuckRuns,
        'never_ran' => $neverRan,
        'log_files' => $logFiles,
        'kpi' => [
            'total_enabled' => $totalEnabled,
            'total_failed' => $totalFailed,
            'total_timeout' => $totalTimeout,
            'total_never_ran' => $totalNeverRan,
            'total_overdue' => $totalOverdue,
            'total_healthy' => $totalHealthy,
        ],
        'backlog' => [
            'queue' => $backlogQueue,
            'by_queue' => $backlogByQueue,
            'overdue_jobs' => $overdueJobsList,
        ],
    ];
}

function log_viewer_format_bytes(int|false $bytes): string
{
    if ($bytes === false || $bytes < 0) {
        return '0 B';
    }
    if ($bytes < 1024) {
        return $bytes . ' B';
    }
    if ($bytes < 1048576) {
        return round($bytes / 1024, 1) . ' KB';
    }
    return round($bytes / 1048576, 1) . ' MB';
}

function log_viewer_tail_file(string $path, int $lines = 5): array
{
    if (!is_file($path) || !is_readable($path)) {
        return [];
    }
    $fp = fopen($path, 'r');
    if ($fp === false) {
        return [];
    }

    $buffer = [];
    while (($line = fgets($fp)) !== false) {
        $buffer[] = rtrim($line, "\r\n");
        if (count($buffer) > $lines) {
            array_shift($buffer);
        }
    }
    fclose($fp);

    return $buffer;
}

function log_viewer_external_health(): array
{
    $results = [];

    // ── Neo4j ─────────────────────────────────────────────────────────
    $neo4jEnabled = (bool) config('neo4j.enabled', false);
    $neo4jUrl = rtrim((string) config('neo4j.url', 'http://127.0.0.1:7474'), '/');
    $neo4jTimeout = max(3, (int) config('neo4j.timeout_seconds', 15));

    if ($neo4jEnabled && $neo4jUrl !== '') {
        $neo4jHealthUrl = $neo4jUrl;
        $ch = curl_init($neo4jHealthUrl);
        curl_setopt_array($ch, [
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_TIMEOUT => min($neo4jTimeout, 5),
            CURLOPT_CONNECTTIMEOUT => 3,
            CURLOPT_HTTPHEADER => ['Accept: application/json'],
            CURLOPT_NOBODY => false,
        ]);
        $username = (string) config('neo4j.username', 'neo4j');
        $password = (string) config('neo4j.password', '');
        if ($username !== '') {
            curl_setopt($ch, CURLOPT_USERPWD, $username . ':' . $password);
        }
        $response = curl_exec($ch);
        $httpCode = (int) curl_getinfo($ch, CURLINFO_HTTP_CODE);
        $curlError = curl_error($ch);
        $connectTime = round((float) curl_getinfo($ch, CURLINFO_CONNECT_TIME) * 1000);
        $totalTime = round((float) curl_getinfo($ch, CURLINFO_TOTAL_TIME) * 1000);
        curl_close($ch);

        $neo4jData = is_string($response) ? @json_decode($response, true) : null;
        $neo4jVersion = is_array($neo4jData) ? ($neo4jData['neo4j_version'] ?? null) : null;

        if ($httpCode >= 200 && $httpCode < 400) {
            $results['neo4j'] = [
                'name' => 'Neo4j',
                'status' => 'online',
                'tone' => 'border-emerald-400/20 bg-emerald-500/10 text-emerald-100',
                'label' => 'Online',
                'url' => $neo4jUrl,
                'http_code' => $httpCode,
                'latency_ms' => $totalTime,
                'connect_ms' => $connectTime,
                'version' => $neo4jVersion,
                'detail' => 'Connected in ' . $totalTime . 'ms',
            ];
        } else {
            $results['neo4j'] = [
                'name' => 'Neo4j',
                'status' => 'offline',
                'tone' => 'border-rose-400/20 bg-rose-500/10 text-rose-100',
                'label' => 'Offline',
                'url' => $neo4jUrl,
                'http_code' => $httpCode,
                'latency_ms' => $totalTime,
                'connect_ms' => $connectTime,
                'version' => null,
                'detail' => $curlError !== '' ? $curlError : ('HTTP ' . $httpCode),
            ];
        }
    } else {
        $results['neo4j'] = [
            'name' => 'Neo4j',
            'status' => 'disabled',
            'tone' => 'border-slate-400/20 bg-slate-500/10 text-slate-300',
            'label' => 'Disabled',
            'url' => $neo4jUrl ?? '',
            'http_code' => 0,
            'latency_ms' => 0,
            'connect_ms' => 0,
            'version' => null,
            'detail' => 'Neo4j integration is disabled in configuration.',
        ];
    }

    // ── InfluxDB ──────────────────────────────────────────────────────
    $influxEnabled = (bool) config('influxdb.enabled', false);
    $influxUrl = rtrim((string) config('influxdb.url', 'http://127.0.0.1:8086'), '/');
    $influxTimeout = max(3, (int) config('influxdb.timeout_seconds', 15));
    $influxToken = (string) config('influxdb.token', '');

    if ($influxEnabled && $influxUrl !== '') {
        $influxHealthUrl = $influxUrl . '/health';
        $ch = curl_init($influxHealthUrl);
        curl_setopt_array($ch, [
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_TIMEOUT => min($influxTimeout, 5),
            CURLOPT_CONNECTTIMEOUT => 3,
            CURLOPT_HTTPHEADER => array_filter([
                'Accept: application/json',
                $influxToken !== '' ? ('Authorization: Token ' . $influxToken) : null,
            ]),
        ]);
        $response = curl_exec($ch);
        $httpCode = (int) curl_getinfo($ch, CURLINFO_HTTP_CODE);
        $curlError = curl_error($ch);
        $connectTime = round((float) curl_getinfo($ch, CURLINFO_CONNECT_TIME) * 1000);
        $totalTime = round((float) curl_getinfo($ch, CURLINFO_TOTAL_TIME) * 1000);
        curl_close($ch);

        $influxData = is_string($response) ? @json_decode($response, true) : null;
        $influxStatus = is_array($influxData) ? ($influxData['status'] ?? null) : null;
        $influxVersion = is_array($influxData) ? ($influxData['version'] ?? null) : null;

        $isHealthy = ($httpCode >= 200 && $httpCode < 400) && ($influxStatus === 'pass' || $influxStatus === null);

        if ($isHealthy) {
            $results['influxdb'] = [
                'name' => 'InfluxDB',
                'status' => 'online',
                'tone' => 'border-emerald-400/20 bg-emerald-500/10 text-emerald-100',
                'label' => 'Online',
                'url' => $influxUrl,
                'http_code' => $httpCode,
                'latency_ms' => $totalTime,
                'connect_ms' => $connectTime,
                'version' => $influxVersion,
                'detail' => 'Connected in ' . $totalTime . 'ms',
            ];
        } else {
            $results['influxdb'] = [
                'name' => 'InfluxDB',
                'status' => 'offline',
                'tone' => 'border-rose-400/20 bg-rose-500/10 text-rose-100',
                'label' => 'Offline',
                'url' => $influxUrl,
                'http_code' => $httpCode,
                'latency_ms' => $totalTime,
                'connect_ms' => $connectTime,
                'version' => null,
                'detail' => $curlError !== '' ? $curlError : ('HTTP ' . $httpCode . ($influxStatus !== null ? ' · status=' . $influxStatus : '')),
            ];
        }
    } else {
        $results['influxdb'] = [
            'name' => 'InfluxDB',
            'status' => 'disabled',
            'tone' => 'border-slate-400/20 bg-slate-500/10 text-slate-300',
            'label' => 'Disabled',
            'url' => $influxUrl ?? '',
            'http_code' => 0,
            'latency_ms' => 0,
            'connect_ms' => 0,
            'version' => null,
            'detail' => 'InfluxDB integration is disabled in configuration.',
        ];
    }

    return $results;
}

function supplycore_threat_corridor_map_cache_minutes(): int
{
    return max(5, min(240, (int) get_setting('threat_corridor_map_cache_minutes', '20')));
}

/**
 * Generate a threat-corridor map SVG.
 *
 * @deprecated Use map_generate_threat_corridor() from src/map.php instead.
 */
function supplycore_threat_corridor_graph_svg(int $corridorId, array $corridorSystemIds, int $surroundingHops = 1): ?string
{
    require_once __DIR__ . '/map.php';
    return map_generate_threat_corridor($corridorId, $corridorSystemIds, $surroundingHops);
}

/**
 * Legacy implementation — kept for reference during migration.
 * @internal
 */
function _supplycore_threat_corridor_graph_svg_legacy(int $corridorId, array $corridorSystemIds, int $surroundingHops = 1): ?string
{
    $corridorSystemIds = array_values(array_unique(array_map('intval', $corridorSystemIds)));
    $corridorSystemIds = array_values(array_filter($corridorSystemIds, static fn (int $sid): bool => $sid > 0));
    if ($corridorId <= 0 || $corridorSystemIds === []) {
        return null;
    }
    $surroundingHops = max(0, min(3, $surroundingHops));
    $cacheDir = dirname(__DIR__) . '/public/threat-corridors/svg';
    if (!is_dir($cacheDir) && !@mkdir($cacheDir, 0775, true) && !is_dir($cacheDir)) {
        return null;
    }
    $cacheFile = sprintf('%s/corridor-%d-h%d-v7.svg', $cacheDir, $corridorId, $surroundingHops);
    $cacheTtl = supplycore_threat_corridor_map_cache_minutes() * 60;
    if (is_file($cacheFile) && ((time() - (int) filemtime($cacheFile)) < $cacheTtl)) {
        return '/threat-corridors/svg/' . basename($cacheFile);
    }
    // Fetch one extra hop beyond the render boundary so we can show stub edges
    // hinting at connectivity beyond the visible graph
    $fetchHops = min(3, $surroundingHops + 1);
    $graph = db_threat_corridor_graph_subgraph($corridorSystemIds, $fetchHops);
    $nodes = (array) ($graph['nodes'] ?? []);
    $edges = (array) ($graph['edges'] ?? []);
    if ($nodes === []) {
        return null;
    }

    $corridorSet = array_fill_keys($corridorSystemIds, true);
    $corridorPathEdges = [];
    for ($i = 0, $n = count($corridorSystemIds) - 1; $i < $n; $i++) {
        $a = (int) $corridorSystemIds[$i];
        $b = (int) $corridorSystemIds[$i + 1];
        if ($a <= 0 || $b <= 0 || $a === $b) {
            continue;
        }
        $left = min($a, $b);
        $right = max($a, $b);
        $corridorPathEdges[$left . ':' . $right] = true;
    }
    $nodeMap = [];
    foreach ($nodes as $node) {
        $sid = (int) ($node['system_id'] ?? 0);
        if ($sid <= 0) {
            continue;
        }
        $nodeMap[$sid] = [
            'system_id' => $sid,
            'name' => (string) ($node['system_name'] ?? (string) $sid),
            'security' => (float) ($node['security'] ?? 0.0),
            'threat_level' => strtolower((string) ($node['threat_level'] ?? '')),
            'is_corridor' => isset($corridorSet[$sid]),
        ];
    }
    if ($nodeMap === []) {
        return null;
    }

    $nodeIds = array_keys($nodeMap);
    $adjacency = [];
    foreach ($edges as $edge) {
        $a = (int) ($edge[0] ?? 0);
        $b = (int) ($edge[1] ?? 0);
        if ($a <= 0 || $b <= 0 || $a === $b || !isset($nodeMap[$a], $nodeMap[$b])) {
            continue;
        }
        $adjacency[$a][] = $b;
        $adjacency[$b][] = $a;
    }
    foreach ($nodeIds as $sid) {
        if (!isset($adjacency[$sid])) {
            $adjacency[$sid] = [];
        }
    }

    $corridorIndexMap = [];
    foreach ($corridorSystemIds as $idx => $sid) {
        $sid = (int) $sid;
        if ($sid > 0 && isset($nodeMap[$sid])) {
            $corridorIndexMap[$sid] = $idx;
        }
    }
    if ($corridorIndexMap === []) {
        $fallbackCorridorId = (int) ($nodeIds[0] ?? 0);
        if ($fallbackCorridorId > 0) {
            $corridorIndexMap[$fallbackCorridorId] = 0;
            $nodeMap[$fallbackCorridorId]['is_corridor'] = true;
        }
    }

    $distance = [];
    $nearestCorridor = [];
    $queue = [];
    foreach ($corridorIndexMap as $sid => $idx) {
        $distance[$sid] = 0;
        $nearestCorridor[$sid] = $sid;
        $queue[] = $sid;
    }
    while ($queue !== []) {
        $current = array_shift($queue);
        $currentDistance = (int) ($distance[$current] ?? 0);
        foreach ($adjacency[$current] as $neighbor) {
            if (!isset($distance[$neighbor]) || $distance[$neighbor] > ($currentDistance + 1)) {
                $distance[$neighbor] = $currentDistance + 1;
                $nearestCorridor[$neighbor] = (int) ($nearestCorridor[$current] ?? $current);
                $queue[] = $neighbor;
            }
        }
    }

    // Mark boundary nodes: beyond the requested hops, used only for stub edges
    $boundarySet = [];
    foreach ($nodeIds as $sid) {
        if (!isset($corridorSet[$sid]) && ($distance[$sid] ?? PHP_INT_MAX) > $surroundingHops) {
            $boundarySet[$sid] = true;
        }
    }

    $positions = [];
    $corridorNodeIds = array_keys($corridorIndexMap);
    usort($corridorNodeIds, static function (int $a, int $b) use ($corridorIndexMap): int {
        return ($corridorIndexMap[$a] ?? 0) <=> ($corridorIndexMap[$b] ?? 0);
    });
    $corridorCount = count($corridorNodeIds);
    foreach ($corridorNodeIds as $idx => $sid) {
        $x = $corridorCount > 1 ? (0.18 + ((0.64 * $idx) / ($corridorCount - 1))) : 0.5;
        $positions[$sid] = ['x' => $x, 'y' => 0.5];
    }

    // Pre-group surrounding nodes by their nearest corridor anchor
    $surroundingByAnchor = [];
    foreach ($nodeIds as $sid) {
        if (isset($positions[$sid])) {
            continue;
        }
        $anchorId = (int) ($nearestCorridor[$sid] ?? 0);
        if ($anchorId <= 0 || !isset($positions[$anchorId])) {
            $anchorId = (int) ($corridorNodeIds[0] ?? 0);
            if ($anchorId <= 0 || !isset($positions[$anchorId])) {
                $anchorId = $sid;
                $positions[$anchorId] = ['x' => 0.5, 'y' => 0.5];
            }
        }
        $hop = max(1, min(3, (int) ($distance[$sid] ?? 1)));
        $surroundingByAnchor[$anchorId][] = ['sid' => $sid, 'hop' => $hop];
    }

    // For each corridor anchor, compute angles pointing toward adjacent corridor nodes
    // Surrounding nodes must avoid these directions so they spread above/below the corridor line
    $corridorNeighborAngles = [];
    foreach ($corridorNodeIds as $idx => $cSid) {
        $blocked = [];
        if ($idx > 0) {
            $prevSid = $corridorNodeIds[$idx - 1];
            $dx = ((float) $positions[$prevSid]['x']) - ((float) $positions[$cSid]['x']);
            $dy = ((float) $positions[$prevSid]['y']) - ((float) $positions[$cSid]['y']);
            $blocked[] = atan2($dy, $dx);
        }
        if ($idx < ($corridorCount - 1)) {
            $nextSid = $corridorNodeIds[$idx + 1];
            $dx = ((float) $positions[$nextSid]['x']) - ((float) $positions[$cSid]['x']);
            $dy = ((float) $positions[$nextSid]['y']) - ((float) $positions[$cSid]['y']);
            $blocked[] = atan2($dy, $dx);
        }
        $corridorNeighborAngles[$cSid] = $blocked;
    }

    // Place surrounding nodes while avoiding corridor directions
    $exclusionZone = M_PI * 0.22; // ~40° exclusion around each corridor direction
    foreach ($surroundingByAnchor as $anchorId => $anchorNodes) {
        $blockedAngles = $corridorNeighborAngles[$anchorId] ?? [];
        usort($anchorNodes, static fn (array $a, array $b): int => $a['hop'] <=> $b['hop'] ?: $a['sid'] <=> $b['sid']);
        $byHop = [];
        foreach ($anchorNodes as $nodeInfo) {
            $byHop[$nodeInfo['hop']][] = $nodeInfo['sid'];
        }
        foreach ($byHop as $hop => $hopSids) {
            $n = count($hopSids);
            $radius = 0.13 + ((float) $hop * 0.065);
            // Generate candidate angles around the circle (starting from top), filtered to avoid blocked zones
            $steps = 360;
            $candidates = [];
            for ($step = 0; $step < $steps; $step++) {
                $angle = (2.0 * M_PI / $steps) * $step - M_PI / 2.0;
                $inBlocked = false;
                foreach ($blockedAngles as $ba) {
                    $diff = fmod(abs($angle - $ba), 2.0 * M_PI);
                    if ($diff > M_PI) {
                        $diff = 2.0 * M_PI - $diff;
                    }
                    if ($diff < $exclusionZone) {
                        $inBlocked = true;
                        break;
                    }
                }
                if (!$inBlocked) {
                    $candidates[] = $angle;
                }
            }
            if ($candidates === []) {
                // Fallback: use full circle if all angles were excluded
                for ($step = 0; $step < $steps; $step++) {
                    $candidates[] = (2.0 * M_PI / $steps) * $step - M_PI / 2.0;
                }
            }
            $nc = count($candidates);
            foreach ($hopSids as $i => $sid) {
                $candidateIdx = min((int) round($i * ($nc / $n)), $nc - 1);
                $angle = $candidates[$candidateIdx];
                $x = ((float) $positions[$anchorId]['x']) + (cos($angle) * $radius);
                $y = ((float) $positions[$anchorId]['y']) + (sin($angle) * $radius * 0.85);
                $positions[$sid] = [
                    'x' => max(0.03, min(0.97, $x)),
                    'y' => max(0.08, min(0.92, $y)),
                ];
            }
        }
    }

    $width = 900;
    $height = 450;
    $pad = 28;
    $sx = static fn (float $x): float => $pad + ($x * ($width - ($pad * 2)));
    $sy = static fn (float $y): float => $pad + ($y * ($height - ($pad * 2)));
    $securityColor = static function (float $sec): string {
        if ($sec >= 0.5) {
            return '#10b981';
        }
        if ($sec > 0.0) {
            return '#f59e0b';
        }
        return '#ef4444';
    };
    $threatColor = static function (string $threatLevel): string {
        return match ($threatLevel) {
            'critical' => '#ef4444',
            'high' => '#f97316',
            'medium' => '#eab308',
            'low' => '#3b82f6',
            default => '#94a3b8',
        };
    };

    $svg = [];
    $svg[] = '<svg xmlns="http://www.w3.org/2000/svg" width="' . $width . '" height="' . $height . '" viewBox="0 0 ' . $width . ' ' . $height . '">';
    $svg[] = '<defs>'
        . '<filter id="hwy-glow" x="-40%" y="-40%" width="180%" height="180%">'
        . '<feGaussianBlur stdDeviation="3.5" result="blur"/>'
        . '<feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>'
        . '</filter>'
        . '<filter id="node-glow" x="-60%" y="-60%" width="220%" height="220%">'
        . '<feGaussianBlur stdDeviation="2.2" result="blur"/>'
        . '<feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>'
        . '</filter>'
        . '<style><![CDATA['
        . '.label-c{font:700 11px Inter,Segoe UI,sans-serif;fill:#e2e8f0}'
        . '.label-s{font:500 9.5px Inter,Segoe UI,sans-serif;fill:#cbd5e1}'
        . '.label-t{font:600 8px Inter,Segoe UI,sans-serif;letter-spacing:.04em}'
        . ']]></style>'
        . '</defs>';
    $svg[] = '<rect width="' . $width . '" height="' . $height . '" fill="#04080f"/>';

    // Pass 0: boundary stub edges – short faded lines hinting at off-screen connections
    foreach ($edges as $edge) {
        $a = (int) ($edge[0] ?? 0);
        $b = (int) ($edge[1] ?? 0);
        if (!isset($positions[$a], $positions[$b])) {
            continue;
        }
        $aB = isset($boundarySet[$a]);
        $bB = isset($boundarySet[$b]);
        if (!$aB && !$bB) {
            continue; // both rendered – handled later
        }
        if ($aB && $bB) {
            continue; // both beyond boundary – skip entirely
        }
        // One rendered, one boundary: draw stub from rendered node partway toward boundary
        $rendered = $aB ? $b : $a;
        $boundary = $aB ? $a : $b;
        $rx = $sx((float) $positions[$rendered]['x']);
        $ry = $sy((float) $positions[$rendered]['y']);
        $bx = $sx((float) $positions[$boundary]['x']);
        $by = $sy((float) $positions[$boundary]['y']);
        // Stub extends 55% of the way toward the boundary node
        $mx = $rx + ($bx - $rx) * 0.55;
        $my = $ry + ($by - $ry) * 0.55;
        $svg[] = '<line x1="' . number_format($rx, 2, '.', '') . '" y1="' . number_format($ry, 2, '.', '') . '" x2="' . number_format($mx, 2, '.', '') . '" y2="' . number_format($my, 2, '.', '') . '" stroke="#374151" stroke-opacity="0.35" stroke-width="1.2" stroke-dasharray="4 3"/>';
    }

    // Pass 1: non-corridor stargate connections (background layer)
    foreach ($edges as $edge) {
        $a = (int) ($edge[0] ?? 0);
        $b = (int) ($edge[1] ?? 0);
        if (!isset($positions[$a], $positions[$b])) {
            continue;
        }
        // Skip edges involving boundary nodes (handled above)
        if (isset($boundarySet[$a]) || isset($boundarySet[$b])) {
            continue;
        }
        $left = min($a, $b);
        $right = max($a, $b);
        if (isset($corridorPathEdges[$left . ':' . $right])) {
            continue;
        }
        $x1 = number_format($sx((float) $positions[$a]['x']), 2, '.', '');
        $y1 = number_format($sy((float) $positions[$a]['y']), 2, '.', '');
        $x2 = number_format($sx((float) $positions[$b]['x']), 2, '.', '');
        $y2 = number_format($sy((float) $positions[$b]['y']), 2, '.', '');
        $svg[] = '<line x1="' . $x1 . '" y1="' . $y1 . '" x2="' . $x2 . '" y2="' . $y2 . '" stroke="#374151" stroke-opacity="0.7" stroke-width="1.5"/>';
    }

    // Pass 2: corridor highway edges (foreground layer, golden glow)
    foreach ($edges as $edge) {
        $a = (int) ($edge[0] ?? 0);
        $b = (int) ($edge[1] ?? 0);
        if (!isset($positions[$a], $positions[$b])) {
            continue;
        }
        $left = min($a, $b);
        $right = max($a, $b);
        if (!isset($corridorPathEdges[$left . ':' . $right])) {
            continue;
        }
        $x1 = number_format($sx((float) $positions[$a]['x']), 2, '.', '');
        $y1 = number_format($sy((float) $positions[$a]['y']), 2, '.', '');
        $x2 = number_format($sx((float) $positions[$b]['x']), 2, '.', '');
        $y2 = number_format($sy((float) $positions[$b]['y']), 2, '.', '');
        // Wide ambient glow
        $svg[] = '<line x1="' . $x1 . '" y1="' . $y1 . '" x2="' . $x2 . '" y2="' . $y2 . '" stroke="#92400e" stroke-opacity="0.45" stroke-width="9" stroke-linecap="round"/>';
        // Core bright line
        $svg[] = '<line x1="' . $x1 . '" y1="' . $y1 . '" x2="' . $x2 . '" y2="' . $y2 . '" stroke="#fbbf24" stroke-opacity="0.88" stroke-width="2.6" stroke-linecap="round" filter="url(#hwy-glow)"/>';
    }

    // Nodes – pill-shaped rounded rectangles with labels inside
    foreach ($nodeMap as $sid => $node) {
        if (!isset($positions[$sid]) || isset($boundarySet[$sid])) {
            continue;
        }
        $px = $sx((float) $positions[$sid]['x']);
        $py = $sy((float) $positions[$sid]['y']);
        $outer = $securityColor((float) $node['security']);
        $inner = $threatColor((string) $node['threat_level']);
        $safeName = htmlspecialchars((string) $node['name'], ENT_QUOTES);
        $threatLabel = ($node['threat_level'] !== '') ? strtoupper((string) $node['threat_level']) : '';
        $hasThreat = $threatLabel !== '';
        $title = $safeName . ' | sec=' . number_format((float) $node['security'], 1) . ' | threat=' . ($node['threat_level'] !== '' ? $node['threat_level'] : 'unknown');
        $titleEsc = htmlspecialchars($title, ENT_QUOTES);
        if ($node['is_corridor'] === true) {
            $nameLen = mb_strlen((string) $node['name']);
            $pw = max(82, (int) ($nameLen * 7.8) + 28);
            $ph = $hasThreat ? 38 : 26;
            $rx = (int) ($ph / 2);
            $svg[] = '<g filter="url(#node-glow)">'
                . '<rect x="' . number_format($px - $pw / 2, 2, '.', '') . '" y="' . number_format($py - $ph / 2, 2, '.', '') . '" width="' . $pw . '" height="' . $ph . '" rx="' . $rx . '" fill="#0f172a" stroke="' . $outer . '" stroke-width="2.2" stroke-opacity="0.9"/>'
                . '<text class="label-c" x="' . number_format($px, 2, '.', '') . '" y="' . number_format($py + ($hasThreat ? -3 : 4), 2, '.', '') . '" text-anchor="middle">' . $safeName . '</text>';
            if ($hasThreat) {
                $svg[] = '<text class="label-t" x="' . number_format($px, 2, '.', '') . '" y="' . number_format($py + 12, 2, '.', '') . '" text-anchor="middle" fill="' . $inner . '">' . $threatLabel . '</text>';
            }
            $svg[] = '<title>' . $titleEsc . '</title></g>';
        } else {
            $nameLen = mb_strlen((string) $node['name']);
            $pw = max(70, (int) ($nameLen * 7.2) + 22);
            $ph = $hasThreat ? 34 : 24;
            $rx = (int) ($ph / 2);
            $svg[] = '<g filter="url(#node-glow)">'
                . '<rect x="' . number_format($px - $pw / 2, 2, '.', '') . '" y="' . number_format($py - $ph / 2, 2, '.', '') . '" width="' . $pw . '" height="' . $ph . '" rx="' . $rx . '" fill="#111827" stroke="' . $outer . '" stroke-width="1.8" stroke-opacity="0.9">'
                . '<title>' . $titleEsc . '</title>'
                . '</rect>'
                . '<text class="label-s" x="' . number_format($px, 2, '.', '') . '" y="' . number_format($py + ($hasThreat ? -2 : 4), 2, '.', '') . '" text-anchor="middle">' . $safeName . '</text>';
            if ($hasThreat) {
                $svg[] = '<text class="label-t" x="' . number_format($px, 2, '.', '') . '" y="' . number_format($py + 11, 2, '.', '') . '" text-anchor="middle" fill="' . $inner . '">' . $threatLabel . '</text>';
            }
            $svg[] = '</g>';
        }
    }
    $svg[] = '</svg>';
    if (@file_put_contents($cacheFile, implode('', $svg)) === false) {
        return null;
    }

    return '/threat-corridors/svg/' . basename($cacheFile);
}

/**
 * Generate a battle-theater map SVG.
 *
 * @deprecated Use map_generate_theater() from src/map.php instead.
 */
function supplycore_theater_map_svg(string $theaterId, array $systemIds, int $hops = 1): ?string
{
    require_once __DIR__ . '/map.php';
    return map_generate_theater($theaterId, $systemIds, $hops);
}

/**
 * Legacy implementation — kept for reference during migration.
 * @internal
 */
function _supplycore_theater_map_svg_legacy(string $theaterId, array $systemIds, int $hops = 1): ?string
{
    $systemIds = array_values(array_unique(array_map('intval', $systemIds)));
    $systemIds = array_values(array_filter($systemIds, static fn(int $sid): bool => $sid > 0));
    if ($systemIds === [] || $theaterId === '') {
        return null;
    }
    $hops = max(1, min(2, $hops));

    // Single-system battles: show 1-hop gate neighbours via neo4j using the
    // same compact horizontal layout as multi-system battles, rather than the
    // tall 2-hop radial map (which left most of the canvas empty).
    // The radial helper (supplycore_system_area_svg) is kept for the dedicated
    // system-map page; here we want consistency and connected-system context.

    $cacheDir = dirname(__DIR__) . '/public/threat-corridors/svg';
    if (!is_dir($cacheDir) && !@mkdir($cacheDir, 0775, true) && !is_dir($cacheDir)) {
        return null;
    }
    $cacheKey = substr(md5($theaterId . ':' . implode(',', $systemIds)), 0, 12);
    $cacheFile = sprintf('%s/theater-%s-h%d-v6.svg', $cacheDir, $cacheKey, $hops);
    $cacheTtl = supplycore_threat_corridor_map_cache_minutes() * 60;
    if (is_file($cacheFile) && ((time() - (int) filemtime($cacheFile)) < $cacheTtl)) {
        return '/threat-corridors/svg/' . basename($cacheFile);
    }

    // Pre-fetch shortest routes between every pair of battle systems so that
    // intermediate systems are included in the graph even when battles are
    // many jumps apart (the hop-limited subgraph fetch alone would miss them).
    $preRoutes = []; // src:dst => [system_id, ...]
    $routeExtraIds = [];
    if (count($systemIds) >= 2) {
        for ($ri = 0; $ri < count($systemIds) - 1; $ri++) {
            for ($rj = $ri + 1; $rj < count($systemIds); $rj++) {
                $route = db_shortest_route_between_systems($systemIds[$ri], $systemIds[$rj]);
                if (count($route) >= 2) {
                    $preRoutes[$systemIds[$ri] . ':' . $systemIds[$rj]] = $route;
                    foreach ($route as $rsid) {
                        $routeExtraIds[$rsid] = true;
                    }
                }
            }
        }
    }

    // Fetch one extra hop for boundary stub edges around battle systems
    $fetchHops = min(3, $hops + 1);
    $graph = db_threat_corridor_graph_subgraph($systemIds, $fetchHops);
    $nodes = (array) ($graph['nodes'] ?? []);
    $edges = (array) ($graph['edges'] ?? []);

    // Merge in route-intermediate systems (with 1-hop context for their
    // connecting edges) so the full corridor is rendered.
    $routeOnlyIds = array_diff(array_keys($routeExtraIds), $systemIds);
    if ($routeOnlyIds !== []) {
        $routeGraph = db_threat_corridor_graph_subgraph(array_values($routeOnlyIds), 1);
        $routeNodes = (array) ($routeGraph['nodes'] ?? []);
        $routeEdges = (array) ($routeGraph['edges'] ?? []);
        // Merge nodes (avoid duplicates by system_id)
        $existingIds = [];
        foreach ($nodes as $n) {
            $existingIds[(int) ($n['system_id'] ?? 0)] = true;
        }
        foreach ($routeNodes as $rn) {
            if (!isset($existingIds[(int) ($rn['system_id'] ?? 0)])) {
                $nodes[] = $rn;
            }
        }
        // Merge edges (avoid duplicates by normalized key)
        $existingEdges = [];
        foreach ($edges as $e) {
            $existingEdges[min($e[0], $e[1]) . ':' . max($e[0], $e[1])] = true;
        }
        foreach ($routeEdges as $re) {
            $ek = min($re[0], $re[1]) . ':' . max($re[0], $re[1]);
            if (!isset($existingEdges[$ek])) {
                $edges[] = $re;
                $existingEdges[$ek] = true;
            }
        }
    }

    if ($nodes === []) {
        return null;
    }

    $battleSet = array_fill_keys($systemIds, true);

    $nodeMap = [];
    foreach ($nodes as $node) {
        $sid = (int) ($node['system_id'] ?? 0);
        if ($sid <= 0) {
            continue;
        }
        $nodeMap[$sid] = [
            'system_id'   => $sid,
            'name'        => (string) ($node['system_name'] ?? (string) $sid),
            'security'    => (float) ($node['security'] ?? 0.0),
            'is_battle'   => isset($battleSet[$sid]),
        ];
    }
    if ($nodeMap === []) {
        return null;
    }

    $nodeIds = array_keys($nodeMap);
    $adjacency = [];
    foreach ($nodeIds as $sid) {
        $adjacency[$sid] = [];
    }
    foreach ($edges as $edge) {
        $a = (int) ($edge[0] ?? 0);
        $b = (int) ($edge[1] ?? 0);
        if ($a <= 0 || $b <= 0 || $a === $b || !isset($nodeMap[$a], $nodeMap[$b])) {
            continue;
        }
        $adjacency[$a][] = $b;
        $adjacency[$b][] = $a;
    }

    // Layout: battle systems spread horizontally
    $battleNodeIds = array_values(array_filter($nodeIds, static fn(int $sid): bool => isset($battleSet[$sid])));
    sort($battleNodeIds);

    // Route edges: find shortest path between every pair of battle systems
    // so the full route is shown even when battles are separated by
    // intermediate (non-battle) systems.
    $battleEdges = [];
    $routeNodeSet = []; // intermediate nodes on the route

    // Seed route edges and intermediates from pre-fetched routes so
    // we don't depend solely on the in-memory BFS (which may miss edges
    // if the subgraph fetch didn't fully connect distant clusters).
    foreach ($preRoutes as $route) {
        for ($pi = 0; $pi < count($route) - 1; $pi++) {
            $a = $route[$pi];
            $b = $route[$pi + 1];
            if (!isset($nodeMap[$a], $nodeMap[$b])) {
                continue;
            }
            $key = min($a, $b) . ':' . max($a, $b);
            $battleEdges[$key] = true;
            if (!isset($battleSet[$a])) {
                $routeNodeSet[$a] = true;
            }
            if (!isset($battleSet[$b])) {
                $routeNodeSet[$b] = true;
            }
            // Ensure adjacency includes this edge
            if (!in_array($b, $adjacency[$a] ?? [], true)) {
                $adjacency[$a][] = $b;
            }
            if (!in_array($a, $adjacency[$b] ?? [], true)) {
                $adjacency[$b][] = $a;
            }
        }
    }

    if (count($battleNodeIds) >= 2) {
        for ($bi = 0; $bi < count($battleNodeIds) - 1; $bi++) {
            for ($bj = $bi + 1; $bj < count($battleNodeIds); $bj++) {
                $src = $battleNodeIds[$bi];
                $dst = $battleNodeIds[$bj];
                $bfsQueue = [$src];
                $bfsPrev  = [$src => -1];
                $found    = false;
                while ($bfsQueue !== []) {
                    $cur = array_shift($bfsQueue);
                    if ($cur === $dst) {
                        $found = true;
                        break;
                    }
                    foreach ($adjacency[$cur] as $nb) {
                        if (!isset($bfsPrev[$nb])) {
                            $bfsPrev[$nb] = $cur;
                            $bfsQueue[]   = $nb;
                        }
                    }
                }
                if ($found) {
                    $cur = $dst;
                    while ($bfsPrev[$cur] !== -1) {
                        $prev = $bfsPrev[$cur];
                        $key  = min($cur, $prev) . ':' . max($cur, $prev);
                        $battleEdges[$key] = true;
                        if (!isset($battleSet[$cur])) {
                            $routeNodeSet[$cur] = true;
                        }
                        $cur = $prev;
                    }
                }
            }
        }
    }
    // Also include direct battle-to-battle edges
    foreach ($edges as $edge) {
        $a = (int) ($edge[0] ?? 0);
        $b = (int) ($edge[1] ?? 0);
        if ($a <= 0 || $b <= 0 || $a === $b) {
            continue;
        }
        if (isset($battleSet[$a], $battleSet[$b])) {
            $battleEdges[min($a, $b) . ':' . max($a, $b)] = true;
        }
    }
    $battleCount = count($battleNodeIds);
    $positions = [];
    foreach ($battleNodeIds as $idx => $sid) {
        $x = $battleCount > 1 ? (0.10 + ((0.80 * $idx) / ($battleCount - 1))) : 0.5;
        $positions[$sid] = ['x' => $x, 'y' => 0.5];
    }

    // Position route-intermediate nodes linearly between their battle endpoints
    // so the full corridor is visible rather than clustering around anchors.
    foreach ($preRoutes as $routeKey => $route) {
        $routeLen = count($route);
        if ($routeLen < 3) {
            continue; // no intermediates
        }
        $srcSid = $route[0];
        $dstSid = $route[$routeLen - 1];
        if (!isset($positions[$srcSid], $positions[$dstSid])) {
            continue;
        }
        $srcPos = $positions[$srcSid];
        $dstPos = $positions[$dstSid];
        for ($ri = 1; $ri < $routeLen - 1; $ri++) {
            $sid = $route[$ri];
            if (isset($positions[$sid]) || !isset($nodeMap[$sid])) {
                continue;
            }
            $t = (float) $ri / (float) ($routeLen - 1);
            // Slight sinusoidal offset on y to avoid overlapping the straight line
            $yOff = sin($t * M_PI) * 0.08;
            $positions[$sid] = [
                'x' => max(0.03, min(0.97, $srcPos['x'] + ($dstPos['x'] - $srcPos['x']) * $t)),
                'y' => max(0.08, min(0.92, $srcPos['y'] + ($dstPos['y'] - $srcPos['y']) * $t - $yOff)),
            ];
        }
    }

    // BFS from all battle systems to assign surrounding nodes to nearest anchor
    $distance    = [];
    $nearestBattle = [];
    $queue = [];
    foreach ($battleNodeIds as $sid) {
        $distance[$sid]     = 0;
        $nearestBattle[$sid] = $sid;
        $queue[] = $sid;
    }
    while ($queue !== []) {
        $cur = array_shift($queue);
        foreach ($adjacency[$cur] as $nb) {
            if (!isset($distance[$nb])) {
                $distance[$nb]      = $distance[$cur] + 1;
                $nearestBattle[$nb] = (int) ($nearestBattle[$cur] ?? $cur);
                $queue[] = $nb;
            }
        }
    }

    // Mark boundary nodes: beyond the requested hops, used only for stub edges.
    // Route-intermediate nodes (on the shortest path between battle systems) are
    // kept as full nodes so the complete route is visible.
    $theaterBoundarySet = [];
    foreach ($nodeIds as $sid) {
        if (!isset($battleSet[$sid]) && !isset($routeNodeSet[$sid]) && ($distance[$sid] ?? PHP_INT_MAX) > $hops) {
            $theaterBoundarySet[$sid] = true;
        }
    }

    // Blocked angles per battle node (directions toward adjacent battle systems)
    $battleNeighborAngles = [];
    foreach ($battleNodeIds as $idx => $sid) {
        $blocked = [];
        if ($idx > 0) {
            $prevSid  = $battleNodeIds[$idx - 1];
            $blocked[] = atan2(
                ((float) $positions[$prevSid]['y']) - ((float) $positions[$sid]['y']),
                ((float) $positions[$prevSid]['x']) - ((float) $positions[$sid]['x'])
            );
        }
        if ($idx < ($battleCount - 1)) {
            $nextSid  = $battleNodeIds[$idx + 1];
            $blocked[] = atan2(
                ((float) $positions[$nextSid]['y']) - ((float) $positions[$sid]['y']),
                ((float) $positions[$nextSid]['x']) - ((float) $positions[$sid]['x'])
            );
        }
        $battleNeighborAngles[$sid] = $blocked;
    }

    // Place surrounding nodes avoiding corridor directions
    $surroundingByAnchor = [];
    foreach ($nodeIds as $sid) {
        if (isset($positions[$sid])) {
            continue;
        }
        $anchorId = (int) ($nearestBattle[$sid] ?? 0);
        if ($anchorId <= 0 || !isset($positions[$anchorId])) {
            $anchorId = (int) ($battleNodeIds[0] ?? 0);
        }
        $surroundingByAnchor[$anchorId][] = ['sid' => $sid, 'hop' => max(1, (int) ($distance[$sid] ?? 1))];
    }

    $exclusionZone = M_PI * 0.28;
    foreach ($surroundingByAnchor as $anchorId => $anchorNodes) {
        $blockedAngles = $battleNeighborAngles[$anchorId] ?? [];
        usort($anchorNodes, static fn(array $a, array $b): int => $a['hop'] <=> $b['hop'] ?: $a['sid'] <=> $b['sid']);
        $byHop = [];
        foreach ($anchorNodes as $ni) {
            $byHop[$ni['hop']][] = $ni['sid'];
        }
        foreach ($byHop as $hop => $hopSids) {
            $n = count($hopSids);
            $radius = 0.11 + ((float) $hop * 0.08);
            $steps = 360;
            $candidates = [];
            for ($step = 0; $step < $steps; $step++) {
                $angle = (2.0 * M_PI / $steps) * $step - M_PI / 2.0;
                $inBlocked = false;
                foreach ($blockedAngles as $ba) {
                    $diff = fmod(abs($angle - $ba), 2.0 * M_PI);
                    if ($diff > M_PI) {
                        $diff = 2.0 * M_PI - $diff;
                    }
                    if ($diff < $exclusionZone) {
                        $inBlocked = true;
                        break;
                    }
                }
                if (!$inBlocked) {
                    $candidates[] = $angle;
                }
            }
            if ($candidates === []) {
                for ($step = 0; $step < $steps; $step++) {
                    $candidates[] = (2.0 * M_PI / $steps) * $step - M_PI / 2.0;
                }
            }
            $nc = count($candidates);
            foreach ($hopSids as $i => $sid) {
                $candidateIdx = min((int) round($i * ($nc / $n)), $nc - 1);
                $angle = $candidates[$candidateIdx];
                $positions[$sid] = [
                    'x' => max(0.03, min(0.97, ((float) $positions[$anchorId]['x']) + cos($angle) * $radius)),
                    'y' => max(0.08, min(0.92, ((float) $positions[$anchorId]['y']) + sin($angle) * $radius * 0.80)),
                ];
            }
        }
    }

    $width  = 900;
    $height = 450;
    $pad    = 28;
    $sx = static fn(float $x): float => $pad + ($x * ($width  - ($pad * 2)));
    $sy = static fn(float $y): float => $pad + ($y * ($height - ($pad * 2)));
    $securityColor = static function(float $sec): string {
        if ($sec >= 0.5) return '#10b981';
        if ($sec > 0.0)  return '#f59e0b';
        return '#ef4444';
    };

    $svg = [];
    $svg[] = '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ' . $width . ' ' . $height . '" style="width:100%;height:auto">';
    $svg[] = '<defs>'
        . '<filter id="battle-glow" x="-40%" y="-40%" width="180%" height="180%">'
        . '<feGaussianBlur stdDeviation="3.5" result="blur"/>'
        . '<feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>'
        . '</filter>'
        . '<style><![CDATA['
        . '.lbl-b{font:700 11px Inter,Segoe UI,sans-serif;fill:#fef3c7}'
        . '.lbl-s{font:500 9.5px Inter,Segoe UI,sans-serif;fill:#cbd5e1}'
        . '.lbl-sec{font:600 8px Inter,Segoe UI,sans-serif;letter-spacing:.04em}'
        . ']]></style>'
        . '</defs>';
    $svg[] = '<rect width="' . $width . '" height="' . $height . '" fill="#04080f"/>';

    // Pass 0: boundary stub edges
    foreach ($edges as $edge) {
        $a = (int) ($edge[0] ?? 0);
        $b = (int) ($edge[1] ?? 0);
        if (!isset($positions[$a], $positions[$b])) {
            continue;
        }
        $aB = isset($theaterBoundarySet[$a]);
        $bB = isset($theaterBoundarySet[$b]);
        if (!$aB && !$bB) {
            continue;
        }
        if ($aB && $bB) {
            continue;
        }
        $rendered = $aB ? $b : $a;
        $boundary = $aB ? $a : $b;
        $rx = $sx((float) $positions[$rendered]['x']);
        $ry = $sy((float) $positions[$rendered]['y']);
        $bx = $sx((float) $positions[$boundary]['x']);
        $by = $sy((float) $positions[$boundary]['y']);
        $mx = $rx + ($bx - $rx) * 0.55;
        $my = $ry + ($by - $ry) * 0.55;
        $svg[] = '<line x1="' . number_format($rx, 2, '.', '') . '" y1="' . number_format($ry, 2, '.', '') . '" x2="' . number_format($mx, 2, '.', '') . '" y2="' . number_format($my, 2, '.', '') . '" stroke="#374151" stroke-opacity="0.35" stroke-width="1.2" stroke-dasharray="4 3"/>';
    }

    // Pass 1: non-battle edges
    $drawnEdges = [];
    foreach ($edges as $edge) {
        $a = (int) ($edge[0] ?? 0);
        $b = (int) ($edge[1] ?? 0);
        if (!isset($positions[$a], $positions[$b])) {
            continue;
        }
        if (isset($theaterBoundarySet[$a]) || isset($theaterBoundarySet[$b])) {
            continue;
        }
        $key = min($a, $b) . ':' . max($a, $b);
        if (isset($drawnEdges[$key]) || isset($battleEdges[$key])) {
            continue;
        }
        $drawnEdges[$key] = true;
        $x1 = number_format($sx((float) $positions[$a]['x']), 2, '.', '');
        $y1 = number_format($sy((float) $positions[$a]['y']), 2, '.', '');
        $x2 = number_format($sx((float) $positions[$b]['x']), 2, '.', '');
        $y2 = number_format($sy((float) $positions[$b]['y']), 2, '.', '');
        $svg[] = '<line x1="' . $x1 . '" y1="' . $y1 . '" x2="' . $x2 . '" y2="' . $y2 . '" stroke="#374151" stroke-opacity="0.7" stroke-width="1.5"/>';
    }

    // Pass 2: battle-system edges (amber glow)
    foreach ($battleEdges as $key => $_) {
        [$a, $b] = array_map('intval', explode(':', $key));
        if (!isset($positions[$a], $positions[$b])) {
            continue;
        }
        $x1 = number_format($sx((float) $positions[$a]['x']), 2, '.', '');
        $y1 = number_format($sy((float) $positions[$a]['y']), 2, '.', '');
        $x2 = number_format($sx((float) $positions[$b]['x']), 2, '.', '');
        $y2 = number_format($sy((float) $positions[$b]['y']), 2, '.', '');
        $svg[] = '<line x1="' . $x1 . '" y1="' . $y1 . '" x2="' . $x2 . '" y2="' . $y2 . '" stroke="#92400e" stroke-opacity="0.45" stroke-width="9" stroke-linecap="round"/>';
        $svg[] = '<line x1="' . $x1 . '" y1="' . $y1 . '" x2="' . $x2 . '" y2="' . $y2 . '" stroke="#fbbf24" stroke-opacity="0.88" stroke-width="2.6" stroke-linecap="round" filter="url(#battle-glow)"/>';
    }

    // Nodes – pill-shaped rounded rectangles with labels inside
    foreach ($nodeMap as $sid => $node) {
        if (!isset($positions[$sid]) || isset($theaterBoundarySet[$sid])) {
            continue;
        }
        $px = $sx((float) $positions[$sid]['x']);
        $py = $sy((float) $positions[$sid]['y']);
        $outer = $securityColor((float) $node['security']);
        $safeName = htmlspecialchars((string) $node['name'], ENT_QUOTES);
        $secFmt   = number_format((float) $node['security'], 1);
        $title    = $safeName . ' | sec=' . $secFmt;
        $titleEsc = htmlspecialchars($title, ENT_QUOTES);
        if ($node['is_battle']) {
            $nameLen = mb_strlen((string) $node['name']);
            $pw = max(82, (int) ($nameLen * 7.8) + 28);
            $ph = 38;
            $rx = (int) ($ph / 2);
            $svg[] = '<g filter="url(#battle-glow)">'
                . '<rect x="' . number_format($px - $pw / 2, 2, '.', '') . '" y="' . number_format($py - $ph / 2, 2, '.', '') . '" width="' . $pw . '" height="' . $ph . '" rx="' . $rx . '" fill="#1a1207" stroke="#fbbf24" stroke-width="2.2" stroke-opacity="0.9"/>'
                . '<text class="lbl-b" x="' . number_format($px, 2, '.', '') . '" y="' . number_format($py - 3, 2, '.', '') . '" text-anchor="middle">' . $safeName . '</text>'
                . '<text class="lbl-sec" x="' . number_format($px, 2, '.', '') . '" y="' . number_format($py + 12, 2, '.', '') . '" text-anchor="middle" fill="#92400e">' . $secFmt . '</text>'
                . '<title>' . $titleEsc . '</title></g>';
        } elseif (isset($routeNodeSet[$sid])) {
            // Route-intermediate node: amber dashed border to distinguish from
            // plain adjacent systems.
            $nameLen = mb_strlen((string) $node['name']);
            $pw = max(70, (int) ($nameLen * 7.2) + 22);
            $ph = 34;
            $rx = (int) ($ph / 2);
            $svg[] = '<g>'
                . '<rect x="' . number_format($px - $pw / 2, 2, '.', '') . '" y="' . number_format($py - $ph / 2, 2, '.', '') . '" width="' . $pw . '" height="' . $ph . '" rx="' . $rx . '" fill="#111827" stroke="#fbbf24" stroke-width="1.5" stroke-opacity="0.8" stroke-dasharray="5 3">'
                . '<title>' . $titleEsc . '</title></rect>'
                . '<text class="lbl-s" x="' . number_format($px, 2, '.', '') . '" y="' . number_format($py - 2, 2, '.', '') . '" text-anchor="middle">' . $safeName . '</text>'
                . '<text class="lbl-sec" x="' . number_format($px, 2, '.', '') . '" y="' . number_format($py + 11, 2, '.', '') . '" text-anchor="middle" fill="' . $outer . '">' . $secFmt . '</text>'
                . '</g>';
        } else {
            $nameLen = mb_strlen((string) $node['name']);
            $pw = max(70, (int) ($nameLen * 7.2) + 22);
            $ph = 34;
            $rx = (int) ($ph / 2);
            $svg[] = '<g filter="url(#battle-glow)">'
                . '<rect x="' . number_format($px - $pw / 2, 2, '.', '') . '" y="' . number_format($py - $ph / 2, 2, '.', '') . '" width="' . $pw . '" height="' . $ph . '" rx="' . $rx . '" fill="#111827" stroke="' . $outer . '" stroke-width="1.8" stroke-opacity="0.9">'
                . '<title>' . $titleEsc . '</title></rect>'
                . '<text class="lbl-s" x="' . number_format($px, 2, '.', '') . '" y="' . number_format($py - 2, 2, '.', '') . '" text-anchor="middle">' . $safeName . '</text>'
                . '<text class="lbl-sec" x="' . number_format($px, 2, '.', '') . '" y="' . number_format($py + 11, 2, '.', '') . '" text-anchor="middle" fill="' . $outer . '">' . $secFmt . '</text>'
                . '</g>';
        }
    }

    // Legend
    $hasRoute = $routeNodeSet !== [];
    $legendRows = $hasRoute ? 3 : 2;
    $lx = $width - $pad - 2;
    $ly = $height - $pad - 4;
    $legendY = $ly - (($legendRows - 1) * 18);
    $svg[] = '<g opacity="0.75">';
    $svg[] = '<rect x="' . ($lx - 120) . '" y="' . ($legendY) . '" width="50" height="16" rx="8" fill="#1a1207" stroke="#fbbf24" stroke-width="1.5"/>'
        . '<text x="' . ($lx - 65) . '" y="' . ($legendY + 12) . '" style="font:500 9px Inter,Segoe UI,sans-serif;fill:#64748b">Battle system</text>';
    if ($hasRoute) {
        $svg[] = '<rect x="' . ($lx - 120) . '" y="' . ($legendY + 18) . '" width="50" height="16" rx="8" fill="#111827" stroke="#fbbf24" stroke-width="1.2" stroke-dasharray="3 2"/>'
            . '<text x="' . ($lx - 65) . '" y="' . ($legendY + 30) . '" style="font:500 9px Inter,Segoe UI,sans-serif;fill:#64748b">Route system</text>';
    }
    $adjY = $legendY + ($hasRoute ? 36 : 18);
    $svg[] = '<rect x="' . ($lx - 120) . '" y="' . ($adjY) . '" width="50" height="16" rx="8" fill="#111827" stroke="#64748b" stroke-width="1.2"/>'
        . '<text x="' . ($lx - 65) . '" y="' . ($adjY + 12) . '" style="font:500 9px Inter,Segoe UI,sans-serif;fill:#64748b">Adjacent system</text>';
    $svg[] = '</g>';

    $svg[] = '</svg>';

    if (@file_put_contents($cacheFile, implode('', $svg)) === false) {
        return null;
    }

    return '/threat-corridors/svg/' . basename($cacheFile);
}

/**
 * Generate a radial neighborhood SVG map.
 *
 * @deprecated Use map_generate_system_neighborhood() from src/map.php instead.
 */
function supplycore_system_area_svg(int $systemId, int $hops = 2): ?string
{
    require_once __DIR__ . '/map.php';
    return map_generate_system_neighborhood($systemId, $hops);
}

/**
 * Legacy implementation — kept for reference during migration.
 * @internal
 */
function _supplycore_system_area_svg_legacy(int $systemId, int $hops = 2): ?string
{
    if ($systemId <= 0) {
        return null;
    }
    $hops = max(1, min(3, $hops));
    $cacheDir = dirname(__DIR__) . '/public/threat-corridors/svg';
    if (!is_dir($cacheDir) && !@mkdir($cacheDir, 0775, true) && !is_dir($cacheDir)) {
        return null;
    }
    $cacheFile = sprintf('%s/system-%d-h%d-v3.svg', $cacheDir, $systemId, $hops);
    $cacheTtl = supplycore_threat_corridor_map_cache_minutes() * 60;
    if (is_file($cacheFile) && ((time() - (int) filemtime($cacheFile)) < $cacheTtl)) {
        return '/threat-corridors/svg/' . basename($cacheFile);
    }

    // Fetch one extra hop for boundary stub edges
    $fetchHops = min(3, $hops + 1);
    $graph = db_threat_corridor_graph_subgraph([$systemId], $fetchHops);
    $nodes = (array) ($graph['nodes'] ?? []);
    $edges = (array) ($graph['edges'] ?? []);
    if ($nodes === []) {
        return null;
    }

    $nodeMap = [];
    foreach ($nodes as $node) {
        $sid = (int) ($node['system_id'] ?? 0);
        if ($sid <= 0) {
            continue;
        }
        $nodeMap[$sid] = [
            'system_id'   => $sid,
            'name'        => (string) ($node['system_name'] ?? (string) $sid),
            'security'    => (float) ($node['security'] ?? 0.0),
            'threat_level' => strtolower((string) ($node['threat_level'] ?? '')),
            'is_focal'    => ($sid === $systemId),
        ];
    }
    if (!isset($nodeMap[$systemId])) {
        return null;
    }

    $nodeIds = array_keys($nodeMap);
    $adjacency = array_fill_keys($nodeIds, []);
    foreach ($edges as $edge) {
        $a = (int) ($edge[0] ?? 0);
        $b = (int) ($edge[1] ?? 0);
        if ($a <= 0 || $b <= 0 || $a === $b || !isset($nodeMap[$a], $nodeMap[$b])) {
            continue;
        }
        $adjacency[$a][] = $b;
        $adjacency[$b][] = $a;
    }

    // BFS from focal to determine hop distances and parents
    $distance = [$systemId => 0];
    $bfsParent = [$systemId => null];
    $queue = [$systemId];
    while ($queue !== []) {
        $cur = array_shift($queue);
        foreach ($adjacency[$cur] as $nb) {
            if (!isset($distance[$nb])) {
                $distance[$nb] = $distance[$cur] + 1;
                $bfsParent[$nb] = $cur;
                $queue[] = $nb;
            }
        }
    }

    // Mark boundary nodes: beyond the requested hops, used only for stub edges
    $areaBoundarySet = [];
    foreach ($nodeIds as $sid) {
        if ($sid !== $systemId && ($distance[$sid] ?? PHP_INT_MAX) > $hops) {
            $areaBoundarySet[$sid] = true;
        }
    }

    // Radial layout: focal at center, hop-1 in inner ring, hop-2 in outer ring
    $positions = [$systemId => ['x' => 0.5, 'y' => 0.5, 'angle' => 0.0]];

    $hop1 = array_values(array_filter($nodeIds, static fn (int $s): bool => ($distance[$s] ?? PHP_INT_MAX) === 1));
    sort($hop1);
    $n1 = count($hop1);
    $r1 = 0.22;
    $parentAngle = [];
    foreach ($hop1 as $i => $sid) {
        $angle = $n1 > 0 ? ((2.0 * M_PI / $n1) * $i - M_PI / 2.0) : 0.0;
        $parentAngle[$sid] = $angle;
        $positions[$sid] = [
            'x'     => max(0.05, min(0.95, 0.5 + cos($angle) * $r1)),
            'y'     => max(0.06, min(0.94, 0.5 + sin($angle) * $r1 * 0.82)),
            'angle' => $angle,
        ];
    }

    $hop2ByParent = [];
    foreach ($nodeIds as $sid) {
        if (($distance[$sid] ?? PHP_INT_MAX) !== 2) {
            continue;
        }
        $par = $bfsParent[$sid] ?? null;
        if ($par === null || !isset($parentAngle[$par])) {
            continue;
        }
        $hop2ByParent[$par][] = $sid;
    }
    $r2 = 0.41;
    $sectorWidth = $n1 > 0 ? (2.0 * M_PI / $n1) : (2.0 * M_PI);
    foreach ($hop2ByParent as $parId => $children) {
        sort($children);
        $nc = count($children);
        $pa = $parentAngle[$parId] ?? 0.0;
        $spread = min($sectorWidth * 0.72, M_PI * 0.55);
        foreach ($children as $ci => $sid) {
            $frac = $nc > 1 ? (($ci / ($nc - 1)) - 0.5) : 0.0;
            $angle = $pa + ($frac * $spread);
            $positions[$sid] = [
                'x'     => max(0.03, min(0.97, 0.5 + cos($angle) * $r2)),
                'y'     => max(0.04, min(0.96, 0.5 + sin($angle) * $r2 * 0.82)),
                'angle' => $angle,
            ];
        }
    }

    // Position boundary nodes (beyond render hops) in an outer ring for stub edge direction
    $r3 = 0.55;
    foreach ($nodeIds as $sid) {
        if (isset($positions[$sid]) || !isset($areaBoundarySet[$sid])) {
            continue;
        }
        $par = $bfsParent[$sid] ?? null;
        if ($par !== null && isset($positions[$par])) {
            $pa = (float) ($positions[$par]['angle'] ?? 0.0);
            $positions[$sid] = [
                'x'     => max(0.01, min(0.99, 0.5 + cos($pa) * $r3)),
                'y'     => max(0.01, min(0.99, 0.5 + sin($pa) * $r3 * 0.82)),
                'angle' => $pa,
            ];
        }
    }

    // Fallback for any orphaned nodes
    foreach ($nodeIds as $sid) {
        if (!isset($positions[$sid])) {
            $positions[$sid] = ['x' => 0.5, 'y' => 0.5, 'angle' => 0.0];
        }
    }

    $width  = 900;
    $height = 700;
    $pad    = 30;
    $sx = static fn (float $x): float => $pad + ($x * ($width  - ($pad * 2)));
    $sy = static fn (float $y): float => $pad + ($y * ($height - ($pad * 2)));
    $securityColor = static function (float $sec): string {
        if ($sec >= 0.5) {
            return '#10b981';
        }
        if ($sec > 0.0) {
            return '#f59e0b';
        }
        return '#ef4444';
    };
    $threatColor = static function (string $tl): string {
        return match ($tl) {
            'critical' => '#ef4444',
            'high'     => '#f97316',
            'medium'   => '#eab308',
            'low'      => '#3b82f6',
            default    => '#94a3b8',
        };
    };

    $svg = [];
    $svg[] = '<svg xmlns="http://www.w3.org/2000/svg" width="' . $width . '" height="' . $height . '" viewBox="0 0 ' . $width . ' ' . $height . '">';
    $svg[] = '<defs>'
        . '<filter id="focal-glow" x="-100%" y="-100%" width="300%" height="300%">'
        . '<feGaussianBlur stdDeviation="5" result="blur"/>'
        . '<feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>'
        . '</filter>'
        . '<filter id="node-glow" x="-60%" y="-60%" width="220%" height="220%">'
        . '<feGaussianBlur stdDeviation="2.2" result="blur"/>'
        . '<feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>'
        . '</filter>'
        . '<style><![CDATA['
        . '.lbl-f{font:700 12px Inter,Segoe UI,sans-serif;fill:#f1f5f9}'
        . '.lbl-f-sub{font:500 9px Inter,Segoe UI,sans-serif;fill:#94a3b8}'
        . '.lbl-1{font:600 10.5px Inter,Segoe UI,sans-serif;fill:#cbd5e1}'
        . '.lbl-2{font:500 9.5px Inter,Segoe UI,sans-serif;fill:#94a3b8}'
        . '.lbl-t{font:600 8px Inter,Segoe UI,sans-serif;letter-spacing:.04em}'
        . ']]></style>'
        . '</defs>';
    $svg[] = '<rect width="' . $width . '" height="' . $height . '" fill="#04080f"/>';

    // Boundary stub edges – short faded lines hinting at off-screen connections
    foreach ($edges as $edge) {
        $a = (int) ($edge[0] ?? 0);
        $b = (int) ($edge[1] ?? 0);
        if (!isset($positions[$a], $positions[$b])) {
            continue;
        }
        $aB = isset($areaBoundarySet[$a]);
        $bB = isset($areaBoundarySet[$b]);
        if (!$aB && !$bB) {
            continue;
        }
        if ($aB && $bB) {
            continue;
        }
        $rendered = $aB ? $b : $a;
        $boundary = $aB ? $a : $b;
        $rx = $sx((float) $positions[$rendered]['x']);
        $ry = $sy((float) $positions[$rendered]['y']);
        $bx = $sx((float) $positions[$boundary]['x']);
        $by = $sy((float) $positions[$boundary]['y']);
        $mx = $rx + ($bx - $rx) * 0.55;
        $my = $ry + ($by - $ry) * 0.55;
        $svg[] = '<line x1="' . number_format($rx, 2, '.', '') . '" y1="' . number_format($ry, 2, '.', '') . '" x2="' . number_format($mx, 2, '.', '') . '" y2="' . number_format($my, 2, '.', '') . '" stroke="#374151" stroke-opacity="0.35" stroke-width="1.2" stroke-dasharray="4 3"/>';
    }

    // Edges: focal→hop1 are slightly brighter; all others dim
    $drawnEdges = [];
    foreach ($edges as $edge) {
        $a = (int) ($edge[0] ?? 0);
        $b = (int) ($edge[1] ?? 0);
        if (!isset($positions[$a], $positions[$b])) {
            continue;
        }
        if (isset($areaBoundarySet[$a]) || isset($areaBoundarySet[$b])) {
            continue;
        }
        $key = min($a, $b) . ':' . max($a, $b);
        if (isset($drawnEdges[$key])) {
            continue;
        }
        $drawnEdges[$key] = true;
        $x1 = number_format($sx((float) $positions[$a]['x']), 2, '.', '');
        $y1 = number_format($sy((float) $positions[$a]['y']), 2, '.', '');
        $x2 = number_format($sx((float) $positions[$b]['x']), 2, '.', '');
        $y2 = number_format($sy((float) $positions[$b]['y']), 2, '.', '');
        if ($a === $systemId || $b === $systemId) {
            $svg[] = '<line x1="' . $x1 . '" y1="' . $y1 . '" x2="' . $x2 . '" y2="' . $y2 . '" stroke="#3b6db5" stroke-opacity="0.85" stroke-width="1.8"/>';
        } else {
            $svg[] = '<line x1="' . $x1 . '" y1="' . $y1 . '" x2="' . $x2 . '" y2="' . $y2 . '" stroke="#374151" stroke-opacity="0.65" stroke-width="1.4"/>';
        }
    }

    // Nodes – pill-shaped rounded rectangles with labels inside
    foreach ($nodeMap as $sid => $node) {
        if (!isset($positions[$sid]) || isset($areaBoundarySet[$sid])) {
            continue;
        }
        $npx  = $sx((float) $positions[$sid]['x']);
        $npy  = $sy((float) $positions[$sid]['y']);
        $outer = $securityColor((float) $node['security']);
        $inner = $threatColor((string) $node['threat_level']);
        $hop  = $distance[$sid] ?? 0;
        $safeName = htmlspecialchars((string) $node['name'], ENT_QUOTES);
        $threatLabel = ($node['threat_level'] !== '') ? strtoupper((string) $node['threat_level']) : '';
        $hasThreat = $threatLabel !== '';
        $secFmt   = number_format((float) $node['security'], 2);
        $titleAttr = $safeName . ' | sec=' . $secFmt . ' | threat=' . ($node['threat_level'] !== '' ? $node['threat_level'] : 'unknown');
        $titleEsc = htmlspecialchars($titleAttr, ENT_QUOTES);

        if ($node['is_focal']) {
            $nameLen = mb_strlen((string) $node['name']);
            $pw = max(90, (int) ($nameLen * 8.2) + 30);
            $ph = $hasThreat ? 42 : 28;
            $rx = (int) ($ph / 2);
            $svg[] = '<g filter="url(#focal-glow)">'
                . '<rect x="' . number_format($npx - $pw / 2, 2, '.', '') . '" y="' . number_format($npy - $ph / 2, 2, '.', '') . '" width="' . $pw . '" height="' . $ph . '" rx="' . $rx . '" fill="#0f172a" stroke="' . $outer . '" stroke-width="2.5" stroke-opacity="0.9"/>'
                . '<text class="lbl-f" x="' . number_format($npx, 2, '.', '') . '" y="' . number_format($npy + ($hasThreat ? -4 : 5), 2, '.', '') . '" text-anchor="middle">' . $safeName . '</text>';
            if ($hasThreat) {
                $svg[] = '<text class="lbl-t" x="' . number_format($npx, 2, '.', '') . '" y="' . number_format($npy + 12, 2, '.', '') . '" text-anchor="middle" fill="' . $inner . '">' . $threatLabel . '</text>';
            }
            $svg[] = '<title>' . $titleEsc . '</title></g>';
        } elseif ($hop === 1) {
            $nameLen = mb_strlen((string) $node['name']);
            $pw = max(72, (int) ($nameLen * 7.2) + 24);
            $ph = $hasThreat ? 36 : 24;
            $rx = (int) ($ph / 2);
            $svg[] = '<g filter="url(#node-glow)">'
                . '<rect x="' . number_format($npx - $pw / 2, 2, '.', '') . '" y="' . number_format($npy - $ph / 2, 2, '.', '') . '" width="' . $pw . '" height="' . $ph . '" rx="' . $rx . '" fill="#0f172a" stroke="' . $outer . '" stroke-width="2.0" stroke-opacity="0.88"/>'
                . '<text class="lbl-1" x="' . number_format($npx, 2, '.', '') . '" y="' . number_format($npy + ($hasThreat ? -2 : 4), 2, '.', '') . '" text-anchor="middle">' . $safeName . '</text>';
            if ($hasThreat) {
                $svg[] = '<text class="lbl-t" x="' . number_format($npx, 2, '.', '') . '" y="' . number_format($npy + 12, 2, '.', '') . '" text-anchor="middle" fill="' . $inner . '">' . $threatLabel . '</text>';
            }
            $svg[] = '<title>' . $titleEsc . '</title></g>';
        } else {
            $nameLen = mb_strlen((string) $node['name']);
            $pw = max(70, (int) ($nameLen * 7.2) + 22);
            $ph = $hasThreat ? 34 : 24;
            $rx = (int) ($ph / 2);
            $svg[] = '<g filter="url(#node-glow)">'
                . '<rect x="' . number_format($npx - $pw / 2, 2, '.', '') . '" y="' . number_format($npy - $ph / 2, 2, '.', '') . '" width="' . $pw . '" height="' . $ph . '" rx="' . $rx . '" fill="#111827" stroke="' . $outer . '" stroke-width="1.8" stroke-opacity="0.9">'
                . '<title>' . $titleEsc . '</title></rect>'
                . '<text class="lbl-2" x="' . number_format($npx, 2, '.', '') . '" y="' . number_format($npy + ($hasThreat ? -1 : 4), 2, '.', '') . '" text-anchor="middle">' . $safeName . '</text>';
            if ($hasThreat) {
                $svg[] = '<text class="lbl-t" x="' . number_format($npx, 2, '.', '') . '" y="' . number_format($npy + 11, 2, '.', '') . '" text-anchor="middle" fill="' . $inner . '">' . $threatLabel . '</text>';
            }
            $svg[] = '</g>';
        }
    }

    // Legend
    $lx = $width - $pad - 2;
    $ly = $height - $pad - 2;
    $svg[] = '<g opacity="0.7">'
        . '<text x="' . $lx . '" y="' . ($ly - 58) . '" text-anchor="end" style="font:600 9px Inter,Segoe UI,sans-serif;fill:#475569;letter-spacing:.06em">SECURITY</text>'
        . '<rect x="' . ($lx - 100) . '" y="' . ($ly - 50) . '" width="40" height="14" rx="7" fill="#111827" stroke="#10b981" stroke-width="1.3"/>'
        . '<text x="' . ($lx - 55) . '" y="' . ($ly - 39) . '" style="font:500 9px Inter,Segoe UI,sans-serif;fill:#64748b">High-sec (&ge;0.5)</text>'
        . '<rect x="' . ($lx - 100) . '" y="' . ($ly - 34) . '" width="40" height="14" rx="7" fill="#111827" stroke="#f59e0b" stroke-width="1.3"/>'
        . '<text x="' . ($lx - 55) . '" y="' . ($ly - 23) . '" style="font:500 9px Inter,Segoe UI,sans-serif;fill:#64748b">Low-sec (0&ndash;0.5)</text>'
        . '<rect x="' . ($lx - 100) . '" y="' . ($ly - 18) . '" width="40" height="14" rx="7" fill="#111827" stroke="#ef4444" stroke-width="1.3"/>'
        . '<text x="' . ($lx - 55) . '" y="' . ($ly - 7) . '" style="font:500 9px Inter,Segoe UI,sans-serif;fill:#64748b">Null-sec (&le;0)</text>'
        . '</g>';

    $svg[] = '</svg>';

    if (@file_put_contents($cacheFile, implode('', $svg)) === false) {
        return null;
    }

    return '/threat-corridors/svg/' . basename($cacheFile);
}

// ---------------------------------------------------------------------------
//  CSV Fit & Doctrine Group Importer
// ---------------------------------------------------------------------------

/**
 * Best-effort extraction of doctrine group labels from WinterCo-style fit names.
 *
 * Fit names typically follow the pattern:
 *   [YYMMDD] [WC|WC-EN|WCEN|FRT] [DoctrineName][-Role] [ShipName] [vX.X] [- Variant]
 *
 * Examples:
 *   "2407 WC Shield Keres v2.0 - AB Refit"           → Shield
 *   "2202 WC AHACs-DPS Deimos v1.2"                  → AHACs
 *   "2211 WC Kikistuka-Logi Kirin v1.1 MWD/..."      → Kikistuka
 *   "2301 WC TFI - Links Damnation v1.2"             → TFI
 *   "2202 WC Hurricane - Bellicose - Ewar"            → Hurricane
 *   "WC-EN - Shield Web Loki (AB refit) v1.0"        → Shield
 *   "2206 WCEN Entosis - Drake V1.0"                  → Entosis
 *   "2403 WC-EN Bombing Purifier v3.0"                → Bombing
 *   "2307 WC Retri-Links Pontifex v1.1"               → Retri
 *
 * The ship name (from the CSV ship_name column) is used as an anchor to isolate
 * the doctrine context that precedes it. Known role keywords (DPS, Logi, Links,
 * etc.) are stripped to surface just the doctrine family name.
 *
 * Returns an array of detected labels (usually zero or one).
 */
/**
 * Handle the edge case where the ship name is at position 0 or absent.
 *
 * When the ship name starts the cleaned string (e.g. "Hurricane T2 - DPS"),
 * it may itself be the doctrine name if role/variant text follows.
 * When the ship name is not found at all, we attempt to split the text
 * on known separators and look for a recognizable doctrine compound.
 */
/**
 * Extract the doctrine family name from the text that precedes the ship name.
 *
 * Splits on " - " (spaced dashes) to separate major segments, then within
 * each segment handles hyphen-compounds (e.g. "AHACs-DPS" → "AHACs").
 * Known role keywords are stripped; the first meaningful segment is returned.
 */
/**
 * Strip known role keywords from the edges of a space-separated label.
 *
 * "Shield DPS LR" → "Shield"
 * "Fast Tackle" → "Fast Tackle" (both are role-ish, keep original)
 * "Ewar" → "" (pure role)
 */
/**
 * Canonical list of role / modifier keywords that describe a fit's role
 * within a doctrine, not the doctrine name itself.
 *
 * @return string[] Lowercase keywords.
 */

// ────────────────────────────────────────────────────────────────────────────
// Opposition Daily Intelligence — AI Briefing System
// ────────────────────────────────────────────────────────────────────────────

function opposition_ai_system_prompt(): string
{
    $config = supplycore_ai_ollama_config();
    $provider = (string) ($config['provider'] ?? 'local');

    if ($provider === 'claude' || $provider === 'groq') {
        return "You are a military intelligence analyst producing daily SITREP briefings for an EVE Online alliance command.\n\n"
             . "INSTRUCTIONS:\n"
             . "- Analyze opposition force activity using only the provided data.\n"
             . "- Write in a professional intelligence briefing style. Use terms like 'opposition forces', 'hostile entities', 'enemy formations'.\n"
             . "- The data represents hostile alliances we are actively monitoring. Write from our perspective as intelligence analysts.\n"
             . "- Generate a DETAILED, COMPREHENSIVE briefing (800-1500 words in the summary field).\n"
             . "- Use markdown formatting: ## for section headers, **bold** for emphasis, - for bullet points.\n"
             . "- Reference specific alliances, systems, regions, ship types, and ISK values from the data.\n"
             . "- When historical context is provided, identify trends and changes from previous days.\n"
             . "- Do NOT invent engagements, pilots, systems, or events not present in the data.\n"
             . "- Return valid JSON matching the required schema.";
    }

    // Concise prompt for local Ollama (CPU-friendly, e.g. Gemma 4 e4b)
    return "You are a military intelligence analyst producing daily SITREP briefings for an EVE Online alliance.\n\n"
         . "INSTRUCTIONS:\n"
         . "- Write a clear, structured intelligence briefing (300-600 words).\n"
         . "- Professional military intel style. Use 'opposition forces', 'hostile entities'.\n"
         . "- Use ## headers, **bold**, and - bullets.\n"
         . "- Reference alliances, systems, ISK values from the data.\n"
         . "- Identify trends if historical data is provided.\n"
         . "- Do not invent data not present in the provided facts.\n"
         . "- Return valid JSON matching the required schema.";
}

function opposition_ai_output_schema(): array
{
    $config = supplycore_ai_ollama_config();
    $provider = (string) ($config['provider'] ?? 'local');

    if ($provider === 'claude' || $provider === 'groq') {
        $summaryDesc = 'Full structured SITREP briefing (800-1500 words). Cover: active opponents, geographic presence, fleet compositions, coalition dynamics, threat level. Use markdown: ## for headers, **bold** for emphasis, - for bullets.';
    } else {
        $summaryDesc = 'Structured SITREP briefing (300-600 words). Cover key opposition activity. Use markdown: ## for headers, **bold** for emphasis, - for bullets.';
    }

    return [
        'type' => 'object',
        'required' => ['headline', 'summary', 'key_developments', 'threat_assessment', 'action_items'],
        'properties' => [
            'headline' => [
                'type' => 'string',
                'description' => 'One-line SITREP summary (max 100 chars). Example: "SITREP: Increased hostile activity in Delve — 3 alliances active"',
            ],
            'summary' => [
                'type' => 'string',
                'description' => $summaryDesc,
            ],
            'key_developments' => [
                'type' => 'string',
                'description' => '3-5 bullet points of the most notable changes or events. Markdown bullet list.',
            ],
            'threat_assessment' => [
                'type' => 'string',
                'enum' => ['low', 'moderate', 'elevated', 'high', 'critical'],
                'description' => 'Overall threat level based on opposition activity.',
            ],
            'action_items' => [
                'type' => 'string',
                'description' => '1-3 recommended responses based on the data. Markdown bullet list.',
            ],
        ],
        'additionalProperties' => false,
    ];
}

function opposition_ai_history_days(): int
{
    $strategy = supplycore_ai_strategy();
    $tier = (string) ($strategy['tier'] ?? 'small');
    $configured = trim((string) get_setting('opposition_intel_history_days', 'auto'));

    if ($configured !== '' && $configured !== 'auto' && is_numeric($configured)) {
        return max(1, min(14, (int) $configured));
    }

    return match ($tier) {
        'small' => 3,
        default => 7,
    };
}

function opposition_ai_briefing_history(string $date, int $days): array
{
    $strategy = supplycore_ai_strategy();
    $tier = (string) ($strategy['tier'] ?? 'small');

    $briefings = db_opposition_daily_briefings_recent($days + 1);
    $history = [];
    foreach ($briefings as $b) {
        if (($b['briefing_date'] ?? '') >= $date) {
            continue;
        }
        $entry = ['date' => $b['briefing_date'], 'headline' => $b['headline'] ?? ''];
        if ($tier !== 'small') {
            $entry['key_developments'] = $b['key_developments'] ?? '';
            $entry['threat_assessment'] = $b['threat_assessment'] ?? '';
        }
        if ($tier === 'large') {
            $summary = $b['summary'] ?? '';
            $entry['summary_excerpt'] = mb_substr($summary, 0, 500);
        }
        $history[] = $entry;
    }
    return array_slice($history, 0, $days);
}

function opposition_ai_compute_deltas(array $todaySnapshots, string $date): array
{
    $yesterday = date('Y-m-d', strtotime($date . ' -1 day'));
    $yesterdaySnapshots = db_opposition_daily_snapshots($yesterday);

    $yesterdayMap = [];
    foreach ($yesterdaySnapshots as $s) {
        $yesterdayMap[(int) $s['alliance_id']] = $s;
    }

    $todayMap = [];
    foreach ($todaySnapshots as $s) {
        $todayMap[(int) $s['alliance_id']] = $s;
    }

    $deltas = [
        'new_alliances' => [],
        'gone_quiet' => [],
        'activity_spikes' => [],
        'posture_changes' => [],
        'new_systems' => [],
    ];

    foreach ($todayMap as $aid => $today) {
        if (!isset($yesterdayMap[$aid])) {
            if (((int) ($today['kills'] ?? 0)) > 0 || ((int) ($today['losses'] ?? 0)) > 0) {
                $deltas['new_alliances'][] = $today['alliance_name'] ?? "Alliance #$aid";
            }
            continue;
        }
        $yest = $yesterdayMap[$aid];

        // Activity spike detection (>2x)
        $todayKills = (int) ($today['kills'] ?? 0);
        $yestKills = (int) ($yest['kills'] ?? 0);
        if ($todayKills > 5 && $yestKills > 0 && $todayKills > $yestKills * 2) {
            $deltas['activity_spikes'][] = ($today['alliance_name'] ?? "Alliance #$aid") . " ($yestKills → $todayKills kills)";
        }

        // Posture changes
        $todayPosture = $today['posture'] ?? '';
        $yestPosture = $yest['posture'] ?? '';
        if ($todayPosture !== '' && $yestPosture !== '' && $todayPosture !== $yestPosture) {
            $deltas['posture_changes'][] = ($today['alliance_name'] ?? "Alliance #$aid") . " ($yestPosture → $todayPosture)";
        }
    }

    foreach ($yesterdayMap as $aid => $yest) {
        if (!isset($todayMap[$aid]) || ((int) ($todayMap[$aid]['kills'] ?? 0)) === 0) {
            if (((int) ($yest['kills'] ?? 0)) > 3) {
                $deltas['gone_quiet'][] = $yest['alliance_name'] ?? "Alliance #$aid";
            }
        }
    }

    return $deltas;
}

function opposition_ai_global_prompt(string $date, array $snapshots, array $history, array $deltas): string
{
    $strategy = supplycore_ai_strategy();
    $tier = (string) ($strategy['tier'] ?? 'small');

    $prompt = ["Generate a daily opposition intelligence SITREP for $date."];
    $prompt[] = '';
    $prompt[] = 'CURRENT DAY DATA:';
    $prompt[] = json_encode($snapshots, ($tier === 'small' ? 0 : JSON_PRETTY_PRINT) | JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);

    if ($history !== []) {
        $prompt[] = '';
        $prompt[] = 'HISTORICAL CONTEXT (previous ' . count($history) . ' days):';
        $prompt[] = json_encode($history, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
    }

    $hasDeltas = array_filter($deltas, static fn (array $v): bool => $v !== []);
    if ($hasDeltas !== []) {
        $prompt[] = '';
        $prompt[] = 'CHANGES DETECTED:';
        $prompt[] = json_encode($deltas, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
    }

    $prompt[] = '';
    $prompt[] = 'OUTPUT SECTIONS:';
    $prompt[] = '1. headline — one-line sitrep (max 100 chars)';
    $prompt[] = '2. key_developments — 3-5 bullet points of notable changes';
    $prompt[] = '3. summary — structured briefing covering: active opponents, where they operate, what they fly, coalition dynamics, threat level';
    $prompt[] = '4. threat_assessment — one of: low, moderate, elevated, high, critical';
    $prompt[] = '5. action_items — 1-3 recommended responses';

    return implode("\n", $prompt);
}

function opposition_ai_alliance_prompt(int $allianceId, string $allianceName, string $date, array $todaySnapshot, array $history, array $relationships): string
{
    $prompt = ["Generate a daily intelligence profile for $allianceName (ID: $allianceId) on $date."];
    $prompt[] = '';
    $prompt[] = "TODAY'S ACTIVITY:";
    $prompt[] = json_encode($todaySnapshot, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);

    if ($history !== []) {
        $prompt[] = '';
        $prompt[] = 'LAST ' . count($history) . ' DAYS:';
        $prompt[] = json_encode($history, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
    }

    if ($relationships !== []) {
        $prompt[] = '';
        $prompt[] = 'RELATIONSHIP CONTEXT:';
        $prompt[] = json_encode($relationships, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE);
    }

    $prompt[] = '';
    $prompt[] = 'OUTPUT: headline, summary, key_developments, threat_assessment, action_items';

    return implode("\n", $prompt);
}

function opposition_ai_validate_response(array $response): array
{
    $headline = mb_substr(trim((string) ($response['headline'] ?? '')), 0, 255);
    $summary = mb_substr(trim((string) ($response['summary'] ?? '')), 0, 16000);
    $keyDev = mb_substr(trim((string) ($response['key_developments'] ?? '')), 0, 4000);
    $threat = trim((string) ($response['threat_assessment'] ?? 'moderate'));
    $actions = mb_substr(trim((string) ($response['action_items'] ?? '')), 0, 4000);

    if ($summary === '') {
        throw new RuntimeException('AI response is missing the summary field.');
    }
    if ($headline === '') {
        $headline = mb_substr($summary, 0, 100);
    }
    if (!in_array($threat, ['low', 'moderate', 'elevated', 'high', 'critical'], true)) {
        $threat = 'moderate';
    }

    return [
        'headline' => $headline,
        'summary' => $summary,
        'key_developments' => $keyDev,
        'threat_assessment' => $threat,
        'action_items' => $actions,
    ];
}

function opposition_ai_fallback_response(array $snapshots, string $type = 'global', ?string $allianceName = null): array
{
    $totalKills = 0;
    $totalLosses = 0;
    $totalIsk = 0;
    $activeAlliances = 0;
    $allSystems = [];

    foreach ($snapshots as $s) {
        $kills = (int) ($s['kills'] ?? 0);
        $losses = (int) ($s['losses'] ?? 0);
        $totalKills += $kills;
        $totalLosses += $losses;
        $totalIsk += (float) ($s['isk_destroyed'] ?? 0);
        if ($kills > 0 || $losses > 0) {
            $activeAlliances++;
        }
        $systems = $s['active_systems_json'] ?? $s['active_systems'] ?? [];
        if (is_string($systems)) {
            $systems = json_decode($systems, true) ?: [];
        }
        foreach ($systems as $sys) {
            $allSystems[] = $sys['system_name'] ?? '';
        }
    }
    $allSystems = array_unique(array_filter($allSystems));

    if ($type === 'alliance') {
        $s = $snapshots[0] ?? [];
        $kills = (int) ($s['kills'] ?? 0);
        $losses = (int) ($s['losses'] ?? 0);
        $name = $allianceName ?: ($s['alliance_name'] ?? 'Unknown');
        return [
            'headline' => "$name: {$kills} kills, {$losses} losses",
            'summary' => "$name recorded {$kills} kills and {$losses} losses. " . ($kills > $losses ? 'Net positive engagement ratio.' : 'Sustained notable losses.'),
            'key_developments' => "- {$kills} kills, {$losses} losses recorded\n- Posture: " . ($s['posture'] ?? 'unknown'),
            'threat_assessment' => $kills > 10 ? 'elevated' : ($kills > 3 ? 'moderate' : 'low'),
            'action_items' => '- Monitor activity in next reporting period.',
            '_fallback_reason' => 'AI disabled or unavailable',
        ];
    }

    $iskFormatted = number_format($totalIsk / 1_000_000, 0) . 'M';
    $topSystems = implode(', ', array_slice($allSystems, 0, 3));

    // Determine threat level from activity
    $threat = 'low';
    if ($totalKills > 50) {
        $threat = 'critical';
    } elseif ($totalKills > 30) {
        $threat = 'high';
    } elseif ($totalKills > 15) {
        $threat = 'elevated';
    } elseif ($totalKills > 5) {
        $threat = 'moderate';
    }

    // Top alliances by kills
    $sorted = $snapshots;
    usort($sorted, static fn ($a, $b): int => ((int) ($b['kills'] ?? 0)) - ((int) ($a['kills'] ?? 0)));
    $topAlliances = array_map(static fn ($s): string => ($s['alliance_name'] ?? 'Unknown') . ' (' . ($s['kills'] ?? 0) . ' kills)', array_slice($sorted, 0, 3));

    return [
        'headline' => "Opposition Activity: {$totalKills} kills across {$activeAlliances} alliances",
        'summary' => "Opposition forces recorded {$totalKills} kills and {$totalLosses} losses totalling {$iskFormatted} ISK destroyed across {$activeAlliances} active alliances."
                    . ($topSystems !== '' ? " Primary areas of operation: {$topSystems}." : ''),
        'key_developments' => "- " . implode("\n- ", array_filter($topAlliances)),
        'threat_assessment' => $threat,
        'action_items' => '- Monitor opposition activity and review operational posture.',
        '_fallback_reason' => 'AI disabled or unavailable',
    ];
}

function opposition_ai_call_provider(string $systemPrompt, string $userPrompt, array $schema): array
{
    $config = supplycore_ai_ollama_config();
    $provider = (string) ($config['provider'] ?? 'local');

    if ($provider === 'claude') {
        return supplycore_ai_claude_generate_json($config, $systemPrompt, $userPrompt, $schema);
    }
    if ($provider === 'groq') {
        return supplycore_ai_groq_generate_json($config, $systemPrompt, $userPrompt, $schema);
    }
    if ($provider === 'runpod') {
        return supplycore_ai_runpod_generate_json($config, $systemPrompt, $userPrompt, $schema);
    }

    // Local Ollama
    $endpoint = $config['url'] . '/generate';
    $requestPayload = [
        'model' => $config['model'],
        'stream' => false,
        'system' => $systemPrompt,
        'prompt' => $userPrompt,
        'format' => $schema,
        // Opposition briefings historically used a slightly higher
        // temperature (0.3) for more varied phrasing.
        'options' => supplycore_ai_ollama_request_options($config, ['temperature' => 0.3]),
    ];
    $response = http_post_json($endpoint, [], $requestPayload, max(300, $config['timeout']));
    $status = (int) ($response['status'] ?? 0);
    $json = is_array($response['json'] ?? null) ? $response['json'] : [];
    if ($status < 200 || $status >= 300) {
        throw new RuntimeException('Ollama returned HTTP ' . $status);
    }
    $rawResponse = trim((string) ($json['response'] ?? ''));
    if ($rawResponse === '') {
        throw new RuntimeException('Ollama returned empty response');
    }
    $decoded = json_decode($rawResponse, true);
    if (!is_array($decoded)) {
        throw new RuntimeException('Ollama returned malformed JSON');
    }
    return $decoded;
}

function opposition_ai_generate_single(string $type, string $date, string $systemPrompt, string $userPrompt, array $schema, ?int $allianceId = null, ?string $allianceName = null): array
{
    $config = supplycore_ai_ollama_config();
    $provider = (string) ($config['provider'] ?? 'local');
    $decoded = null;

    try {
        $decoded = opposition_ai_call_provider($systemPrompt, $userPrompt, $schema);
        $validated = opposition_ai_validate_response($decoded);

        $modelLabel = match ($provider) {
            'runpod' => (string) ($config['runpod_model'] ?? $config['model'] ?? ''),
            'claude' => (string) ($config['claude_model'] ?? 'claude-sonnet-4-20250514'),
            'groq' => (string) ($config['groq_model'] ?? 'llama-4-scout'),
            default => (string) $config['model'],
        };

        return [
            'briefing_date' => $date,
            'briefing_type' => $type,
            'alliance_id' => $allianceId,
            'alliance_name' => $allianceName,
            'generation_status' => 'ready',
            'model_name' => $modelLabel,
            'headline' => $validated['headline'],
            'summary' => $validated['summary'],
            'key_developments' => $validated['key_developments'],
            'threat_assessment' => $validated['threat_assessment'],
            'action_items' => $validated['action_items'],
            'source_payload_json' => json_encode(['system_prompt' => $systemPrompt, 'user_prompt' => mb_substr($userPrompt, 0, 4000)], JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
            'response_json' => json_encode($decoded, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
            'error_message' => null,
            'computed_at' => gmdate('Y-m-d H:i:s'),
        ];
    } catch (Throwable $e) {
        // Preserve the raw AI response so operators can see exactly what
        // came back when validation fails (wrong schema, empty fields,
        // markdown fences wrapping the JSON, etc.).
        $rawResponseJson = is_array($decoded)
            ? json_encode($decoded, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE)
            : null;

        error_log('[opposition-ai] Failed to generate ' . $type . ' briefing: ' . $e->getMessage()
            . ($rawResponseJson !== null ? ' | raw_response=' . mb_substr((string) $rawResponseJson, 0, 2000) : ''));

        return [
            'briefing_date' => $date,
            'briefing_type' => $type,
            'alliance_id' => $allianceId,
            'alliance_name' => $allianceName,
            'generation_status' => 'failed',
            'model_name' => null,
            'headline' => null,
            'summary' => null,
            'key_developments' => null,
            'threat_assessment' => null,
            'action_items' => null,
            'source_payload_json' => json_encode(['system_prompt' => $systemPrompt, 'user_prompt' => mb_substr($userPrompt, 0, 4000)], JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
            'response_json' => $rawResponseJson,
            'error_message' => mb_substr($e->getMessage(), 0, 500),
            'computed_at' => gmdate('Y-m-d H:i:s'),
        ];
    }
}

function opposition_ai_generate_daily_briefings(?string $date = null): int
{
    $date = $date ?: gmdate('Y-m-d');
    $snapshots = db_opposition_daily_snapshots($date);
    $generated = 0;

    if ($snapshots === []) {
        error_log('[opposition-ai] No snapshots found for ' . $date);
        return 0;
    }

    $systemPrompt = opposition_ai_system_prompt();
    $schema = opposition_ai_output_schema();
    $historyDays = opposition_ai_history_days();

    // Concurrency lock
    $lockFile = sys_get_temp_dir() . '/supplycore_ai_generation.lock';
    $lockFp = fopen($lockFile, 'c');
    if ($lockFp === false || !flock($lockFp, LOCK_EX | LOCK_NB)) {
        if ($lockFp !== false) {
            fclose($lockFp);
        }
        error_log('[opposition-ai] Another AI generation is running, skipping');
        return 0;
    }

    try {
        $aiEnabled = supplycore_ai_ollama_enabled();

        // 1. Global SITREP
        if ($aiEnabled) {
            $history = opposition_ai_briefing_history($date, $historyDays);
            $deltas = opposition_ai_compute_deltas($snapshots, $date);
            $userPrompt = opposition_ai_global_prompt($date, $snapshots, $history, $deltas);
            $briefing = opposition_ai_generate_single('global', $date, $systemPrompt, $userPrompt, $schema);
        } else {
            $fallback = opposition_ai_fallback_response($snapshots, 'global');
            $briefing = [
                'briefing_date' => $date,
                'briefing_type' => 'global',
                'alliance_id' => null,
                'alliance_name' => null,
                'generation_status' => 'fallback',
                'model_name' => 'deterministic-fallback-v1',
                'headline' => $fallback['headline'],
                'summary' => $fallback['summary'],
                'key_developments' => $fallback['key_developments'],
                'threat_assessment' => $fallback['threat_assessment'],
                'action_items' => $fallback['action_items'],
                'source_payload_json' => null,
                'response_json' => null,
                'error_message' => null,
                'computed_at' => gmdate('Y-m-d H:i:s'),
            ];
        }

        // If AI failed, use fallback
        if (($briefing['generation_status'] ?? '') === 'failed') {
            $fallback = opposition_ai_fallback_response($snapshots, 'global');
            $briefing['generation_status'] = 'fallback';
            $briefing['model_name'] = 'deterministic-fallback-v1';
            $briefing['headline'] = $fallback['headline'];
            $briefing['summary'] = $fallback['summary'];
            $briefing['key_developments'] = $fallback['key_developments'];
            $briefing['threat_assessment'] = $fallback['threat_assessment'];
            $briefing['action_items'] = $fallback['action_items'];
        }

        db_opposition_daily_briefing_save($briefing);
        $generated++;

        // 2. Per-alliance briefings (only for tracked alliances)
        $trackedAlliances = db_opposition_intel_tracked_alliances();
        $trackedIds = array_map(static fn ($a): int => (int) $a['alliance_id'], $trackedAlliances);
        $trackedNames = [];
        foreach ($trackedAlliances as $a) {
            $trackedNames[(int) $a['alliance_id']] = (string) $a['alliance_name'];
        }

        $snapshotMap = [];
        foreach ($snapshots as $s) {
            $snapshotMap[(int) $s['alliance_id']] = $s;
        }

        foreach ($trackedIds as $aid) {
            if (!isset($snapshotMap[$aid])) {
                continue;
            }
            $allianceName = $trackedNames[$aid] ?? "Alliance #$aid";

            if ($aiEnabled) {
                $allianceHistory = db_opposition_daily_snapshot_alliance($aid, $date, $historyDays);
                $relationships = [
                    'allies' => $snapshotMap[$aid]['allies_json'] ?? [],
                    'enemies' => $snapshotMap[$aid]['enemies_json'] ?? [],
                ];
                $userPrompt = opposition_ai_alliance_prompt($aid, $allianceName, $date, $snapshotMap[$aid], $allianceHistory, $relationships);
                $allianceBriefing = opposition_ai_generate_single('alliance', $date, $systemPrompt, $userPrompt, $schema, $aid, $allianceName);
            } else {
                $fallback = opposition_ai_fallback_response([$snapshotMap[$aid]], 'alliance', $allianceName);
                $allianceBriefing = [
                    'briefing_date' => $date,
                    'briefing_type' => 'alliance',
                    'alliance_id' => $aid,
                    'alliance_name' => $allianceName,
                    'generation_status' => 'fallback',
                    'model_name' => 'deterministic-fallback-v1',
                    'headline' => $fallback['headline'],
                    'summary' => $fallback['summary'],
                    'key_developments' => $fallback['key_developments'],
                    'threat_assessment' => $fallback['threat_assessment'],
                    'action_items' => $fallback['action_items'],
                    'source_payload_json' => null,
                    'response_json' => null,
                    'error_message' => null,
                    'computed_at' => gmdate('Y-m-d H:i:s'),
                ];
            }

            // Fallback on failure
            if (($allianceBriefing['generation_status'] ?? '') === 'failed') {
                $fallback = opposition_ai_fallback_response([$snapshotMap[$aid]], 'alliance', $allianceName);
                $allianceBriefing['generation_status'] = 'fallback';
                $allianceBriefing['model_name'] = 'deterministic-fallback-v1';
                $allianceBriefing['headline'] = $fallback['headline'];
                $allianceBriefing['summary'] = $fallback['summary'];
                $allianceBriefing['key_developments'] = $fallback['key_developments'];
                $allianceBriefing['threat_assessment'] = $fallback['threat_assessment'];
                $allianceBriefing['action_items'] = $fallback['action_items'];
            }

            db_opposition_daily_briefing_save($allianceBriefing);
            $generated++;
        }
    } finally {
        flock($lockFp, LOCK_UN);
        fclose($lockFp);
    }

    return $generated;
}


function supplycore_markdown_to_html(string $raw): string
{
    $rendered = htmlspecialchars($raw, ENT_QUOTES);
    // Bold and italic
    $rendered = preg_replace('/\*\*(.+?)\*\*/', '<strong>$1</strong>', $rendered);
    $rendered = preg_replace('/\*(.+?)\*/', '<em>$1</em>', $rendered);
    // Markdown headers
    $rendered = preg_replace('/^###\s+(.+)$/m', '<h4>$1</h4>', $rendered);
    $rendered = preg_replace('/^##\s+(.+)$/m', '<h3>$1</h3>', $rendered);
    // Numbered section headers: 1. **Title**
    $rendered = preg_replace('/^(\d+)\.\s*<strong>(.+?)<\/strong>/m', '<h3>$1. $2</h3>', $rendered);
    // Bullet lists
    $rendered = preg_replace_callback('/(?:^- .+$\n?)+/m', static function (array $m): string {
        $items = preg_split('/\n/', trim($m[0]));
        $lis = '';
        foreach ($items as $item) {
            $text = preg_replace('/^- /', '', $item);
            if ($text !== '') {
                $lis .= '<li>' . $text . '</li>';
            }
        }
        return '<ul>' . $lis . '</ul>';
    }, $rendered);
    // Numbered lists
    $rendered = preg_replace_callback('/(?:^\d+\.\s+.+$\n?)+/m', static function (array $m): string {
        $items = preg_split('/\n/', trim($m[0]));
        $lis = '';
        foreach ($items as $item) {
            $text = preg_replace('/^\d+\.\s+/', '', $item);
            if ($text !== '') {
                $lis .= '<li>' . $text . '</li>';
            }
        }
        return '<ol>' . $lis . '</ol>';
    }, $rendered);
    // Paragraphs
    $rendered = preg_replace('/\n{2,}/', '</p><p>', $rendered);
    $rendered = str_replace("\n", '<br>', $rendered);
    return '<p>' . $rendered . '</p>';
}
